	public class TimeoutWebClient : System.Net.WebClient
	{
		public int TimeoutMs { get; set; } = 5000;

		protected override System.Net.WebRequest GetWebRequest (Uri address)
		{
			System.Net.WebRequest webRequest = base.GetWebRequest (address);
			if (webRequest != null) {
				webRequest.Timeout = TimeoutMs;
			}
			return webRequest;
		}
	}


	public static class SoundEffects

	{

		private static bool _isEnabled = true;



		private static bool _isMuted = false;



		private static double _volume = 1.0;



		private static SoundPlayer _hoverPlayer;



		private static SoundPlayer _poofPlayer;



		private static SoundPlayer _swooshPlayer;



		public static double Volume {

			get {

				return _volume;

			}

			set {

				_volume = Math.Max (0.0, Math.Min (1.0, value));

				if (_isEnabled) {

					Initialize (_isEnabled);

				}

			}

		}



		public static bool IsMuted {

			get {

				return _isMuted;

			}

			set {

				_isMuted = value;

			}

		}



		public static void Initialize (bool enabled)

		{

			_isEnabled = enabled;

			try {

				_hoverPlayer = new SoundPlayer (new MemoryStream (ScaleVolume (GenerateClickWav (), _volume)));

				_hoverPlayer.Load ();

				_poofPlayer = new SoundPlayer (new MemoryStream (ScaleVolume (GeneratePoofWav (), _volume)));

				_poofPlayer.Load ();

				_swooshPlayer = new SoundPlayer (new MemoryStream (ScaleVolume (GenerateSwooshWav (), _volume)));

				_swooshPlayer.Load ();

			} catch {

			}

		}



		public static void SetEnabled (bool enabled)

		{

			_isEnabled = enabled;

			if (_isEnabled && _hoverPlayer == null) {

				Initialize (enabled: true);

			}

		}



		private static byte[] ScaleVolume (byte[] wav, double vol)

		{

			if (vol >= 0.99 || wav == null || wav.Length <= 44) {

				return wav;

			}

			byte[] array = new byte[wav.Length];

			Array.Copy (wav, array, 44);

			for (int i = 44; i < wav.Length; i++) {

				double num = (double)(wav [i] - 128) * vol;

				array [i] = (byte)Math.Max (0, Math.Min (255, 128 + (int)num));

			}

			return array;

		}



		public static void PlayHover ()

		{

			if (!_isEnabled || _isMuted || _hoverPlayer == null) {

				return;

			}

			try {

				_hoverPlayer.Play ();

			} catch {

			}

		}



		public static void PlayPoof ()

		{

			if (!_isEnabled || _isMuted || _poofPlayer == null) {

				return;

			}

			try {

				_poofPlayer.Play ();

			} catch {

			}

		}



		public static void PlaySwoosh ()

		{

			if (!_isEnabled || _isMuted || _swooshPlayer == null) {

				return;

			}

			try {

				_swooshPlayer.Play ();

			} catch {

			}

		}



		private static byte[] GenerateClickWav ()

		{

			int num = 22050;

			double num2 = 0.015;

			int num3 = (int)((double)num * num2);

			byte[] array = new byte[num3];

			for (int i = 0; i < num3; i++) {

				double num4 = (double)i / (double)num;

				double num5 = Math.Sin (Math.PI * 3600.0 * num4) * Math.Exp (-250.0 * num4);

				array [i] = (byte)(128 + (int)(32.0 * num5));

			}

			return BuildWav (array, num);

		}



		private static byte[] GeneratePoofWav ()

		{

			int num = 22050;

			double num2 = 0.35;

			int num3 = (int)((double)num * num2);

			byte[] array = new byte[num3];

			Random random = new Random ();

			for (int i = 0; i < num3; i++) {

				double num4 = (double)i / (double)num;

				double num5 = 0.0;

				num5 = ((!(num4 < 0.08)) ? Math.Exp (-8.0 * (num4 - 0.08)) : (num4 / 0.08));

				double num6 = random.NextDouble () * 2.0 - 1.0;

				array [i] = (byte)(128 + (int)(25.0 * num6 * num5));

			}

			return BuildWav (array, num);

		}



		private static byte[] GenerateSwooshWav ()

		{

			int num = 22050;

			double num2 = 0.25;

			int num3 = (int)((double)num * num2);

			byte[] array = new byte[num3];

			double num4 = 0.0;

			for (int i = 0; i < num3; i++) {

				double num5 = (double)i / (double)num;

				double num6 = 120.0 + 260.0 * (num5 / num2);

				num4 += Math.PI * 2.0 * num6 / (double)num;

				double num7 = Math.Sin (Math.PI * (num5 / num2));

				double num8 = Math.Sin (num4) * num7;

				array [i] = (byte)(128 + (int)(35.0 * num8));

			}

			return BuildWav (array, num);

		}



		private static byte[] BuildWav (byte[] data, int sampleRate)

		{

			byte[] array = new byte[44];

			array [0] = 82;

			array [1] = 73;

			array [2] = 70;

			array [3] = 70;

			Array.Copy (BitConverter.GetBytes (data.Length + 36), 0, array, 4, 4);

			array [8] = 87;

			array [9] = 65;

			array [10] = 86;

			array [11] = 69;

			array [12] = 102;

			array [13] = 109;

			array [14] = 116;

			array [15] = 32;

			Array.Copy (BitConverter.GetBytes (16), 0, array, 16, 4);

			array [20] = 1;

			array [21] = 0;

			array [22] = 1;

			array [23] = 0;

			Array.Copy (BitConverter.GetBytes (sampleRate), 0, array, 24, 4);

			Array.Copy (BitConverter.GetBytes (sampleRate), 0, array, 28, 4);

			array [32] = 1;

			array [33] = 0;

			array [34] = 8;

			array [35] = 0;

			array [36] = 100;

			array [37] = 97;

			array [38] = 116;

			array [39] = 97;

			Array.Copy (BitConverter.GetBytes (data.Length), 0, array, 40, 4);

			byte[] array2 = new byte[44 + data.Length];

			Array.Copy (array, 0, array2, 0, 44);

			Array.Copy (data, 0, array2, 44, data.Length);

			return array2;

		}

	}

