					return !settings.PerformanceMode;

				}

				return false;

			}

		}



		private double baseSize => settings.BaseSize;



		private double maxSize => settings.MaxSize;



		private double range => (settings == null || settings.Range <= 40.0 || double.IsNaN (settings.Range)) ? 160.0 : settings.Range;



		public double lerpFactor => settings.AnimationSpeedValue switch {

			1 => 0.14, 

			2 => 0.24, 

			4 => 0.48, 

			5 => 0.62, 

			_ => 0.35, 

		};



		private TimeSpan slideDuration => settings.AnimationSpeedValue switch {

			1 => TimeSpan.FromMilliseconds (650.0), 

			2 => TimeSpan.FromMilliseconds (450.0), 

