		public static bool MoveToRecycleBin (string filePath)

		{

			try {

				if (!File.Exists (filePath) && !Directory.Exists (filePath)) {

					return false;

				}

				SHFILEOPSTRUCT lpFileOp = default(SHFILEOPSTRUCT);

				lpFileOp.hwnd = IntPtr.Zero;

				lpFileOp.wFunc = 3u;

				lpFileOp.pFrom = filePath + "\0\0";

				lpFileOp.pTo = null;

				lpFileOp.fFlags = 84;

				lpFileOp.fAnyOperationsAborted = false;

				lpFileOp.hNameMappings = IntPtr.Zero;

				lpFileOp.lpszProgressTitle = null;

				return SHFileOperation (ref lpFileOp) == 0 && !lpFileOp.fAnyOperationsAborted;

			} catch {

				return false;

			}

		}



