		public void ToggleControlCenterWindow ()

		{

			if (controlCenterOverlay == null) {

				controlCenterOverlay = new ControlCenterWindow (this);

			}

			if (controlCenterOverlay.IsVisible) {

				controlCenterOverlay.Hide ();

				return;

			}

			System.Windows.Point point = PhysicalToLogical (PointToScreen (new System.Windows.Point (0.0, 0.0)), this);

			if (settings.Position == "Left") {

				controlCenterOverlay.Left = point.X + base.ActualWidth + 8.0 - 20.0;

				controlCenterOverlay.Top = point.Y + (base.ActualHeight - controlCenterOverlay.Height) / 2.0;

			} else if (settings.Position == "Right") {

				controlCenterOverlay.Left = point.X - controlCenterOverlay.Width - 8.0 + 20.0;

				controlCenterOverlay.Top = point.Y + (base.ActualHeight - controlCenterOverlay.Height) / 2.0;

			} else if (settings.Position == "Top") {

				controlCenterOverlay.Left = point.X + (base.ActualWidth - controlCenterOverlay.Width) / 2.0;

				controlCenterOverlay.Top = point.Y + base.ActualHeight + 8.0 - 20.0;

			} else {

				controlCenterOverlay.Left = point.X + (base.ActualWidth - controlCenterOverlay.Width) - 10.0 + 20.0;

				controlCenterOverlay.Top = point.Y - controlCenterOverlay.Height - 8.0 + 20.0;

			}

			controlCenterOverlay.Show ();

			controlCenterOverlay.Activate ();

		}



