		private IntPtr HwndHook (IntPtr hwnd, int msg, IntPtr wParam, IntPtr lParam, ref bool handled)
		{
			if (msg == 0x0021) {
				handled = true;
				return (IntPtr)3;
			}
			if (msg == 786) {
				int hotkeyId = wParam.ToInt32 ();
				if (hotkeyId == 9009) {
					ToggleAIAssistant ();
					handled = true;
				} else if (hotkeyId == 9010 || hotkeyId == 9011) {
					ToggleSearchWindow ();
					handled = true;
				} else if (hotkeyId == 9012) {
					ToggleLaunchpad ();
					handled = true;
				}
			}
			return IntPtr.Zero;
		}



		private static bool TryParseJsonDouble (string json, string key, out double value)

		{

