				return false;

			}

			int i;

			for (i = num + key.Length; i < json.Length && (json [i] == ':' || json [i] == ' '); i++) {

			}

			int j;

			for (j = i; j < json.Length && json [j] != ',' && json [j] != '}' && json [j] != ']'; j++) {

			}

			return double.TryParse (json.Substring (i, j - i).Trim (), NumberStyles.Any, CultureInfo.InvariantCulture, out value);

		}



		private static string ExtractJsonString (string json, string key)

		{

