		private void AnimateOverlayShow (Window overlay, double targetLeft, double targetTop, string position)

		{

			overlay.Opacity = 0.0;

			if (position.ToLower () == "bottom") {

				overlay.Top = targetTop + 15.0;

			} else if (position.ToLower () == "top") {

				overlay.Top = targetTop - 15.0;

			} else {

				overlay.Top = targetTop;

			}

			if (position.ToLower () == "left") {

				overlay.Left = targetLeft - 15.0;

			} else if (position.ToLower () == "right") {

				overlay.Left = targetLeft + 15.0;

			} else {

				overlay.Left = targetLeft;

			}

			overlay.Show ();

			DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (250.0)) {

				EasingFunction = new QuadraticEase {

					EasingMode = EasingMode.EaseOut

				}

			};

			overlay.BeginAnimation (UIElement.OpacityProperty, animation);

			if (position.ToLower () == "bottom" || position.ToLower () == "top") {

				DoubleAnimation animation2 = new DoubleAnimation (overlay.Top, targetTop, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new QuadraticEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				overlay.BeginAnimation (Window.TopProperty, animation2);

			} else {

				DoubleAnimation animation3 = new DoubleAnimation (overlay.Left, targetLeft, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new QuadraticEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				overlay.BeginAnimation (Window.LeftProperty, animation3);

			}

		}



		private void AnimateOverlayHide (Window overlay, string position)

		{

			DoubleAnimation doubleAnimation = new DoubleAnimation (overlay.Opacity, 0.0, TimeSpan.FromMilliseconds (200.0)) {

				EasingFunction = new QuadraticEase {

					EasingMode = EasingMode.EaseIn

				}

			};

			double num = overlay.Top;

			double num2 = overlay.Left;

			if (position.ToLower () == "bottom") {

				num += 15.0;

			} else if (position.ToLower () == "top") {

				num -= 15.0;

			} else if (position.ToLower () == "left") {

				num2 -= 15.0;

			} else if (position.ToLower () == "right") {

				num2 += 15.0;

			}

			if (position.ToLower () == "bottom" || position.ToLower () == "top") {

				DoubleAnimation animation = new DoubleAnimation (overlay.Top, num, TimeSpan.FromMilliseconds (200.0)) {

					EasingFunction = new QuadraticEase {

						EasingMode = EasingMode.EaseIn

					}

				};

				overlay.BeginAnimation (Window.TopProperty, animation);

			} else {

				DoubleAnimation animation2 = new DoubleAnimation (overlay.Left, num2, TimeSpan.FromMilliseconds (200.0)) {

					EasingFunction = new QuadraticEase {

						EasingMode = EasingMode.EaseIn

					}

				};

				overlay.BeginAnimation (Window.LeftProperty, animation2);

			}

			doubleAnimation.Completed += delegate {

				overlay.Hide ();

			};

			overlay.BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

		}



