		{

			if (previewOverlayTimer != null) {

				previewOverlayTimer.Stop ();

			}

			if (targetItem.TargetHwnd == IntPtr.Zero) {

				return;

			}

			if (previewOverlay == null) {

				previewOverlay = new WindowPreviewOverlay (this);

				previewOverlay.MouseEnter += delegate {

					if (previewOverlayTimer != null) {

						previewOverlayTimer.Stop ();

					}

				};

				previewOverlay.MouseLeave += delegate {

					StartHideWindowPreview ();

				};

			}

			try {

				System.Windows.Point point = PhysicalToLogical (targetItem.PointToScreen (new System.Windows.Point (0.0, 0.0)), targetItem);

				if (settings.Position == "Left") {

					previewOverlay.Left = point.X + targetItem.ActualWidth + 8.0 - 20.0;

					previewOverlay.Top = point.Y + (targetItem.ActualHeight - previewOverlay.Height) / 2.0;

				} else if (settings.Position == "Right") {

					previewOverlay.Left = point.X - previewOverlay.Width - 8.0 + 20.0;

					previewOverlay.Top = point.Y + (targetItem.ActualHeight - previewOverlay.Height) / 2.0;

				} else if (settings.Position == "Top") {

					previewOverlay.Left = point.X + (targetItem.ActualWidth - previewOverlay.Width) / 2.0;

					previewOverlay.Top = point.Y + targetItem.ActualHeight + 8.0 - 20.0;

				} else {

					previewOverlay.Left = point.X + (targetItem.ActualWidth - previewOverlay.Width) / 2.0;

					previewOverlay.Top = point.Y - previewOverlay.Height - 8.0 + 20.0;

				}

				double primaryScreenWidth = SystemParameters.PrimaryScreenWidth;

				double primaryScreenHeight = SystemParameters.PrimaryScreenHeight;

				if (previewOverlay.Left < 0.0) {

					previewOverlay.Left = 0.0;

				}

				if (previewOverlay.Left + previewOverlay.Width > primaryScreenWidth) {

					previewOverlay.Left = primaryScreenWidth - previewOverlay.Width;

				}

				if (previewOverlay.Top < 0.0) {

					previewOverlay.Top = 0.0;

				}

				if (previewOverlay.Top + previewOverlay.Height > primaryScreenHeight) {

					previewOverlay.Top = primaryScreenHeight - previewOverlay.Height;

				}

				previewOverlay.ShowPreview (targetItem.TargetHwnd, targetItem.Config.Name);

			} catch {

			}

		}



