		public bool IsMousePhysicallyOverDock ()

		{

			try {

				if (dockBorder == null || !dockBorder.IsLoaded) {

					return false;

				}

				System.Windows.Point position = Mouse.GetPosition (dockBorder);

				return position.X >= 0.0 && position.X <= dockBorder.ActualWidth && 

				       position.Y >= 0.0 && position.Y <= dockBorder.ActualHeight;

			} catch {

			}

			return false;

		}

		public bool IsMousePhysicallyOverDock (System.Windows.Point mousePosInWindow)
		{
			if (dockBorder == null || !dockBorder.IsLoaded || settings == null) {
				return false;
			}
			
			double x = 0.0;
			double y = 0.0;
			double w = dockBorder.ActualWidth;
			double h = dockBorder.ActualHeight;
			string position = settings.Position ?? "Bottom";

			if (position == "Left") {
				x = dockBorder.Margin.Left;
				y = (this.ActualHeight - h) / 2.0;
			} else if (position == "Right") {
				x = this.ActualWidth - w - dockBorder.Margin.Right;
				y = (this.ActualHeight - h) / 2.0;
			} else if (position == "Top") {
				x = (this.ActualWidth - w) / 2.0;
				y = dockBorder.Margin.Top;
			} else { // Bottom
				x = (this.ActualWidth - w) / 2.0;
				y = this.ActualHeight - h - dockBorder.Margin.Bottom;
			}

			return mousePosInWindow.X >= x && mousePosInWindow.X <= x + w &&
			       mousePosInWindow.Y >= y && mousePosInWindow.Y <= y + h;
		}



		public System.Windows.Point PhysicalToLogical (System.Windows.Point physicalPoint, Visual visual)

		{

			PresentationSource presentationSource = PresentationSource.FromVisual (visual);

			double num = ((presentationSource != null && presentationSource.CompositionTarget != null) ? presentationSource.CompositionTarget.TransformToDevice.M11 : 1.0);

			double num2 = ((presentationSource != null && presentationSource.CompositionTarget != null) ? presentationSource.CompositionTarget.TransformToDevice.M22 : 1.0);

			return new System.Windows.Point (physicalPoint.X / num, physicalPoint.Y / num2);

		}



		private void RepositionWindow ()

		{

			Screen[] allScreens = Screen.AllScreens;

			int num = settings.MonitorIndex;

			if (num < 0 || num >= allScreens.Length) {

				num = 0;

			}

			Screen screen = allScreens [num];

			double num2 = SystemParameters.PrimaryScreenWidth;

			double num3 = SystemParameters.PrimaryScreenHeight;

			double num4 = 0.0;

			double num5 = 0.0;

			if (num != 0) {

				double num6 = (double)allScreens [0].Bounds.Width / SystemParameters.PrimaryScreenWidth;

				num2 = (double)screen.Bounds.Width / num6;

				num3 = (double)screen.Bounds.Height / num6;

				num4 = (double)screen.Bounds.X / num6;

				num5 = (double)screen.Bounds.Y / num6;

			}

			if (string.IsNullOrEmpty (settings.Position)) {

				settings.Position = "Bottom";

			}

			if (settings.Position == "Left") {

				base.Width = 260.0;

				base.Height = num3;

				base.Left = num4;

				base.Top = num5;

				dockBorder.HorizontalAlignment = System.Windows.HorizontalAlignment.Left;

				dockBorder.VerticalAlignment = VerticalAlignment.Center;

				dockBorder.Margin = new Thickness (12.0, 0.0, 0.0, 0.0);

				dockPanel.Orientation = System.Windows.Controls.Orientation.Vertical;

				hotzone.Width = 12.0;

				hotzone.Height = double.NaN;

				hotzone.HorizontalAlignment = System.Windows.HorizontalAlignment.Left;

				hotzone.VerticalAlignment = VerticalAlignment.Stretch;

			} else if (settings.Position == "Right") {

				base.Width = 260.0;

				base.Height = num3;

				base.Left = num4 + num2 - base.Width;

				base.Top = num5;

				dockBorder.HorizontalAlignment = System.Windows.HorizontalAlignment.Right;

				dockBorder.VerticalAlignment = VerticalAlignment.Center;

				dockBorder.Margin = new Thickness (0.0, 0.0, 12.0, 0.0);

				dockPanel.Orientation = System.Windows.Controls.Orientation.Vertical;

				hotzone.Width = 12.0;

				hotzone.Height = double.NaN;

				hotzone.HorizontalAlignment = System.Windows.HorizontalAlignment.Right;

				hotzone.VerticalAlignment = VerticalAlignment.Stretch;

			} else if (settings.Position == "Top") {

				base.Width = num2;

				base.Height = 260.0;

				base.Left = num4;

				base.Top = num5;

				dockBorder.HorizontalAlignment = System.Windows.HorizontalAlignment.Center;

				dockBorder.VerticalAlignment = VerticalAlignment.Top;

				dockBorder.Margin = new Thickness (0.0, 12.0, 0.0, 0.0);

				dockPanel.Orientation = System.Windows.Controls.Orientation.Horizontal;

				hotzone.Height = 12.0;

				hotzone.Width = double.NaN;

				hotzone.HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch;

				hotzone.VerticalAlignment = VerticalAlignment.Top;

			} else {

				base.Width = num2;

				base.Height = 260.0;

				base.Left = num4;

				base.Top = num5 + num3 - base.Height;

				dockBorder.HorizontalAlignment = System.Windows.HorizontalAlignment.Center;

				dockBorder.VerticalAlignment = VerticalAlignment.Bottom;

				dockBorder.Margin = new Thickness (0.0, 0.0, 0.0, 48.0);

				dockPanel.Orientation = System.Windows.Controls.Orientation.Horizontal;

				hotzone.Height = 12.0;

				hotzone.Width = double.NaN;

				hotzone.HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch;

				hotzone.VerticalAlignment = VerticalAlignment.Bottom;

			}

			if (dockSlideTransform != null) {

				dockSlideTransform.X = 0.0;

				dockSlideTransform.Y = 0.0;

			}

			bool isHorizontal = (settings.Position == "Bottom" || settings.Position == "Top");
			if (dockBorder != null) {
			dockBorder.Padding = isHorizontal ? new Thickness (16.0, 10.0, 16.0, 10.0) : new Thickness (14.0, 16.0, 14.0, 16.0);
			}

			if (dockPanel != null) {
				foreach (UIElement child in dockPanel.Children) {
					if (child is DockItemControl dic) {
						dic.Margin = isHorizontal ? new Thickness (5.0, 0.0, 5.0, 0.0) : new Thickness (0.0, 5.0, 0.0, 5.0);
					}
				}
			}

			UpdateHotzoneDimensions ();

		}



		private void UpdateHotzoneDimensions ()

		{

			if (hotzone == null || dockBorder == null) {

				return;

			}

			try {

				if (settings.Position == "Bottom" || settings.Position == "Top") {

					hotzone.Width = double.NaN;

					hotzone.Height = 24.0;

					hotzone.HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch;

					hotzone.VerticalAlignment = ((settings.Position == "Bottom") ? VerticalAlignment.Bottom : VerticalAlignment.Top);

				} else {

					hotzone.Height = double.NaN;

					hotzone.Width = 24.0;

					hotzone.VerticalAlignment = VerticalAlignment.Stretch;

					hotzone.HorizontalAlignment = ((!(settings.Position == "Left")) ? System.Windows.HorizontalAlignment.Right : System.Windows.HorizontalAlignment.Left);

				}

			} catch {

			}

		}



		private double GetHideTargetValue (out DependencyProperty propToAnimate)

		{

			double result = 0.0;

			propToAnimate = TranslateTransform.YProperty;

			if (settings.Position == "Bottom") {

				result = ((dockBorder.ActualHeight > 0.0) ? dockBorder.ActualHeight : 80.0) + dockBorder.Margin.Bottom + 12.0;

				propToAnimate = TranslateTransform.YProperty;

			} else if (settings.Position == "Top") {

				result = 0.0 - (((dockBorder.ActualHeight > 0.0) ? dockBorder.ActualHeight : 80.0) + dockBorder.Margin.Top + 12.0);

				propToAnimate = TranslateTransform.YProperty;

			} else if (settings.Position == "Left") {

				result = 0.0 - (((dockBorder.ActualWidth > 0.0) ? dockBorder.ActualWidth : 80.0) + dockBorder.Margin.Left + 12.0);

				propToAnimate = TranslateTransform.XProperty;

			} else if (settings.Position == "Right") {

				result = ((dockBorder.ActualWidth > 0.0) ? dockBorder.ActualWidth : 80.0) + dockBorder.Margin.Right + 12.0;

				propToAnimate = TranslateTransform.XProperty;

			}

			return result;

		}



		private void UpdateHideTranslation ()

		{

			if (!isDockHidden) {

				return;

			}

			DependencyProperty propToAnimate;

			double hideTargetValue = GetHideTargetValue (out propToAnimate);

			if (propToAnimate == null) {

				return;

			}

			try {

				dockSlideTransform.BeginAnimation (propToAnimate, null);

				if (propToAnimate == TranslateTransform.XProperty) {

					dockSlideTransform.X = hideTargetValue;

				} else {

					dockSlideTransform.Y = hideTargetValue;

				}

			} catch {

			}

		}



		private void LoadSettings ()

		{

			string path = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "config.json");

			if (File.Exists (path)) {

				try {

					using (FileStream stream = File.OpenRead (path)) {

						DataContractJsonSerializer dataContractJsonSerializer = new DataContractJsonSerializer (typeof(DockSettings));

						settings = (DockSettings)dataContractJsonSerializer.ReadObject ((Stream)stream);

					}

					try {

						string text = File.ReadAllText (path);

						bool flag = false;

						if (!text.Contains ("AutoHide")) {

							settings.AutoHide = true;

							flag = true;

						}

						if (!text.Contains ("Position")) {

							settings.Position = "Bottom";

							flag = true;

						}

						if (!text.Contains ("AnimationsEnabled")) {

							settings.AnimationsEnabled = true;

							flag = true;

						}

						if (!text.Contains ("AnimationSpeedValue")) {

							settings.AnimationSpeedValue = 3;

							flag = true;

						}

						if (!text.Contains ("PerformanceMode")) {

							settings.PerformanceMode = false;

							flag = true;

						}

						if (!text.Contains ("SpotifyClientId")) {

							settings.SpotifyClientId = "";

							flag = true;

						}

						if (!text.Contains ("ShowLyricsOnFullscreen")) {

							settings.ShowLyricsOnFullscreen = false;

							flag = true;

