				settings.GlassOpacity = 0.7;

			}

			if (settings.AutoHideDelay < 1 || settings.AutoHideDelay > 15) {

				settings.AutoHideDelay = 5;

			}

			if (settings.TargetFPS != 30 && settings.TargetFPS != 60 && settings.TargetFPS != 120 && settings.TargetFPS != 240) {

				settings.TargetFPS = 240;

			}

		}



