		public static void SetAutoStart (bool enable)

		{

			try {

				using RegistryKey registryKey = Registry.CurrentUser.OpenSubKey ("Software\\Microsoft\\Windows\\CurrentVersion\\Run", writable: true);

				if (registryKey == null) {

					return;

				}

				if (enable) {

					string fileName = Process.GetCurrentProcess ().MainModule.FileName;

					registryKey.SetValue ("MacStyleDock", "\"" + fileName + "\"");

					return;

				}

				try {

					registryKey.DeleteValue ("MacStyleDock", throwOnMissingValue: false);

				} catch {

				}

			} catch {

			}

		}



		public void ApplySettings (DockSettings newSettings)

		{

			bool needsRebuild = (_lastAppliedPosition != newSettings.Position) ||

			                    (_lastAppliedMonitorIndex != newSettings.MonitorIndex) ||

			                    (!_lastAppliedShowRecentApps.HasValue || _lastAppliedShowRecentApps.Value != newSettings.ShowRecentApps) ||

			                    (_lastAppliedItemsCount != (newSettings.Items != null ? newSettings.Items.Count : 0)) ||

			                    (!_lastAppliedEnableLiveWeather.HasValue || _lastAppliedEnableLiveWeather.Value != newSettings.EnableLiveWeather) ||

			                    (!_lastAppliedEnableControlCenter.HasValue || _lastAppliedEnableControlCenter.Value != newSettings.EnableControlCenter) ||

			                    (!_lastAppliedShowLaunchpad.HasValue || _lastAppliedShowLaunchpad.Value != newSettings.ShowLaunchpad) ||

			                    (!_lastAppliedShowCalendarWidget.HasValue || _lastAppliedShowCalendarWidget.Value != newSettings.ShowCalendarWidget) ||

			                    (!_lastAppliedShowClockWidget.HasValue || _lastAppliedShowClockWidget.Value != newSettings.ShowClockWidget) ||

			                    (!_lastAppliedBaseSize.HasValue || _lastAppliedBaseSize.Value != newSettings.BaseSize) ||

			                    (!_lastAppliedMaxSize.HasValue || _lastAppliedMaxSize.Value != newSettings.MaxSize);

			_lastAppliedPosition = newSettings.Position;

			_lastAppliedMonitorIndex = newSettings.MonitorIndex;

			_lastAppliedShowRecentApps = newSettings.ShowRecentApps;

			_lastAppliedItemsCount = newSettings.Items != null ? newSettings.Items.Count : 0;

			_lastAppliedEnableLiveWeather = newSettings.EnableLiveWeather;

			_lastAppliedEnableControlCenter = newSettings.EnableControlCenter;

			_lastAppliedShowLaunchpad = newSettings.ShowLaunchpad;

			_lastAppliedShowCalendarWidget = newSettings.ShowCalendarWidget;

			_lastAppliedShowClockWidget = newSettings.ShowClockWidget;

			_lastAppliedBaseSize = newSettings.BaseSize;

			_lastAppliedMaxSize = newSettings.MaxSize;

			settings = newSettings;

			SoundEffects.SetEnabled (newSettings.EnableMicroSounds);

			SoundEffects.IsMuted = newSettings.SoundsMuted;

			SoundEffects.Volume = ((newSettings.SoundVolume > 0.0) ? newSettings.SoundVolume : 1.0);

			SaveSettings ();

			GenieEffect.IsEnabled = newSettings.EnableGenieEffect;

			SetAutoStart (newSettings.AutoStart);

			RepositionWindow ();

			if (controlCenterOverlay != null) {

				try {

					controlCenterOverlay.Close ();

				} catch {

				}

				controlCenterOverlay = null;

			}

			if (weatherOverlay != null) {

				try {

					weatherOverlay.Close ();

				} catch {

				}

				weatherOverlay = null;

			}

			if (settings.EnableLiveWeather) {

				FetchWeatherBackground ();

			}

			if (mediaOverlay != null) {

				try {

					mediaOverlay.Close ();

				} catch {

				}

				mediaOverlay = null;

			}

			if (searchWindow != null) {

				try {

					searchWindow.Close ();

				} catch {

				}

				searchWindow = null;

			}

			if (previewOverlay != null) {

				try {

					previewOverlay.Close ();

				} catch {

				}

				previewOverlay = null;

			}

			if (newSettings.EnableVoiceCommands) {

				StartSpeechManager ();

			} else {

				StopSpeechManager ();

			}

			if (needsRebuild) {

				RebuildDockUI ();

			} else {

				ApplyTheme ();

			}

			CreateDockContextMenu ();

			ApplyAutoHideState ();

			UpdateSpotifyDockIcon (null);

		}



		public void PlayLaunchGlow (DockItemControl item)

		{

			try {

				if (!IsAnimationEnabled || dockBorder == null || item == null) {

					return;

				}

				Grid contentGrid = dockBorder.Child as Grid;

				if (contentGrid == null) {

					return;

				}

				System.Windows.Point point = item.TransformToVisual (dockBorder).Transform (new System.Windows.Point (item.ActualWidth / 2.0, item.ActualHeight));

				string effectiveTheme = GetEffectiveTheme ();

				System.Windows.Media.Color color = ((effectiveTheme == "light") ? System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue) : ((effectiveTheme == "tahoe") ? System.Windows.Media.Color.FromRgb (218, 0, byte.MaxValue) : System.Windows.Media.Color.FromRgb (0, 200, byte.MaxValue)));

				Ellipse glowEllipse = new Ellipse {

					Width = 80.0,

					Height = 22.0,

					Fill = new RadialGradientBrush (new GradientStopCollection {

						new GradientStop (System.Windows.Media.Color.FromArgb (190, color.R, color.G, color.B), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (0, color.R, color.G, color.B), 1.0)

					}),

					HorizontalAlignment = System.Windows.HorizontalAlignment.Left,

					VerticalAlignment = VerticalAlignment.Top,

					IsHitTestVisible = false,

					Margin = new Thickness (Math.Max (0.0, point.X - 40.0), Math.Max (0.0, point.Y - 10.0), 0.0, 0.0)

				};

				contentGrid.Children.Add (glowEllipse);

				ScaleTransform scaleTransform = new ScaleTransform (1.0, 1.0, 40.0, 11.0);

				glowEllipse.RenderTransform = scaleTransform;

				DoubleAnimation doubleAnimation = new DoubleAnimation (0.95, 0.0, TimeSpan.FromMilliseconds (700.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				doubleAnimation.Completed += delegate {

					try {

						contentGrid.Children.Remove (glowEllipse);

					} catch {

					}

				};

				glowEllipse.BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

				DoubleAnimation animation = new DoubleAnimation (1.0, 2.5, TimeSpan.FromMilliseconds (700.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, animation);

				scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, animation);

			} catch {

			}

		}



		private void UpdateClockWidget ()

		{

			try {

				if (_clockLabel != null) {

					_clockLabel.Text = DateTime.Now.ToString ("HH:mm");

				}

				if (_batteryLabel == null) {

					return;

				}

				try {

					PowerStatus powerStatus = SystemInformation.PowerStatus;

					int num = (int)(powerStatus.BatteryLifePercent * 100f);

					string text = ((powerStatus.PowerLineStatus == System.Windows.Forms.PowerLineStatus.Online) ? " âš¡" : "");

					_batteryLabel.Text = ((num >= 0 && num <= 100) ? (num + "%" + text) : "");

				} catch {

					if (_batteryLabel != null) {

						_batteryLabel.Text = "";

					}

				}

			} catch {

			}

		}



		private void OnDockMouseWheel (object sender, MouseWheelEventArgs e)

		{

			try {

				if ((DateTime.Now - _lastDockScrollTime).TotalMilliseconds < 180.0) {

					e.Handled = true;

					return;

				}

				_lastDockScrollTime = DateTime.Now;

				List<DockItemControl> list = (from it in dockItems.Concat (runningItems)

					where it != null && it.TargetHwnd != IntPtr.Zero

					select it).ToList ();

				if (list.Count != 0) {

					int num = ((e.Delta <= 0) ? 1 : (-1));

					IntPtr fg = GetForegroundWindow ();

					int index = ((list.FindIndex ((DockItemControl it) => it.TargetHwnd == fg) + num) % list.Count + list.Count) % list.Count;

					DockItemControl dockItemControl = list [index];

					if (IsIconic (dockItemControl.TargetHwnd)) {

						ShowWindow (dockItemControl.TargetHwnd, 9);

					}

					SetForegroundWindow (dockItemControl.TargetHwnd);

					e.Handled = true;

				}

			} catch {

			}

		}



		public void UpdateSpotifyDockIcon (ImageSource customImage)

		{

			try {

				foreach (DockItemControl item in (from item in dockItems.Concat (runningItems)

					where item.Config.ProcessName.ToLower () == "spotify" || item.Config.Name.ToLower ().Contains ("spotify")

					select item).ToList ()) {

					if (settings.ShowSpotifyAlbumArt && customImage != null) {

						item.IconImage.Source = customImage;

					} else {

						item.LoadIcon ();

					}

				}

			} catch {

			}

		}



		public void ToggleSearchWindow ()

		{

			if (searchWindow == null) {

				searchWindow = new FinderSearchWindow (this);

			}

			if (searchWindow.IsVisible) {

				searchWindow.Hide ();

				return;

			}

			double primaryScreenWidth = SystemParameters.PrimaryScreenWidth;

			double primaryScreenHeight = SystemParameters.PrimaryScreenHeight;

			searchWindow.Left = (primaryScreenWidth - searchWindow.Width) / 2.0;

			searchWindow.Top = primaryScreenHeight * 0.15;

			searchWindow.ApplyTheme ();

			searchWindow.Show ();

			searchWindow.Activate ();

		}



		public void QueryRecycleBinState ()

		{

			if (trashItemControl == null) {

				return;

			}

			try {

				SHQUERYRBINFO pSHQueryRBInfo = default(SHQUERYRBINFO);

				pSHQueryRBInfo.cbSize = Marshal.SizeOf (typeof(SHQUERYRBINFO));

				bool isFull = SHQueryRecycleBin (null, ref pSHQueryRBInfo) == 0 && pSHQueryRBInfo.i64NumItems > 0;

				trashItemControl.UpdateTrashIconState (isFull);

			} catch {

			}

		}



		private bool IsCalendarItem (DockItemControl item)
		{
			if (item == null || item.Config == null) {
				return false;
			}
			string name = (item.Config.Name ?? "").ToLower ();
			string processName = (item.Config.ProcessName ?? "").ToLower ();
			string filePath = (item.Config.FilePath ?? "").ToLower ();
			return name.Contains ("calendar") || processName.Contains ("calendar") || filePath.Contains ("calendar");
		}

		public void UpdateCalendarIconState ()
		{
			_lastCalendarDay = DateTime.Now.Day;
			List<DockItemControl> list = dockItems.Concat (runningItems).Where (IsCalendarItem).ToList ();
			foreach (DockItemControl current in list) {
				Grid container = current.VisualContainer;
				if (container.Opacity > 0.1) {
					DoubleAnimation doubleAnimation = new DoubleAnimation (container.Opacity, 0.0, TimeSpan.FromMilliseconds (150.0));
					DockItemControl closureItem = current;
					doubleAnimation.Completed += delegate {
						UpdateCalendarIconStateInternal (closureItem);
						DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (150.0));
						container.BeginAnimation (UIElement.OpacityProperty, animation);
					};
					container.BeginAnimation (UIElement.OpacityProperty, doubleAnimation);
				} else {
					UpdateCalendarIconStateInternal (current);
				}
			}
		}

		private void UpdateCalendarIconStateInternal (DockItemControl dockItemControl)
