				};
				System.Windows.Shapes.Rectangle element = new System.Windows.Shapes.Rectangle {
					Width = 48.0,
					Height = 48.0,
					RadiusX = 11.0,
					RadiusY = 11.0,
					Fill = new SolidColorBrush (System.Windows.Media.Color.FromArgb (80, 0, 0, 0))
				};
				Canvas.SetLeft (element, 3.0);
				Canvas.SetTop (element, 5.0);
				canvas.Children.Add (element);
				System.Windows.Shapes.Rectangle element2 = new System.Windows.Shapes.Rectangle {
					Width = 48.0,
					Height = 48.0,
					RadiusX = 11.0,
					RadiusY = 11.0,
					Fill = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (45, 45, 45)) : System.Windows.Media.Brushes.White),
					Stroke = new SolidColorBrush (System.Windows.Media.Color.FromArgb (40, 0, 0, 0)),
					StrokeThickness = 0.5
				};
				Canvas.SetLeft (element2, 3.0);
				Canvas.SetTop (element2, 3.0);
				canvas.Children.Add (element2);
				System.Windows.Shapes.Rectangle rectangle = new System.Windows.Shapes.Rectangle {
					Width = 48.0,
					Height = 14.0,
					RadiusX = 11.0,
					RadiusY = 11.0,
					Fill = new SolidColorBrush (System.Windows.Media.Color.FromRgb (byte.MaxValue, 59, 48))
				};
				rectangle.Clip = new RectangleGeometry (new Rect (0.0, 0.0, 48.0, 12.0));
				Canvas.SetLeft (rectangle, 3.0);
				Canvas.SetTop (rectangle, 3.0);
				canvas.Children.Add (rectangle);
				TextBlock element3 = new TextBlock {
					Text = DateTime.Now.ToString ("MMM").ToUpper (),
					Foreground = System.Windows.Media.Brushes.White,
					FontSize = 9.5,
					FontWeight = FontWeights.Bold,
					Width = 54.0,
