					Foreground = (flag ? System.Windows.Media.Brushes.White : System.Windows.Media.Brushes.Black),
					FontSize = 26.0,
					FontWeight = FontWeights.Normal,
					Width = 54.0,
					TextAlignment = TextAlignment.Center
				};
				Canvas.SetLeft (element4, 0.0);
				Canvas.SetTop (element4, 16.0);
				canvas.Children.Add (element4);
				Viewbox element5 = new Viewbox {
