		public void UpdateClockIconState ()

		{

			if (clockItemControl == null) {

				return;

			}

			Grid container = clockItemControl.VisualContainer;

			if (container.Opacity > 0.1) {

				DoubleAnimation doubleAnimation = new DoubleAnimation (container.Opacity, 0.0, TimeSpan.FromMilliseconds (150.0));

				doubleAnimation.Completed += delegate {

					UpdateClockIconStateInternal ();

					DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (150.0));

					container.BeginAnimation (UIElement.OpacityProperty, animation);

				};

				container.BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

			} else {

				UpdateClockIconStateInternal ();

			}

		}



		private void UpdateClockIconStateInternal ()

		{

			if (clockItemControl == null) {

				return;

			}

			clockItemControl.IconImage.Visibility = Visibility.Collapsed;

			FrameworkElement frameworkElement = clockItemControl.VisualContainer.Children.OfType<FrameworkElement> ().FirstOrDefault ((FrameworkElement g) => g.Name == "ClockVector");

			if (frameworkElement != null) {

				clockItemControl.VisualContainer.Children.Remove (frameworkElement);

			}

			_clockHourTransform = null;

			_clockMinTransform = null;

			_clockSecTransform = null;

			_clockDigitalTimeText = null;

			_clockDigitalDateText = null;

			Canvas canvas = new Canvas ();

			canvas.Width = 48.0;

			canvas.Height = 48.0;

			string text = settings.ClockStyle ?? "analog-adaptive";

			string text2 = (_lastClockTheme = GetEffectiveTheme ());

			_lastClockStyle = text;

			if (text == "digital") {

				Grid grid = new Grid {

					Width = 48.0,

					Height = 48.0

				};

				Border border = new Border {

					Width = 46.0,

					Height = 46.0,

					CornerRadius = new CornerRadius (10.0),

					Background = new LinearGradientBrush (System.Windows.Media.Color.FromArgb (40, byte.MaxValue, byte.MaxValue, byte.MaxValue), System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue), 45.0),

					BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (60, byte.MaxValue, byte.MaxValue, byte.MaxValue)),

					BorderThickness = new Thickness (1.2),

					VerticalAlignment = VerticalAlignment.Center,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Center

				};

				if (settings == null || !settings.PerformanceMode) {

					border.Effect = new DropShadowEffect {

						BlurRadius = 6.0,

						ShadowDepth = 1.5,

						Direction = 270.0,

						Opacity = 0.3,

						Color = Colors.Black

					};

				}

				StackPanel stackPanel = new StackPanel {

					VerticalAlignment = VerticalAlignment.Center,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Center

				};

				_clockDigitalDateText = new TextBlock {

					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (byte.MaxValue, 69, 58)),

					FontSize = 7.0,

					FontFamily = new System.Windows.Media.FontFamily ("Segoe UI, sans-serif"),

					FontWeight = FontWeights.Bold,

					TextAlignment = TextAlignment.Center,

					Margin = new Thickness (0.0, 0.0, 0.0, 1.0)

				};

				_clockDigitalTimeText = new TextBlock {

					Foreground = System.Windows.Media.Brushes.White,

					FontSize = 10.0,

					FontFamily = new System.Windows.Media.FontFamily ("Segoe UI Variable Display, Segoe UI"),

					FontWeight = FontWeights.SemiBold,

					TextAlignment = TextAlignment.Center

				};

				stackPanel.Children.Add (_clockDigitalDateText);

				stackPanel.Children.Add (_clockDigitalTimeText);

				border.Child = stackPanel;

				grid.Children.Add (border);

				Grid grid2 = new Grid ();

				grid2.Children.Add (grid);

				canvas.Children.Add (grid2);

			} else {

				bool flag = false;

				flag = text == "analog-dark" || (!(text == "analog-light") && text2 == "dark");

				Ellipse ellipse = new Ellipse {

					Width = 44.0,

					Height = 44.0,

					StrokeThickness = 1.5

				};

				if (flag) {

					ellipse.Fill = new RadialGradientBrush (System.Windows.Media.Color.FromRgb (30, 30, 30), System.Windows.Media.Color.FromRgb (15, 15, 15));

					ellipse.Stroke = new LinearGradientBrush (System.Windows.Media.Color.FromRgb (60, 60, 60), System.Windows.Media.Color.FromRgb (30, 30, 30), 90.0);

				} else {

					ellipse.Fill = new RadialGradientBrush (System.Windows.Media.Color.FromRgb (byte.MaxValue, byte.MaxValue, byte.MaxValue), System.Windows.Media.Color.FromRgb (235, 235, 235));

					ellipse.Stroke = new LinearGradientBrush (System.Windows.Media.Color.FromRgb (220, 220, 220), System.Windows.Media.Color.FromRgb (180, 180, 180), 90.0);

				}

				if (settings == null || !settings.PerformanceMode) {

					ellipse.Effect = new DropShadowEffect {

						BlurRadius = 6.0,

						ShadowDepth = 2.0,

						Direction = 270.0,

						Opacity = 0.35,

						Color = Colors.Black

					};

				}

				Canvas.SetLeft (ellipse, 2.0);

				Canvas.SetTop (ellipse, 2.0);

				canvas.Children.Add (ellipse);

				for (int i = 0; i < 12; i++) {

					double num = ((i % 3 == 0) ? 4.0 : 2.5);

					double num2 = ((i % 3 == 0) ? 1.2 : 0.7);

					System.Windows.Shapes.Rectangle rectangle = new System.Windows.Shapes.Rectangle {

						Width = num2,

						Height = num,

						Fill = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (180, byte.MaxValue, byte.MaxValue, byte.MaxValue)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (180, 0, 0, 0))),

						RenderTransformOrigin = new System.Windows.Point (0.5, 19.5 / num)

					};

					rectangle.RenderTransform = new RotateTransform (i * 30);

					Canvas.SetLeft (rectangle, 24.0 - num2 / 2.0);

					Canvas.SetTop (rectangle, 4.5);

					canvas.Children.Add (rectangle);

				}

				_clockHourTransform = new RotateTransform (0.0);

				System.Windows.Shapes.Rectangle rectangle2 = new System.Windows.Shapes.Rectangle {

					Width = 2.2,

					Height = 11.0,

