		private void TickClockAppIcon ()

		{

			try {

				if (clockItemControl == null || !settings.ShowClockWidget) {

					if (_clockAppTimer != null) {

						_clockAppTimer.Stop ();

						_clockAppTimer = null;

					}

					return;

				}

				string effectiveTheme = GetEffectiveTheme ();

				string text = settings.ClockStyle ?? "analog-adaptive";

				if (effectiveTheme != _lastClockTheme || text != _lastClockStyle) {

					_lastClockTheme = effectiveTheme;

					_lastClockStyle = text;

					UpdateClockIconState ();

					UpdateCalendarIconState ();

					return;

				}

				DateTime now = DateTime.Now;
				if (now.Day != _lastCalendarDay) {
					UpdateCalendarIconState ();
				}
				if (_clockHourTransform != null) {

					_clockHourTransform.Angle = (double)(now.Hour % 12 * 30) + (double)now.Minute * 0.5;

				}

				if (_clockMinTransform != null) {

					_clockMinTransform.Angle = (double)(now.Minute * 6) + (double)now.Second * 0.1;

				}

				if (_clockSecTransform != null) {

					_clockSecTransform.Angle = now.Second * 6;

				}

				if (_clockDigitalTimeText != null) {

					_clockDigitalTimeText.Text = now.ToString ("HH:mm:ss");

				}

				if (_clockDigitalDateText != null) {

					_clockDigitalDateText.Text = now.ToString ("ddd d").ToUpper ();

				}

			} catch {

			}

		}



		private Border CreateDividerControl ()

		{

			Border border = new Border ();

			border.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (60, byte.MaxValue, byte.MaxValue, byte.MaxValue));

			if (settings.Position == "Left" || settings.Position == "Right") {

				border.Height = 1.2;

				border.Width = 36.0;

				border.HorizontalAlignment = System.Windows.HorizontalAlignment.Center;

				border.Margin = new Thickness (0.0, 10.0, 0.0, 10.0);

			} else {

				border.Width = 1.2;

				border.Height = 36.0;

				border.VerticalAlignment = VerticalAlignment.Center;

				border.Margin = new Thickness (10.0, 0.0, 10.0, 0.0);

			}

			return border;

		}



		private DockItemControl CreateDockItemControlHelper (DockItemConfig config, bool canDrag)

		{

			DockItemControl itemControl = new DockItemControl (config, baseSize);

			if (config.FilePath == "action:trash") {

				itemControl.MouseLeftButtonDown += delegate {

					try {

						itemControl.Bounce ();

						Process.Start (new ProcessStartInfo ("explorer.exe", "shell:RecycleBinFolder") {

							UseShellExecute = true

						});

					} catch {

					}

				};

				itemControl.AllowDrop = true;

				itemControl.DragOver += delegate(object s, System.Windows.DragEventArgs e) {

					if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

						e.Effects = System.Windows.DragDropEffects.Move;

						itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.18, TimeSpan.FromMilliseconds (120.0)));

						itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.18, TimeSpan.FromMilliseconds (120.0)));

					}

				};

				itemControl.DragLeave += delegate {

					itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

					itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

				};

				itemControl.Drop += delegate(object s, System.Windows.DragEventArgs e) {

					itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

					itemControl.scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

					if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

						string[] array = (string[])e.Data.GetData (System.Windows.DataFormats.FileDrop);

						if (array != null) {

							string[] array2 = array;

							for (int i = 0; i < array2.Length; i++) {

								MoveToRecycleBin (array2 [i]);

							}

							QueryRecycleBinState ();

						}

					}

				};

				System.Windows.Controls.ContextMenu contextMenu = new System.Windows.Controls.ContextMenu ();

				System.Windows.Controls.MenuItem menuItem = new System.Windows.Controls.MenuItem {

					Header = "Empty Trash"

				};

				menuItem.Click += delegate {

					itemControl.PlayShakeAnimation ();

					SHEmptyRecycleBin (IntPtr.Zero, null, 3u);

					QueryRecycleBinState ();

					try {

						string text = "C:\\Windows\\Media\\Windows Recycle.wav";

						if (File.Exists (text)) {

							using (SoundPlayer soundPlayer = new SoundPlayer (text)) {

								soundPlayer.Play ();

								return;

							}

						}

						SystemSounds.Asterisk.Play ();

					} catch {

					}

				};

				contextMenu.Items.Add (menuItem);

				itemControl.ContextMenu = contextMenu;

			} else {

				CreateItemContextMenu (itemControl);

				if (config.FilePath == "action:weather") {

					DockItemControl closureItem = itemControl;

					itemControl.MouseEnter += delegate {

						ShowWeatherOverlay (closureItem);

					};

					itemControl.MouseLeave += delegate {

						StartHideWeatherOverlay ();

					};

				} else if (config.FilePath == "action:f1") {

					DockItemControl closureItem2 = itemControl;

					itemControl.MouseEnter += delegate {

						ShowF1Overlay (closureItem2);

					};

					itemControl.MouseLeave += delegate {

						StartHideF1Overlay ();

					};

				} else if (config.FilePath == "action:calendar" || config.Name.ToLower () == "calendar") {

					DockItemControl closureItem3 = itemControl;

					itemControl.MouseEnter += delegate {

						ShowCalendarOverlay (closureItem3);

					};

					itemControl.MouseLeave += delegate {

						StartHideCalendarOverlay ();

					};

				} else if (config.ProcessName.ToLower () == "spotify" || config.Name.ToLower ().Contains ("spotify")) {

					DockItemControl closureItem4 = itemControl;

					itemControl.MouseEnter += delegate {

						ShowMediaOverlay (closureItem4);

					};

					itemControl.MouseLeave += delegate {

						StartHideMediaOverlay ();

					};

				} else {

					DockItemControl closureItem5 = itemControl;

					itemControl.MouseEnter += delegate {

						ShowWindowPreview (closureItem5);

					};

					itemControl.MouseLeave += delegate {

						StartHideWindowPreview ();

					};

				}

			}

			try {

				DockItemControl exposeItem = itemControl;

				DispatcherTimer holdTimer = null;

				exposeItem.PreviewMouseLeftButtonDown += delegate {

					holdTimer = new DispatcherTimer {

						Interval = TimeSpan.FromMilliseconds (600.0)

					};

					holdTimer.Tick += delegate {

						holdTimer.Stop ();

						if (Window.GetWindow (exposeItem) is DockWindow dockWindow) {

							dockWindow.ShowAppExpose (exposeItem);

						}

					};

					holdTimer.Start ();

				};

				exposeItem.PreviewMouseLeftButtonUp += delegate {

					if (holdTimer != null) {

						holdTimer.Stop ();

						holdTimer = null;

					}

				};

				exposeItem.MouseLeave += delegate {

					if (holdTimer != null) {

						holdTimer.Stop ();

						holdTimer = null;

					}

				};

			} catch {

			}

			if (config != null && Directory.Exists (config.FilePath) && config.FilePath != "action:trash") {

				itemControl.AllowDrop = true;

				DispatcherTimer springLoadTimer = null;

				DockItemControl capturedItem = itemControl;

				capturedItem.DragEnter += delegate(object s, System.Windows.DragEventArgs e) {

					if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop) && springLoadTimer == null) {

						springLoadTimer = new DispatcherTimer {

							Interval = TimeSpan.FromMilliseconds (850.0)

						};

						springLoadTimer.Tick += delegate {

							springLoadTimer.Stop ();

							springLoadTimer = null;

							try {

								capturedItem.Launch ();

							} catch {

							}

						};

						springLoadTimer.Start ();

					}

					e.Effects = System.Windows.DragDropEffects.Copy;

					e.Handled = true;

				};

				capturedItem.DragLeave += delegate {

					if (springLoadTimer != null) {

						springLoadTimer.Stop ();

						springLoadTimer = null;

					}

				};

				capturedItem.Drop += delegate {

					if (springLoadTimer != null) {

						springLoadTimer.Stop ();

						springLoadTimer = null;

					}

				};

				capturedItem.DragOver += delegate(object s, System.Windows.DragEventArgs e) {

					if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

						e.Effects = System.Windows.DragDropEffects.Copy;

					}

					e.Handled = true;

				};

			}

			return itemControl;

		}



		public void CheckDragCollisionHorizontal (DockItemControl dragged, System.Windows.Point curMousePos)

		{

			int num = dockItems.IndexOf (dragged);

			if (num == -1) {

				return;

			}

			if (num > 0) {

				DockItemControl dockItemControl = dockItems [num - 1];

				double num2 = dockItemControl.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).X + dockItemControl.ActualWidth / 2.0;

				if (curMousePos.X < num2) {

					SwapItems (num, num - 1);

					dragged.dragStartPoint.X -= dockItemControl.ActualWidth + 10.0;

					return;

				}

			}

			if (num < dockItems.Count - 1) {

				DockItemControl dockItemControl2 = dockItems [num + 1];

				double num3 = dockItemControl2.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).X + dockItemControl2.ActualWidth / 2.0;

				if (curMousePos.X > num3) {

					SwapItems (num, num + 1);

					dragged.dragStartPoint.X += dockItemControl2.ActualWidth + 10.0;

				}

			}

		}



		public void CheckDragCollisionVertical (DockItemControl dragged, System.Windows.Point curMousePos)

		{

			int num = dockItems.IndexOf (dragged);

			if (num == -1) {

				return;

			}

			if (num > 0) {

				DockItemControl dockItemControl = dockItems [num - 1];

				double num2 = dockItemControl.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).Y + dockItemControl.ActualHeight / 2.0;

				if (curMousePos.Y < num2) {

					SwapItems (num, num - 1);

					dragged.dragStartPoint.Y -= dockItemControl.ActualHeight + 12.0;

					return;

				}

			}

			if (num < dockItems.Count - 1) {

				DockItemControl dockItemControl2 = dockItems [num + 1];

				double num3 = dockItemControl2.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).Y + dockItemControl2.ActualHeight / 2.0;

				if (curMousePos.Y > num3) {

					SwapItems (num, num + 1);

					dragged.dragStartPoint.Y += dockItemControl2.ActualHeight + 12.0;

				}

			}

		}



		private void SwapItems (int idx1, int idx2)

		{

			DockItemConfig value = settings.Items [idx1];

			settings.Items [idx1] = settings.Items [idx2];

			settings.Items [idx2] = value;

			DockItemControl dockItemControl = dockItems [idx1];

			DockItemControl dockItemControl2 = dockItems [idx2];

			dockItems [idx1] = dockItemControl2;

			dockItems [idx2] = dockItemControl;

			int num = dockPanel.Children.IndexOf (dockItemControl);

			int num2 = dockPanel.Children.IndexOf (dockItemControl2);

			if (num != -1 && num2 != -1) {

				dockPanel.Children.Remove (dockItemControl);

				dockPanel.Children.Remove (dockItemControl2);

				if (num < num2) {

					dockPanel.Children.Insert (num, dockItemControl2);

					dockPanel.Children.Insert (num2, dockItemControl);

				} else {

					dockPanel.Children.Insert (num2, dockItemControl);

					dockPanel.Children.Insert (num, dockItemControl2);

				}

			}

		}



		private void SafeAdd (System.Windows.Controls.Panel panel, UIElement child, string description)

		{

			if (panel == null || child == null) {

				return;

			}

			try {

				DependencyObject parent = LogicalTreeHelper.GetParent (child);

				if (parent != null) {

					string text = parent.GetType ().Name;

					if (parent is FrameworkElement) {

						text = text + " Name=" + ((FrameworkElement)parent).Name;

					}

					string text2 = child.GetType ().Name;

					if (child is FrameworkElement) {

						text2 = text2 + " Name=" + ((FrameworkElement)child).Name;

					}

					try {

						File.AppendAllText ("crash.txt", DateTime.Now.ToString ("o") + " [conflict] " + description + " - Child " + text2 + " already has parent: " + text + "\r\n");

					} catch {

					}

					try {

						if (parent is System.Windows.Controls.Panel) {

							((System.Windows.Controls.Panel)parent).Children.Remove (child);

						} else if (parent is Decorator) {

							((Decorator)parent).Child = null;

						} else if (parent is ContentControl) {

							((ContentControl)parent).Content = null;

						}

					} catch (Exception ex) {

						try {

							File.AppendAllText ("crash.txt", DateTime.Now.ToString ("o") + " [detach-error] Failed to detach: " + ex.ToString () + "\r\n");

						} catch {

						}

					}

				}

				panel.Children.Add (child);

			} catch (Exception ex2) {

				try {

					File.AppendAllText ("crash.txt", DateTime.Now.ToString ("o") + " [add-error] Add failed for " + description + ": " + ex2.ToString () + "\r\n");

				} catch {

				}

				throw;

			}

		}



		public void RebuildDockUI ()
		{
			trashItemControl = null;
			clockItemControl = null;

			foreach (DockItemControl runningItem in runningItems) {
				try {
					if (LogicalTreeHelper.GetParent (runningItem) is System.Windows.Controls.Panel panel) {
						panel.Children.Remove (runningItem);
					}
				} catch {
				}
			}

			dockPanel.Children.Clear ();
			dockItems.Clear ();
			recentControls.Clear ();

			if (dockBorder.Child is Grid grid) {
				try {
					grid.Children.Remove (dockPanel);
				} catch {
				}

				if (_shimmerOverlay != null) {
					try {
						grid.Children.Remove (_shimmerOverlay);
					} catch {
					}
				}
			}

			Grid grid2 = new Grid ();
			SafeAdd (grid2, dockPanel, "dockContentGrid.Add(dockPanel)");

			if (_shimmerOverlay != null) {
				_shimmerOverlay.HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch;
				_shimmerOverlay.VerticalAlignment = VerticalAlignment.Stretch;
				SafeAdd (grid2, _shimmerOverlay, "dockContentGrid.Add(_shimmerOverlay)");
			}

			_clockLabel = null;
			_batteryLabel = null;

			if (_clockTimer != null) {
				_clockTimer.Stop ();
				_clockTimer = null;
			}

			dockBorder.Child = grid2;
			List<DockItemConfig> list = new List<DockItemConfig> ();

			foreach (DockItemConfig item in settings.Items) {
				if ((!(item.FilePath == "action:weather") || settings.EnableLiveWeather) && (!(item.FilePath == "action:controlcenter") || settings.EnableControlCenter) && (!(item.FilePath == "action:launchpad") || settings.ShowLaunchpad) && !Directory.Exists (item.FilePath) && item.FilePath != "action:search" && item.FilePath != "action:trash") {
					list.Add (item);
				}
			}

			DockItemConfig dockItemConfig = settings.Items.FirstOrDefault ((DockItemConfig i) => i.FilePath == "action:search");
			if (dockItemConfig != null) {
				DockItemControl dockItemControl = CreateDockItemControlHelper (dockItemConfig, canDrag: true);
				SafeAdd (dockPanel, dockItemControl, "dockPanel.Add(searchCtrl)");
				dockItems.Add (dockItemControl);
			}

			foreach (DockItemConfig item2 in list) {
				DockItemControl dockItemControl2 = CreateDockItemControlHelper (item2, canDrag: true);
				SafeAdd (dockPanel, dockItemControl2, "dockPanel.Add(pinnedItem)");
				dockItems.Add (dockItemControl2);
			}

			Border border = CreateDividerControl ();
			SafeAdd (dockPanel, border, "dockPanel.Add(divider1)");

			int num = 0;
			foreach (DockItemControl itemControl in runningItems) {
				itemControl.UpdateBaseSize (baseSize);
				if (!settings.Items.Any ((DockItemConfig p) => p.ProcessName.ToLower () == itemControl.Config.ProcessName.ToLower ())) {
					SafeAdd (dockPanel, itemControl, "dockPanel.Add(runningItem)");
					num++;
				}
			}

			int num2 = 0;
			if (settings.ShowRecentApps) {
				foreach (DockItemConfig config in recentApps) {
					if (!runningItems.Any ((DockItemControl r) => r.Config.ProcessName.ToLower () == config.ProcessName.ToLower ())) {
						DockItemControl dockItemControl3 = CreateDockItemControlHelper (config, canDrag: false);
						dockItemControl3.IndicatorDot.Opacity = 0.0;
						SafeAdd (dockPanel, dockItemControl3, "dockPanel.Add(recentItem)");
						recentControls.Add (dockItemControl3);
						num2++;
					}
				}
			}

			border.Visibility = ((num + num2 <= 0) ? Visibility.Collapsed : Visibility.Visible);
			Border border2 = CreateDividerControl ();
			SafeAdd (dockPanel, border2, "dockPanel.Add(divider2)");

			List<DockItemConfig> list2 = new List<DockItemConfig> ();
			foreach (DockItemConfig item3 in settings.Items) {
				if (Directory.Exists (item3.FilePath)) {
					list2.Add (item3);
				}
			}

			int num3 = 0;
			foreach (DockItemConfig item4 in list2) {
				DockItemControl dockItemControl4 = CreateDockItemControlHelper (item4, canDrag: true);
				SafeAdd (dockPanel, dockItemControl4, "dockPanel.Add(folderStack)");
				dockItems.Add (dockItemControl4);
				num3++;
			}

			foreach (DockItemControl item in minimizedItems) {
				item.UpdateBaseSize (baseSize);
				if (item.Parent != null) {
					try {
						((System.Windows.Controls.Panel)item.Parent).Children.Remove (item);
					} catch {}
				}
				SafeAdd (dockPanel, item, "dockPanel.Add(minimizedItem)");
			}

			if (trashItemControl == null) {
				DockItemConfig config2 = new DockItemConfig {
					Name = "Trash",
					FilePath = "action:trash",
					ProcessName = "Trash"
				};
				trashItemControl = CreateDockItemControlHelper (config2, canDrag: false);
			}

			SafeAdd (dockPanel, trashItemControl, "dockPanel.Add(trashItem)");
			QueryRecycleBinState ();

			if (settings.ShowCalendarWidget) {
				DockItemConfig config3 = new DockItemConfig {
					Name = "Calendar",
					FilePath = "action:calendar",
					ProcessName = "Calendar"
				};
				DockItemControl dockItemControl5 = CreateDockItemControlHelper (config3, canDrag: false);
				SafeAdd (dockPanel, dockItemControl5, "dockPanel.Add(calItem)");
				dockItems.Add (dockItemControl5);
				UpdateCalendarIconState ();
			}

			if (settings.ShowClockWidget) {
				if (clockItemControl == null) {
					DockItemConfig config4 = new DockItemConfig {
						Name = "Clock",
						FilePath = "action:clock",
						ProcessName = "Clock"
					};
					clockItemControl = CreateDockItemControlHelper (config4, canDrag: false);
					clockItemControl.MouseEnter += delegate {
						ShowClockOverlay (clockItemControl);
					};
					clockItemControl.MouseLeave += delegate {
						StartHideClockOverlay ();
					};
				}

				UpdateClockIconState ();
				SafeAdd (dockPanel, clockItemControl, "dockPanel.Add(clockItem)");
				dockItems.Add (clockItemControl);
			} else {

				if (clockItemControl != null) {

					try {

						clockItemControl.VisualContainer.Children.Clear ();

					} catch {

					}

					clockItemControl = null;

				}

				if (_clockAppTimer != null) {

					_clockAppTimer.Stop ();

					_clockAppTimer = null;

				}

			}

			border2.Visibility = ((num3 <= 0 && trashItemControl == null && clockItemControl == null) ? Visibility.Collapsed : Visibility.Visible);

			ApplyTheme ();

		}



		internal string GetEffectiveTheme ()

		{

			if (settings.Theme == "auto") {

				return autoDetectedTheme;

			}

			if (settings.Theme == "auto-windows") {

				try {

					using RegistryKey registryKey = Registry.CurrentUser.OpenSubKey ("Software\\Microsoft\\Windows\\CurrentVersion\\Themes\\Personalize");

					if (registryKey != null) {

						object value = registryKey.GetValue ("AppsUseLightTheme");

						if (value != null) {

							return ((int)value == 1) ? "light" : "dark";

						}

					}

				} catch {

				}

				return "dark";

			}

			return settings.Theme;

		}



		internal void ApplyTheme ()

		{

			string effectiveTheme = GetEffectiveTheme ();

			byte b = (byte)(settings.GlassOpacity * 255.0);

			byte b2 = (byte)(Math.Min (1.0, settings.GlassOpacity * 1.25) * 255.0);

			System.Windows.Media.Color? color = null;

