		private Polygon _shelfPolygon;
		private Line _shelfHighlightLine;
		private double _lastShelfW;
		private double _lastShelfH;

		public void Update3DShelf ()
		{
			if (dockBorder == null) return;
			try {
				if (dockBorder.Effect is LiquidGlassEffect glassEffect) {
					glassEffect.RefractionStrength += (6.0 - glassEffect.RefractionStrength) * 0.12;
					glassEffect.SpecularIntensity += (0.35 - glassEffect.SpecularIntensity) * 0.12;
				}
			} catch { }
			Grid grid2 = dockBorder.Child as Grid;
			if (grid2 == null) return;

			double w = dockBorder.ActualWidth;
			double h = dockBorder.ActualHeight;
			if (w <= 0) w = 600.0;
			if (h <= 0) h = 80.0;
			double skew = 16.0;

			if (_shelfPolygon == null) {
				_shelfPolygon = new Polygon ();
				grid2.Children.Insert (0, _shelfPolygon);
			}
			_shelfPolygon.Visibility = Visibility.Visible;

			if (_shelfHighlightLine == null) {
				_shelfHighlightLine = new Line ();
				grid2.Children.Add (_shelfHighlightLine);
			}
			_shelfHighlightLine.Visibility = Visibility.Visible;

			if (_shelfPolygon.Points == null || _shelfPolygon.Points.Count != 4) {
				_shelfPolygon.Points = new PointCollection {
					new System.Windows.Point (0, 0),
					new System.Windows.Point (0, 0),
					new System.Windows.Point (0, 0),
					new System.Windows.Point (0, 0)
				};
			}

			if (settings.Position == "Bottom") {
				_shelfPolygon.Points [0] = new System.Windows.Point (skew, 0);
				_shelfPolygon.Points [1] = new System.Windows.Point (w - skew, 0);
				_shelfPolygon.Points [2] = new System.Windows.Point (w, h);
				_shelfPolygon.Points [3] = new System.Windows.Point (0, h);

				if (_shelfHighlightLine.X1 != skew) _shelfHighlightLine.X1 = skew;
				if (_shelfHighlightLine.Y1 != 0.0) _shelfHighlightLine.Y1 = 0.0;
				if (_shelfHighlightLine.X2 != w - skew) _shelfHighlightLine.X2 = w - skew;
				if (_shelfHighlightLine.Y2 != 0.0) _shelfHighlightLine.Y2 = 0.0;
			} else if (settings.Position == "Top") {
				_shelfPolygon.Points [0] = new System.Windows.Point (0, 0);
				_shelfPolygon.Points [1] = new System.Windows.Point (w, 0);
				_shelfPolygon.Points [2] = new System.Windows.Point (w - skew, h);
				_shelfPolygon.Points [3] = new System.Windows.Point (skew, h);

				if (_shelfHighlightLine.X1 != skew) _shelfHighlightLine.X1 = skew;
				if (_shelfHighlightLine.Y1 != h) _shelfHighlightLine.Y1 = h;
				if (_shelfHighlightLine.X2 != w - skew) _shelfHighlightLine.X2 = w - skew;
				if (_shelfHighlightLine.Y2 != h) _shelfHighlightLine.Y2 = h;
			} else if (settings.Position == "Left") {
				_shelfPolygon.Points [0] = new System.Windows.Point (0, 0);
				_shelfPolygon.Points [1] = new System.Windows.Point (w, skew);
				_shelfPolygon.Points [2] = new System.Windows.Point (w, h - skew);
				_shelfPolygon.Points [3] = new System.Windows.Point (0, h);

				if (_shelfHighlightLine.X1 != w) _shelfHighlightLine.X1 = w;
				if (_shelfHighlightLine.Y1 != skew) _shelfHighlightLine.Y1 = skew;
				if (_shelfHighlightLine.X2 != w) _shelfHighlightLine.X2 = w;
				if (_shelfHighlightLine.Y2 != h - skew) _shelfHighlightLine.Y2 = h - skew;
			} else { // "Right"
				_shelfPolygon.Points [0] = new System.Windows.Point (0, skew);
				_shelfPolygon.Points [1] = new System.Windows.Point (w, 0);
				_shelfPolygon.Points [2] = new System.Windows.Point (w, h);
				_shelfPolygon.Points [3] = new System.Windows.Point (0, h - skew);

				if (_shelfHighlightLine.X1 != 0.0) _shelfHighlightLine.X1 = 0.0;
				if (_shelfHighlightLine.Y1 != skew) _shelfHighlightLine.Y1 = skew;
				if (_shelfHighlightLine.X2 != 0.0) _shelfHighlightLine.X2 = 0.0;
				if (_shelfHighlightLine.Y2 != h - skew) _shelfHighlightLine.Y2 = h - skew;
			}

			System.Windows.Media.Brush targetFill = null;
			if (dockBorder.Background is LinearGradientBrush lgb) {
				targetFill = lgb;
			} else if (dockBorder.Background != System.Windows.Media.Brushes.Transparent) {
				targetFill = dockBorder.Background;
			}

			if (targetFill != null && _shelfPolygon.Fill != targetFill) {
				_shelfPolygon.Fill = targetFill;
			}

			if (_shelfHighlightLine.Stroke != _cachedHighlightBrush) {
				_shelfHighlightLine.Stroke = _cachedHighlightBrush;
			}
			if (_shelfHighlightLine.StrokeThickness != 1.2) {
				_shelfHighlightLine.StrokeThickness = 1.2;
			}

			if (dockBorder.Background != System.Windows.Media.Brushes.Transparent) {
				dockBorder.Background = System.Windows.Media.Brushes.Transparent;
			}
			if (dockBorder.BorderBrush != System.Windows.Media.Brushes.Transparent) {
				dockBorder.BorderBrush = System.Windows.Media.Brushes.Transparent;
			}
			if (dockBorder.BorderThickness.Left != 0) {
				dockBorder.BorderThickness = new Thickness (0);
			}
			if (dockBorder.Effect != null) {
				dockBorder.Effect = null;
			}

			if (_shelfPolygon.Effect != null) {
				_shelfPolygon.Effect = null;
			}
		}



		internal System.Windows.Media.Color? SampleWallpaperAccentColor ()

		{

			try {

				string text = null;

				using (RegistryKey registryKey = Registry.CurrentUser.OpenSubKey ("Control Panel\\Desktop", writable: false)) {

					if (registryKey != null) {

						text = registryKey.GetValue ("Wallpaper") as string;

					}

				}

				if (string.IsNullOrEmpty (text) || !File.Exists (text)) {

					return null;

				}

				if (text == _cachedWallpaperPath && _cachedWallpaperAccent.HasValue) {

					return _cachedWallpaperAccent;

				}

				_cachedWallpaperPath = text;

				BitmapImage bitmapImage = new BitmapImage ();

				bitmapImage.BeginInit ();

				bitmapImage.UriSource = new Uri (text, UriKind.Absolute);

				bitmapImage.DecodePixelWidth = 64;

				bitmapImage.CacheOption = BitmapCacheOption.OnLoad;

				bitmapImage.EndInit ();

				int num = 32;

				int num2 = 32;

				RenderTargetBitmap renderTargetBitmap = new RenderTargetBitmap (num, num2, 96.0, 96.0, PixelFormats.Pbgra32);

				DrawingVisual drawingVisual = new DrawingVisual ();

				using (DrawingContext drawingContext = drawingVisual.RenderOpen ()) {

					drawingContext.DrawImage (bitmapImage, new Rect (0.0, 0.0, num, num2));

				}

				renderTargetBitmap.Render (drawingVisual);

				int num3 = num * 4;

				byte[] array = new byte[num2 * num3];

				renderTargetBitmap.CopyPixels (array, num3, 0);

				System.Windows.Media.Color value = Colors.CornflowerBlue;

				double num4 = -1.0;

				for (int i = 0; i < num2; i++) {

					for (int j = 0; j < num; j++) {

						int num5 = i * num3 + j * 4;

						byte b = array [num5];

						byte b2 = array [num5 + 1];

						byte b3 = array [num5 + 2];

						if (array [num5 + 3] >= 20) {

							double val = (double)(int)b3 / 255.0;

							double val2 = (double)(int)b2 / 255.0;

							double val3 = (double)(int)b / 255.0;

							double num6 = Math.Max (val, Math.Max (val2, val3));

							double num7 = Math.Min (val, Math.Min (val2, val3));

							double num8 = ((num6 == 0.0) ? 0.0 : ((num6 - num7) / num6)) * num6;

							if (num8 > num4) {

								num4 = num8;

								value = System.Windows.Media.Color.FromRgb (b3, b2, b);

							}

						}

					}

				}

				_cachedWallpaperAccent = value;

				return value;

			} catch {

				return null;

			}

		}



		private void AnimateDockShadow (bool hover)

		{

			if (!(dockBorder.Effect is DropShadowEffect dropShadowEffect)) {

				return;

			}

			double num = 25.0;

			double num2 = 4.0;

			double num3 = 0.45;

			System.Windows.Media.Color black = Colors.Black;

			if (settings.Theme == "tahoe" || (settings.Theme == "auto" && autoDetectedTheme == "tahoe") || (settings.Theme == "auto-windows" && autoDetectedTheme == "tahoe")) {

				num = (hover ? 45 : 35);

				num2 = (hover ? 1 : 2);

				num3 = (hover ? 0.5 : 0.35);

				black = System.Windows.Media.Color.FromRgb (140, 0, byte.MaxValue);

			} else {

				num = (hover ? 35 : 25);

				num2 = (hover ? 2 : 4);

				num3 = (hover ? 0.55 : 0.45);

				black = Colors.Black;

			}

			try {

				dropShadowEffect.BeginAnimation (DropShadowEffect.BlurRadiusProperty, null);

				dropShadowEffect.BeginAnimation (DropShadowEffect.ShadowDepthProperty, null);

				dropShadowEffect.BeginAnimation (DropShadowEffect.OpacityProperty, null);

				DoubleAnimation animation = new DoubleAnimation (dropShadowEffect.BlurRadius, num, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				DoubleAnimation animation2 = new DoubleAnimation (dropShadowEffect.ShadowDepth, num2, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				DoubleAnimation animation3 = new DoubleAnimation (dropShadowEffect.Opacity, num3, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				dropShadowEffect.BeginAnimation (DropShadowEffect.BlurRadiusProperty, animation);

				dropShadowEffect.BeginAnimation (DropShadowEffect.ShadowDepthProperty, animation2);

				dropShadowEffect.BeginAnimation (DropShadowEffect.OpacityProperty, animation3);

				dropShadowEffect.Color = black;

			} catch {

				dropShadowEffect.BlurRadius = num;

				dropShadowEffect.ShadowDepth = num2;

				dropShadowEffect.Opacity = num3;

				dropShadowEffect.Color = black;

			}

		}



		private void SetupDragAndDrop ()

		{

			dockBorder.AllowDrop = true;

			dockBorder.DragEnter += delegate(object s, System.Windows.DragEventArgs e) {

				if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

					e.Effects = System.Windows.DragDropEffects.Copy;

					dockBorder.BorderThickness = new Thickness (2.0);

					dockBorder.BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 210, byte.MaxValue));

					isExternalDragOver = true;

					externalDragMousePosition = e.GetPosition (dockPanel);

				}

			};

			dockBorder.DragLeave += delegate {

				dockBorder.BorderThickness = (settings.ShowDockBorder ? new Thickness (1.2) : new Thickness (0.0));

				ApplyTheme ();

				isExternalDragOver = false;

			};

			dockBorder.DragOver += delegate(object s, System.Windows.DragEventArgs e) {

				if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

					e.Effects = System.Windows.DragDropEffects.Copy;

					isExternalDragOver = true;

					externalDragMousePosition = e.GetPosition (dockPanel);

				}

			};

			dockBorder.Drop += delegate(object s, System.Windows.DragEventArgs e) {

				dockBorder.BorderThickness = (settings.ShowDockBorder ? new Thickness (1.2) : new Thickness (0.0));

				ApplyTheme ();

				isExternalDragOver = false;

				if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

					string[] array = (string[])e.Data.GetData (System.Windows.DataFormats.FileDrop);

					if (array != null) {

						string[] array2 = array;

						foreach (string filePath in array2) {

							AddAppToDock (filePath);

						}

					}

				}

			};

		}



		private void AddAppToDock (string filePath)

		{

			if (string.IsNullOrEmpty (filePath)) {

				return;

			}

			string fileNameWithoutExtension = System.IO.Path.GetFileNameWithoutExtension (filePath);

			string processName = fileNameWithoutExtension;

			if (filePath.EndsWith (".lnk", StringComparison.OrdinalIgnoreCase)) {

				string path = IconExtractor.ResolveShortcut (filePath);

				if (File.Exists (path)) {

					processName = System.IO.Path.GetFileNameWithoutExtension (path);

				}

			}

			DockItemConfig item = new DockItemConfig {

				Name = fileNameWithoutExtension,

				FilePath = filePath,

				ProcessName = processName

			};

			settings.Items.Add (item);

			SaveSettings ();

			RebuildDockUI ();

		}



		private void CreateDockContextMenu ()

		{

			System.Windows.Controls.ContextMenu contextMenu = new System.Windows.Controls.ContextMenu ();

			System.Windows.Controls.MenuItem menuItem = new System.Windows.Controls.MenuItem {

				Header = "Pin Application..."

			};

			menuItem.Click += delegate {

				PinNewApplication ();

			};

			contextMenu.Items.Add (menuItem);

			System.Windows.Controls.MenuItem menuItem2 = new System.Windows.Controls.MenuItem {

				Header = "Dock Settings..."

			};

			menuItem2.Click += delegate {

				try {

					new SettingsWindow (this, settings).ShowDialog ();

				} catch (Exception ex) {

					System.Windows.MessageBox.Show ("Could not load Preferences panel: " + ex.Message + "\n" + ex.StackTrace, "System Preferences Error", MessageBoxButton.OK, MessageBoxImage.Hand);

				}

			};

			contextMenu.Items.Add (menuItem2);

			contextMenu.Items.Add (new Separator ());

			System.Windows.Controls.MenuItem recentToggle = new System.Windows.Controls.MenuItem {

				Header = "Show Recent Apps",

				IsCheckable = true,

				IsChecked = settings.ShowRecentApps

			};

			recentToggle.Click += delegate {

				settings.ShowRecentApps = recentToggle.IsChecked;

				SaveSettings ();

				RebuildDockUI ();

			};

			contextMenu.Items.Add (recentToggle);

			contextMenu.Items.Add (new Separator ());

			System.Windows.Controls.MenuItem menuItem3 = new System.Windows.Controls.MenuItem {

				Header = "Exit Dock"

			};

			menuItem3.Click += delegate {

				System.Windows.Application.Current.Shutdown ();

			};

			contextMenu.Items.Add (menuItem3);

			dockBorder.ContextMenu = contextMenu;

		}



		private void PinNewApplication ()

		{

			Microsoft.Win32.OpenFileDialog openFileDialog = new Microsoft.Win32.OpenFileDialog ();

			openFileDialog.Filter = "Applications (*.exe;*.lnk)|*.exe;*.lnk|All Files (*.*)|*.*";

			openFileDialog.Title = "Select Application to Pin to Dock";

			if (openFileDialog.ShowDialog ().GetValueOrDefault ()) {

				AddAppToDock (openFileDialog.FileName);

			}

		}



