					} catch (Exception ex3) {

						System.Windows.MessageBox.Show ("Could not open containing folder: " + ex3.Message, "Error", MessageBoxButton.OK, MessageBoxImage.Hand);

					}

				};

				contextMenu2.Items.Add (menuItem2);

				contextMenu2.Items.Add (new Separator ());

				System.Windows.Controls.MenuItem menuItem3 = new System.Windows.Controls.MenuItem {
					Header = "Display as Fan",
					IsChecked = (item.Config.Arguments != "Grid" && item.Config.Arguments != "List")
				};
				menuItem3.Click += delegate {
					item.Config.Arguments = "Fan";
