				contextMenu2.Items.Add (menuItem3);
				System.Windows.Controls.MenuItem menuItem4 = new System.Windows.Controls.MenuItem {
					Header = "Display as Grid",
					IsChecked = (item.Config.Arguments == "Grid")
				};
				menuItem4.Click += delegate {
					item.Config.Arguments = "Grid";
					SaveSettings ();
					RebuildDockUI ();
				};
				contextMenu2.Items.Add (menuItem4);
				System.Windows.Controls.MenuItem menuItemList = new System.Windows.Controls.MenuItem {
					Header = "Display as List",
					IsChecked = (item.Config.Arguments == "List")
				};
				menuItemList.Click += delegate {
					item.Config.Arguments = "List";
