		private bool IsMouseAlignedWithDock (System.Windows.Point p)
		{
			if (dockBorder == null || !dockBorder.IsLoaded) {
				return true;
			}
			try {
				double width = dockBorder.ActualWidth > 0 ? dockBorder.ActualWidth : dockPanel != null && dockPanel.ActualWidth > 0 ? dockPanel.ActualWidth : 500.0;
				double height = dockBorder.ActualHeight > 0 ? dockBorder.ActualHeight : dockPanel != null && dockPanel.ActualHeight > 0 ? dockPanel.ActualHeight : 500.0;

				if (settings.Position == "Bottom" || settings.Position == "Top") {
					double x = dockBorder.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).X;
					if ((x <= 0 || x >= this.ActualWidth) && this.ActualWidth > 0) {
						x = (this.ActualWidth - width) / 2.0;
					}
					double num = x + width;
					return p.X >= (x - 60.0) && p.X <= (num + 60.0);
				} else {
					double y = dockBorder.TranslatePoint (new System.Windows.Point (0.0, 0.0), this).Y;
					if ((y <= 0 || y >= this.ActualHeight) && this.ActualHeight > 0) {
						y = (this.ActualHeight - height) / 2.0;
					}
					double num2 = y + height;
					return p.Y >= (y - 60.0) && p.Y <= (num2 + 60.0);
				}
			} catch {
				return true;
			}
		}



		private void SetupAutoHide ()
		{
			_edgeHoverTimer = new DispatcherTimer { Interval = TimeSpan.FromMilliseconds (120) };
			_edgeHoverTimer.Tick += delegate {
				_edgeHoverTimer.Stop ();
				if (isDockHidden && settings.AutoHide) {
					ShowDock ();
				}
			};

			autoHideTimer = new DispatcherTimer ();
			autoHideTimer.Interval = TimeSpan.FromSeconds (settings.AutoHideDelay);
			autoHideTimer.Tick += delegate {
				autoHideTimer.Stop ();
				if (settings.AutoHide && !isDockHidden) {
					if (!IsMousePhysicallyOverDock ()) {
						HideDock ();
					} else {
						autoHideTimer.Start ();
					}
				}
			};

			dockBorder.MouseEnter += delegate {
				_edgeHoverTimer.Stop ();
				autoHideTimer.Stop ();
				if (isDockHidden && settings.AutoHide) {
					ShowDock ();
				}
				AnimateDockShadow (hover: true);
			};

			dockBorder.MouseLeave += delegate {
				_edgeHoverTimer.Stop ();
				if (settings.AutoHide) {
					autoHideTimer.Interval = TimeSpan.FromSeconds (settings.AutoHideDelay);
					autoHideTimer.Start ();
				}
				AnimateDockShadow (hover: false);
			};

			base.MouseMove += delegate(object s, System.Windows.Input.MouseEventArgs e) {
				if (isDockHidden && settings.AutoHide) {
					System.Windows.Point position = e.GetPosition (this);
					bool isNearEdge = false;
					double edgeThreshold = 35.0;

					if (settings.Position == "Bottom") {
						if (position.Y >= base.Height - edgeThreshold) isNearEdge = true;
					} else if (settings.Position == "Top") {
						if (position.Y <= edgeThreshold) isNearEdge = true;
					} else if (settings.Position == "Left") {
						if (position.X <= edgeThreshold) isNearEdge = true;
					} else if (settings.Position == "Right" && position.X >= base.Width - edgeThreshold) {
						isNearEdge = true;
					}

					if (isNearEdge && IsMouseAlignedWithDock (position)) {
						if (!_edgeHoverTimer.IsEnabled) {
							_edgeHoverTimer.Start ();
						}
					} else {
						bool isFar = false;
						if (settings.Position == "Bottom" && position.Y < base.Height - 50.0) isFar = true;
						else if (settings.Position == "Top" && position.Y > 50.0) isFar = true;
						else if (settings.Position == "Left" && position.X > 50.0) isFar = true;
						else if (settings.Position == "Right" && position.X < base.Width - 50.0) isFar = true;

						if (isFar) {
							_edgeHoverTimer.Stop ();
						}
					}
				}
			};

			base.Loaded += delegate {
				ApplyAutoHideState ();
			};
		}

		private void ApplyAutoHideState ()
		{
			autoHideTimer.Stop ();
			_edgeHoverTimer?.Stop ();

			if (settings.AutoHide) {
				autoHideTimer.Interval = TimeSpan.FromSeconds (settings.AutoHideDelay);
				if (!IsMousePhysicallyOverDock ()) {
					HideDock ();
				} else {
					ShowDock ();
				}
			} else {
				ShowDock ();
			}
		}

		private void HideDock ()
		{
			SoundEffects.PlaySwoosh ();
			isDockHidden = true;
			_edgeHoverTimer?.Stop ();

			if (hotzone != null) {
				try {
					hotzone.Visibility = Visibility.Visible;
				} catch {
				}
			}

			DependencyProperty propToAnimate;
			double hideTargetValue = GetHideTargetValue (out propToAnimate);

			double currentVal = (propToAnimate == TranslateTransform.XProperty) ? dockSlideTransform.X : dockSlideTransform.Y;

			try {
				dockSlideTransform.BeginAnimation (TranslateTransform.XProperty, null);
				dockSlideTransform.BeginAnimation (TranslateTransform.YProperty, null);
				dockBorder.BeginAnimation (UIElement.OpacityProperty, null);
			} catch {
			}

			dockBorder.Opacity = 1.0;

			TimeSpan slideDur = IsAnimationEnabled ? TimeSpan.FromMilliseconds (220.0) : TimeSpan.Zero;

			DoubleAnimation slideAnim = new DoubleAnimation (currentVal, hideTargetValue, slideDur) {
				EasingFunction = new CubicEase {
					EasingMode = EasingMode.EaseIn
				}
			};

			dockSlideTransform.BeginAnimation (propToAnimate, slideAnim);
		}

		private void ShowDock ()
		{
			SoundEffects.PlaySwoosh ();
			isDockHidden = false;
			_edgeHoverTimer?.Stop ();

			if (hotzone != null) {
				try {
					hotzone.Visibility = Visibility.Collapsed;
				} catch {
				}
			}

			DependencyProperty dp = TranslateTransform.YProperty;
			if (settings.Position == "Left" || settings.Position == "Right") {
				dp = TranslateTransform.XProperty;
			}

			double hideTargetValue = GetHideTargetValue (out dp);

			double currentVal = (dp == TranslateTransform.XProperty) ? dockSlideTransform.X : dockSlideTransform.Y;
			if (currentVal == 0.0) {
				currentVal = hideTargetValue;
			}

			try {
				dockSlideTransform.BeginAnimation (TranslateTransform.XProperty, null);
				dockSlideTransform.BeginAnimation (TranslateTransform.YProperty, null);
				dockBorder.BeginAnimation (UIElement.OpacityProperty, null);
			} catch {
			}

			dockSlideTransform.X = (dp == TranslateTransform.XProperty) ? currentVal : 0.0;
			dockSlideTransform.Y = (dp == TranslateTransform.YProperty) ? currentVal : 0.0;
			dockBorder.Opacity = 1.0;

			TimeSpan slideDur = IsAnimationEnabled ? TimeSpan.FromMilliseconds (250.0) : TimeSpan.Zero;

			DoubleAnimation slideAnim = new DoubleAnimation (currentVal, 0.0, slideDur) {
				EasingFunction = new CubicEase {
					EasingMode = EasingMode.EaseOut
				}
			};

			dockSlideTransform.BeginAnimation (dp, slideAnim);
		}

		private double GetStableCrossCenter ()
		{
			if (settings == null) return 80.0;
			string position = settings.Position ?? "Bottom";

			if (position == "Left") {
				double margin = dockBorder != null ? dockBorder.Margin.Left : 12.0;
				double padding = dockBorder != null ? dockBorder.Padding.Left : 12.0;
				return margin + padding + baseSize / 2.0;
			}
			if (position == "Right") {
				double margin = dockBorder != null ? dockBorder.Margin.Right : 12.0;
				double padding = dockBorder != null ? dockBorder.Padding.Right : 12.0;
				return this.Width - margin - padding - baseSize / 2.0;
			}
			if (position == "Top") {
				double margin = dockBorder != null ? dockBorder.Margin.Top : 12.0;
				double padding = dockBorder != null ? dockBorder.Padding.Top : 6.0;
				return margin + padding + baseSize / 2.0;
			}
			{
				double margin = dockBorder != null ? dockBorder.Margin.Bottom : 48.0;
				double padding = dockBorder != null ? dockBorder.Padding.Bottom : 6.0;
				return this.Height - margin - padding - baseSize / 2.0;
			}
		}



		private void OnRenderTick (object sender, EventArgs e)

		{

			if (dockBorder == null || dockPanel == null) {

				return;

			}



			System.Windows.Point mousePosInWindow = Mouse.GetPosition (this);

			bool flag = IsMousePhysicallyOverDock (mousePosInWindow);

			TimeSpan timeSpan = TimeSpan.Zero;

			try {

				if (e is RenderingEventArgs renderingEventArgs2) {

					timeSpan = renderingEventArgs2.RenderingTime;

				}

			} catch {

			}

			double num2 = 16.7;

			if (_lastRenderTime.HasValue && timeSpan != TimeSpan.Zero) {

				num2 = Math.Min (50.0, (timeSpan - _lastRenderTime.Value).TotalMilliseconds);

			}

			if (timeSpan != TimeSpan.Zero) {

				_lastRenderTime = timeSpan;

			}

			if (flag && IsAnimationEnabled) {

				wavePhase += 0.0108 * num2;

			} else {

				wavePhase *= Math.Pow (0.92, num2 / 16.7);

			}

			try {

				if (_shimmerOverlay != null && IsAnimationEnabled && (flag || _shimmerOverlay.Opacity > 0.001)) {

					_shimmerPhase += num2 * 0.00038;

					if (_shimmerPhase > 1.0) {

						_shimmerPhase = 0.0;

					}

					if (flag) {

						double val = Math.Sin (_shimmerPhase * Math.PI) * 0.45;

						_shimmerOverlay.Opacity = Math.Max (0.0, val);

					} else if (_shimmerOverlay.Opacity > 0.01) {

						_shimmerOverlay.Opacity *= 0.82;

					} else {

						_shimmerOverlay.Opacity = 0.0;

					}

				}

			} catch {

			}

			int childrenCount = dockPanel.Children.Count;
			if (_targetCenters == null || _targetCenters.Length != childrenCount) {
				_targetCenters = new double[childrenCount];
				_childTargetSizes = new double[childrenCount];
				_unmagSizes = new double[childrenCount];
				_marginBefore = new double[childrenCount];
				_marginAfter = new double[childrenCount];
				_targetScales = new double[childrenCount];
				_unmagCenters = new double[childrenCount];
				_magSizes = new double[childrenCount];
				_magCenters = new double[childrenCount];
			}
			double[] targetCenters = _targetCenters;
			double[] childTargetSizes = _childTargetSizes;
			bool isHorizontal = (dockPanel.Orientation == System.Windows.Controls.Orientation.Horizontal);

			double[] unmagSizes = _unmagSizes;
			double[] marginBefore = _marginBefore;
			double[] marginAfter = _marginAfter;
			double[] targetScales = _targetScales;
			double[] unmagCenters = _unmagCenters;
			double totalUnmagSize = 0.0;

			for (int i = 0; i < childrenCount; i++) {
				UIElement child = dockPanel.Children[i];
				double size = 0.0;
				double marginB = 0.0;
				double marginA = 0.0;

				if (child is DockItemControl) {
					size = isHorizontal ? baseSize : (baseSize + 12.0);
					marginB = 5.0;
					marginA = 5.0;
				} else if (child is Border) {
					size = 1.2;
					marginB = 10.0;
					marginA = 10.0;
				} else if (child is FrameworkElement fe) {
					if (isHorizontal) {
						size = fe.Width > 0 && !double.IsNaN (fe.Width) ? fe.Width : fe.ActualWidth;
						if (size <= 0) size = baseSize;
						marginB = fe.Margin.Left;
						marginA = fe.Margin.Right;
					} else {
						size = fe.Height > 0 && !double.IsNaN (fe.Height) ? fe.Height : fe.ActualHeight;
						if (size <= 0) size = baseSize;
						marginB = fe.Margin.Top;
						marginA = fe.Margin.Bottom;
					}
				}

				unmagSizes[i] = size;
				marginBefore[i] = marginB;
				marginAfter[i] = marginA;
				totalUnmagSize += size + marginB + marginA;
			}

			double dockCenter = isHorizontal ? (this.ActualWidth / 2.0) : (this.ActualHeight / 2.0);
			double targetStart = dockCenter - totalUnmagSize / 2.0;

			double currentPos = targetStart;
			for (int i = 0; i < childrenCount; i++) {
				unmagCenters[i] = currentPos + marginBefore[i] + unmagSizes[i] / 2.0;
				targetCenters[i] = unmagCenters[i];
				currentPos += unmagSizes[i] + marginBefore[i] + marginAfter[i];
			}



			for (int i = 0; i < childrenCount; i++) {
				UIElement child = dockPanel.Children[i];
				if (!(child is DockItemControl)) {
					targetScales[i] = 1.0;
					continue;
				}

				double center = unmagCenters[i];
				double dist = isHorizontal ? Math.Abs (mousePosInWindow.X - center) : Math.Abs (mousePosInWindow.Y - center);

				if (flag && !isDockHidden && IsAnimationEnabled && dist < range) {
					double num8 = Math.Sin ((1.0 - dist / range) * Math.PI / 2.0);
					targetScales[i] = 1.0 + (maxSize / baseSize - 1.0) * num8;
				} else {
					targetScales[i] = 1.0;
				}
			}

			double[] magSizes = _magSizes;
			double factor = lerpFactor;
			if (num2 > 0.0) {
				factor = 1.0 - Math.Pow (1.0 - lerpFactor, num2 / 16.67);
			}

			for (int i = 0; i < childrenCount; i++) {
				UIElement child = dockPanel.Children[i];
				if (child is DockItemControl dockItemControl) {
					double curScale = dockItemControl.scaleTransform.ScaleX;
					double lerpedScale = curScale + (targetScales[i] - curScale) * factor;
					if (Math.Abs (lerpedScale - targetScales[i]) < 0.005) {
						lerpedScale = targetScales[i];
					}
					if (Math.Abs (curScale - lerpedScale) > 0.0002) {
						dockItemControl.scaleTransform.ScaleX = lerpedScale;
						dockItemControl.scaleTransform.ScaleY = lerpedScale;
					}
					magSizes[i] = (isHorizontal ? baseSize : (baseSize + 12.0)) * lerpedScale;
				} else {
					magSizes[i] = unmagSizes[i];
				}
			}

			double[] magCenters = _magCenters;
			double currentMagPos = 0.0;
			for (int i = 0; i < childrenCount; i++) {
				magCenters[i] = currentMagPos + marginBefore[i] + magSizes[i] / 2.0;
				currentMagPos += magSizes[i] + marginBefore[i] + marginAfter[i];
			}
			double totalMagSize = currentMagPos;

			double maxScale = 1.0;
			for (int i = 0; i < childrenCount; i++) {
				if (dockPanel.Children[i] is DockItemControl dic) {
					if (dic.scaleTransform.ScaleX > maxScale) {
						maxScale = dic.scaleTransform.ScaleX;
					}
				}
			}

			if (isHorizontal) {
				double targetW = totalMagSize + dockBorder.Padding.Left + dockBorder.Padding.Right;
				double targetH = baseSize * maxScale + dockBorder.Padding.Top + dockBorder.Padding.Bottom + 12.0;
				if (Math.Abs (dockBorder.Width - targetW) > 0.2) {
					dockBorder.Width = targetW;
				}
				if (Math.Abs (dockBorder.Height - targetH) > 0.2) {
					dockBorder.Height = targetH;
				}
			} else {
				double targetW = baseSize * maxScale + dockBorder.Padding.Left + dockBorder.Padding.Right + 12.0;
				double targetH = totalMagSize + dockBorder.Padding.Top + dockBorder.Padding.Bottom;
				if (Math.Abs (dockBorder.Width - targetW) > 0.2) {
					dockBorder.Width = targetW;
				}
				if (Math.Abs (dockBorder.Height - targetH) > 0.2) {
					dockBorder.Height = targetH;
				}
			}

			int insertIndex = -1;
			bool isDragActive = (activeDraggedItem != null) || isExternalDragOver;
			double dragPos = 0.0;

			if (isDragActive) {
				System.Windows.Point dragMousePos = activeDraggedItem != null ? Mouse.GetPosition (dockPanel) : externalDragMousePosition;
				dragPos = isHorizontal ? dragMousePos.X : dragMousePos.Y;
				for (int i = 0; i < childrenCount; i++) {
					double relCenter = unmagCenters[i] - targetStart;
					if (dragPos < relCenter) {
						insertIndex = i;
						break;
					}
				}
				if (insertIndex == -1) {
					insertIndex = childrenCount;
				}
			}

			if (_dragShifts == null) {
				_dragShifts = new Dictionary<UIElement, double> ();
			}

			for (int i = 0; i < childrenCount; i++) {
				UIElement child = dockPanel.Children[i];
				double targetDragShift = 0.0;

				if (isDragActive) {
					if (child == activeDraggedItem) {
						targetDragShift = 0.0;
					} else if (i < insertIndex) {
						targetDragShift = -baseSize * 0.45;
					} else {
						targetDragShift = baseSize * 0.45;
					}
				}

				if (!_dragShifts.TryGetValue (child, out double curDragShift)) {
					curDragShift = 0.0;
				}
				double newDragShift = curDragShift + (targetDragShift - curDragShift) * 0.25;
				_dragShifts[child] = newDragShift;
			}

			double Shift = (totalUnmagSize / 2.0) - (totalMagSize / 2.0);
			int num3 = 0;
			double stableCross = GetStableCrossCenter ();
			for (int i = 0; i < childrenCount; i++) {
				UIElement child = dockPanel.Children[i];
				double targetMagCenter = magCenters[i] + Shift;
				double defaultUnmagCenter = unmagCenters[i] - targetStart;
				double offset = targetMagCenter - defaultUnmagCenter + _dragShifts[child];

				if (child is DockItemControl dockItemControl) {
					double num5 = isHorizontal ? Math.Abs (mousePosInWindow.X - unmagCenters[i]) : Math.Abs (mousePosInWindow.Y - unmagCenters[i]);



					double num12 = 0.0;
					try {
						if (IsAnimationEnabled && dockItemControl.WaveTransform != null) {
							if (flag && num5 < range * 1.5) {
								double a2 = wavePhase - (double)num3 * 0.55;
								double num13 = Math.Max (0.0, 1.0 - num5 / (range * 1.5));
								num12 = Math.Sin (a2) * 4.5 * num13;
							}
							double crossVal = isHorizontal ? dockItemControl.WaveTransform.Y : dockItemControl.WaveTransform.X;
							if (Math.Abs (num12 - crossVal) > 0.005 || Math.Abs (crossVal) > 0.005) {
