		}



		public static string CleanTrackTitleStatic (string title)

		{

			if (string.IsNullOrEmpty (title)) {

				return "";

			}

			int num = title.IndexOf (" (");

			if (num != -1) {

				title = title.Substring (0, num);

			}

			num = title.IndexOf (" - Live");

			if (num != -1) {

				title = title.Substring (0, num);

			}

			num = title.IndexOf (" - Remaster");

			if (num != -1) {

				title = title.Substring (0, num);

			}

			num = title.IndexOf (" - Radio Edit");

			if (num != -1) {

				title = title.Substring (0, num);

			}

			return title.Trim ();

		}



		private static void FetchTrackDetailsStatic (string artist, string track, out string artUrl, out int durationSeconds)

		{

			artUrl = null;

			durationSeconds = 200;

			if (string.IsNullOrEmpty (artist) || string.IsNullOrEmpty (track) || artist == "Spotify") {

				return;

			}

			switch (track) {

			case "Spotify Closed":

				return;

			case "No Track Playing":

				return;

			}

			try {

				ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

				using TimeoutWebClient webClient = new TimeoutWebClient { TimeoutMs = 8000 };

				webClient.Encoding = Encoding.UTF8;

				webClient.Headers.Add ("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)");

				string text = CleanTrackTitleStatic (track);

				string text2 = Uri.EscapeDataString (artist + " " + text);

				string address = "https://itunes.apple.com/search?term=" + text2 + "&limit=1&media=music";

				string text3 = webClient.DownloadString (address);

				int num = text3.IndexOf ("\"trackTimeMillis\":");

				if (num != -1) {

					int num2 = num + "\"trackTimeMillis\":".Length;

					int i;

					for (i = num2; i < text3.Length && char.IsDigit (text3 [i]); i++) {

					}

					if (int.TryParse (text3.Substring (num2, i - num2), out var result) && result > 0) {

						durationSeconds = result / 1000;

					}

				}

				int num3 = text3.IndexOf ("\"artworkUrl100\":\"");

				if (num3 != -1) {

					int num4 = num3 + "\"artworkUrl100\":\"".Length;

					int num5 = text3.IndexOf ("\"", num4);

					string text4 = text3.Substring (num4, num5 - num4);

					text4 = text4.Replace ("\\/", "/");

					artUrl = text4.Replace ("100x100", "600x600");

				}

			} catch {

			}

		}



