		private void UpdateNotificationBadges ()

		{

			try {

				ThreadPool.QueueUserWorkItem (delegate {

					try {

						Dictionary<string, string> windowTitles = new Dictionary<string, string> ();

						EnumWindows (delegate(IntPtr hWnd, IntPtr lParam) {

							try {

								if (!IsWindowVisible (hWnd)) {

									return true;

								}

								int windowTextLength = GetWindowTextLength (hWnd);

								if (windowTextLength < 1) {

									return true;

								}

								StringBuilder stringBuilder = new StringBuilder (windowTextLength + 1);

								GetWindowText (hWnd, stringBuilder, stringBuilder.Capacity);

								string value = stringBuilder.ToString ();

								if (string.IsNullOrWhiteSpace (value)) {

									return true;

								}

								GetWindowThreadProcessId (hWnd, out var lpdwProcessId);

								try {

									string key = Process.GetProcessById ((int)lpdwProcessId).ProcessName.ToLower ();

									if (!windowTitles.ContainsKey (key)) {

										windowTitles [key] = value;

									}

								} catch {

								}

							} catch {

							}

							return true;

						}, IntPtr.Zero);

						base.Dispatcher.BeginInvoke ((Action)delegate {

							try {

								List<DockItemControl> list = new List<DockItemControl> ();

								list.AddRange (dockItems);

								list.AddRange (runningItems);

								list.AddRange (recentControls);

								foreach (DockItemControl item in list) {

									if (item == null || item.BadgeBorder == null) {

										continue;

									}

									try {

										string text = ((item.Config != null && item.Config.ProcessName != null) ? item.Config.ProcessName : "").ToLower ();

										if (string.IsNullOrEmpty (text)) {

											continue;

										}

										int num = 0;

										foreach (KeyValuePair<string, string> item2 in windowTitles) {

											if (!item2.Key.Contains (text) && !text.Contains (item2.Key)) {

												continue;

											}

											string text2 = item2.Value ?? "";

											if (text2.Length > 2 && text2 [0] == '(') {

												int num2 = text2.IndexOf (')');

												if (num2 > 1 && int.TryParse (text2.Substring (1, num2 - 1), out var result) && result > 0) {

													num = result;

												}

											}

											break;

										}

										if (num > 0) {

											item.BadgeText.Text = ((num > 99) ? "99+" : num.ToString ());

											if (item.BadgeBorder.Visibility != 0) {

												item.BadgeBorder.Visibility = Visibility.Visible;

												item.BadgeBorder.RenderTransform = new ScaleTransform (0.0, 0.0, 7.0, 7.0);

												item.BadgeBorder.RenderTransformOrigin = new System.Windows.Point (1.0, 0.0);

												DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (200.0)) {

													EasingFunction = new BackEase {

														Amplitude = 0.4,

														EasingMode = EasingMode.EaseOut

													}

												};

												DoubleAnimation animation2 = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (200.0)) {

													EasingFunction = new BackEase {

														Amplitude = 0.4,

														EasingMode = EasingMode.EaseOut

													}

												};

												((ScaleTransform)item.BadgeBorder.RenderTransform).BeginAnimation (ScaleTransform.ScaleXProperty, animation);

												((ScaleTransform)item.BadgeBorder.RenderTransform).BeginAnimation (ScaleTransform.ScaleYProperty, animation2);

												DoubleAnimation animation3 = new DoubleAnimation (1.0, 0.75, TimeSpan.FromMilliseconds (700.0)) {

													AutoReverse = true,

													RepeatBehavior = RepeatBehavior.Forever,

													EasingFunction = new SineEase {

														EasingMode = EasingMode.EaseInOut

													}

												};

												item.BadgeBorder.BeginAnimation (UIElement.OpacityProperty, animation3);

											}

										} else {

											item.BadgeBorder.Visibility = Visibility.Collapsed;

										}

									} catch {

									}

								}

							} catch {

							}

						});

					} catch {

					}

				});

			} catch {

			}

		}



