		private static System.Windows.Media.Color DockLerpColor (System.Windows.Media.Color a, System.Windows.Media.Color b, float t)

		{

			t = Math.Max (0f, Math.Min (1f, t));

			return System.Windows.Media.Color.FromRgb ((byte)((float)(int)a.R + (float)(b.R - a.R) * t), (byte)((float)(int)a.G + (float)(b.G - a.G) * t), (byte)((float)(int)a.B + (float)(b.B - a.B) * t));

		}



		private static System.Windows.Media.Color DockHsvToColor (double hDeg, double s, double v)

		{

			hDeg = (hDeg % 360.0 + 360.0) % 360.0;

			double num = v * s;

			double num2 = num * (1.0 - Math.Abs (hDeg / 60.0 % 2.0 - 1.0));

			double num3 = v - num;

			double num4 = 0.0;

			double num5 = 0.0;

			double num6 = 0.0;

			if (hDeg < 60.0) {

				num4 = num;

				num5 = num2;

			} else if (hDeg < 120.0) {

				num4 = num2;

				num5 = num;

			} else if (hDeg < 180.0) {

				num5 = num;

				num6 = num2;

			} else if (hDeg < 240.0) {

				num5 = num2;

				num6 = num;

			} else if (hDeg < 300.0) {

				num4 = num2;

				num6 = num;

			} else {

				num4 = num;

				num6 = num2;

			}

			return System.Windows.Media.Color.FromRgb ((byte)((num4 + num3) * 255.0), (byte)((num5 + num3) * 255.0), (byte)((num6 + num3) * 255.0));

		}



		private static System.Windows.Media.Color DockShiftHue (System.Windows.Media.Color c, double degrees)

		{

			double num = (double)(int)c.R / 255.0;

			double num2 = (double)(int)c.G / 255.0;

			double num3 = (double)(int)c.B / 255.0;

			double num4 = Math.Max (num, Math.Max (num2, num3));

			double num5 = Math.Min (num, Math.Min (num2, num3));

			double num6 = num4 - num5;

			double num7 = 0.0;

			double s = ((num4 > 0.0) ? (num6 / num4) : 0.0);

			double v = num4;

			if (num6 > 0.0) {

				num7 = ((num4 == num) ? (60.0 * ((num2 - num3) / num6 % 6.0)) : ((num4 != num2) ? (60.0 * ((num - num2) / num6 + 4.0)) : (60.0 * ((num3 - num) / num6 + 2.0))));

			}

			return DockHsvToColor (num7 + degrees, s, v);

		}



