					double num3 = 2.5 + _particleRand.NextDouble () * 3.5;

					double num4 = 3.5 + _particleRand.NextDouble () * 4.0;

					double value = 0.45 + _particleRand.NextDouble () * 0.25;

					System.Windows.Media.Color color = DockShiftHue (accentColor, _particleRand.NextDouble () * 60.0 - 30.0);

