					_particleCanvas.Children.Add (ellipse);

					double num8 = num3 * 45.0;

					double toValue = num6 + Math.Cos (num2) * num8;

					double toValue2 = num7 + Math.Sin (num2) * num8 - 25.0;

					TimeSpan timeSpan = TimeSpan.FromSeconds (value);

