					};

					DoubleAnimation animation2 = new DoubleAnimation (num7, toValue2, timeSpan) {

						EasingFunction = easingFunction

					};

					DoubleAnimation doubleAnimation = new DoubleAnimation (0.95, 0.0, timeSpan) {

						EasingFunction = easingFunction

					};

					Ellipse localParticle = ellipse;

					doubleAnimation.Completed += delegate {

						try {

							_particleCanvas.Children.Remove (localParticle);

						} catch {

						}

					};

					ellipse.BeginAnimation (Canvas.LeftProperty, animation);

