		public void StartBorderPulsing (System.Windows.Media.Color c1, System.Windows.Media.Color c2)

		{

			try {

				_borderPulseC1 = c1;

				_borderPulseC2 = c2;

				if (_borderPulseTimer != null) {

					return;

				}

				_borderPulsePhase = 0.0;

				_borderPulseTimer = new DispatcherTimer {

					Interval = TimeSpan.FromMilliseconds (50.0)

				};

				System.Windows.Media.Color? lastC3 = null;

				System.Windows.Media.Color? lastC4 = null;

				System.Windows.Media.Color? lastC = null;

				_borderPulseTimer.Tick += delegate {

					try {

						if (dockBorder != null && settings.ShowDockBorder) {

							_borderPulsePhase += 0.03;

							double num = (Math.Sin (_borderPulsePhase) + 1.0) / 2.0;

							System.Windows.Media.Color color = DockLerpColor (_borderPulseC1, _borderPulseC2, (float)num);

							System.Windows.Media.Color color2 = DockLerpColor (_borderPulseC2, _borderPulseC1, (float)num);

							System.Windows.Media.Color color3 = System.Windows.Media.Color.FromArgb ((byte)(160.0 + 60.0 * num), color.R, color.G, color.B);

							System.Windows.Media.Color color4 = System.Windows.Media.Color.FromArgb ((byte)(80.0 + 40.0 * num), color2.R, color2.G, color2.B);

							if (dockBorder.BorderBrush is LinearGradientBrush linearGradientBrush && !linearGradientBrush.IsFrozen && linearGradientBrush.GradientStops.Count >= 2) {

								if (lastC3 != color3) {

									linearGradientBrush.GradientStops [0].Color = color3;

									lastC3 = color3;

								}

								if (lastC4 != color4) {

									linearGradientBrush.GradientStops [1].Color = color4;

									lastC4 = color4;

								}

							}

							if (dockBorder.Effect is DropShadowEffect dropShadowEffect) {

								if (lastC != color) {

									dropShadowEffect.Color = color;

									lastC = color;

								}

							}

						}

					} catch {

					}

				};

				_borderPulseTimer.Start ();

			} catch {

			}

		}



		public void StopBorderPulsing ()

		{

			try {

				if (_borderPulseTimer != null) {

					_borderPulseTimer.Stop ();

					_borderPulseTimer = null;

				}

				ApplyTheme ();

			} catch {

			}

		}



		private List<string> GetChromiumHistoryPaths ()

		{

			List<string> list = new List<string> ();

			try {

				string folderPath = Environment.GetFolderPath (Environment.SpecialFolder.LocalApplicationData);

				string[] array = new string[3] {

					System.IO.Path.Combine (folderPath, "Google\\Chrome\\User Data"),

					System.IO.Path.Combine (folderPath, "Microsoft\\Edge\\User Data"),

					System.IO.Path.Combine (folderPath, "BraveSoftware\\Brave-Browser\\User Data")

				};

