									int delta = maxC - minC;

									if (delta > 25) {

										System.Windows.Media.Color color = System.Windows.Media.Color.FromArgb (30, avgR, avgG, avgB);

										if (color != liquidGlassTintColor) {

											liquidGlassTintColor = color;

											liquidTintStrength = Math.Min (1.0, (double)delta / 80.0);

											ApplyLiquidGlassTint ();

										}

									} else if (liquidGlassTintColor.A > 0) {

										liquidGlassTintColor = System.Windows.Media.Color.FromArgb (0, 0, 0, 0);

										liquidTintStrength = 0.0;

										ApplyLiquidGlassTint ();

									}

								} catch {

								}

							});

						}

					} catch {

					}

				});

			} catch {

			}

			try {

				if (!settings.AmbientWallpaperTint || !settings.AutoAccentFromWallpaper) {

					return;

				}

				string text3 = null;

				using (RegistryKey registryKey2 = Registry.CurrentUser.OpenSubKey ("Control Panel\\Desktop", writable: false)) {

					if (registryKey2 != null) {

						text3 = registryKey2.GetValue ("Wallpaper") as string;

					}

				}

				if (!string.IsNullOrEmpty (text3) && text3 != _cachedWallpaperPath) {

					_cachedWallpaperAccent = null;

					base.Dispatcher.BeginInvoke ((Action)delegate {

						ApplyTheme ();

					});

				}

			} catch {

			}

		}



		public void ApplyLiquidGlassTint ()
		{
			try {
				if (dockBorder == null) return;
				if (settings != null && settings.EnableLiquidGlass) {
					LiquidGlassEffect glassEffect = dockBorder.Effect as LiquidGlassEffect;
					if (glassEffect == null) {
						glassEffect = new LiquidGlassEffect {
							CornerRadius = dockBorder.CornerRadius.TopLeft > 0 ? dockBorder.CornerRadius.TopLeft : 22.0,
							RefractionStrength = 6.0,
							TintOpacity = 0.08,
							SpecularIntensity = 0.35,
							DockSize = new System.Windows.Size (dockBorder.ActualWidth > 0 ? dockBorder.ActualWidth : 500.0, dockBorder.ActualHeight > 0 ? dockBorder.ActualHeight : 80.0)
						};
						dockBorder.Effect = glassEffect;
					}

					dockBorder.Background = new LinearGradientBrush (
						new GradientStopCollection {
							new GradientStop (System.Windows.Media.Color.FromArgb (165, 255, 255, 255), 0.0),
							new GradientStop (System.Windows.Media.Color.FromArgb (115, 242, 245, 250), 0.35),
							new GradientStop (System.Windows.Media.Color.FromArgb (145, 255, 255, 255), 1.0)
						},
						new System.Windows.Point (0.0, 0.0),
						new System.Windows.Point (0.0, 1.0)
					);

					dockBorder.BorderBrush = new LinearGradientBrush (
						new GradientStopCollection {
							new GradientStop (System.Windows.Media.Color.FromArgb (240, 255, 255, 255), 0.0),
							new GradientStop (System.Windows.Media.Color.FromArgb (160, 255, 255, 255), 0.4),
							new GradientStop (System.Windows.Media.Color.FromArgb (200, 255, 255, 255), 1.0)
						},
						new System.Windows.Point (0.0, 0.0),
						new System.Windows.Point (1.0, 1.0)
					);
					dockBorder.BorderThickness = new Thickness (1.5);

					if (_shimmerOverlay != null) {
						_shimmerOverlay.CornerRadius = dockBorder.CornerRadius;
						_shimmerOverlay.Opacity = 0.75;
						_shimmerOverlay.Background = new LinearGradientBrush (
							new GradientStopCollection {
								new GradientStop (System.Windows.Media.Color.FromArgb (70, 255, 255, 255), 0.0),
								new GradientStop (System.Windows.Media.Color.FromArgb (0, 255, 255, 255), 0.5),
								new GradientStop (System.Windows.Media.Color.FromArgb (40, 255, 255, 255), 1.0)
							},
							new System.Windows.Point (0.2, 0.0),
							new System.Windows.Point (0.8, 1.0)
						);
					}
				} else {
					ApplyTheme ();
				}
			} catch {
			}
		}



		private string GetSpotifyTitleFast ()

		{

			try {

				if (_cachedSpotifyHwnd != IntPtr.Zero) {

					if (IsWindow (_cachedSpotifyHwnd)) {

						int windowTextLength = GetWindowTextLength (_cachedSpotifyHwnd);

						if (windowTextLength > 0) {

							StringBuilder stringBuilder = new StringBuilder (windowTextLength + 1);

							GetWindowText (_cachedSpotifyHwnd, stringBuilder, stringBuilder.Capacity);

							string text = stringBuilder.ToString ();

							if (!string.IsNullOrEmpty (text)) {

								return text;

							}

						}

					} else {

						_cachedSpotifyHwnd = IntPtr.Zero;

					}

				}

			} catch {

			}

			try {

				IntPtr intPtr = FindWindow ("SpotifyMainWindow", null);

				if (intPtr != IntPtr.Zero) {

					int windowTextLength2 = GetWindowTextLength (intPtr);

					if (windowTextLength2 > 0) {

						StringBuilder stringBuilder2 = new StringBuilder (windowTextLength2 + 1);

						GetWindowText (intPtr, stringBuilder2, stringBuilder2.Capacity);

						string text2 = stringBuilder2.ToString ();

						if (!string.IsNullOrEmpty (text2)) {

							_cachedSpotifyHwnd = intPtr;

							return text2;

						}

					}

				}

			} catch {

			}

			if ((DateTime.Now - _lastSpotifyProcessCheck).TotalSeconds > 2.0 && !_isCheckingSpotifyProcess) {

				_isCheckingSpotifyProcess = true;

				_lastSpotifyProcessCheck = DateTime.Now;

				ThreadPool.QueueUserWorkItem (delegate {

					try {

						Process[] processesByName = Process.GetProcessesByName ("spotify");

						foreach (Process process in processesByName) {

							if (process != null && !string.IsNullOrEmpty (process.MainWindowTitle)) {

								IntPtr mainWindowHandle = process.MainWindowHandle;

								if (mainWindowHandle != IntPtr.Zero) {

									_cachedSpotifyHwnd = mainWindowHandle;

									base.Dispatcher.BeginInvoke ((Action)delegate {

										SyncSpotifyStateFast ();

									});

								}

								break;

							}

						}

					} catch {

					} finally {

						_isCheckingSpotifyProcess = false;

					}

				});

			}

			return null;

		}



		private void SyncSpotifyStateFast ()

		{

			try {

				string spotifyTitleFast = GetSpotifyTitleFast ();

				if (spotifyTitleFast == null) {

					bgSpotifyIsPlaying = false;

					bgSpotifyTrackKey = "";

					bgSpotifyPosition = 0.0;

					return;

				}

				switch (spotifyTitleFast) {

				case "Spotify":

				case "Spotify Premium":

				case "Spotify Free":

					bgSpotifyIsPlaying = false;

					bgSpotifyLastUpdate = DateTime.Now;

					return;

				}

				bool flag = bgSpotifyIsPlaying;

				bgSpotifyIsPlaying = true;

				string text = spotifyTitleFast;

				if (text != bgSpotifyTrackKey) {

					bgSpotifyTrackKey = text;

					bgSpotifyPosition = 0.0;

					bgSpotifyDuration = 200.0;

					bgSpotifyLastUpdate = DateTime.Now;

					int num = spotifyTitleFast.IndexOf (" - ");

					string bgArtist = "Spotify";

					string bgTrack = spotifyTitleFast;

					if (num != -1) {

						bgArtist = spotifyTitleFast.Substring (0, num).Trim ();

						bgTrack = spotifyTitleFast.Substring (num + 3).Trim ();

					}

					string closureQueryKey = text;

					int durationSec;

					ThreadPool.QueueUserWorkItem (delegate {

						try {

							FetchTrackDetailsStatic (bgArtist, bgTrack, out var _, out durationSec);

							base.Dispatcher.BeginInvoke ((Action)delegate {

								if (bgSpotifyTrackKey == closureQueryKey) {

									bgSpotifyDuration = durationSec;

								}

							});

						} catch {

						}

					});

					return;

				}

				DateTime now = DateTime.Now;

				if (flag) {

					double num2 = (now - bgSpotifyLastUpdate).TotalSeconds;

					if (num2 > 5.0) {

						num2 = 0.1;

					}

					bgSpotifyPosition += num2;

					if (bgSpotifyPosition > bgSpotifyDuration) {

						bgSpotifyPosition = bgSpotifyDuration;

					}

				}

				bgSpotifyLastUpdate = now;

			} catch {

			}

		}



		private void CheckRunningProcesses ()

		{

			try {

				if (_isCheckingProcesses) {

					return;

				}

				_isCheckingProcesses = true;

				List<PinnedItemProcessInfo> pinnedList = new List<PinnedItemProcessInfo> ();

				foreach (DockItemControl dockItem in dockItems) {

					string text = dockItem.Config.ProcessName;

					if (string.IsNullOrEmpty (text) && !string.IsNullOrEmpty (dockItem.Config.FilePath)) {

						try {

							text = System.IO.Path.GetFileNameWithoutExtension (dockItem.Config.FilePath);

						} catch {

						}

					}

					pinnedList.Add (new PinnedItemProcessInfo {

						Control = dockItem,

						ProcessName = text

					});

				}

				HashSet<string> pinnedPaths = new HashSet<string> ();

				HashSet<string> pinnedProcNames = new HashSet<string> ();

				foreach (DockItemConfig item3 in settings.Items) {

					if (!string.IsNullOrEmpty (item3.FilePath)) {

						pinnedPaths.Add (item3.FilePath.ToLower ());

						if (item3.FilePath.EndsWith (".lnk", StringComparison.OrdinalIgnoreCase)) {

							try {

								string text2 = IconExtractor.ResolveShortcut (item3.FilePath);

								if (!string.IsNullOrEmpty (text2)) {

									pinnedPaths.Add (text2.ToLower ());

								}

							} catch {

							}

						}

					}

					if (!string.IsNullOrEmpty (item3.ProcessName)) {

						pinnedProcNames.Add (item3.ProcessName.ToLower ());

					}

				}

				int currentPid = Process.GetCurrentProcess ().Id;

				ThreadPool.QueueUserWorkItem (delegate {

					try {

						List<PinnedProcessResult> pinnedResults = new List<PinnedProcessResult> ();

						foreach (var info in pinnedList) {

							IntPtr hwnd = IntPtr.Zero;

							bool isActive = false;

							if (!string.IsNullOrEmpty (info.ProcessName)) {

								hwnd = GetMainWindowHandleForProcess (info.ProcessName);

								isActive = hwnd != IntPtr.Zero;

							}

							pinnedResults.Add (new PinnedProcessResult {

								Control = info.Control,

								Hwnd = hwnd,

								IsActive = isActive

							});

						}

						List<ProcessWindowInfo> activeRunningApps = new List<ProcessWindowInfo> ();
						List<ProcessWindowInfo> minimizedApps = new List<ProcessWindowInfo> ();

						EnumWindows (delegate(IntPtr hWnd, IntPtr lParam) {

							if (IsTaskbarWindow (hWnd)) {

								uint uwpActualProcessId = GetUwpActualProcessId (hWnd);

								bool isMin = IsIconic (hWnd);

								if (isMin) {
									try {
										Process processById = Process.GetProcessById ((int)uwpActualProcessId);
										string name = processById.ProcessName.ToLower ();
										if (name != "shellexperiencehost" && name != "searchhost") {
											int windowTextLength = GetWindowTextLength (hWnd);
											if (windowTextLength > 0) {
												StringBuilder stringBuilder = new StringBuilder (windowTextLength + 1);
												GetWindowText (hWnd, stringBuilder, stringBuilder.Capacity);
												string text4 = stringBuilder.ToString ();
												if (!string.IsNullOrEmpty (text4)) {
													string processPath = GetProcessPath (processById);
													if (!string.IsNullOrEmpty (processPath)) {
														minimizedApps.Add (new ProcessWindowInfo {
															Process = processById,
															Hwnd = hWnd,
															Title = text4,
															ProcessName = processById.ProcessName,
															Path = processPath
														});
													}
												}
											}
										}
									} catch {}
								}

								if (uwpActualProcessId == currentPid) {

									return true;

								}

								try {

									Process processById = Process.GetProcessById ((int)uwpActualProcessId);

									string name = processById.ProcessName.ToLower ();

									if (name == "explorer") {

										if (!IsRealExplorerWindow (hWnd)) {

											return true;

										}

									} else if (name == "shellexperiencehost" || name == "searchhost") {

										return true;

									}

									int windowTextLength = GetWindowTextLength (hWnd);

									if (windowTextLength == 0) {

										return true;

									}

									StringBuilder stringBuilder = new StringBuilder (windowTextLength + 1);

									GetWindowText (hWnd, stringBuilder, stringBuilder.Capacity);

									string text4 = stringBuilder.ToString ();

									if (string.IsNullOrEmpty (text4)) {

										return true;

									}

									string processPath = GetProcessPath (processById);

									if (string.IsNullOrEmpty (processPath)) {

										return true;

									}

									if (pinnedPaths.Contains (processPath.ToLower ()) || pinnedProcNames.Contains (name)) {

										return true;

									}

									if (activeRunningApps.Any ((ProcessWindowInfo x) => x.ProcessName.ToLower () == name)) {

										return true;

									}

									activeRunningApps.Add (new ProcessWindowInfo {

										Process = processById,

										Hwnd = hWnd,

										Title = text4,

										ProcessName = processById.ProcessName,

										Path = processPath

									});

								} catch {

								}

							}

							return true;

						}, IntPtr.Zero);

						base.Dispatcher.BeginInvoke ((Action)delegate {

							try {

								foreach (var res in pinnedResults) {

									res.Control.TargetHwnd = res.Hwnd;

									if (res.IsActive) {
										res.Control.StartBreathingDot ();
									} else {
										res.Control.StopBreathingDot ();
									}

									if (res.Control.isLaunching && (res.IsActive || (DateTime.Now - res.Control.launchTime).TotalSeconds > 8.0)) {

										res.Control.isLaunching = false;

										res.Control.StopPersistentBounce ();

									}

								}

								bool uiChanged = false;

								List<DockItemControl> minListToRemove = new List<DockItemControl> ();
								foreach (DockItemControl minItem in minimizedItems) {
									if (!minimizedApps.Any (x => x.Hwnd == minItem.TargetHwnd)) {
										minListToRemove.Add (minItem);
									}
								}
								foreach (DockItemControl minItem in minListToRemove) {
									minimizedItems.Remove (minItem);
									dockPanel.Children.Remove (minItem);
									uiChanged = true;
								}

								foreach (ProcessWindowInfo appInfo in minimizedApps) {
									if (minimizedItems.Any (x => x.TargetHwnd == appInfo.Hwnd)) {
										continue;
									}
									string title = appInfo.Title;
									if (title.Length > 24) {
										title = appInfo.ProcessName;
									}
									DockItemConfig config = new DockItemConfig {
										Name = title,
										FilePath = appInfo.Path,
										ProcessName = appInfo.ProcessName
									};
									DockItemControl itemControl = new DockItemControl (config, baseSize);
									itemControl.TargetHwnd = appInfo.Hwnd;
									itemControl.Opacity = 0.85;

									IntPtr hwnd = appInfo.Hwnd;
									itemControl.MouseLeftButtonDown += delegate {
										try {
											itemControl.Bounce ();
											if (hwnd != IntPtr.Zero) {
												ShowWindow (hwnd, 9); // SW_RESTORE
												SetForegroundWindow (hwnd);
											}
										} catch {}
									};

									minimizedItems.Add (itemControl);
									uiChanged = true;
								}

								List<DockItemControl> listToRemove = new List<DockItemControl> ();

								foreach (DockItemControl item2 in runningItems) {

									if (activeRunningApps.Any ((ProcessWindowInfo x) => x.ProcessName.ToLower () == item2.Config.ProcessName.ToLower ())) {

										continue;

									}

									listToRemove.Add (item2);

									if (!settings.Items.Any ((DockItemConfig p) => p.ProcessName.ToLower () == item2.Config.ProcessName.ToLower ())) {

										recentApps.RemoveAll ((DockItemConfig x) => x.ProcessName.ToLower () == item2.Config.ProcessName.ToLower ());

										recentApps.Insert (0, item2.Config);

										if (recentApps.Count > 3) {

											recentApps.RemoveAt (recentApps.Count - 1);

										}

										uiChanged = true;

									}

								}

								foreach (DockItemControl item4 in listToRemove) {

									runningItems.Remove (item4);

									dockPanel.Children.Remove (item4);

									uiChanged = true;

								}

								foreach (ProcessWindowInfo appInfo in activeRunningApps) {

									if (runningItems.Any ((DockItemControl x) => x.Config.ProcessName.ToLower () == appInfo.ProcessName.ToLower ())) {

										continue;

									}

									recentApps.RemoveAll ((DockItemConfig x) => x.ProcessName.ToLower () == appInfo.ProcessName.ToLower ());

									string text3 = appInfo.Title;

									if (text3.Length > 24) {

										text3 = appInfo.ProcessName;

									}

									DockItemConfig config = new DockItemConfig {

										Name = text3,

										FilePath = appInfo.Path,

										ProcessName = appInfo.ProcessName

									};

									DockItemControl itemControl = new DockItemControl (config, baseSize);

									itemControl.TargetHwnd = appInfo.Hwnd;

									itemControl.IndicatorDot.Opacity = 1.0;

									IntPtr hwnd = appInfo.Hwnd;

									itemControl.MouseLeftButtonDown += delegate {

										try {

											itemControl.Bounce ();

											if (hwnd != IntPtr.Zero) {

												if (GetForegroundWindow () == hwnd) {

													ShowWindow (hwnd, 6);

												} else {

													if (IsIconic (hwnd)) {

														ShowWindow (hwnd, 9);

													}

													SetForegroundWindow (hwnd);

												}

											}

										} catch {

										}

									};

									CreateRunningItemContextMenu (itemControl, appInfo.Process);

									if (appInfo.ProcessName.ToLower () == "calendar" || text3.ToLower () == "calendar") {

										DockItemControl closureItem3 = itemControl;

										itemControl.MouseEnter += delegate {

											ShowCalendarOverlay (closureItem3);

										};

										itemControl.MouseLeave += delegate {

											StartHideCalendarOverlay ();

										};

									} else if (appInfo.ProcessName.ToLower () == "spotify" || text3.ToLower ().Contains ("spotify")) {

										DockItemControl closureItem2 = itemControl;

										itemControl.MouseEnter += delegate {

											ShowMediaOverlay (closureItem2);

										};

										itemControl.MouseLeave += delegate {

											StartHideMediaOverlay ();

										};

									} else {

										DockItemControl closureItem = itemControl;

										itemControl.MouseEnter += delegate {

											ShowWindowPreview (closureItem);

										};

										itemControl.MouseLeave += delegate {

											StartHideWindowPreview ();

										};

									}

									runningItems.Add (itemControl);

									SafeAdd (dockPanel, itemControl, "CheckRunningProcesses.Add(runningItem)");

									uiChanged = true;

								}

								foreach (DockItemControl item in runningItems) {

									ProcessWindowInfo processWindowInfo = activeRunningApps.FirstOrDefault ((ProcessWindowInfo x) => x.ProcessName.ToLower () == item.Config.ProcessName.ToLower ());

									if (processWindowInfo != null) {

										item.TargetHwnd = processWindowInfo.Hwnd;

										if (processWindowInfo.Title != item.Config.Name) {

											item.Config.Name = processWindowInfo.Title;

											item.ToolTip = item.CreateCustomToolTip (processWindowInfo.Title);

										}

									}

								}

								if (uiChanged) {

									RebuildDockUI ();

								}

								QueryRecycleBinState ();

							} catch {

							}

						});

					} catch {

					} finally {

						_isCheckingProcesses = false;

					}

				});

			} catch {

			}

		}



		private string GetProcessPath (Process p)

		{

			try {

				return p.MainModule.FileName;

			} catch {

				try {

					IntPtr intPtr = OpenProcess (1040u, bInheritHandle: false, p.Id);

					if (intPtr != IntPtr.Zero) {

						try {

							uint lpdwSize = 1024u;

							StringBuilder stringBuilder = new StringBuilder ((int)lpdwSize);

							if (QueryFullProcessImageName (intPtr, 0u, stringBuilder, ref lpdwSize)) {

								return stringBuilder.ToString ();

							}

						} finally {

							CloseHandle (intPtr);

						}

					}

				} catch {

				}

			}

			return null;

		}



		private void CreateRunningItemContextMenu (DockItemControl item, Process p)

		{

			System.Windows.Controls.ContextMenu contextMenu = new System.Windows.Controls.ContextMenu ();

			System.Windows.Controls.MenuItem menuItem = new System.Windows.Controls.MenuItem {

				Header = "Keep in Dock"

			};

			menuItem.Click += delegate {

				settings.Items.Add (item.Config);

				SaveSettings ();

				runningItems.Remove (item);

				RebuildDockUI ();

			};

			contextMenu.Items.Add (menuItem);

			System.Windows.Controls.MenuItem menuItem2 = new System.Windows.Controls.MenuItem {

				Header = "Close"

			};

			menuItem2.Click += delegate {

				try {

					p.CloseMainWindow ();

				} catch {

				}

			};

			contextMenu.Items.Add (menuItem2);

			item.ContextMenu = contextMenu;

		}

	}

	public class DockItemControl : Grid

	{

		public TranslateTransform dragTransform = new TranslateTransform ();



		public ScaleTransform scaleTransform = new ScaleTransform (1.0, 1.0);



		public System.Windows.Point dragStartPoint;



		public bool isDragging;



		public bool isBouncingPersistently;



		public bool isLaunching;



		public DateTime launchTime;



		private double _downloadProgress;



		public TextBlock _downloadLabel;



		public bool _downloadPulseActive;



		public DispatcherTimer _downloadPulseTimer;



		public System.Windows.Media.Color dominantColor = System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue);



		private DoubleAnimation _breathingAnim;



		public DockItemConfig Config { get; private set; }



		public System.Windows.Controls.Image IconImage { get; private set; }



		public Ellipse IndicatorDot { get; private set; }



		public TranslateTransform BounceTransform { get; private set; }

		public SkewTransform TiltTransform { get; private set; } = new SkewTransform (0.0, 0.0);

		private System.Windows.Point _lastMousePos;
		private DateTime _lastMouseMoveTime = DateTime.Now;



		public IntPtr TargetHwnd { get; set; }



		public Grid VisualContainer { get; private set; }



		public Grid ReflectionGrid { get; private set; }

		public void UpdateReflectionVisibility ()
		{
			if (ReflectionGrid == null) return;
			bool isHorizontal = DockWindow.Instance == null || DockWindow.Instance.settings == null || 
				(DockWindow.Instance.settings.Position.ToLower () != "left" && DockWindow.Instance.settings.Position.ToLower () != "right");
			ReflectionGrid.Visibility = isHorizontal ? Visibility.Visible : Visibility.Collapsed;
		}



		public TranslateTransform WaveTransform { get; private set; }



		public Border BadgeBorder { get; private set; }



		public TextBlock BadgeText { get; private set; }



		public System.Windows.Shapes.Path DownloadArc { get; private set; }



		public double DownloadProgress {

			get {

				return _downloadProgress;

			}

			set {

				_downloadProgress = value;

			}

		}



		public DockItemControl (DockItemConfig config, double baseSize)

		{

			TargetHwnd = IntPtr.Zero;

			Config = config;

			base.Width = baseSize;

			base.Height = baseSize + 12.0;

			Thickness defaultMargin = new Thickness (5.0, 0.0, 5.0, 0.0);
			try {
				if (System.Windows.Application.Current != null && System.Windows.Application.Current.MainWindow is DockWindow dw && dw.settings != null) {
					bool isHorizontal = (dw.settings.Position == "Bottom" || dw.settings.Position == "Top");
					defaultMargin = isHorizontal ? new Thickness (5.0, 0.0, 5.0, 0.0) : new Thickness (0.0, 5.0, 0.0, 5.0);
				}
			} catch {}
			base.Margin = defaultMargin;

			base.VerticalAlignment = VerticalAlignment.Bottom;

			base.HorizontalAlignment = CenterAlignmentHelper ();

			base.Background = System.Windows.Media.Brushes.Transparent;

			base.UseLayoutRounding = true;

			base.SnapsToDevicePixels = true;

			TransformGroup transformGroup = new TransformGroup {

				Children = {

					(Transform)dragTransform,

					(Transform)scaleTransform

