					if (transformGroup4 != null) {

						transformGroup4.Children.OfType<RotateTransform> ().FirstOrDefault ()?.BeginAnimation (RotateTransform.AngleProperty, new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (150.0)));

						SkewTransform skewTransform2 = transformGroup4.Children.OfType<SkewTransform> ().FirstOrDefault ();

						if (skewTransform2 != null) {

							skewTransform2.BeginAnimation (SkewTransform.AngleXProperty, new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (150.0)));

							skewTransform2.BeginAnimation (SkewTransform.AngleYProperty, new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (150.0)));

						}

					}

				}

			};

			base.MouseMove += delegate(object s, System.Windows.Input.MouseEventArgs e) {

				if (System.Windows.Application.Current.MainWindow is DockWindow dockWindow2 && dockWindow2.settings.EnableIconEffects) {

					System.Windows.Point position = e.GetPosition (this);

					double num = base.ActualWidth / 2.0;

					double num2 = base.ActualHeight / 2.0;

					double num3 = (position.X - num) / base.ActualWidth;

					double num4 = (position.Y - num2) / base.ActualHeight;

					double angleX = num3 * 6.5;

					double angleY = (0.0 - num4) * 6.5;

					double angle = num3 * 4.0;

					TransformGroup transformGroup2 = base.RenderTransform as TransformGroup;

					if (transformGroup2 != null && transformGroup2.Children.FirstOrDefault ((Transform c) => c is TransformGroup) is TransformGroup transformGroup3) {

