			if (config.FilePath == "action:weather" || (!string.IsNullOrEmpty (config.ProcessName) && config.ProcessName.ToLower () == "spotify") || (!string.IsNullOrEmpty (config.Name) && config.Name.ToLower ().Contains ("spotify"))) {

