				}

			};

			base.DragOver += delegate(object s, System.Windows.DragEventArgs e) {

				if (Config.FilePath == "action:search" || Config.FilePath == "action:clock") {

					e.Effects = System.Windows.DragDropEffects.None;

				} else if (e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

					e.Effects = ((!Directory.Exists (Config.FilePath)) ? System.Windows.DragDropEffects.Copy : System.Windows.DragDropEffects.Move);

				}

			};

			base.Drop += delegate(object s, System.Windows.DragEventArgs e) {

				scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

				scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (120.0)));

				if (IconImage.Effect is DropShadowEffect dropShadowEffect) {

					dropShadowEffect.BeginAnimation (DropShadowEffect.ColorProperty, new ColorAnimation (Colors.Black, TimeSpan.FromMilliseconds (120.0)));

					dropShadowEffect.BeginAnimation (DropShadowEffect.BlurRadiusProperty, new DoubleAnimation (8.0, TimeSpan.FromMilliseconds (120.0)));

					dropShadowEffect.BeginAnimation (DropShadowEffect.OpacityProperty, new DoubleAnimation (0.4, TimeSpan.FromMilliseconds (120.0)));

				}

				if (!(Config.FilePath == "action:search") && !(Config.FilePath == "action:clock") && e.Data.GetDataPresent (System.Windows.DataFormats.FileDrop)) {

					string[] array = (string[])e.Data.GetData (System.Windows.DataFormats.FileDrop);

					if (array != null && array.Length != 0) {

						if (Directory.Exists (Config.FilePath)) {

							DoubleAnimationUsingKeyFrames animation = new DoubleAnimationUsingKeyFrames {

								Duration = TimeSpan.FromMilliseconds (450.0),

								KeyFrames = {

									(DoubleKeyFrame)new EasingDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.0))),

									(DoubleKeyFrame)new EasingDoubleKeyFrame (1.3, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.12)), new CircleEase {

										EasingMode = EasingMode.EaseOut

									}),

									(DoubleKeyFrame)new EasingDoubleKeyFrame (0.85, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.26)), new CircleEase {

										EasingMode = EasingMode.EaseIn

									}),

									(DoubleKeyFrame)new EasingDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.45)), new CircleEase {

										EasingMode = EasingMode.EaseOut

									})

								}

							};

							scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, animation);

							scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, animation);

							SoundEffects.PlayPoof ();

							string[] array2 = array;

							foreach (string text2 in array2) {

								try {

									string text3 = System.IO.Path.Combine (Config.FilePath, System.IO.Path.GetFileName (text2));

									if (File.Exists (text2)) {

										File.Move (text2, text3);

									} else if (Directory.Exists (text2)) {

										Directory.Move (text2, text3);

									}

								} catch (Exception ex) {

									System.Windows.MessageBox.Show ("Could not move item to stack: " + ex.Message, "Folder Stack Error");

								}

							}

						} else if (Config.FilePath == "action:trash") {
							ThreadPool.QueueUserWorkItem (delegate {
								bool flag2 = false;
								string[] array3 = array;
								foreach (string filePath in array3) {
									if (DockWindow.MoveToRecycleBin (filePath)) {
										flag2 = true;
									}
								}
								if (flag2) {
									base.Dispatcher.BeginInvoke ((Action)delegate {
										if (Window.GetWindow (this) is DockWindow dockWindow3) {
											dockWindow3.QueryRecycleBinState ();
											PlayShakeAnimation ();
										}
									});
								}
							});
						} else if (Config.FilePath != "action:trash") {
							try {
								Process.Start (new ProcessStartInfo (Config.FilePath, "\"" + array [0] + "\"") {
									UseShellExecute = true
								});
							} catch {
							}
						}

					}

				}

			};
		}

		public void UpdateBaseSize (double newBaseSize)
		{
			base.Width = newBaseSize;
			base.Height = newBaseSize + 12.0;

			if (VisualContainer != null) {
				VisualContainer.Width = newBaseSize;
				VisualContainer.Height = newBaseSize;
			}

			if (IconImage != null) {
				IconImage.Width = newBaseSize;
				IconImage.Height = newBaseSize;
			}

			if (ReflectionGrid != null) {
				ReflectionGrid.Width = newBaseSize;
				ReflectionGrid.Height = newBaseSize * 0.4;
				ReflectionGrid.Margin = new Thickness (0.0, 0.0, 0.0, (0.0 - newBaseSize) * 0.38);
				UpdateReflectionVisibility ();
			}

			if (IndicatorDot != null) {
				IndicatorDot.Width = Math.Max (3.0, Math.Min (6.0, newBaseSize * 0.09));
				IndicatorDot.Height = IndicatorDot.Width;
			}

			if (BadgeBorder != null) {
				BadgeBorder.MinWidth = Math.Max (14.0, newBaseSize * 0.29);
				BadgeBorder.Height = BadgeBorder.MinWidth;
				BadgeBorder.CornerRadius = new CornerRadius (BadgeBorder.MinWidth / 2.0);
			}
		}

