		public static FrameworkElement CreateVectorTrashIcon (bool full)

		{

			Grid grid = new Grid ();

			grid.Width = 48.0;

			grid.Height = 48.0;

			Ellipse ellipse = new Ellipse ();

			ellipse.Width = 24.0;

