		protected override void OnMouseLeftButtonDown (MouseButtonEventArgs e)

		{

			base.OnMouseLeftButtonDown (e);

			if (Window.GetWindow (this) is DockWindow relativeTo) {

				CaptureMouse ();

				dragStartPoint = e.GetPosition (relativeTo);

				isDragging = false;

				dragTransform.X = 0.0;

				dragTransform.Y = 0.0;

				e.Handled = true;

			}

		}



		protected override void OnMouseMove (System.Windows.Input.MouseEventArgs e)

		{

			base.OnMouseMove (e);

			if (!base.IsMouseCaptured || !(Window.GetWindow (this) is DockWindow dockWindow)) {

				return;

			}

			if (!dockWindow.settings.Items.Contains (Config) || !(Config.FilePath != "action:search") || !(Config.FilePath != "action:trash") || !(Config.FilePath != "action:clock")) {

				e.Handled = true;

				return;

			}

			System.Windows.Point position = e.GetPosition (dockWindow);

			double num = position.X - dragStartPoint.X;

			double num2 = position.Y - dragStartPoint.Y;

			if (!isDragging && (Math.Abs (num) > 10.0 || Math.Abs (num2) > 10.0)) {

				isDragging = true;

				dockWindow.activeDraggedItem = this;

			}

			if (isDragging) {

				if (dockWindow.settings.Position == "Bottom" || dockWindow.settings.Position == "Top") {

					dragTransform.X = num;

					dragTransform.Y = num2;

					dockWindow.CheckDragCollisionHorizontal (this, position);

				} else {

					dragTransform.X = num;

					dragTransform.Y = num2;

					dockWindow.CheckDragCollisionVertical (this, position);

				}

				if (dockWindow.settings.EnablePoofAnimation) {

					try {

						new Rect (dockWindow.dockBorder.TransformToVisual (dockWindow).Transform (new System.Windows.Point (0.0, 0.0)), new System.Windows.Size (dockWindow.dockBorder.ActualWidth, dockWindow.dockBorder.ActualHeight));

						double num3 = 0.0;

						num3 = ((!(dockWindow.settings.Position == "Bottom") && !(dockWindow.settings.Position == "Top")) ? Math.Max (0.0, Math.Abs (num) - dockWindow.dockBorder.ActualWidth / 2.0) : Math.Max (0.0, Math.Abs (num2) - dockWindow.dockBorder.ActualHeight / 2.0));

						double num4 = ((num3 > 25.0) ? Math.Max (0.25, 1.0 - (num3 - 70.0) / 60.0) : 1.0);

						if (Math.Abs (base.Opacity - num4) > 0.02) {

							base.Opacity = num4;

						}

					} catch {

					}

				}

			}

			e.Handled = true;

		}



		protected override void OnMouseLeftButtonUp (MouseButtonEventArgs e)

		{

			base.OnMouseLeftButtonUp (e);

			if (!base.IsMouseCaptured) {

				return;

			}

			ReleaseMouseCapture ();

			if (isDragging) {

				DockWindow parent = Window.GetWindow (this) as DockWindow;

				bool flag = false;

				if (parent != null && parent.settings.EnablePoofAnimation && parent.settings.Items.Contains (Config)) {

					try {

						double num = 0.0;

						num = ((!(parent.settings.Position == "Bottom") && !(parent.settings.Position == "Top")) ? Math.Max (0.0, Math.Abs (dragTransform.X) - parent.dockBorder.ActualWidth / 2.0) : Math.Max (0.0, Math.Abs (dragTransform.Y) - parent.dockBorder.ActualHeight / 2.0));

						if (num > 25.0) {

							flag = true;

							if (parent._particleCanvas != null) {

								try {

									System.Windows.Point centerPoint = this.TransformToVisual (parent._particleCanvas).Transform (new System.Windows.Point (base.ActualWidth / 2.0, base.ActualHeight / 2.0));

									parent.SpawnPoofSmoke (centerPoint);

								} catch {

									SoundEffects.PlayPoof ();

								}

							} else {

								SoundEffects.PlayPoof ();

							}

							DockItemConfig config = Config;

							parent.settings.Items.Remove (config);

							parent.SaveSettings ();

							DispatcherTimer removeTimer = new DispatcherTimer {

								Interval = TimeSpan.FromMilliseconds (120.0)

							};

							removeTimer.Tick += delegate {

								removeTimer.Stop ();

								try {

									parent.RebuildDockUI ();

								} catch {

								}

							};

							removeTimer.Start ();

						}

					} catch {

					}

				}

				if (!flag) {

					DoubleAnimation animation = new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (180.0)) {

						EasingFunction = new CubicEase {

							EasingMode = EasingMode.EaseOut

						}

					};

					if (parent != null) {

						dragTransform.BeginAnimation (TranslateTransform.XProperty, animation);

						dragTransform.BeginAnimation (TranslateTransform.YProperty, animation);

						parent.SaveSettings ();

					} else {

						dragTransform.X = 0.0;

						dragTransform.Y = 0.0;

					}

				}

				base.Opacity = 1.0;

			} else {

				if (Window.GetWindow (this) is DockWindow dockWindow && dockWindow.settings.EnableClickSquish && dockWindow.IsAnimationEnabled) {

					try {

						DoubleAnimationUsingKeyFrames doubleAnimationUsingKeyFrames = new DoubleAnimationUsingKeyFrames ();

						doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (0.78, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (65.0))));

						doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (1.14, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (130.0))));

						doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (220.0))));

						DoubleAnimationUsingKeyFrames doubleAnimationUsingKeyFrames2 = new DoubleAnimationUsingKeyFrames ();

						doubleAnimationUsingKeyFrames2.KeyFrames.Add (new LinearDoubleKeyFrame (0.78, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (65.0))));

						doubleAnimationUsingKeyFrames2.KeyFrames.Add (new LinearDoubleKeyFrame (1.14, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (130.0))));

						doubleAnimationUsingKeyFrames2.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (220.0))));

						doubleAnimationUsingKeyFrames.Completed += delegate {

							scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, null);

							scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, null);

						};

						scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, doubleAnimationUsingKeyFrames);

						scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, doubleAnimationUsingKeyFrames2);

					} catch {

					}

				}

				try {

					if (Window.GetWindow (this) is DockWindow dockWindow2 && dockWindow2.IsAnimationEnabled && dockWindow2.settings.EnableLaunchParticles) {

						dominantColor = ExtractDominantColor (IconImage.Source);

						if (Config != null && (Config.FilePath == "action:f1" || (Config.Name != null && Config.Name.ToLower ().Contains ("f1")))) {

							dominantColor = System.Windows.Media.Color.FromRgb (229, 9, 20);

						}

						System.Windows.Media.Color accentColor = System.Windows.Media.Color.FromRgb (0, 200, byte.MaxValue);

						try {

							if (!string.IsNullOrEmpty (dockWindow2.settings.AccentColor)) {

								accentColor = (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString (dockWindow2.settings.AccentColor);

							} else {

								double num2 = Math.Abs ((Config.Name ?? "App").GetHashCode ()) % 360;

								double num3 = 0.9;

								num2 = (num2 % 360.0 + 360.0) % 360.0;

								double num4 = 1.0 * num3;

								double num5 = num4 * (1.0 - Math.Abs (num2 / 60.0 % 2.0 - 1.0));

								double num6 = 1.0 - num4;

								double num7 = 0.0;

								double num8 = 0.0;

								double num9 = 0.0;

								if (num2 < 60.0) {

									num7 = num4;

									num8 = num5;

								} else if (num2 < 120.0) {

									num7 = num5;

									num8 = num4;

								} else if (num2 < 180.0) {

									num8 = num4;

									num9 = num5;

								} else if (num2 < 240.0) {

									num8 = num5;

									num9 = num4;

								} else if (num2 < 300.0) {

									num7 = num5;

									num9 = num4;

								} else {

									num7 = num4;

									num9 = num5;

								}

								accentColor = System.Windows.Media.Color.FromRgb ((byte)((num7 + num6) * 255.0), (byte)((num8 + num6) * 255.0), (byte)((num9 + num6) * 255.0));

							}

						} catch {

						}

						dockWindow2.SpawnLaunchParticles (this, accentColor);

					}

				} catch {

				}

				Launch ();

			}

			if (Window.GetWindow (this) is DockWindow parentWindow) {

				parentWindow.activeDraggedItem = null;

			}

			isDragging = false;

			e.Handled = true;

		}



