				Placement = PlacementMode.Top,

				VerticalOffset = -10.0

			};

			ControlTemplate controlTemplate = new ControlTemplate (typeof(System.Windows.Controls.ToolTip));

			FrameworkElementFactory frameworkElementFactory = new FrameworkElementFactory (typeof(Border));

			frameworkElementFactory.SetValue (Border.CornerRadiusProperty, new CornerRadius (8.0));

			frameworkElementFactory.SetValue (Border.BackgroundProperty, new SolidColorBrush (System.Windows.Media.Color.FromArgb (235, 18, 18, 18)));

			frameworkElementFactory.SetValue (Border.BorderBrushProperty, new SolidColorBrush (System.Windows.Media.Color.FromArgb (35, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

