				if (rotateTransform != null) {

					DoubleAnimationUsingKeyFrames doubleAnimationUsingKeyFrames = new DoubleAnimationUsingKeyFrames ();

					doubleAnimationUsingKeyFrames.Duration = TimeSpan.FromMilliseconds (600.0);

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (-5.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (60.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (5.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (120.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (-4.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (180.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (4.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (240.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (-3.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (300.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (3.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (360.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (-2.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (420.0))));

					doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (2.0, KeyTime.FromTimeSpan (TimeSpan.FromMilliseconds (480.0))));

