				} else {
					IndicatorDot.BeginAnimation (UIElement.OpacityProperty, null);
					IndicatorDot.Opacity = 1.0;
				}
			} catch {
			}
		}

		public void StopBreathingDot ()
		{
			if (!_isBreathingDotRunning && IndicatorDot.Opacity == 1.0) return;
			_isBreathingDotRunning = false;

			try {
				IndicatorDot.BeginAnimation (UIElement.OpacityProperty, null);
				if (IndicatorDot.RenderTransform is ScaleTransform scaleTransform) {
					scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, null);
					scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, null);
					IndicatorDot.RenderTransform = null;
				}
				IndicatorDot.Opacity = 1.0;
			} catch {
			}
		}



		public void Bounce ()

		{

			double bounceDuration = GetBounceDuration ();

			DoubleAnimationUsingKeyFrames doubleAnimationUsingKeyFrames = new DoubleAnimationUsingKeyFrames ();

			doubleAnimationUsingKeyFrames.Duration = TimeSpan.FromSeconds (bounceDuration);

			doubleAnimationUsingKeyFrames.KeyFrames.Add (new LinearDoubleKeyFrame (0.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.0))));

			doubleAnimationUsingKeyFrames.KeyFrames.Add (new EasingDoubleKeyFrame (-26.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.25)), new CircleEase {

				EasingMode = EasingMode.EaseOut

			}));

			doubleAnimationUsingKeyFrames.KeyFrames.Add (new EasingDoubleKeyFrame (0.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.5)), new CircleEase {

				EasingMode = EasingMode.EaseIn

			}));

			doubleAnimationUsingKeyFrames.KeyFrames.Add (new EasingDoubleKeyFrame (-13.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.71)), new CircleEase {

				EasingMode = EasingMode.EaseOut

			}));

			doubleAnimationUsingKeyFrames.KeyFrames.Add (new EasingDoubleKeyFrame (0.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.92)), new CircleEase {

				EasingMode = EasingMode.EaseIn

			}));

			DoubleAnimationUsingKeyFrames scaleXAnim = new DoubleAnimationUsingKeyFrames ();

			scaleXAnim.Duration = TimeSpan.FromSeconds (bounceDuration);

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.0))));

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (0.95, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.25))));

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.18, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.5))));

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (0.97, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.71))));

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.08, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.92))));

			scaleXAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration))));

			DoubleAnimationUsingKeyFrames scaleYAnim = new DoubleAnimationUsingKeyFrames ();

			scaleYAnim.Duration = TimeSpan.FromSeconds (bounceDuration);

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (0.0))));

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.1, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.25))));

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (0.78, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.5))));

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.05, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.71))));

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (0.88, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration * 0.92))));

			scaleYAnim.KeyFrames.Add (new LinearDoubleKeyFrame (1.0, KeyTime.FromTimeSpan (TimeSpan.FromSeconds (bounceDuration))));

			scaleXAnim.Completed += delegate {

				scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, null);

				scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, null);

			};

			BounceTransform.BeginAnimation (TranslateTransform.YProperty, doubleAnimationUsingKeyFrames);

			scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, scaleXAnim);

			scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, scaleYAnim);

		}

	}

