				LinearGradientBrush brush = new LinearGradientBrush (System.Windows.Media.Color.FromRgb (41, 121, byte.MaxValue), System.Windows.Media.Color.FromRgb (101, 31, byte.MaxValue), new System.Windows.Point (0.0, 0.0), new System.Windows.Point (1.0, 1.0));

				drawingContext.DrawEllipse (brush, new System.Windows.Media.Pen (new SolidColorBrush (System.Windows.Media.Color.FromArgb (90, byte.MaxValue, byte.MaxValue, byte.MaxValue)), 2.0), new System.Windows.Point ((double)num / 2.0, (double)num / 2.0), (double)num / 2.0 - 4.0, (double)num / 2.0 - 4.0);

				System.Windows.Media.Pen pen = new System.Windows.Media.Pen (System.Windows.Media.Brushes.White, 5.5);

				drawingContext.DrawEllipse (System.Windows.Media.Brushes.Transparent, pen, new System.Windows.Point (54.0, 54.0), 18.0, 18.0);

				drawingContext.DrawLine (pen, new System.Windows.Point (67.0, 67.0), new System.Windows.Point (88.0, 88.0));

			}

			renderTargetBitmap.Render (drawingVisual);

			renderTargetBitmap.Freeze ();

			return renderTargetBitmap;

		}

		public static ImageSource GetWindowsFolderIcon ()
		{
			try {
				SHFILEINFO psfi = default(SHFILEINFO);
				IntPtr hIcon = SHGetFileInfo ("C:\\dummy_dir_to_get_windows_folder_icon", 0x10, ref psfi, (uint)Marshal.SizeOf (psfi), 0x100 | 0x10);
				if (psfi.hIcon != IntPtr.Zero) {
					try {
						BitmapSource bitmapSource = Imaging.CreateBitmapSourceFromHIcon (psfi.hIcon, Int32Rect.Empty, BitmapSizeOptions.FromEmptyOptions ());
						bitmapSource.Freeze ();
						return bitmapSource;
					} finally {
						DestroyIcon (psfi.hIcon);
					}
				}
			} catch {}
			return null;
		}

		public static ImageSource GetAssociatedExtensionIcon (string path)
		{
			try {
				string extension = System.IO.Path.GetExtension (path);
				if (string.IsNullOrEmpty (extension)) {
					extension = ".exe";
				}
				SHFILEINFO psfi = default(SHFILEINFO);
				IntPtr hIcon = SHGetFileInfo (extension, 0x80, ref psfi, (uint)Marshal.SizeOf (psfi), 0x100 | 0x10);
				if (psfi.hIcon != IntPtr.Zero) {
					try {
						BitmapSource bitmapSource = Imaging.CreateBitmapSourceFromHIcon (psfi.hIcon, Int32Rect.Empty, BitmapSizeOptions.FromEmptyOptions ());
						bitmapSource.Freeze ();
						return bitmapSource;
					} finally {
						DestroyIcon (psfi.hIcon);
					}
				}
			} catch {}
			return null;
		}

		public static ImageSource ExtractIconFromUrlFile (string urlFilePath)
		{
			try {
				if (!File.Exists (urlFilePath)) return null;
				string iconFile = null;
				int iconIndex = 0;
				foreach (var line in File.ReadLines (urlFilePath)) {
					if (line.StartsWith ("IconFile=", StringComparison.OrdinalIgnoreCase)) {
						iconFile = line.Substring ("IconFile=".Length).Trim ();
					} else if (line.StartsWith ("IconIndex=", StringComparison.OrdinalIgnoreCase)) {
						int.TryParse (line.Substring ("IconIndex=".Length).Trim (), out iconIndex);
					}
				}
				if (!string.IsNullOrEmpty (iconFile)) {
					iconFile = Environment.ExpandEnvironmentVariables (iconFile);
					if (File.Exists (iconFile)) {
						IntPtr[] array = new IntPtr[1];
						uint[] piconid = new uint[1];
						if (PrivateExtractIcons (iconFile, iconIndex, 48, 48, array, piconid, 1u, 0u) != 0 && array [0] != IntPtr.Zero) {
							try {
								BitmapSource bitmapSource = Imaging.CreateBitmapSourceFromHIcon (array [0], Int32Rect.Empty, BitmapSizeOptions.FromEmptyOptions ());
								bitmapSource.Freeze ();
								return bitmapSource;
							} finally {
								DestroyIcon (array [0]);
							}
						}
						ImageSource img = GetHighQualityIcon (iconFile, 48);
						if (img != null) return img;
						return GetJumboIcon (iconFile);
					}
				}
			} catch {}
			return null;
		}

		public static ImageSource ExtractHighQualityIconForSearch (SearchResultItem match)
		{
			if (string.IsNullOrEmpty (match.Path)) return null;

			if (_searchIconCache.TryGetValue (match.Path, out var cachedIcon)) {
				return cachedIcon;
			}

			try {
				string targetPath = match.Path;
				if (!string.IsNullOrEmpty (match.Path) && match.Path.EndsWith (".lnk", StringComparison.OrdinalIgnoreCase)) {
					targetPath = IconExtractor.ResolveShortcut (match.Path);
				}

				ImageSource icon = null;

				// Spotify custom check
				if (match.IsApp && ((!string.IsNullOrEmpty (match.Path) && match.Path.ToLower ().Contains ("spotify")) || (!string.IsNullOrEmpty (match.Name) && match.Name.ToLower ().Contains ("spotify")))) {
					string text = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "spotify_logo.png");
					if (File.Exists (text)) {
						BitmapImage bitmapImage = new BitmapImage ();
						bitmapImage.BeginInit ();
						bitmapImage.UriSource = new Uri (text);
						bitmapImage.CacheOption = BitmapCacheOption.OnLoad;
						bitmapImage.DecodePixelWidth = 256;
						bitmapImage.EndInit ();
						bitmapImage.Freeze ();
						icon = bitmapImage;
					}
				}

				// Dolby custom check
				if (icon == null && match.IsApp && !string.IsNullOrEmpty (match.Path) && (match.Path.ToLower ().Contains ("dolby") || match.Name.ToLower ().Contains ("dolby"))) {
					string text = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "dolby_logo.png");
					if (File.Exists (text)) {
						BitmapImage bitmapImage = new BitmapImage ();
						bitmapImage.BeginInit ();
						bitmapImage.UriSource = new Uri (text);
						bitmapImage.CacheOption = BitmapCacheOption.OnLoad;
						bitmapImage.DecodePixelWidth = 256;
						bitmapImage.EndInit ();
						bitmapImage.Freeze ();
						icon = bitmapImage;
					}
				}

				if (icon == null && !string.IsNullOrEmpty (match.Path) && match.Path.EndsWith (".url", StringComparison.OrdinalIgnoreCase)) {
					icon = ExtractIconFromUrlFile (match.Path);
				}

				if (icon == null && !string.IsNullOrEmpty (targetPath) && File.Exists (targetPath)) {
					icon = IconExtractor.GetJumboIcon (targetPath);
					if (icon == null) {
						icon = IconExtractor.GetHighQualityIcon (targetPath, 256);
					}
					if (icon == null) {
						icon = IconExtractor.GetHighQualityIcon (targetPath, 48);
					}
				}

				if (icon == null && !string.IsNullOrEmpty (match.Path) && File.Exists (match.Path)) {
					icon = IconExtractor.GetJumboIcon (match.Path);
					if (icon == null) {
						icon = IconExtractor.GetHighQualityIcon (match.Path, 256);
					}
					if (icon == null) {
						icon = IconExtractor.GetHighQualityIcon (match.Path, 48);
					}
				}

				// Handle UWP/Store apps (shell:AppsFolder\...) and protocol URLs (steam://...)
				if (icon == null && !string.IsNullOrEmpty (match.Path) && !File.Exists (match.Path)) {
					try {
						string pathLower = match.Path.ToLower ();
						if (pathLower.StartsWith ("shell:appsfolder\\") || pathLower.Contains ("!") ||
							pathLower.StartsWith ("steam://") || pathLower.Contains ("://")) {
							icon = ExtractUwpOrProtocolIcon (match.Path, match.Name);
						}
					} catch {}
				}

				if (icon == null && !string.IsNullOrEmpty (match.Path)) {
					icon = GetAssociatedExtensionIcon (match.Path);
				}

				if (icon != null) {
					_searchIconCache[match.Path] = icon;
				}
				return icon;
			} catch {
				return null;
			}
		}

		private static ImageSource ExtractUwpOrProtocolIcon (string appPath, string appName)
		{
			ImageSource result = null;
			try {
				// COM Shell.Application requires STA thread, but we may be on MTA ThreadPool
				if (Thread.CurrentThread.GetApartmentState () == ApartmentState.STA) {
					result = ExtractUwpOrProtocolIconCore (appPath, appName);
				} else {
					Thread staThread = new Thread (() => {
						result = ExtractUwpOrProtocolIconCore (appPath, appName);
					});
					staThread.SetApartmentState (ApartmentState.STA);
					staThread.Start ();
					staThread.Join (3000); // 3 second timeout
				}
			} catch {}
			return result;
		}

		private static ImageSource ExtractUwpOrProtocolIconCore (string appPath, string appName)
		{
			try {
				if (string.IsNullOrEmpty (appPath)) return null;

				// 1. Check if Steam game
				if (appPath.StartsWith ("steam://", StringComparison.OrdinalIgnoreCase)) {
					string gameId = "";
					int runGameIdIdx = appPath.IndexOf ("rungameid/", StringComparison.OrdinalIgnoreCase);
					if (runGameIdIdx >= 0) {
						gameId = appPath.Substring (runGameIdIdx + "rungameid/".Length).Trim ();
					}
					if (!string.IsNullOrEmpty (gameId)) {
						string[] uninstallPaths = {
							@"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\Steam App " + gameId,
							@"SOFTWARE\Wow6432Node\Microsoft\Windows\CurrentVersion\Uninstall\Steam App " + gameId
						};
						foreach (var path in uninstallPaths) {
							try {
								using (var baseKey = RegistryKey.OpenBaseKey (RegistryHive.LocalMachine, RegistryView.Registry64)) {
									using (var key = baseKey.OpenSubKey (path)) {
										if (key != null) {
											string iconPath = key.GetValue ("DisplayIcon") as string;
											if (!string.IsNullOrEmpty (iconPath) && File.Exists (iconPath)) {
												var icon = GetJumboIcon (iconPath);
												if (icon == null) icon = GetHighQualityIcon (iconPath, 256);
												if (icon == null) icon = GetHighQualityIcon (iconPath, 48);
												if (icon != null) {
													icon.Freeze ();
													return icon;
												}
											}
										}
									}
								}
							} catch {}
						}
					}
				}

				// 2. Try registry lookup for UWP package path
				string cleanPath = appPath.Replace ("shell:AppsFolder\\", "");
				string packageFamilyName = cleanPath.Contains ("!") ? cleanPath.Split ('!') [0] : cleanPath;

				if (packageFamilyName.Contains ("_")) {
					string prefix = packageFamilyName;
					string suffix = "";
					int underscoreIdx = packageFamilyName.LastIndexOf ('_');
					if (underscoreIdx >= 0) {
						prefix = packageFamilyName.Substring (0, underscoreIdx);
						suffix = packageFamilyName.Substring (underscoreIdx + 1);
					}

					string registryPath = @"Software\Classes\Local Settings\Software\Microsoft\Windows\CurrentVersion\AppModel\PackageRepository\Packages";
					string installPath = null;

					try {
						using (var baseKey = RegistryKey.OpenBaseKey (RegistryHive.LocalMachine, RegistryView.Registry64)) {
							using (var key = baseKey.OpenSubKey (registryPath)) {
								if (key != null) {
									foreach (var subKeyName in key.GetSubKeyNames ()) {
										if (subKeyName.StartsWith (prefix + "_", StringComparison.OrdinalIgnoreCase) && 
											subKeyName.EndsWith (suffix, StringComparison.OrdinalIgnoreCase)) {
											using (var subKey = key.OpenSubKey (subKeyName)) {
												if (subKey != null) {
													installPath = subKey.GetValue ("Path") as string;
													if (!string.IsNullOrEmpty (installPath)) {
														break;
													}
												}
											}
										}
									}
								}
							}
						}
					} catch {}

					if (!string.IsNullOrEmpty (installPath) && Directory.Exists (installPath)) {
						string[] logoPatterns = { 
							"*Square310x310Logo*.png",
							"*Square150x150Logo*.png",
							"*Square71x71Logo*.png",
							"*Square44x44Logo*scale-200*.png", 
							"*Square44x44Logo*.png", 
							"*Logo*scale-200*.png", 
							"*Logo*.png", 
							"*StoreLogo*.png" 
						};
						foreach (var pattern in logoPatterns) {
							try {
								var logos = Directory.GetFiles (installPath, pattern, SearchOption.AllDirectories);
								if (logos.Length > 0) {
									string bestLogo = logos.OrderByDescending (l => new FileInfo (l).Length).First ();
									var bmp = new BitmapImage ();
									bmp.BeginInit ();
									bmp.UriSource = new Uri (bestLogo);
									bmp.CacheOption = BitmapCacheOption.OnLoad;
									bmp.DecodePixelWidth = 256;
									bmp.EndInit ();
									bmp.Freeze ();
									return bmp;
								}
							} catch {}
						}
					}
				}

				// 3. Fall back to legacy COM namespace folder lookup
				Type shellType = Type.GetTypeFromProgID ("Shell.Application");
				if (shellType == null) return null;
				object shell = Activator.CreateInstance (shellType);
				object folder = shellType.InvokeMember ("NameSpace", BindingFlags.InvokeMethod, null, shell, new object[] { "shell:AppsFolder" });
				if (folder == null) return null;
				object items = folder.GetType ().InvokeMember ("Items", BindingFlags.InvokeMethod, null, folder, null);
				if (items == null) return null;
				int count = (int)items.GetType ().InvokeMember ("Count", BindingFlags.GetProperty, null, items, null);

				for (int i = 0; i < count; i++) {
					try {
						object item = items.GetType ().InvokeMember ("Item", BindingFlags.InvokeMethod, null, items, new object[] { i });
						if (item == null) continue;
						string name = (string)item.GetType ().InvokeMember ("Name", BindingFlags.GetProperty, null, item, null);
						string path = (string)item.GetType ().InvokeMember ("Path", BindingFlags.GetProperty, null, item, null);

						bool isMatch = false;
						if (!string.IsNullOrEmpty (name) && !string.IsNullOrEmpty (appName) &&
							name.Equals (appName, StringComparison.OrdinalIgnoreCase)) {
							isMatch = true;
						}
						if (!isMatch && !string.IsNullOrEmpty (path) && !string.IsNullOrEmpty (appPath)) {
							string cleanAppPath = appPath.Replace ("shell:AppsFolder\\", "");
							if (path.Equals (cleanAppPath, StringComparison.OrdinalIgnoreCase) ||
								path.Equals (appPath, StringComparison.OrdinalIgnoreCase)) {
								isMatch = true;
							}
						}

						if (isMatch) {
							if (!string.IsNullOrEmpty (path) && (path.Contains ("\\") || path.Contains (":")) && File.Exists (path)) {
								var icon = GetJumboIcon (path);
								if (icon == null) icon = GetHighQualityIcon (path, 256);
								if (icon == null) icon = GetHighQualityIcon (path, 48);
								if (icon != null) { icon.Freeze (); return icon; }
							}
							break;
						}
					} catch {}
				}
			} catch {}
			return null;
		}

	}

	public class SettingsWindow : Window

	{

		internal struct WinCompositionAttrData

		{

			public int Attribute;



			public IntPtr Data;



			public int SizeOfData;

		}



		internal struct AccentPolicy

		{

			public int AccentState;



			public int AccentFlags;



			public int GradientColor;



			public int AnimationId;

		}



		private DockWindow ownerWindow;



		private DockSettings settings;



		private FrameworkElement root;



		[DllImport ("user32.dll")]

		internal static extern int SetWindowCompositionAttribute (IntPtr hwnd, ref WinCompositionAttrData data);



		public void EnableBlur (bool enable)

		{

			try {

				IntPtr handle = new WindowInteropHelper (this).Handle;

				if (handle != IntPtr.Zero) {

					AccentPolicy structure = default(AccentPolicy);

					structure.AccentState = (enable ? 3 : 0);

					if (enable) {

						structure.AccentFlags = 2;

						double blurAmount = (settings != null) ? settings.BlurAmount : 0.7;

						bool isDark = (settings != null) ? (settings.Theme.ToLower () == "dark" || settings.Theme.ToLower () == "tahoe") : true;

						byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);

						uint colorVal = isDark ? 0x1A1A1AU : 0xF2F2F7U;

						structure.GradientColor = (int)(((uint)alpha << 24) | (colorVal & 0x00FFFFFF));

					}

					int num = Marshal.SizeOf (structure);

					IntPtr intPtr = Marshal.AllocHGlobal (num);

					Marshal.StructureToPtr (structure, intPtr, fDeleteOld: false);

					WinCompositionAttrData data = default(WinCompositionAttrData);

					data.Attribute = 19;

					data.SizeOfData = num;

					data.Data = intPtr;

					SetWindowCompositionAttribute (handle, ref data);

					Marshal.FreeHGlobal (intPtr);

				}

			} catch {

			}

		}



		public SettingsWindow (DockWindow owner, DockSettings currentSettings)

		{

			ownerWindow = owner;

			settings = currentSettings;

			base.Title = "Settings";

			base.Width = 800.0;

			base.Height = 600.0;

			base.WindowStyle = WindowStyle.None;

			base.AllowsTransparency = true;

			base.Background = System.Windows.Media.Brushes.Transparent;

			base.WindowStartupLocation = WindowStartupLocation.CenterScreen;

			base.Topmost = true;

			base.ShowInTaskbar = false;

			string text = null;
			string macSettingsPath = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "MacSettings.txt");
			if (File.Exists (macSettingsPath)) {
				text = File.ReadAllText (macSettingsPath);
			} else {
				try {
					var asm = System.Reflection.Assembly.GetExecutingAssembly ();
					using (var stream = asm.GetManifestResourceStream ("WinDock.MacSettings.txt")) {
						if (stream != null) {
							using (var reader = new System.IO.StreamReader (stream)) {
								text = reader.ReadToEnd ();
							}
						}
					}
				} catch {}
			}

			if (string.IsNullOrEmpty (text)) {
				throw new System.IO.FileNotFoundException ("MacSettings.txt could not be loaded from disk or embedded resources.", macSettingsPath);
			}

			if (!(ownerWindow.GetEffectiveTheme ().ToLower () == "dark")) {

				text = text.Replace ("#1E1E1E", "#E6F2F2F7");

				text = text.Replace ("#282828", "#E6E5E5EA");

				text = text.Replace ("#000000", "#00000000");

				text = text.Replace ("BorderBrush=\"#1C1C1E\"", "BorderBrush=\"#20000000\"");

				text = text.Replace ("BorderBrush=\"#333333\"", "BorderBrush=\"#40000000\"");

				text = text.Replace ("Background=\"#333333\"", "Background=\"#E5E5EA\"");

				text = text.Replace ("#FFFFFF", "#000000");

				text = text.Replace ("Foreground=\"White\"", "Foreground=\"Black\"");

				text = text.Replace ("Value=\"White\"", "Value=\"Black\"");

				text = text.Replace ("#1C1C1E", "#FFFFFF");

				text = text.Replace ("#8E8E93", "#6E6E73");

				text = text.Replace ("#2C2C2E", "#20000000");

				text = text.Replace ("#39393D", "#30000000");

				text = text.Replace ("#1AFFFFFF", "#1A000000");

				text = text.Replace ("Fill=\"#000000\" HorizontalAlignment=\"Left\" Margin=\"2,0,0,0\"", "Fill=\"White\" HorizontalAlignment=\"Left\" Margin=\"2,0,0,0\"");

			} else {

				text = text.Replace ("#1E1E1E", "#D91E1E1E");

				text = text.Replace ("#282828", "#CC282828");

				text = text.Replace ("#000000", "#B3000000");

			}

			root = XamlReader.Parse (text) as FrameworkElement;

			base.Content = root;

			if (root.FindName ("TitleBar") is Border border) {

				border.MouseLeftButtonDown += delegate {

					DragMove ();

				};

			}

			if (root.FindName ("BtnClose") is System.Windows.Controls.Button button) {

				button.Click += delegate {

					Close ();

				};

			}

			BindNavigation ();

			BindSettings ();

		}



		private void BindNavigation ()

		{

			System.Windows.Controls.TabControl tabControl = root.FindName ("MainTabControl") as System.Windows.Controls.TabControl;

			TextBlock header = root.FindName ("HeaderTitle") as TextBlock;

			Action<string, int, string> obj = delegate(string name, int index, string title) {

				if (root.FindName (name) is System.Windows.Controls.RadioButton radioButton) {

					radioButton.Checked += delegate {

						tabControl.SelectedIndex = index;

						if (header != null) {

							header.Text = title;

						}

					};

				}

			};

			obj ("NavAppearance", 0, "Appearance");

			obj ("NavDesktop", 1, "Desktop & Dock");

			obj ("NavAnimations", 2, "Animations");

			obj ("NavWidgets", 3, "Widgets & Modules");

			obj ("NavGeneral", 4, "General");

		}



