		private void BindToggle (string name, bool initial, Action<bool> setter)

		{

			if (root.FindName (name) is System.Windows.Controls.CheckBox checkBox) {

				checkBox.IsChecked = initial;

				checkBox.Checked += delegate {

					setter (obj: true);

					ApplyChanges ();

				};

				checkBox.Unchecked += delegate {

					setter (obj: false);

					ApplyChanges ();

				};

			}

		}



		private void BindComboBox (string name, int initialValue, Action<int> updateAction)

		{

			System.Windows.Controls.ComboBox combo = root.FindName (name) as System.Windows.Controls.ComboBox;

			if (combo != null) {

				if (initialValue >= 0 && initialValue < combo.Items.Count) {

					combo.SelectedIndex = initialValue;

				}

				combo.SelectionChanged += delegate {

					updateAction (combo.SelectedIndex);

					ApplyChanges ();

				};

			}

		}



		private void BindRadio (string name, bool initial, Action<bool> setter)

		{

			if (root.FindName (name) is System.Windows.Controls.RadioButton radioButton) {

				radioButton.IsChecked = initial;

				radioButton.Checked += delegate {

					setter (obj: true);

					ApplyChanges ();

				};

			}

		}



		private void BindSlider (string name, double initial, Action<double> setter)

		{

			Slider sl = root.FindName (name) as Slider;

			if (sl != null) {

				sl.Value = initial;

				sl.ValueChanged += delegate {

					setter (sl.Value);

					ApplyChanges ();

				};

			}

		}



		private void ApplyChanges ()

		{

			ownerWindow.settings = settings;

			ownerWindow.SaveSettings ();

			ownerWindow.ApplySettings (settings);

		}

	}

