		private string FormatTime (int seconds)

		{

			if (seconds < 0) {

				seconds = 0;

			}

			int num = seconds / 60;

			int num2 = seconds % 60;

			return $"{num}:{num2:D2}";

		}



		private void UpdateSimulatedProgress ()

		{

			if (base.Owner is DockWindow dockWindow) {

				double bgSpotifyPosition = dockWindow.bgSpotifyPosition;

				simulatedDuration = (int)Math.Round (dockWindow.bgSpotifyDuration);

				if (timeDurationText != null) {

					timeDurationText.Text = FormatTime (simulatedDuration);

				}

				isSongPlaying = dockWindow.bgSpotifyIsPlaying;

				if (Math.Abs (smoothProgressPosition - bgSpotifyPosition) > 0.3 && !isSeeking) {

					smoothProgressPosition = bgSpotifyPosition;

				}

				if (timeCurrentText != null && !isSeeking) {

					timeCurrentText.Text = FormatTime ((int)Math.Round (smoothProgressPosition));

				}

				if (timeDurationText != null) {

					timeDurationText.Text = FormatTime (simulatedDuration);

				}

			}

		}



