		private float GetProcessVolume (string processName)

		{

			try {

				Process[] processesByName = Process.GetProcessesByName (processName);

				if (processesByName.Length == 0) {

					return 0.66f;

				}

				HashSet<uint> hashSet = new HashSet<uint> ();

				Process[] array = processesByName;

				foreach (Process process in array) {

					hashSet.Add ((uint)process.Id);

				}

				if (!(new MMDeviceEnumerator () is IMMDeviceEnumerator iMMDeviceEnumerator)) {

					return 0.66f;

				}

				if (iMMDeviceEnumerator.GetDefaultAudioEndpoint (0, 0, out var ppEndpoint) == 0 && ppEndpoint != null) {

					Guid iid = new Guid ("77AA99A0-1BD6-484F-8BC7-2C654C9A9B6F");

					if (ppEndpoint.Activate (ref iid, 23, IntPtr.Zero, out var ppInterface) == 0 && ppInterface != null) {

						if (ppInterface is IAudioSessionManager2 audioSessionManager && audioSessionManager.GetSessionEnumerator (out var SessionList) == 0 && SessionList != null) {

							if (SessionList.GetCount (out var SessionCount) == 0) {

								for (int j = 0; j < SessionCount; j++) {

									if (SessionList.GetSession (j, out var Session) == 0 && Session != null) {

										if (Session is IAudioSessionControl2 audioSessionControl && audioSessionControl.GetProcessId (out var pRetVal) == 0 && hashSet.Contains (pRetVal) && Session is ISimpleAudioVolume simpleAudioVolume && simpleAudioVolume.GetMasterVolume (out var pfLevel) == 0) {

											Marshal.ReleaseComObject (Session);

											Marshal.ReleaseComObject (SessionList);

											Marshal.ReleaseComObject (ppInterface);

											Marshal.ReleaseComObject (ppEndpoint);

											return pfLevel;

										}

										Marshal.ReleaseComObject (Session);

									}

								}

							}

							Marshal.ReleaseComObject (SessionList);

						}

						Marshal.ReleaseComObject (ppInterface);

					}

					Marshal.ReleaseComObject (ppEndpoint);

				}

			} catch {

			}

			return 0.66f;

		}



