		private string CleanTrackName (string name)

		{

			if (string.IsNullOrEmpty (name)) {

				return name;

			}

			int num = name.IndexOf (" - ");

			if (num > 0) {

				name = name.Substring (0, num);

			}

			int num2 = name.IndexOf (" (");

			if (num2 > 0) {

				name = name.Substring (0, num2);

			}

			return name.Trim ();

		}



		private string FetchLyricsFromOvh (string artist, string track)

		{

			try {

				string address = "https://api.lyrics.ovh/v1/" + Uri.EscapeDataString (artist) + "/" + Uri.EscapeDataString (track);

				using TimeoutWebClient timeoutWebClient = new TimeoutWebClient ();

				timeoutWebClient.Headers.Add ("User-Agent", "WinDock/1.0 (https://github.com/SahilK044/WinDock)");

				timeoutWebClient.Encoding = Encoding.UTF8;

				string text = timeoutWebClient.DownloadString (address);

				if (!string.IsNullOrEmpty (text)) {

					Dictionary<string, object> dictionary = new JavaScriptSerializer ().Deserialize<Dictionary<string, object>> (text);

					if (dictionary != null && dictionary.ContainsKey ("lyrics")) {

						string text2 = dictionary ["lyrics"] as string;

						if (!string.IsNullOrWhiteSpace (text2)) {

							return text2;

						}

					}

				}

			} catch (Exception ex) {

				try {

					File.AppendAllText ("lyrics_error.txt", "OVH Error: " + ex.ToString () + "\n");

				} catch {

				}

			}

			return null;

		}



		private string CleanArtistName (string artist)

		{

			if (string.IsNullOrEmpty (artist)) {

				return artist;

			}

			int num = artist.IndexOf (',');

			if (num > 0) {

				artist = artist.Substring (0, num);

			}

			int num2 = artist.IndexOf (" & ");

			if (num2 > 0) {

				artist = artist.Substring (0, num2);

			}

			int num3 = artist.IndexOf (" feat", StringComparison.OrdinalIgnoreCase);

			if (num3 > 0) {

				artist = artist.Substring (0, num3);

			}

			return artist.Trim ();

		}



