					if (list != null && list.Count > 0) {

						foreach (Dictionary<string, object> item in list) {

							if (item.ContainsKey ("syncedLyrics") && item ["syncedLyrics"] != null) {

								string text2 = item ["syncedLyrics"].ToString ();

