									return text2;

								}

							}

							if (item.ContainsKey ("plainLyrics") && item ["plainLyrics"] != null) {

								string text3 = item ["plainLyrics"].ToString ();

								if (!string.IsNullOrWhiteSpace (text3)) {

									return text3;

								}

							}

						}

					}

				}

			} catch {

			}

			return null;

		}



		private string FetchLyricsInternal (string artist, string track)

		{

			try {

				ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

				string text = CleanArtistName (artist);

				string text2 = CleanTrackName (track);

				try {

					File.WriteAllText ("lyrics_debug.txt", "Fetching: artist=" + artist + ", track=" + track + " (Cleaned: artist=" + text + ", track=" + text2 + ")\n");

				} catch {

				}

				string text3 = TryLrclibGet (artist, track);

				if (!string.IsNullOrEmpty (text3)) {

					try {

						File.AppendAllText ("lyrics_debug.txt", "GET Raw Success\n");

					} catch {

					}

					return text3;

				}

				if (text != artist || text2 != track) {

					text3 = TryLrclibGet (text, text2);

					if (!string.IsNullOrEmpty (text3)) {

						try {

							File.AppendAllText ("lyrics_debug.txt", "GET Clean Success\n");

						} catch {

						}

						return text3;

					}

				}

				if (text != artist) {

					text3 = TryLrclibGet (text, track);

					if (!string.IsNullOrEmpty (text3)) {

						try {

							File.AppendAllText ("lyrics_debug.txt", "GET CleanArtist RawTrack Success\n");

						} catch {

						}

						return text3;

					}

				}

				if (text2 != track) {

					text3 = TryLrclibGet (artist, text2);

					if (!string.IsNullOrEmpty (text3)) {

						try {

							File.AppendAllText ("lyrics_debug.txt", "GET RawArtist CleanTrack Success\n");

						} catch {

						}

						return text3;

					}

				}

				string text4 = text + " " + text2;

				text3 = TryLrclibSearch (text4);

				if (!string.IsNullOrEmpty (text3)) {

					try {

						File.AppendAllText ("lyrics_debug.txt", "Search Clean Success\n");

					} catch {

					}

					return text3;

				}

				string text5 = artist + " " + track;

				if (text5 != text4) {

					text3 = TryLrclibSearch (text5);

					if (!string.IsNullOrEmpty (text3)) {

						try {

							File.AppendAllText ("lyrics_debug.txt", "Search Raw Success\n");

						} catch {

						}

						return text3;

					}

				}

			} catch (Exception ex) {

				try {

					File.AppendAllText ("lyrics_error.txt", "Lrclib Error: " + ex.ToString () + "\n");

				} catch {

				}

			}

			try {

				File.AppendAllText ("lyrics_debug.txt", "Falling back to lyrics.ovh\n");

			} catch {

			}

			string text6 = FetchLyricsFromOvh (artist, track);

			if (!string.IsNullOrEmpty (text6)) {

				return text6;

			}

			string text7 = CleanArtistName (artist);

			string text8 = CleanTrackName (track);

			if (text7 != artist || text8 != track) {

				text6 = FetchLyricsFromOvh (text7, text8);

				if (!string.IsNullOrEmpty (text6)) {

					return text6;

				}

			}

			return null;

		}



		private void ParseLyrics (string lyricsText)

		{

			parsedLyrics.Clear ();

			plainLyricsTextBlock = null;

			lyricsPanel.Children.Clear ();

			currentLyricIndex = -1;

			try {

				File.AppendAllText ("lyrics_debug.txt", "Parsing lyrics text, length: " + (lyricsText ?? "").Length + "\n");

			} catch {

			}

			if (((base.Owner is DockWindow dockWindow) ? dockWindow.GetEffectiveTheme () : "dark") == "light") {

				lyricActiveColor = System.Windows.Media.Color.FromRgb (30, 30, 30);

				lyricInactiveColor = System.Windows.Media.Color.FromRgb (30, 30, 30);

			} else {

				lyricActiveColor = Colors.White;

				lyricInactiveColor = Colors.White;

			}

			string[] array = lyricsText.Split (new char[2] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);

			bool flag = false;

			string[] array2 = array;

			foreach (string input in array2) {

				Match match = Regex.Match (input, "^\\[(\\d+):(\\d+\\.\\d+)\\](.*)");

				if (!match.Success) {

					match = Regex.Match (input, "^\\[(\\d+):(\\d+)\\](.*)");

				}

				if (match.Success) {

					flag = true;

					int num = int.Parse (match.Groups [1].Value);

					double value = double.Parse (match.Groups [2].Value, CultureInfo.InvariantCulture);

					string text = match.Groups [3].Value.Trim ();

					TimeSpan timeSpan = TimeSpan.FromMinutes (num) + TimeSpan.FromSeconds (value);

					try {

						File.AppendAllText ("lyrics_debug.txt", "  Parsed line: " + text + "\n");

					} catch {

					}

					switch (text) {

					case "---":

					case "- - -":

					case "Instrumental":

						text = "♪";

						break;

					}

					TextBlock textBlock = new TextBlock {

						Text = (string.IsNullOrWhiteSpace (text) ? "♪" : text),

						Foreground = new SolidColorBrush (lyricInactiveColor),

						FontSize = 15.0,

						FontFamily = new System.Windows.Media.FontFamily ("Segoe UI, Arial, sans-serif, Global User Interface"),

						FontWeight = FontWeights.Bold,

						Margin = new Thickness (15.0, 6.0, 15.0, 6.0),

						TextWrapping = TextWrapping.Wrap,

						TextAlignment = TextAlignment.Center,

						Opacity = 0.5,

						RenderTransform = new ScaleTransform (0.95, 0.95),

						RenderTransformOrigin = new System.Windows.Point (0.5, 0.5),

						Effect = new DropShadowEffect {

							Color = lyricActiveColor,

							BlurRadius = 15.0,

							ShadowDepth = 0.0,

							Opacity = 0.0

						},

						Cursor = System.Windows.Input.Cursors.Hand

					};

					TimeSpan clickTime = timeSpan;

					textBlock.PreviewMouseLeftButtonDown += delegate(object sender, MouseButtonEventArgs ev) {

						SeekToLyricTime (clickTime);

						ev.Handled = true;

					};

					parsedLyrics.Add (new LyricLine {

						Time = timeSpan,

						Text = text,

						TextBlock = textBlock

					});

					lyricsPanel.Children.Add (textBlock);

				}

			}

			isLyricsSynced = flag;

			try {

				double num2 = lyricsScroll.ActualHeight / 2.0;

				if (isLyricsSynced) {

					if (num2 > 0.0) {

						lyricsBorder.Padding = new Thickness (20.0, num2 - 15.0, 20.0, num2 - 15.0);

					} else {

						lyricsBorder.Padding = new Thickness (20.0, 0.0, 20.0, 0.0);

					}

				} else {

					lyricsBorder.Padding = new Thickness (20.0, 15.0, 20.0, 40.0);

				}

			} catch {

			}

			if (!flag) {

				try {

					File.AppendAllText ("lyrics_debug.txt", "  Not synced lyrics: " + lyricsText + "\n");

				} catch {

				}

				plainLyricsTextBlock = new TextBlock {

					Text = lyricsText,

					Foreground = new SolidColorBrush (lyricActiveColor),

					FontSize = 14.0,

					FontFamily = new System.Windows.Media.FontFamily ("Segoe UI, Arial, sans-serif"),

					FontWeight = FontWeights.Medium,

					TextWrapping = TextWrapping.Wrap,

					TextAlignment = TextAlignment.Center,

					Opacity = 0.9,

					LineHeight = 22.0,

					Margin = new Thickness (10.0, 0.0, 10.0, 0.0)

				};

				lyricsPanel.Children.Add (plainLyricsTextBlock);

				lyricsScroll.ScrollToVerticalOffset (0.0);

			} else {

				lyricsPanel.Children.Add (new TextBlock {

					Height = 150.0

				});

			}

		}



		private void FetchAndDisplayLyrics (string artist, string track)

		{

			if (string.IsNullOrEmpty (artist) || string.IsNullOrEmpty (track) || track == "No Track Playing" || track == "Spotify Closed" || track == "Not Playing") {

				currentTrackLyrics = "";

				lastLyricsTrackKey = "";

				base.Dispatcher.BeginInvoke ((Action)delegate {

					parsedLyrics.Clear ();

					plainLyricsTextBlock = null;

					currentLyricIndex = -1;

					lyricsPanel.Children.Clear ();

					lyricsTextBlock.Text = "Play a song on Spotify to view lyrics.";

					lyricsPanel.Children.Add (lyricsTextBlock);

				});

				return;

			}

			string text = artist + " - " + track;

			if (text == lastLyricsTrackKey) {

				return;

			}

			lastLyricsTrackKey = text;

			base.Dispatcher.BeginInvoke ((Action)delegate {

				parsedLyrics.Clear ();

				plainLyricsTextBlock = null;

				currentLyricIndex = -1;

				lyricsPanel.Children.Clear ();

				lyricsTextBlock.Text = "Loading lyrics...";

				lyricsPanel.Children.Add (lyricsTextBlock);

			});

			ThreadPool.QueueUserWorkItem (delegate {

				string lyrics = FetchLyricsInternal (artist, track);

				if (string.IsNullOrWhiteSpace (lyrics)) {

					string text2 = CleanTrackName (track);

					if (text2 != track) {

						lyrics = FetchLyricsInternal (artist, text2);

					}

				}

				if (string.IsNullOrWhiteSpace (lyrics)) {

					lyrics = "Lyrics not found.";

				}

				currentTrackLyrics = lyrics;

				base.Dispatcher.BeginInvoke ((Action)delegate {

					if (artist + " - " + track == lastLyricsTrackKey) {

						ParseLyrics (lyrics);

					}

				});

			});

		}



		private void AdaptToSong (string trackName)

		{

			if (!string.IsNullOrEmpty (trackName)) {

				switch (trackName) {

				case "Not Playing":

				case "No Track Playing":

				case "Spotify Closed":

