						double num = rangeValuePattern.Current.Value + (double)secondsDiff * 1000.0;

						if (num > rangeValuePattern.Current.Maximum) {

							num = rangeValuePattern.Current.Maximum;

						}

						if (num < rangeValuePattern.Current.Minimum) {

							num = rangeValuePattern.Current.Minimum;

