		private static bool? CheckIfSpotifyTrackLiked ()

		{

			try {

				IntPtr intPtr = FindWindow ("SpotifyMainWindow", null);

				if (intPtr == IntPtr.Zero) {

					Process process = Process.GetProcessesByName ("spotify").FirstOrDefault ((Process x) => !string.IsNullOrEmpty (x.MainWindowTitle));

					if (process != null) {

						intPtr = process.MainWindowHandle;

					}

				}

				if (intPtr != IntPtr.Zero) {

					AutomationElement automationElement = AutomationElement.FromHandle (intPtr);

					if (automationElement != null) {

						System.Windows.Automation.Condition condition = new OrCondition (new PropertyCondition (AutomationElement.NameProperty, "Remove from Your Library"), new PropertyCondition (AutomationElement.NameProperty, "Remove from Liked Songs"), new PropertyCondition (AutomationElement.NameProperty, "Liked"));

						if (automationElement.FindFirst (TreeScope.Descendants, condition) != null) {

							return true;

						}

						System.Windows.Automation.Condition condition2 = new OrCondition (new PropertyCondition (AutomationElement.NameProperty, "Save to Your Library"), new PropertyCondition (AutomationElement.NameProperty, "Save to Liked Songs"), new PropertyCondition (AutomationElement.NameProperty, "Add to Liked Songs"), new PropertyCondition (AutomationElement.NameProperty, "Add to Library"));

						if (automationElement.FindFirst (TreeScope.Descendants, condition2) != null) {

							return false;

						}

					}

				}

			} catch {

			}

			return null;

		}



		private string FetchAlbumArtUrl (string artist, string track)

		{

			if (string.IsNullOrEmpty (artist) || string.IsNullOrEmpty (track) || artist == "Spotify" || track == "Not Playing" || track == "Spotify Closed") {

				return null;

			}

			try {

				using TimeoutWebClient webClient = new TimeoutWebClient { TimeoutMs = 8000 };

				webClient.Encoding = Encoding.UTF8;

				webClient.Headers.Add ("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)");

				string text = Uri.EscapeDataString (artist + " " + track);

				string address = "https://itunes.apple.com/search?term=" + text + "&limit=1&media=music";

				string text2 = webClient.DownloadString (address);

				int num = text2.IndexOf ("\"artworkUrl100\":\"");

				if (num != -1) {

					int num2 = num + "\"artworkUrl100\":\"".Length;

					int num3 = text2.IndexOf ("\"", num2);

					return text2.Substring (num2, num3 - num2).Replace ("\\/", "/").Replace ("100x100", "640x640");

				}

			} catch {

			}

			return null;

		}



		private System.Windows.Media.Color[] ExtractColorsFromBitmap (BitmapImage bitmap)

		{

			try {

				FormatConvertedBitmap formatConvertedBitmap = new FormatConvertedBitmap ();

				formatConvertedBitmap.BeginInit ();

				formatConvertedBitmap.Source = bitmap;

				formatConvertedBitmap.DestinationFormat = PixelFormats.Pbgra32;

				formatConvertedBitmap.EndInit ();

				formatConvertedBitmap.Freeze ();

				int pixelWidth = formatConvertedBitmap.PixelWidth;

				int pixelHeight = formatConvertedBitmap.PixelHeight;

				if (pixelWidth <= 0 || pixelHeight <= 0) {

					return null;

				}

				int num = pixelWidth * 4;

				byte[] array = new byte[pixelHeight * num];

				formatConvertedBitmap.CopyPixels (array, num, 0);

				List<System.Windows.Media.Color> list = new List<System.Windows.Media.Color> ();

				int num2 = Math.Max (1, pixelWidth / 32);

				int num3 = Math.Max (1, pixelHeight / 32);

				for (int i = 0; i < pixelHeight; i += num3) {

					for (int j = 0; j < pixelWidth; j += num2) {

						int num4 = i * num + j * 4;

						if (num4 + 3 < array.Length) {

							byte b = array [num4];

							byte g = array [num4 + 1];

							byte r = array [num4 + 2];

							if (array [num4 + 3] >= 20) {

								list.Add (System.Windows.Media.Color.FromRgb (r, g, b));

							}

						}

					}

				}

				if (list.Count == 0) {

					return null;

				}

				System.Windows.Media.Color color = list [0];

				double num5 = -1.0;

				foreach (System.Windows.Media.Color item in list) {

					double vibrancy = GetVibrancy (item);

					if (vibrancy > num5) {

						num5 = vibrancy;

						color = item;

					}

				}

				System.Windows.Media.Color c = ShiftHue (color, 150.0);

				double num6 = 0.0;

				foreach (System.Windows.Media.Color item2 in list) {

					double num7 = ColorDistance (item2, color);

					if (!(num7 < 55.0)) {

						double num8 = GetVibrancy (item2) * 0.6 + num7 * 0.4;

						if (num8 > num6) {

							num6 = num8;

							c = item2;

						}

					}

				}

				return new System.Windows.Media.Color[2] {

					BoostSaturation (color, 1.5),

					BoostSaturation (c, 1.5)

				};

			} catch {

				return null;

			}

		}



		private double GetVibrancy (System.Windows.Media.Color c)

		{

			double val = (double)(int)c.R / 255.0;

			double val2 = (double)(int)c.G / 255.0;

			double val3 = (double)(int)c.B / 255.0;

			double num = Math.Max (val, Math.Max (val2, val3));

			double num2 = Math.Min (val, Math.Min (val2, val3));

			double num3 = num - num2;

			double num4 = ((num == 0.0) ? 0.0 : (num3 / num));

			double num5 = num;

			return num4 * num5;

		}



		private double ColorDistance (System.Windows.Media.Color a, System.Windows.Media.Color b)

		{

			double num = a.R - b.R;

			double num2 = a.G - b.G;

			double num3 = a.B - b.B;

			return Math.Sqrt (num * num + num2 * num2 + num3 * num3);

		}



		private System.Windows.Media.Color BoostSaturation (System.Windows.Media.Color c, double factor)

		{

			double num = (double)(int)c.R / 255.0;

			double num2 = (double)(int)c.G / 255.0;

			double num3 = (double)(int)c.B / 255.0;

			double num4 = Math.Max (num, Math.Max (num2, num3));

			double num5 = Math.Min (num, Math.Min (num2, num3));

			double num6 = 0.0;

			double num7 = num4;

			double num8 = num4 - num5;

			double num9 = ((num4 == 0.0) ? 0.0 : (num8 / num4));

			if (num4 != num5) {

				num6 = ((num4 == num) ? ((num2 - num3) / num8 + (double)((num2 < num3) ? 6 : 0)) : ((num4 != num2) ? ((num - num2) / num8 + 4.0) : ((num3 - num) / num8 + 2.0)));

				num6 /= 6.0;

			}

			num9 = Math.Max (0.0, Math.Min (1.0, num9 * factor));

			int num10 = (int)(num6 * 6.0);

			double num11 = num6 * 6.0 - (double)num10;

			double num12 = num7 * (1.0 - num9);

			double num13 = num7 * (1.0 - num11 * num9);

			double num14 = num7 * (1.0 - (1.0 - num11) * num9);

			double num15;

			double num16;

			double num17;

			switch (num10 % 6) {

			case 0:

				num15 = num7;

				num16 = num14;

				num17 = num12;

				break;

			case 1:

				num15 = num13;

				num16 = num7;

				num17 = num12;

				break;

			case 2:

				num15 = num12;

				num16 = num7;

				num17 = num14;

				break;

			case 3:

				num15 = num12;

				num16 = num13;

				num17 = num7;

				break;

			case 4:

				num15 = num14;

				num16 = num12;

				num17 = num7;

				break;

			default:

				num15 = num7;

				num16 = num12;

				num17 = num13;

				break;

			}

			return System.Windows.Media.Color.FromRgb ((byte)(num15 * 255.0), (byte)(num16 * 255.0), (byte)(num17 * 255.0));

		}



		private ImageSource CreateDefaultArt ()

		{

			int num = 128;

			RenderTargetBitmap renderTargetBitmap = new RenderTargetBitmap (num, num, 96.0, 96.0, PixelFormats.Pbgra32);

			DrawingVisual drawingVisual = new DrawingVisual ();

			using (DrawingContext drawingContext = drawingVisual.RenderOpen ()) {

				RadialGradientBrush brush = new RadialGradientBrush (System.Windows.Media.Color.FromRgb (40, 40, 40), System.Windows.Media.Color.FromRgb (15, 15, 15));

				drawingContext.DrawEllipse (brush, new System.Windows.Media.Pen (new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, byte.MaxValue, byte.MaxValue, byte.MaxValue)), 1.5), new System.Windows.Point ((double)num / 2.0, (double)num / 2.0), (double)num / 2.0 - 2.0, (double)num / 2.0 - 2.0);

				drawingContext.DrawEllipse (System.Windows.Media.Brushes.Transparent, new System.Windows.Media.Pen (new SolidColorBrush (System.Windows.Media.Color.FromRgb (30, 215, 96)), 2.5), new System.Windows.Point ((double)num / 2.0, (double)num / 2.0), 12.0, 12.0);

			}

			renderTargetBitmap.Render (drawingVisual);

			renderTargetBitmap.Freeze ();

			return renderTargetBitmap;

		}

	}

	public class WindowPreviewOverlay : Window

