		private static string GetWeatherEmoji (int code, bool isNight)

		{

			if (code <= 1) {

				if (!isNight) {

					return "â\u02dc€\ufe0f";

				}

				return "\ud83c\udf19";

			}

			switch (code) {

			case 2:

				if (!isNight) {

					return "â›…";

				}

				return "\ud83c\udf19";

			case 3:

				return "â\u02dc\u0081\ufe0f";

			case 45:

			case 48:

				return "\ud83c\udf2b\ufe0f";

			case 51:

			case 52:

			case 53:

			case 54:

			case 55:

				return "\ud83c\udf26\ufe0f";

			case 56:

			case 57:

			case 58:

			case 59:

			case 60:

			case 61:

			case 62:

			case 63:

			case 64:

			case 65:

			case 66:

			case 67:

				return "\ud83c\udf27\ufe0f";

			default:

				if (code >= 71 && code <= 77) {

					return "â\u009d„\ufe0f";

				}

				if (code >= 80 && code <= 82) {

					return "\ud83c\udf27\ufe0f";

				}

				if (code >= 95) {

					return "â›ˆ\ufe0f";

				}

				return "â\u02dc€\ufe0f";

			}

		}



		private static string GetConditionText (int code)

		{

			switch (code) {

			case 0:

				return "Clear Sky";

			case 1:

				return "Mainly Clear";

			case 2:

				return "Partly Cloudy";

			case 3:

				return "Overcast";

			case 45:

				return "Foggy";

			case 48:

				return "Depositing Rime Fog";

			case 51:

			case 52:

			case 53:

			case 54:

			case 55:

				return "Drizzle";

			case 56:

			case 57:

				return "Freezing Drizzle";

			default:

				if (code >= 61 && code <= 65) {

					return "Rain";

				}

				if (code >= 66 && code <= 67) {

					return "Freezing Rain";

				}

				if (code >= 71 && code <= 75) {

					return "Snowfall";

				}

				if (code != 77) {

					if ((uint)(code - 80) <= 2u) {

						return "Rain Showers";

					}

					if (code == 85 || code == 86) {

						return "Snow Showers";

					}

					if (code == 95) {

						return "Thunderstorm";

					}

					if (code >= 96) {

						return "Thunderstorm with Hail";

					}

					return "Clear";

				}

				return "Snow Grains";

			}

		}



		private static System.Windows.Media.Color BlendColors (System.Windows.Media.Color c1, System.Windows.Media.Color c2, double p)

		{

			if (p < 0.0) {

				p = 0.0;

			}

			if (p > 1.0) {

				p = 1.0;

			}

			byte r = (byte)((double)(int)c1.R + (double)(c2.R - c1.R) * p);

			byte g = (byte)((double)(int)c1.G + (double)(c2.G - c1.G) * p);

			byte b = (byte)((double)(int)c1.B + (double)(c2.B - c1.B) * p);

			return System.Windows.Media.Color.FromRgb (r, g, b);

		}



		private static System.Windows.Media.Color TempToColor (double temp, double minT, double maxT)

		{

			double num = maxT - minT;

			if (num < 1.0) {

				num = 1.0;

			}

			double num2 = (temp - minT) / num;

			if (num2 < 0.0) {

				num2 = 0.0;

			}

			if (num2 > 1.0) {

				num2 = 1.0;

			}

			if (num2 < 0.25) {

				double p = num2 / 0.25;

				return BlendColors (System.Windows.Media.Color.FromRgb (90, 150, byte.MaxValue), System.Windows.Media.Color.FromRgb (70, 210, 220), p);

			}

			if (num2 < 0.5) {

				double p2 = (num2 - 0.25) / 0.25;

				return BlendColors (System.Windows.Media.Color.FromRgb (70, 210, 220), System.Windows.Media.Color.FromRgb (100, 210, 80), p2);

			}

			if (num2 < 0.75) {

				double p3 = (num2 - 0.5) / 0.25;

				return BlendColors (System.Windows.Media.Color.FromRgb (100, 210, 80), System.Windows.Media.Color.FromRgb (byte.MaxValue, 210, 50), p3);

			}

			double p4 = (num2 - 0.75) / 0.25;

			return BlendColors (System.Windows.Media.Color.FromRgb (byte.MaxValue, 210, 50), System.Windows.Media.Color.FromRgb (byte.MaxValue, 130, 40), p4);

		}



		private static double ParseTimeToHours (string timeStr)

		{

			if (string.IsNullOrEmpty (timeStr)) {

				return 0.0;

			}

			string[] array = timeStr.Split (':');

			if (array.Length >= 2 && int.TryParse (array [0], out var result) && int.TryParse (array [1], out var result2)) {

				return (double)result + (double)result2 / 60.0;

			}

			return 0.0;

		}



		private static double CalculateAqiPercentage (int aqi)

		{

			if (aqi <= 0) {

				return 0.0;

			}

			if (aqi >= 300) {

				return 1.0;

			}

			return (double)aqi / 300.0;

		}



		private static double CalculateUvPercentage (double uv)

		{

			if (uv <= 0.0) {

				return 0.0;

			}

			if (uv >= 11.0) {

				return 1.0;

			}

			return uv / 11.0;

		}



		public WeatherOverlayWindow (DockWindow parent)

		{

			base.AllowsTransparency = true;

			base.WindowStyle = WindowStyle.None;

			base.Background = System.Windows.Media.Brushes.Transparent;

			base.Topmost = true;

			base.ShowInTaskbar = false;

			base.Width = 860.0;

			base.Height = 750.0;

			base.Cursor = System.Windows.Input.Cursors.Hand;

			base.MouseLeftButtonDown += delegate {
				try {
					string weatherExe = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "Weather", "Weather.exe");
					if (File.Exists (weatherExe)) {
						Process.Start (new ProcessStartInfo (weatherExe) {
							UseShellExecute = true,
							WorkingDirectory = System.IO.Path.GetDirectoryName (weatherExe)
						});
					} else {
						try {
							Process.Start (new ProcessStartInfo ("ms-weather:") { UseShellExecute = true });
						} catch {
							Process.Start (new ProcessStartInfo ("https://weather.com") { UseShellExecute = true });
						}
					}
					this.Hide ();
				} catch {}
			};

			double totalHours = DateTime.Now.TimeOfDay.TotalHours;

			if (parent != null && parent.settings != null && !string.IsNullOrEmpty (parent.settings.WeatherUnit) && !parent.settings.WeatherUnit.Equals ("fahrenheit", StringComparison.OrdinalIgnoreCase)) {

				parent.settings.WeatherUnit.Equals ("F", StringComparison.OrdinalIgnoreCase);

			}

			double num = ParseTimeToHours (DockWindow.activeSunrise);

			double num2 = ParseTimeToHours (DockWindow.activeSunset);

			if (num < 1.0) {

				num = 6.0;

			}

			if (num2 < 1.0) {

				num2 = 18.0;

			}

			bool flag = totalHours < num || totalHours >= num2;

			Border border = new Border {

				CornerRadius = new CornerRadius (22.0),

				BorderThickness = new Thickness (0.0),

				BorderBrush = System.Windows.Media.Brushes.Transparent

