				border.Effect = new DropShadowEffect {

					BlurRadius = 18.0,

					ShadowDepth = 3.0,

					Opacity = 0.45,

					Color = Colors.Black

				};

			}

			border.Margin = new Thickness (20.0);

			System.Windows.Media.Color c;

			System.Windows.Media.Color c2;

			if (flag) {

				int activeWeatherCode = DockWindow.activeWeatherCode;

				if ((activeWeatherCode >= 51 && activeWeatherCode <= 67) || (activeWeatherCode >= 80 && activeWeatherCode <= 82) || activeWeatherCode >= 95) {

					c = System.Windows.Media.Color.FromRgb (10, 15, 28);

					c2 = System.Windows.Media.Color.FromRgb (24, 30, 48);

				} else {

					c = System.Windows.Media.Color.FromRgb (15, 23, 42);

					c2 = System.Windows.Media.Color.FromRgb (30, 41, 59);

				}

			} else {

				int activeWeatherCode2 = DockWindow.activeWeatherCode;

				if (activeWeatherCode2 >= 51 && activeWeatherCode2 <= 82) {

					c = System.Windows.Media.Color.FromRgb (100, 120, 150);

					c2 = System.Windows.Media.Color.FromRgb (140, 155, 175);

				} else if (activeWeatherCode2 == 3 || activeWeatherCode2 == 45 || activeWeatherCode2 == 48) {

					c = System.Windows.Media.Color.FromRgb (130, 150, 175);

					c2 = System.Windows.Media.Color.FromRgb (160, 175, 195);

				} else {

					c = System.Windows.Media.Color.FromRgb (55, 130, 220);

