		public void ApplyTheme ()

		{

			if (ownerWindow == null) {

				return;

			}

			string effectiveTheme = ownerWindow.GetEffectiveTheme ();

			if (lastTheme == effectiveTheme) {

				return;

			}

			lastTheme = effectiveTheme;

			isLight = lastTheme == "light";

			System.Windows.Media.Brush background;

			System.Windows.Media.Brush borderBrush;

			if (isLight) {

				background = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.2, 0.0),

					EndPoint = new System.Windows.Point (0.8, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (240, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (235, 245, 245, 247), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 230, 230, 235), 1.0)

					}

				};

				borderBrush = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (180, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (50, 0, 0, 0), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (100, 0, 0, 0), 1.0)

					}

				};

			} else {

				background = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.2, 0.0),

					EndPoint = new System.Windows.Point (0.8, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 40, 40, 45), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (235, 28, 28, 33), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 18, 18, 22), 1.0)

					}

				};

				borderBrush = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (180, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (50, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (100, 0, 0, 0), 1.0)

					}

				};

			}

			if (rootBorder != null) {

				rootBorder.Background.BeginAnimation (SolidColorBrush.ColorProperty, null);

				rootBorder.BorderBrush.BeginAnimation (SolidColorBrush.ColorProperty, null);

				rootBorder.Background = background;

				rootBorder.BorderBrush = borderBrush;

			}

			if (tabContainer != null) {

				ColorAnimation animation = new ColorAnimation (isLight ? System.Windows.Media.Color.FromArgb (15, 0, 0, 0) : System.Windows.Media.Color.FromArgb (25, byte.MaxValue, byte.MaxValue, byte.MaxValue), TimeSpan.FromMilliseconds (400.0));

				tabContainer.Background.BeginAnimation (SolidColorBrush.ColorProperty, animation);

			}

			if (lightLogo != null && darkLogo != null) {

				DoubleAnimation animation2 = new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (400.0));

				DoubleAnimation animation3 = new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (400.0));

				if (isLight) {

					lightLogo.BeginAnimation (UIElement.OpacityProperty, animation2);

					darkLogo.BeginAnimation (UIElement.OpacityProperty, animation3);

				} else {

					lightLogo.BeginAnimation (UIElement.OpacityProperty, animation3);

					darkLogo.BeginAnimation (UIElement.OpacityProperty, animation2);

				}

			}

			if (tabDriversBtn != null) {

				UpdateTabButtonState (tabDriversBtn, activeTab == "Drivers");

				UpdateTabButtonState (tabConstructorsBtn, activeTab == "Constructors");

				UpdateTabButtonState (tabPodiumsBtn, activeTab == "Podiums");

				UpdateTabButtonState (tabScheduleBtn, activeTab == "Schedule");

				UpdateTabButtonState (tabTelemetryBtn, activeTab == "Telemetry");

				UpdateTabButtonState (tabLapsBtn, activeTab == "Laps");

				UpdateTabButtonState (tabPositionsBtn, activeTab == "Positions");

				UpdateTabButtonState (tabPitStopsBtn, activeTab == "Pit Stops");

				UpdateTabButtonState (tabWeatherBtn, activeTab == "Weather");

				UpdateTabButtonState (tabRaceControlBtn, activeTab == "Race Control");

				RenderActiveTab ();

			}

		}



		[DllImport ("user32.dll")]

		internal static extern int SetWindowCompositionAttribute (IntPtr hwnd, ref WinCompositionAttrData data);



		public void EnableBlur (bool enable)

		{

			try {

				IntPtr handle = new WindowInteropHelper (this).Handle;

				if (handle != IntPtr.Zero) {

					AccentPolicy structure = default(AccentPolicy);

					structure.AccentState = (enable ? 3 : 0);

					if (enable) {

						structure.AccentFlags = 2;

						double blurAmount = (ownerWindow != null && ownerWindow.settings != null) ? ownerWindow.settings.BlurAmount : 0.7;

						bool isDark = (ownerWindow != null && ownerWindow.settings != null) ? (ownerWindow.settings.Theme.ToLower () == "dark" || ownerWindow.settings.Theme.ToLower () == "tahoe") : true;

						byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);

						uint colorVal = isDark ? 0x1A1A1AU : 0xF2F2F7U;

						structure.GradientColor = (int)(((uint)alpha << 24) | (colorVal & 0x00FFFFFF));

					}

					int num = Marshal.SizeOf (structure);

					IntPtr intPtr = Marshal.AllocHGlobal (num);

					Marshal.StructureToPtr (structure, intPtr, fDeleteOld: false);

					WinCompositionAttrData data = default(WinCompositionAttrData);

					data.Attribute = 19;

					data.SizeOfData = num;

					data.Data = intPtr;

					SetWindowCompositionAttribute (handle, ref data);

					Marshal.FreeHGlobal (intPtr);

				}

			} catch {

			}

		}



