		private System.Windows.Controls.Button CreateTabButton (string text, bool isActive)

		{

			System.Windows.Controls.Button obj = new System.Windows.Controls.Button {

				Content = text,

				Background = System.Windows.Media.Brushes.Transparent,

				Foreground = (isActive ? System.Windows.Media.Brushes.White : (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, byte.MaxValue, byte.MaxValue, byte.MaxValue)))),

				FontSize = 11.0,

				FontWeight = FontWeights.SemiBold,

				FontFamily = new System.Windows.Media.FontFamily ("Source Sans Pro, Segoe UI, sans-serif"),

				BorderThickness = new Thickness (0.0),

				Height = 28.0,

				Padding = new Thickness (16.0, 0.0, 16.0, 0.0),

				Cursor = System.Windows.Input.Cursors.Hand,

				VerticalAlignment = VerticalAlignment.Center

			};

			ControlTemplate controlTemplate = new ControlTemplate (typeof(System.Windows.Controls.Button));

			FrameworkElementFactory frameworkElementFactory = new FrameworkElementFactory (typeof(Border));

			frameworkElementFactory.Name = "border";

			frameworkElementFactory.SetValue (Border.CornerRadiusProperty, new CornerRadius (14.0));

			frameworkElementFactory.SetBinding (Border.BackgroundProperty, new System.Windows.Data.Binding ("Background") {

				RelativeSource = RelativeSource.TemplatedParent

			});

			frameworkElementFactory.SetBinding (Border.PaddingProperty, new System.Windows.Data.Binding ("Padding") {

				RelativeSource = RelativeSource.TemplatedParent

			});

			FrameworkElementFactory frameworkElementFactory2 = new FrameworkElementFactory (typeof(ContentPresenter));

			frameworkElementFactory2.SetValue (FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Center);

			frameworkElementFactory2.SetValue (FrameworkElement.VerticalAlignmentProperty, VerticalAlignment.Center);

			frameworkElementFactory2.SetBinding (TextElement.ForegroundProperty, new System.Windows.Data.Binding ("Foreground") {

				RelativeSource = RelativeSource.TemplatedParent

			});

			frameworkElementFactory.AppendChild (frameworkElementFactory2);

			controlTemplate.VisualTree = frameworkElementFactory;

			Trigger trigger = new Trigger {

				Property = UIElement.IsMouseOverProperty,

				Value = true

			};

			trigger.Setters.Add (new Setter (UIElement.OpacityProperty, 0.9, "border"));

			Trigger trigger2 = new Trigger {

				Property = System.Windows.Controls.Primitives.ButtonBase.IsPressedProperty,

				Value = true

			};

			trigger2.Setters.Add (new Setter (UIElement.OpacityProperty, 0.75, "border"));

			controlTemplate.Triggers.Add (trigger);

			controlTemplate.Triggers.Add (trigger2);

			obj.Template = controlTemplate;

			return obj;

		}



		private void SwitchTab (string tabName)

		{

			if (activeTab == tabName) {

				return;

			}

			activeTab = tabName;

			UpdateTabButtonState (tabDriversBtn, activeTab == "Drivers");

			UpdateTabButtonState (tabConstructorsBtn, activeTab == "Constructors");

			UpdateTabButtonState (tabPodiumsBtn, activeTab == "Podiums");

			UpdateTabButtonState (tabScheduleBtn, activeTab == "Schedule");

			UpdateTabButtonState (tabTelemetryBtn, activeTab == "Telemetry");

			UpdateTabButtonState (tabLapsBtn, activeTab == "Laps");

			UpdateTabButtonState (tabPositionsBtn, activeTab == "Positions");

			UpdateTabButtonState (tabPitStopsBtn, activeTab == "Pit Stops");

			UpdateTabButtonState (tabWeatherBtn, activeTab == "Weather");

			UpdateTabButtonState (tabRaceControlBtn, activeTab == "Race Control");

			if (dataScrollViewer != null) {

				DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (200.0));

				TranslateTransform translateTransform = new TranslateTransform (15.0, 0.0);

				dataScrollViewer.RenderTransform = translateTransform;

				DoubleAnimation doubleAnimation = new DoubleAnimation (15.0, 0.0, TimeSpan.FromMilliseconds (250.0));

				doubleAnimation.EasingFunction = new CubicEase {

					EasingMode = EasingMode.EaseOut

				};

				dataScrollViewer.BeginAnimation (UIElement.OpacityProperty, animation);

				translateTransform.BeginAnimation (TranslateTransform.XProperty, doubleAnimation);

			}

			if (tabsGrid != null && activeTabBg != null && liveTabsGrid != null && liveActiveTabBg != null) {

				bool flag = activeTab == "Drivers" || activeTab == "Constructors" || activeTab == "Podiums" || activeTab == "Schedule";

				System.Windows.Controls.Button activeBtn = tabDriversBtn;

				if (activeTab == "Constructors") {

					activeBtn = tabConstructorsBtn;

				}

				if (activeTab == "Podiums") {

					activeBtn = tabPodiumsBtn;

				}

				if (activeTab == "Schedule") {

					activeBtn = tabScheduleBtn;

				}

				if (activeTab == "Telemetry") {

					activeBtn = tabTelemetryBtn;

				}

				if (activeTab == "Laps") {

					activeBtn = tabLapsBtn;

				}

				if (activeTab == "Positions") {

					activeBtn = tabPositionsBtn;

				}

				if (activeTab == "Pit Stops") {

					activeBtn = tabPitStopsBtn;

				}

				if (activeTab == "Weather") {

					activeBtn = tabWeatherBtn;

				}

				if (activeTab == "Race Control") {

					activeBtn = tabRaceControlBtn;

				}

				DoubleAnimation animation2 = new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (150.0));

				DoubleAnimation animation3 = new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (150.0));

				if (flag) {

					activeTabBg.BeginAnimation (UIElement.OpacityProperty, animation3);

					liveActiveTabBg.BeginAnimation (UIElement.OpacityProperty, animation2);

				} else {

					activeTabBg.BeginAnimation (UIElement.OpacityProperty, animation2);

					liveActiveTabBg.BeginAnimation (UIElement.OpacityProperty, animation3);

				}

				Grid targetGrid = (flag ? tabsGrid : liveTabsGrid);

				Border targetBg = (flag ? activeTabBg : liveActiveTabBg);

				base.Dispatcher.BeginInvoke ((Action)delegate {

					if (activeBtn.ActualWidth != 0.0) {

						double actualWidth = activeBtn.ActualWidth;

						double x = activeBtn.TransformToAncestor (targetGrid).Transform (new System.Windows.Point (0.0, 0.0)).X;

						DoubleAnimation animation4 = new DoubleAnimation (actualWidth, TimeSpan.FromMilliseconds (250.0)) {

							EasingFunction = new CubicEase {

								EasingMode = EasingMode.EaseOut

							}

						};

						targetBg.BeginAnimation (FrameworkElement.WidthProperty, animation4);

						DoubleAnimation animation5 = new DoubleAnimation (x, TimeSpan.FromMilliseconds (250.0)) {

							EasingFunction = new CubicEase {

								EasingMode = EasingMode.EaseOut

							}

						};

						if (targetBg.RenderTransform is TranslateTransform translateTransform2) {

							translateTransform2.BeginAnimation (TranslateTransform.XProperty, animation5);

						}

					}

				}, DispatcherPriority.Normal);

			}

			RenderActiveTab ();

		}



		private void UpdateTabButtonState (System.Windows.Controls.Button btn, bool isActive)

		{

			btn.Foreground = (isActive ? System.Windows.Media.Brushes.White : (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, byte.MaxValue, byte.MaxValue, byte.MaxValue))));

		}



		private void LoadData ()

		{

			if (cachedDriversJson != null && cachedConstructorsJson != null && cachedScheduleJson != null && cachedResultsJson != null && DateTime.Now - lastFetchTime < CacheDuration) {

				RenderActiveTab ();

				return;

			}

			dataScrollViewer.Visibility = Visibility.Collapsed;

			errorGrid.Visibility = Visibility.Collapsed;

			loadingGrid.Visibility = Visibility.Visible;

			ThreadPool.QueueUserWorkItem (delegate {

				try {

					using TimeoutWebClient webClient = new TimeoutWebClient { TimeoutMs = 8000 };

					webClient.Encoding = Encoding.UTF8;

					webClient.Headers.Add ("user-agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)");

					string address = "https://api.jolpi.ca/ergast/f1/current/driverStandings.json";

					string address2 = "https://api.jolpi.ca/ergast/f1/current/constructorStandings.json";

					string address3 = "https://api.jolpi.ca/ergast/f1/current.json";

					string address4 = "https://api.jolpi.ca/ergast/f1/current/results.json?limit=1000";

					string value = webClient.DownloadString (address);

					string value2 = webClient.DownloadString (address2);

					string value3 = webClient.DownloadString (address3);

					string text = "";

					try {

						text = webClient.DownloadString (address4);

					} catch {

					}

					if (!string.IsNullOrEmpty (value) && !string.IsNullOrEmpty (value2) && !string.IsNullOrEmpty (value3)) {

						cachedDriversJson = value;

						cachedConstructorsJson = value2;

						cachedScheduleJson = value3;

						cachedResultsJson = text;

						lastFetchTime = DateTime.Now;

						base.Dispatcher.BeginInvoke ((Action)delegate {

							loadingGrid.Visibility = Visibility.Collapsed;

							dataScrollViewer.Visibility = Visibility.Visible;

							RenderActiveTab ();

						});

						return;

					}

					throw new Exception ("Empty API response");

				} catch (Exception ex) {

					try {

						File.WriteAllText ("f1_widget_error.txt", ex.ToString ());

					} catch {

					}

					base.Dispatcher.BeginInvoke ((Action)delegate {

						loadingGrid.Visibility = Visibility.Collapsed;

						errorGrid.Visibility = Visibility.Visible;

					});

				}

			});

		}



		private void ForceRefreshData ()

		{

			lastFetchTime = DateTime.MinValue;

			LoadData ();

		}



		private bool IsLiveRace (out DateTime? nextRaceDate, out string nextRaceName)

		{

			nextRaceDate = null;

			nextRaceName = "";

			if (string.IsNullOrEmpty (cachedScheduleJson)) {

				return false;

			}

			try {

				List<F1Race> list = new JavaScriptSerializer ().Deserialize<F1ScheduleResponse> (cachedScheduleJson)?.MRData?.RaceTable?.Races;

				if (list == null) {

					return false;

				}

				DateTime utcNow = DateTime.UtcNow;

				foreach (F1Race item in list) {

					if (DateTime.TryParse (item.date + "T" + (item.time ?? "00:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result)) {

						if (utcNow >= result && utcNow <= result.AddHours (2.5)) {

							nextRaceDate = result;

							nextRaceName = item.raceName;

							return true;

						}

						if (result > utcNow && !nextRaceDate.HasValue) {

							nextRaceDate = result;

							nextRaceName = item.raceName;

						}

					}

				}

			} catch {

			}

			return false;

		}



