		private void UpdateFlipCard (Grid cardGrid, TextBlock tb, string newValue)

		{

			if (!(cardGrid.Tag is FlipCardHelper flipCardHelper)) {

				tb.Text = newValue;

			} else if (!(flipCardHelper.CurrentValue == newValue)) {

				string currentValue = flipCardHelper.CurrentValue;

				flipCardHelper.CurrentValue = newValue;

				FlipCardAnimation (flipCardHelper, currentValue, newValue);

			}

		}



		private void FlipCardAnimation (FlipCardHelper helper, string oldValue, string newValue)

		{

			helper.TopFlapScale.BeginAnimation (ScaleTransform.ScaleYProperty, null);

			helper.BottomFlapScale.BeginAnimation (ScaleTransform.ScaleYProperty, null);

			helper.TopStaticText.Text = newValue;

			helper.BottomStaticText.Text = oldValue;

			helper.TopFlapText.Text = oldValue;

			helper.BottomFlapText.Text = newValue;

			helper.TopFlap.Visibility = Visibility.Visible;

			helper.BottomFlap.Visibility = Visibility.Collapsed;

			helper.TopFlapScale.ScaleY = 1.0;

			helper.BottomFlapScale.ScaleY = 0.0;

			DoubleAnimation doubleAnimation = new DoubleAnimation (1.0, 0.0, TimeSpan.FromMilliseconds (180.0));

			doubleAnimation.EasingFunction = new PowerEase {

				Power = 2.0,

				EasingMode = EasingMode.EaseIn

			};

			DoubleAnimation animBottom = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (180.0));

			animBottom.EasingFunction = new PowerEase {

				Power = 2.0,

				EasingMode = EasingMode.EaseOut

			};

			doubleAnimation.Completed += delegate {

				helper.TopFlap.Visibility = Visibility.Collapsed;

				helper.BottomFlap.Visibility = Visibility.Visible;

				animBottom.Completed += delegate {

					helper.BottomStaticText.Text = newValue;

					helper.BottomFlap.Visibility = Visibility.Collapsed;

				};

				helper.BottomFlapScale.BeginAnimation (ScaleTransform.ScaleYProperty, animBottom);

			};

			helper.TopFlapScale.BeginAnimation (ScaleTransform.ScaleYProperty, doubleAnimation);

		}



		private bool GetUpcomingRound (out string round, out string country, out string name)

		{

			round = "";

			country = "";

			name = "";

			if (string.IsNullOrEmpty (cachedScheduleJson)) {

				return false;

			}

			try {

				List<F1Race> list = new JavaScriptSerializer ().Deserialize<F1ScheduleResponse> (cachedScheduleJson)?.MRData?.RaceTable?.Races;

				if (list == null) {

					return false;

				}

				DateTime utcNow = DateTime.UtcNow;

				foreach (F1Race item in list) {

					if (DateTime.TryParse (item.date + "T" + (item.time ?? "00:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result) && result.AddHours (2.5) > utcNow) {

						round = item.round;

						country = item.Circuit?.Location?.country ?? "";

						name = item.raceName;

						return true;

					}

				}

			} catch {

			}

			return false;

		}



		private string CleanCountry (string c)

		{

			if (string.IsNullOrEmpty (c)) {

				return "";

			}

			c = c.ToLower ();

			if (c.Contains ("united states") || c.Contains ("usa")) {

				return "united states";

			}

			if (c.Contains ("uk") || c.Contains ("great britain") || c.Contains ("british")) {

				return "great britain";

			}

			if (c.Contains ("uae") || c.Contains ("abu dhabi")) {

				return "abu dhabi";

			}

			return c;

		}



		private string FormatLapTime (double seconds)

		{

			TimeSpan timeSpan = TimeSpan.FromSeconds (seconds);

			if (timeSpan.TotalMinutes >= 1.0) {

				return $"{(int)timeSpan.TotalMinutes}:{timeSpan.Seconds:D2}.{timeSpan.Milliseconds:D3}";

			}

			return $"{seconds:F3}";

		}



