		private F1Race GetUpcomingRace ()

		{

			if (string.IsNullOrEmpty (cachedScheduleJson)) {

				return null;

			}

			try {

				List<F1Race> list = new JavaScriptSerializer ().Deserialize<F1ScheduleResponse> (cachedScheduleJson)?.MRData?.RaceTable?.Races;

				if (list == null) {

					return null;

				}

				DateTime utcNow = DateTime.UtcNow;

				F1Race f1Race = null;

				foreach (F1Race item in list) {

					if (DateTime.TryParse (item.date + "T" + (item.time ?? "00:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result)) {

						if (utcNow >= result && utcNow <= result.AddHours (2.5)) {

							return item;

						}

						if (result > utcNow && f1Race == null) {

							f1Race = item;

						}

					}

				}

				return f1Race;

			} catch {

				return null;

			}

		}



		private DateTime? GetSessionScheduledTime (F1Race race, string sessionKey)

		{

			if (race == null) {

				return null;

			}

			F1SessionInfo f1SessionInfo = null;

			switch (sessionKey) {

			case "FP1":

				f1SessionInfo = race.FirstPractice;

				break;

			case "FP2":

				f1SessionInfo = race.SecondPractice;

				break;

			case "FP3":

				f1SessionInfo = race.ThirdPractice;

				break;

			case "Qualifying":

				f1SessionInfo = race.Qualifying;

				break;

			case "Countdown":

			case "Race": {

				if (DateTime.TryParse (race.date + "T" + (race.time ?? "00:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result)) {

					return result;

				}

				break;

			}

			}

			if (f1SessionInfo != null && !string.IsNullOrEmpty (f1SessionInfo.date) && DateTime.TryParse (f1SessionInfo.date + "T" + (f1SessionInfo.time ?? "00:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result2)) {

				return result2;

			}

			if (DateTime.TryParse (race.date + "T" + (race.time ?? "14:00:00Z"), null, DateTimeStyles.AdjustToUniversal, out var result3)) {

				switch (sessionKey) {

				case "FP1":

					return result3.AddHours (-50.0);

				case "FP2":

					return result3.AddHours (-45.0);

				case "FP3":

					return result3.AddHours (-26.0);

				case "Qualifying":

					return result3.AddHours (-22.0);

				}

			}

			return null;

		}



