		private void RenderPracticeResults (string fpSession)

		{

			TextBlock loading = new TextBlock {

				Text = "Loading Practice Results...",

				Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

				FontSize = 14.0,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				Margin = new Thickness (0.0, 50.0, 0.0, 0.0)

			};

			listPanel.Children.Add (loading);

			string sessionNameMatch = "Practice 1";

			if (fpSession == "FP2") {

				sessionNameMatch = "Practice 2";

			} else if (fpSession == "FP3") {

				sessionNameMatch = "Practice 3";

			}

			string upcomingRaceName;

			List<KeyValuePair<int, double>> sorted;

			Dictionary<int, OpenF1Driver> driverMap;

			Exception ex;

			ThreadPool.QueueUserWorkItem (delegate {

				try {

					if (!GetUpcomingRound (out var _, out var country, out upcomingRaceName)) {

						throw new Exception ("Could not determine upcoming round.");

					}

					if (cachedOpenF1Sessions == null || (DateTime.Now - lastSessionsFetch).TotalHours > 12.0) {

						cachedOpenF1Sessions = OpenF1Client.GetSessionsAsync (DateTime.UtcNow.Year).GetAwaiter ().GetResult ();

						lastSessionsFetch = DateTime.Now;

					}

					if (cachedOpenF1Sessions == null) {

						throw new Exception ("Failed to retrieve sessions from OpenF1.");

					}

					string text = CleanCountry (country);

					OpenF1Session openF1Session = null;

					foreach (OpenF1Session cachedOpenF1Session in cachedOpenF1Sessions) {

						if (CleanCountry (cachedOpenF1Session.country_name) == text && cachedOpenF1Session.session_name == sessionNameMatch) {

							openF1Session = cachedOpenF1Session;

							break;

						}

					}

					if (openF1Session == null || !openF1Session.session_key.HasValue) {

						foreach (OpenF1Session cachedOpenF1Session2 in cachedOpenF1Sessions) {

							if (cachedOpenF1Session2.session_name == sessionNameMatch && (CleanCountry (cachedOpenF1Session2.circuit_short_name) == text || cachedOpenF1Session2.circuit_short_name.ToLower ().Contains (text))) {

								openF1Session = cachedOpenF1Session2;

								break;

							}

						}

					}

					if (openF1Session == null || !openF1Session.session_key.HasValue) {

						F1Race upcomingRace = GetUpcomingRace ();

						DateTime? sessionScheduledTime = GetSessionScheduledTime (upcomingRace, fpSession);

						if (!sessionScheduledTime.HasValue) {

							throw new Exception ("Session not found for " + upcomingRaceName);

						}

						RenderSessionCountdown (fpSession, sessionScheduledTime.Value, fpSession);

					} else {

						int value = openF1Session.session_key.Value;

						List<OpenF1Lap> result = OpenF1Client.GetLapsAsync (value.ToString ()).GetAwaiter ().GetResult ();

						List<OpenF1Driver> result2 = OpenF1Client.GetDriversAsync (value.ToString ()).GetAwaiter ().GetResult ();

						if (result == null || result.Count == 0) {

