		private void RenderActiveTab ()

		{

			listPanel.Children.Clear ();

			if (countdownTimer != null) {

				countdownTimer.Stop ();

				countdownTimer = null;

			}

			try {

				JavaScriptSerializer javaScriptSerializer = new JavaScriptSerializer ();

				javaScriptSerializer.MaxJsonLength = 10485760;

	
				if (activeTab == "Drivers") {

					RenderDrivers (javaScriptSerializer);

				} else if (activeTab == "Constructors") {

					RenderConstructors (javaScriptSerializer);

				} else if (activeTab == "Podiums") {

					RenderPodiums (javaScriptSerializer);

				} else if (activeTab == "Schedule") {

					RenderSchedule (javaScriptSerializer);

				} else {

					F1TelemetryRenderer.Render (activeTab, listPanel, isLight);

				}

			} catch (Exception ex) {

				try {

					File.WriteAllText ("f1_render_error.txt", ex.ToString ());

				} catch {

				}

				TextBlock element = new TextBlock {

					Text = "Error rendering: " + ex.Message,

					Foreground = System.Windows.Media.Brushes.Red,

					Margin = new Thickness (10.0)

				};

				listPanel.Children.Add (element);

			}

		}



		private Dictionary<string, DriverPodiums> CalculatePodiums (JavaScriptSerializer serializer)

		{

			Dictionary<string, DriverPodiums> dictionary = new Dictionary<string, DriverPodiums> ();

			if (string.IsNullOrEmpty (cachedResultsJson)) {

				return dictionary;

			}

			try {

				F1ResultsResponse f1ResultsResponse = serializer.Deserialize<F1ResultsResponse> (cachedResultsJson);

				if (f1ResultsResponse == null || f1ResultsResponse.MRData == null || f1ResultsResponse.MRData.RaceTable == null || f1ResultsResponse.MRData.RaceTable.Races == null) {

					return dictionary;

				}

				foreach (F1RaceResults race in f1ResultsResponse.MRData.RaceTable.Races) {

					if (race.Results == null) {

						continue;

					}

					foreach (F1Result result in race.Results) {

						if (result.Driver == null) {

							continue;

						}

						string driverId = result.Driver.driverId;

						string position = result.position;

						switch (position) {

						case "1":

						case "2":

						case "3": {

							if (!dictionary.ContainsKey (driverId)) {

								dictionary [driverId] = new DriverPodiums {

									DriverName = result.Driver.givenName + " " + result.Driver.familyName,

									DriverCode = result.Driver.code,

									ConstructorName = ((result.Constructor != null) ? result.Constructor.name : "N/A"),

									Gold = 0,

									Silver = 0,

									Bronze = 0

								};

							}

							DriverPodiums driverPodiums = dictionary [driverId];

							switch (position) {

							case "1":

								driverPodiums.Gold++;

								break;

							case "2":

								driverPodiums.Silver++;

								break;

							case "3":

								driverPodiums.Bronze++;

								break;

							}

							break;

						}

						}

					}

				}

				return dictionary;

			} catch {

				return dictionary;

			}

		}



		private System.Windows.Media.Brush GetConstructorColor (string name)

		{

			if (string.IsNullOrEmpty (name)) {

				return new SolidColorBrush (System.Windows.Media.Color.FromArgb (100, byte.MaxValue, byte.MaxValue, byte.MaxValue));

			}

			string text = name.ToLower ();

			if (text.Contains ("ferrari")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (249, 21, 54));

			}

			if (text.Contains ("mercedes")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 210, 190));

			}

			if (text.Contains ("red bull")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (30, 65, byte.MaxValue));

			}

			if (text.Contains ("mclaren")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (byte.MaxValue, 135, 0));

			}

			if (text.Contains ("aston martin")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 111, 98));

			}

			if (text.Contains ("alpine")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 144, byte.MaxValue));

			}

			if (text.Contains ("williams")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 160, 222));

			}

			if (text.Contains ("haas")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (182, 186, 189));

			}

			if (text.Contains ("rb") || text.Contains ("racing bulls") || text.Contains ("alphatauri") || text.Contains ("toro rosso")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (102, 146, byte.MaxValue));

			}

			if (text.Contains ("audi")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (192, 57, 43));

			}

			if (text.Contains ("cadillac")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (204, 204, 204));

			}

			if (text.Contains ("sauber") || text.Contains ("kick") || text.Contains ("alfa romeo")) {

				return new SolidColorBrush (System.Windows.Media.Color.FromRgb (82, 226, 82));

			}

			return new SolidColorBrush (System.Windows.Media.Color.FromArgb (80, byte.MaxValue, byte.MaxValue, byte.MaxValue));

		}



