		private void RenderDrivers (JavaScriptSerializer serializer)

		{

			if (string.IsNullOrEmpty (cachedDriversJson)) {

				return;

			}

			F1DriverStandingsResponse f1DriverStandingsResponse = serializer.Deserialize<F1DriverStandingsResponse> (cachedDriversJson);

			if (f1DriverStandingsResponse == null || f1DriverStandingsResponse.MRData == null || f1DriverStandingsResponse.MRData.StandingsTable == null || f1DriverStandingsResponse.MRData.StandingsTable.StandingsLists == null || f1DriverStandingsResponse.MRData.StandingsTable.StandingsLists.Count == 0) {

				return;

			}

			List<F1DriverStanding> driverStandings = f1DriverStandingsResponse.MRData.StandingsTable.StandingsLists [0].DriverStandings;

			if (driverStandings == null) {

				return;

			}

			CalculatePodiums (serializer);

			double maxPoints = 1.0;
			if (driverStandings.Count > 0) {
				double.TryParse (driverStandings [0].points, out maxPoints);
			}
			if (maxPoints <= 0.0) {
				maxPoints = 1.0;
			}

			int num = 0;

			foreach (F1DriverStanding item in driverStandings) {

				string text = item.Driver?.givenName ?? "";

				string text2 = item.Driver?.familyName ?? "Unknown";

				string name = ((item.Constructors != null && item.Constructors.Count > 0) ? item.Constructors [0].name : "N/A");

				System.Windows.Media.Color teamColor = ((SolidColorBrush)GetConstructorColor (name)).Color;

				Grid grid = new Grid {

					Margin = new Thickness (40.0, 8.0, 15.0, 8.0),

					Height = 80.0

				};

				LinearGradientBrush gradient = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 0.0)

				};

				gradient.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (byte.MaxValue, (byte)((double)(int)teamColor.R * 0.2), (byte)((double)(int)teamColor.G * 0.2), (byte)((double)(int)teamColor.B * 0.2)), 0.0));

				gradient.GradientStops.Add (new GradientStop (teamColor, 1.0));

				Border cardBorder = new Border {

					Background = gradient,

					CornerRadius = new CornerRadius (8.0),

					ClipToBounds = true

				};

				Grid grid2 = new Grid ();

				string constructorLogoPath = GetConstructorLogoPath (name);

				if (!string.IsNullOrEmpty (constructorLogoPath)) {

					System.Windows.Controls.Image image = new System.Windows.Controls.Image {

						Source = new BitmapImage (new Uri (constructorLogoPath, UriKind.Absolute)),

						Stretch = Stretch.Uniform,

						HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

						VerticalAlignment = VerticalAlignment.Center,

						Height = 160.0,

						Margin = new Thickness (0.0, 0.0, -20.0, 0.0),

						Opacity = 0.15

					};

					RenderOptions.SetBitmapScalingMode (image, BitmapScalingMode.HighQuality);

					grid2.Children.Add (image);

				}

				StackPanel stackPanel = new StackPanel {

					Orientation = System.Windows.Controls.Orientation.Vertical,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					VerticalAlignment = VerticalAlignment.Center,

					Margin = new Thickness (0.0, 0.0, 20.0, 0.0)

				};

				TextBlock element = new TextBlock {

					Text = "P" + item.position,

					FontSize = 14.0,

					FontWeight = FontWeights.Bold,

					Foreground = System.Windows.Media.Brushes.White,

					Opacity = 0.8,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					Margin = new Thickness (0.0, 0.0, 0.0, -5.0)

				};

				stackPanel.Children.Add (element);

				TextBlock element2 = new TextBlock {

					Text = item.points,

					FontSize = 52.0,

					FontWeight = FontWeights.Black,

					FontFamily = new System.Windows.Media.FontFamily ("Bahnschrift, Segoe UI, sans-serif"),

					Foreground = System.Windows.Media.Brushes.White,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					Effect = new DropShadowEffect {

						Color = Colors.Black,

						BlurRadius = 10.0,

						ShadowDepth = 2.0,

						Opacity = 0.5

					}

				};

				stackPanel.Children.Add (element2);

				grid2.Children.Add (stackPanel);

				double points = 0.0;
				double.TryParse (item.points, out points);
				double pct = points / maxPoints;
				if (pct < 0.0) pct = 0.0;
				if (pct > 1.0) pct = 1.0;

				Grid progressGrid = new Grid {
					VerticalAlignment = VerticalAlignment.Bottom,
					Height = 4.0,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
				};
				progressGrid.ColumnDefinitions.Add (new ColumnDefinition {
					Width = new GridLength (pct, GridUnitType.Star)
				});
				progressGrid.ColumnDefinitions.Add (new ColumnDefinition {
					Width = new GridLength (1.0 - pct, GridUnitType.Star)
				});

				Border progressFill = new Border {
					Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (200, teamColor.R, teamColor.G, teamColor.B))
				};
				Grid.SetColumn (progressFill, 0);
