		private void OpenTeamUrl (string teamName)

		{

			if (string.IsNullOrEmpty (teamName)) {

				return;

			}

			string text = teamName.ToLowerInvariant ();

			string text2 = null;

			if (text.Contains ("mercedes")) {

				text2 = "https://www.formula1.com/en/teams/mercedes";

			} else if (text.Contains ("ferrari")) {

				text2 = "https://www.formula1.com/en/teams/ferrari";

			} else if (text.Contains ("mclaren")) {

				text2 = "https://www.formula1.com/en/teams/mclaren";

			} else if (text.Contains ("red bull")) {

				text2 = "https://www.formula1.com/en/teams/red-bull-racing";

			} else if (text.Contains ("alpine")) {

				text2 = "https://www.formula1.com/en/teams/alpine";

			} else if (text.Contains ("racing bulls") || text.Contains ("rb") || text.Contains ("visa cash app")) {

				text2 = "https://www.formula1.com/en/teams/racing-bulls";

			} else if (text.Contains ("haas")) {

				text2 = "https://www.formula1.com/en/teams/haas";

			} else if (text.Contains ("williams")) {

				text2 = "https://www.formula1.com/en/teams/williams";

			} else if (text.Contains ("audi") || text.Contains ("kick sauber") || text.Contains ("sauber")) {

				text2 = "https://www.formula1.com/en/teams/audi";

			} else if (text.Contains ("aston martin")) {

				text2 = "https://www.formula1.com/en/teams/aston-martin";

			} else if (text.Contains ("cadillac")) {

				text2 = "https://www.formula1.com/en/teams/cadillac";

			}

			if (text2 == null) {

				return;

			}

			try {

				Process.Start (new ProcessStartInfo {

					FileName = text2,

					UseShellExecute = true

				});

			} catch {

			}

		}



		private void RenderConstructors (JavaScriptSerializer serializer)

		{

			if (string.IsNullOrEmpty (cachedConstructorsJson)) {

				return;

			}

			F1ConstructorStandingsResponse f1ConstructorStandingsResponse = serializer.Deserialize<F1ConstructorStandingsResponse> (cachedConstructorsJson);

			if (f1ConstructorStandingsResponse == null || f1ConstructorStandingsResponse.MRData == null || f1ConstructorStandingsResponse.MRData.StandingsTable == null || f1ConstructorStandingsResponse.MRData.StandingsTable.StandingsLists == null || f1ConstructorStandingsResponse.MRData.StandingsTable.StandingsLists.Count == 0) {

				return;

			}

			List<F1ConstructorStanding> constructorStandings = f1ConstructorStandingsResponse.MRData.StandingsTable.StandingsLists [0].ConstructorStandings;

			if (constructorStandings == null) {

				return;

			}

			double maxPoints = 1.0;
			if (constructorStandings.Count > 0) {
				double.TryParse (constructorStandings [0].points, out maxPoints);
			}
			if (maxPoints <= 0.0) {
				maxPoints = 1.0;
			}

			int num = 0;

			foreach (F1ConstructorStanding item in constructorStandings) {

				string text = ((item.Constructor != null) ? item.Constructor.name : "Unknown");

				System.Windows.Media.Color color = ((SolidColorBrush)GetConstructorColor (text)).Color;

				Grid grid = new Grid {

					Margin = new Thickness (40.0, 8.0, 15.0, 8.0),

					Height = 80.0

				};

				LinearGradientBrush linearGradientBrush = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 0.0)

				};

				linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (byte.MaxValue, (byte)((double)(int)color.R * 0.2), (byte)((double)(int)color.G * 0.2), (byte)((double)(int)color.B * 0.2)), 0.0));

				linearGradientBrush.GradientStops.Add (new GradientStop (color, 1.0));

				Border border = new Border {

					Background = linearGradientBrush,

					CornerRadius = new CornerRadius (8.0),

					ClipToBounds = true

				};

				Grid grid2 = new Grid ();

				string constructorLogoPath = GetConstructorLogoPath (text);

				if (!string.IsNullOrEmpty (constructorLogoPath)) {

					System.Windows.Controls.Image image = new System.Windows.Controls.Image {

						Source = new BitmapImage (new Uri (constructorLogoPath, UriKind.Absolute)),

						Stretch = Stretch.Uniform,

						HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

						VerticalAlignment = VerticalAlignment.Center,

						Height = 160.0,

						Margin = new Thickness (0.0, 0.0, -20.0, 0.0),

						Opacity = 0.15

					};

					RenderOptions.SetBitmapScalingMode (image, BitmapScalingMode.HighQuality);

					grid2.Children.Add (image);

				}

				StackPanel teamInfoPanel = new StackPanel {
					Orientation = System.Windows.Controls.Orientation.Horizontal,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Left,
					VerticalAlignment = VerticalAlignment.Center,
					Margin = new Thickness (20.0, 0.0, 0.0, 0.0)
				};

				if (!string.IsNullOrEmpty (constructorLogoPath)) {
					System.Windows.Controls.Image logoFront = new System.Windows.Controls.Image {
						Source = new BitmapImage (new Uri (constructorLogoPath, UriKind.Absolute)),
						Stretch = Stretch.Uniform,
						Height = 36.0,
						Width = 36.0,
						VerticalAlignment = VerticalAlignment.Center,
						Margin = new Thickness (0.0, 0.0, 12.0, 0.0)
					};
					RenderOptions.SetBitmapScalingMode (logoFront, BitmapScalingMode.HighQuality);
					teamInfoPanel.Children.Add (logoFront);
				}

				TextBlock teamNameText = new TextBlock {
					Text = text.ToUpper (),
					FontSize = 24.0,
					FontWeight = FontWeights.Black,
					FontFamily = new System.Windows.Media.FontFamily ("Segoe UI, Bahnschrift, sans-serif"),
					Foreground = System.Windows.Media.Brushes.White,
					VerticalAlignment = VerticalAlignment.Center,
					Effect = new DropShadowEffect {
						Color = Colors.Black,
						BlurRadius = 6.0,
						ShadowDepth = 1.0,
						Opacity = 0.5
					}
				};
				teamInfoPanel.Children.Add (teamNameText);
				grid2.Children.Add (teamInfoPanel);

				TextBlock element = new TextBlock {

					Text = item.points,

					FontSize = 52.0,

					FontWeight = FontWeights.Black,

					FontFamily = new System.Windows.Media.FontFamily ("Bahnschrift, Segoe UI, sans-serif"),

					Foreground = System.Windows.Media.Brushes.White,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					VerticalAlignment = VerticalAlignment.Center,

					Margin = new Thickness (0.0, 0.0, 20.0, 0.0),

					Effect = new DropShadowEffect {

						Color = Colors.Black,

						BlurRadius = 10.0,

						ShadowDepth = 2.0,

						Opacity = 0.5

					}

				};

				grid2.Children.Add (element);

				double points = 0.0;
				double.TryParse (item.points, out points);
				double pct = points / maxPoints;
				if (pct < 0.0) pct = 0.0;
				if (pct > 1.0) pct = 1.0;

				Grid progressGrid = new Grid {
					VerticalAlignment = VerticalAlignment.Bottom,
					Height = 4.0,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
				};
