							ShadowDepth = 5.0,

							Opacity = 0.6

						}

					};

					RenderOptions.SetBitmapScalingMode (carImg, BitmapScalingMode.HighQuality);

					grid.Children.Add (carImg);

				}

				grid.MouseEnter += delegate {

					if (carImg != null) {

						ScaleTransform scaleTransform2 = new ScaleTransform (1.0, 1.0);

						carImg.RenderTransform = scaleTransform2;

						carImg.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);

						DoubleAnimation animation2 = new DoubleAnimation (1.0, 1.08, TimeSpan.FromMilliseconds (200.0));

						scaleTransform2.BeginAnimation (ScaleTransform.ScaleXProperty, animation2);

						scaleTransform2.BeginAnimation (ScaleTransform.ScaleYProperty, animation2);

					}

				};

				grid.MouseLeave += delegate {

					if (carImg != null && carImg.RenderTransform is ScaleTransform scaleTransform) {

						DoubleAnimation animation = new DoubleAnimation (scaleTransform.ScaleX, 1.0, TimeSpan.FromMilliseconds (200.0));

						scaleTransform.BeginAnimation (ScaleTransform.ScaleXProperty, animation);

						scaleTransform.BeginAnimation (ScaleTransform.ScaleYProperty, animation);

					}

