				DoubleAnimation doubleAnimation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (300.0));

				TranslateTransform translateTransform = (TranslateTransform)(grid.RenderTransform = new TranslateTransform (0.0, 15.0));

				DoubleAnimation doubleAnimation2 = new DoubleAnimation (15.0, 0.0, TimeSpan.FromMilliseconds (400.0));

				doubleAnimation2.EasingFunction = new CubicEase {

