				doubleAnimation2.BeginTime = TimeSpan.FromMilliseconds (num * 40);

				grid.BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

				translateTransform.BeginAnimation (TranslateTransform.YProperty, doubleAnimation2);

				grid.Cursor = System.Windows.Input.Cursors.Hand;

				string closureTeam = text;

				grid.MouseLeftButtonDown += delegate {

					OpenTeamUrl (closureTeam);

				};

				listPanel.Children.Add (grid);

				num++;

			}

		}



