				int num3 = b.Total.CompareTo (a.Total);

				if (num3 != 0) {

					return num3;

				}

				num3 = b.Gold.CompareTo (a.Gold);

				return (num3 != 0) ? num3 : b.Silver.CompareTo (a.Silver);

