							}

							return "mx";

						}

						return "mc";

					case 'b':

						if (!(text == "brazil")) {

							break;

						}

						return "br";

					case 'f':

						if (!(text == "france")) {

							break;

						}

						return "fr";

					case 'r':

						if (!(text == "russia")) {

							break;

						}

						return "ru";

					case 't':

						if (!(text == "turkey")) {

							break;

						}

						return "tr";

					}

					break;

				case 11:

					switch (text [0]) {

					case 'n':

						if (!(text == "netherlands")) {

							break;

						}

						return "nl";

					case 's':

						if (!(text == "switzerland")) {

							break;

						}

						return "ch";

					}

					break;

				case 7:

					switch (text [2]) {

