						}

						return "at";

					case 'l':

						if (!(text == "belgium")) {

							break;

						}

						return "be";

					case 'n':

						if (!(text == "hungary")) {

							break;

						}

						return "hu";

					case 'h':

						if (!(text == "bahrain")) {

							break;

						}

						return "bh";

					case 'r':

						if (!(text == "germany")) {

							break;

						}

						return "de";

					}

					break;

				case 8:

					switch (text [0]) {

					case 'p':

						if (!(text == "portugal")) {

							break;

						}

						return "pt";

					case 'm':

						if (!(text == "malaysia")) {

							break;

						}

						return "my";

					}

					break;

				case 13:

					if (!(text == "united states")) {

						break;

					}

					goto IL_044d;

				case 2:

					if (!(text == "uk")) {

						break;

					}

					goto IL_0477;

				case 14:

					if (!(text == "united kingdom")) {

						break;

