		private string GetTrackImagePath (string country, string locality, string raceName)

		{

			if (string.IsNullOrEmpty (country)) {

				return null;

			}

			string text = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "Track");

			if (!Directory.Exists (text)) {

				return null;

			}

			string text2 = country.ToLower ();

			if (raceName.ToLower ().Contains ("miami") || locality.ToLower ().Contains ("miami")) {

				text2 = "miami";

			} else if (raceName.ToLower ().Contains ("las vegas") || locality.ToLower ().Contains ("las vegas")) {

				text2 = "las vegas";

			} else if (raceName.ToLower ().Contains ("sao paulo") || locality.ToLower ().Contains ("sao paulo") || country.ToLower ().Contains ("brazil")) {

				text2 = "sao paulo";

			} else if (raceName.ToLower ().Contains ("abu dhabi") || locality.ToLower ().Contains ("abu dhabi") || locality.ToLower ().Contains ("yas marina")) {

				text2 = "abu dhabi";

			} else if (locality.ToLower ().Contains ("barcelona") || locality.ToLower ().Contains ("catalunya")) {

				text2 = "spain";

			} else if (country.ToLower ().Contains ("united kingdom") || country.ToLower ().Contains ("uk") || raceName.ToLower ().Contains ("british") || country.ToLower ().Contains ("great britain")) {

				text2 = "great britain";

			} else if (country.ToLower ().Contains ("netherlands") || country.ToLower ().Contains ("dutch")) {

				text2 = "neatherlands";

			} else if (locality.ToLower ().Contains ("mexico") || raceName.ToLower ().Contains ("mexico")) {

				text2 = "mexico city";

			}

			string text3 = System.IO.Path.Combine (text, text2 + " track.png");

			if (File.Exists (text3)) {

				return text3;

			}

			try {

				string[] files = Directory.GetFiles (text, "*.png");

				foreach (string text4 in files) {

					if (System.IO.Path.GetFileName (text4).ToLower ().Contains (text2)) {

						return text4;

					}

				}

			} catch {

			}

			return null;

		}



		private void RenderSchedule (JavaScriptSerializer serializer)

