		private void AnimateCapsuleState (Border cap, TextBlock txt, bool isActive)
		{
			string effectiveTheme = ownerWindow.GetEffectiveTheme ();
			bool isDark = (effectiveTheme == "dark" || effectiveTheme == "tahoe");

			SolidColorBrush bgBrush = cap.Background as SolidColorBrush;
			if (bgBrush == null || bgBrush.IsFrozen) {
				bgBrush = new SolidColorBrush (isActive ? System.Windows.Media.Color.FromArgb (0, 0, 120, 255) : System.Windows.Media.Brushes.Transparent.Color);
				cap.Background = bgBrush;
			}
			
			SolidColorBrush borderBrush = cap.BorderBrush as SolidColorBrush;
			if (borderBrush == null || borderBrush.IsFrozen) {
				borderBrush = new SolidColorBrush (isActive ? System.Windows.Media.Color.FromArgb (0, 0, 120, 255) : (isDark ? System.Windows.Media.Color.FromArgb (20, 255, 255, 255) : System.Windows.Media.Color.FromArgb (20, 0, 0, 0)));
				cap.BorderBrush = borderBrush;
			}
			
			SolidColorBrush fgBrush = txt.Foreground as SolidColorBrush;
			if (fgBrush == null || fgBrush.IsFrozen) {
				fgBrush = new SolidColorBrush (isActive ? (isDark ? System.Windows.Media.Color.FromRgb (100, 180, 255) : System.Windows.Media.Color.FromRgb (0, 102, 204)) : (isDark ? System.Windows.Media.Color.FromRgb (180, 185, 195) : System.Windows.Media.Color.FromRgb (80, 85, 95)));
				txt.Foreground = fgBrush;
			}

			System.Windows.Media.Color targetBg = isActive ? (isDark ? System.Windows.Media.Color.FromArgb (44, 255, 255, 255) : System.Windows.Media.Color.FromArgb (115, 255, 255, 255)) : System.Windows.Media.Color.FromArgb (0, 255, 255, 255);
			System.Windows.Media.Color targetBorder = isActive ? (isDark ? System.Windows.Media.Color.FromArgb (60, 255, 255, 255) : System.Windows.Media.Color.FromArgb (120, 255, 255, 255)) : (isDark ? System.Windows.Media.Color.FromArgb (18, 255, 255, 255) : System.Windows.Media.Color.FromArgb (24, 0, 0, 0));
			System.Windows.Media.Color targetFg = isActive ? (isDark ? System.Windows.Media.Color.FromRgb (245, 247, 250) : System.Windows.Media.Color.FromRgb (34, 38, 44)) : (isDark ? System.Windows.Media.Color.FromRgb (178, 183, 194) : System.Windows.Media.Color.FromRgb (84, 89, 98));

			System.Windows.Media.Animation.ColorAnimation bgAnim = new System.Windows.Media.Animation.ColorAnimation {
				To = targetBg,
				Duration = new Duration (TimeSpan.FromMilliseconds (200)),
				EasingFunction = new System.Windows.Media.Animation.CubicEase { EasingMode = System.Windows.Media.Animation.EasingMode.EaseOut }
			};
			
			System.Windows.Media.Animation.ColorAnimation borderAnim = new System.Windows.Media.Animation.ColorAnimation {
				To = targetBorder,
				Duration = new Duration (TimeSpan.FromMilliseconds (200)),
				EasingFunction = new System.Windows.Media.Animation.CubicEase { EasingMode = System.Windows.Media.Animation.EasingMode.EaseOut }
			};
			
			System.Windows.Media.Animation.ColorAnimation fgAnim = new System.Windows.Media.Animation.ColorAnimation {
				To = targetFg,
				Duration = new Duration (TimeSpan.FromMilliseconds (200)),
				EasingFunction = new System.Windows.Media.Animation.CubicEase { EasingMode = System.Windows.Media.Animation.EasingMode.EaseOut }
			};

			bgBrush.BeginAnimation (SolidColorBrush.ColorProperty, bgAnim);
			borderBrush.BeginAnimation (SolidColorBrush.ColorProperty, borderAnim);
			fgBrush.BeginAnimation (SolidColorBrush.ColorProperty, fgAnim);
		}

		private void ToggleTahoeFilter (string category, Border clickedCapsule, TextBlock clickedText, List<Border> allCapsules)
		{
			if (_activeFilter == category) {
				_activeFilter = "All";
			} else {
				_activeFilter = category;
			}
			
			for (int j = 0; j < allCapsules.Count; j++) {
				Border cap = allCapsules [j];
				TextBlock t = cap.Child as TextBlock;
				if (t == null) continue;
				
				string capLabel = t.Text;
				bool isActive = (_activeFilter == capLabel);
				
				AnimateCapsuleState (cap, t, isActive);
			}
			
			if (string.IsNullOrEmpty (searchBox.Text)) {
				ShowSuggestions ();
			} else {
				lastQuery = "";
				TriggerSearch (searchBox.Text);
			}
		}

		private void ToggleTahoeFilterByIndex (int index, List<Border> allCapsules)
		{
			if (index >= 0 && index < allCapsules.Count) {
				Border cap = allCapsules [index];
				TextBlock txt = cap.Child as TextBlock;
				if (txt != null) {
					ToggleTahoeFilter (txt.Text, cap, txt, allCapsules);
				}
			}
		}

