			} else if (_currentMatches != null) {
				RenderResults (_currentMatches);
			}
		}

		private void ExecuteItem (SearchResultItem match)
		{
			try {
				if (match.IsWebSuggestion) {
					try {
						Process.Start (new ProcessStartInfo {
							FileName = "chrome.exe",
							Arguments = "\"" + "https://www.google.com/search?q=" + Uri.EscapeDataString (match.Path) + "\"",
							UseShellExecute = true
						});
					} catch {
						Process.Start (new ProcessStartInfo {
							FileName = "https://www.google.com/search?q=" + Uri.EscapeDataString (match.Path),
							UseShellExecute = true
						});
					}
				} else if (match.IsAction) {
					ExecuteQuickAction (match.Path);
				} else if (match.IsClipboard) {
					try {
						System.Windows.Clipboard.SetText (match.Path);
					} catch {}
				} else {
					Process.Start (new ProcessStartInfo (match.Path) {
						UseShellExecute = true
					});
				}
				Hide ();
			} catch (Exception ex) {
				System.Windows.MessageBox.Show ("Could not open item: " + ex.Message, "Search Error", MessageBoxButton.OK, MessageBoxImage.Hand);
			}
		}

		private void ExecuteQuickAction (string path)
		{
			string code = path;
			string param = "";
			int queryIdx = path.IndexOf ('?');
			if (queryIdx >= 0) {
				code = path.Substring (0, queryIdx);
				param = path.Substring (queryIdx + 1);
			}

			if (code == "action://lock") {
				try {
					Process.Start ("rundll32.exe", "user32.dll,LockWorkStation");
				} catch {}
			} else if (code == "action://darkmode") {
				try {
					Process.Start ("explorer.exe", "ms-settings:personalization-colors");
				} catch {}
			} else if (code == "action://shutdown") {
				try {
					if (ConfirmSystemAction ("Shut down this PC now?")) {
						Process.Start ("shutdown.exe", "/s /t 0");
					}
				} catch {}
			} else if (code == "action://restart") {
				try {
					if (ConfirmSystemAction ("Restart this PC now?")) {
						Process.Start ("shutdown.exe", "/r /t 0");
					}
				} catch {}
			} else if (code == "action://sleep") {
				try {
					if (ConfirmSystemAction ("Put this PC to sleep now?")) {
						Process.Start ("rundll32.exe", "powrprof.dll,SetSuspendState 0,1,0");
					}
				} catch {}
			} else if (code == "action://hibernate") {
				try {
					if (ConfirmSystemAction ("Hibernate this PC now?")) {
						Process.Start ("shutdown.exe", "/h");
					}
				} catch {}
			} else if (code == "action://signout") {
				try {
					if (ConfirmSystemAction ("Sign out of Windows now?")) {
						Process.Start ("shutdown.exe", "/l");
					}
				} catch {}
			} else if (code == "action://abortshutdown") {
				try { Process.Start ("shutdown.exe", "/a"); } catch {}
			} else if (code == "action://taskmanager") {
				try { Process.Start (new ProcessStartInfo ("taskmgr.exe") { UseShellExecute = true }); } catch {}
			} else if (code == "action://settings") {
				OpenShellUri ("ms-settings:");
			} else if (code == "action://displaysettings") {
				OpenShellUri ("ms-settings:display");
			} else if (code == "action://soundsettings") {
				OpenShellUri ("ms-settings:sound");
			} else if (code == "action://networksettings") {
				OpenShellUri ("ms-settings:network");
			} else if (code == "action://wifisettings") {
				OpenShellUri ("ms-settings:network-wifi");
			} else if (code == "action://bluetoothsettings") {
				OpenShellUri ("ms-settings:bluetooth");
			} else if (code == "action://appsettings") {
				OpenShellUri ("ms-settings:appsfeatures");
			} else if (code == "action://startupsettings") {
				OpenShellUri ("ms-settings:startupapps");
			} else if (code == "action://updatesettings") {
				OpenShellUri ("ms-settings:windowsupdate");
			} else if (code == "action://storagesettings") {
				OpenShellUri ("ms-settings:storagesense");
			} else if (code == "action://clipboardsettings") {
				OpenShellUri ("ms-settings:clipboard");
			} else if (code == "action://snip") {
				OpenShellUri ("ms-screenclip:");
			} else if (code == "action://calculator") {
				try { Process.Start (new ProcessStartInfo ("calc.exe") { UseShellExecute = true }); } catch {}
			} else if (code == "action://notepad") {
				try { Process.Start (new ProcessStartInfo ("notepad.exe") { UseShellExecute = true }); } catch {}
			} else if (code == "action://terminal") {
				try {
					Process.Start (new ProcessStartInfo ("wt.exe") { UseShellExecute = true });
				} catch {
					try { Process.Start (new ProcessStartInfo ("powershell.exe") { UseShellExecute = true }); } catch {}
				}
			} else if (code == "action://downloads") {
				OpenFolder (System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.UserProfile), "Downloads"));
			} else if (code == "action://documents") {
				OpenFolder (Environment.GetFolderPath (Environment.SpecialFolder.MyDocuments));
			} else if (code == "action://desktop") {
				OpenFolder (Environment.GetFolderPath (Environment.SpecialFolder.Desktop));
			} else if (code == "action://recyclebin") {
				OpenShellUri ("shell:RecycleBinFolder");
			} else if (code == "action://emptyrecyclebin") {
				try {
					if (ConfirmSystemAction ("Empty the Recycle Bin?")) {
						RunHiddenPowerShell ("Clear-RecycleBin -Force");
					}
				} catch {}
			} else if (code == "action://clearclipboard") {
				try { System.Windows.Clipboard.Clear (); } catch {}
			} else if (code == "action://mute") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]173)");
			} else if (code == "action://volumeup") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]175)");
			} else if (code == "action://volumedown") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]174)");
			} else if (code == "action://playpause") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]179)");
			} else if (code == "action://nexttrack") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]176)");
			} else if (code == "action://prevtrack") {
				RunHiddenPowerShell ("$w = New-Object -ComObject Wscript.Shell; $w.SendKeys([char]177)");
			} else if (code == "action://email") {
				string subject = string.IsNullOrWhiteSpace (param) ? "" : "?subject=" + Uri.EscapeDataString (param);
				OpenShellUri ("mailto:" + subject);
			} else if (code == "action://message") {
				try {
					OpenShellUri ("ms-chat:");
				} catch {
					OpenShellUri ("https://teams.microsoft.com/");
				}
			} else if (code == "action://newnote") {
				try {
					string noteFile = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.MyDocuments), "SpotlightNotes.txt");
					if (!File.Exists (noteFile)) {
						File.WriteAllText (noteFile, "");
					}
					Process.Start (new ProcessStartInfo (noteFile) { UseShellExecute = true });
				} catch {}
			} else if (code == "action://reminder") {
				try {
					string reminderFile = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.MyDocuments), "SpotlightReminders.txt");
					string text = string.IsNullOrWhiteSpace (param) ? "New reminder" : param;
					File.AppendAllText (reminderFile, DateTime.Now.ToString ("yyyy-MM-dd HH:mm") + " - " + text + Environment.NewLine);
					Process.Start (new ProcessStartInfo (reminderFile) { UseShellExecute = true });
				} catch {}
			} else if (code == "action://event") {
				try {
					string eventName = string.IsNullOrWhiteSpace (param) ? "New Event" : param;
					string calendarDir = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.MyDocuments), "WinDock Calendar Events");
					Directory.CreateDirectory (calendarDir);
					string icsPath = System.IO.Path.Combine (calendarDir, "event-" + DateTime.Now.ToString ("yyyyMMdd-HHmmss") + ".ics");
					DateTime start = DateTime.Now.AddHours (1);
					DateTime end = start.AddHours (1);
					string ics = "BEGIN:VCALENDAR\r\nVERSION:2.0\r\nPRODID:-//WinDock//Spotlight//EN\r\nBEGIN:VEVENT\r\nUID:" + Guid.NewGuid ().ToString () + "@windock\r\nDTSTAMP:" + DateTime.UtcNow.ToString ("yyyyMMdd'T'HHmmss'Z'") + "\r\nDTSTART:" + start.ToUniversalTime ().ToString ("yyyyMMdd'T'HHmmss'Z'") + "\r\nDTEND:" + end.ToUniversalTime ().ToString ("yyyyMMdd'T'HHmmss'Z'") + "\r\nSUMMARY:" + eventName.Replace ("\r", " ").Replace ("\n", " ") + "\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n";
					File.WriteAllText (icsPath, ics);
					Process.Start (new ProcessStartInfo (icsPath) { UseShellExecute = true });
				} catch {}
			} else if (code == "action://uppercase") {
				TransformClipboardText (s => s.ToUpperInvariant ());
			} else if (code == "action://lowercase") {
				TransformClipboardText (s => s.ToLowerInvariant ());
			} else if (code == "action://titlecase") {
				TransformClipboardText (s => CultureInfo.CurrentCulture.TextInfo.ToTitleCase (s.ToLower ()));
			} else if (code == "action://sentencecase") {
				TransformClipboardText (delegate(string s) {
					if (string.IsNullOrWhiteSpace (s)) return s;
					string lower = s.ToLower ();
					return char.ToUpper (lower [0]) + (lower.Length > 1 ? lower.Substring (1) : "");
				});
			} else if (code == "action://trimclipboard") {
				TransformClipboardText (s => s.Trim ());
			} else if (code == "action://wordcount") {
				try {
					string text = System.Windows.Clipboard.ContainsText () ? System.Windows.Clipboard.GetText () : "";
					int words = string.IsNullOrWhiteSpace (text) ? 0 : Regex.Matches (text, @"\S+").Count;
					System.Windows.MessageBox.Show (words + " words, " + text.Length + " characters", "Clipboard Word Count", MessageBoxButton.OK, MessageBoxImage.Information);
				} catch {}
			} else if (code == "action://google") {
				OpenShellUri ("https://www.google.com/search?q=" + Uri.EscapeDataString (param));
			} else if (code == "action://youtube") {
				OpenShellUri ("https://www.youtube.com/results?search_query=" + Uri.EscapeDataString (param));
			} else if (code == "action://amazon") {
				OpenShellUri ("https://www.amazon.com/s?k=" + Uri.EscapeDataString (param));
			} else if (code == "action://maps") {
				OpenShellUri ("https://www.google.com/maps/search/" + Uri.EscapeDataString (param));
			} else if (code == "action://google") {
				OpenShellUri (string.IsNullOrWhiteSpace (param) ? "https://www.google.com/" : "https://www.google.com/search?q=" + Uri.EscapeDataString (param));
			} else if (code == "action://bing") {
				OpenShellUri (string.IsNullOrWhiteSpace (param) ? "https://www.bing.com/" : "https://www.bing.com/search?q=" + Uri.EscapeDataString (param));
			} else if (code == "action://camera") {
				OpenShellUri ("microsoft.windows.camera:");
			} else if (code == "action://soundrecorder") {
				OpenShellUri ("ms-soundrecorder:");
			} else if (code == "action://magnifier") {
				try { Process.Start (new ProcessStartInfo ("magnify.exe") { UseShellExecute = true }); } catch {}
			} else if (code == "action://print") {
				try {
					if (!string.IsNullOrWhiteSpace (param) && File.Exists (param)) {
						Process.Start (new ProcessStartInfo (param) { Verb = "print", UseShellExecute = true });
					}
				} catch {}
			} else if (code == "action://timer") {
				try {
					int mins = 5;
					if (!string.IsNullOrEmpty (param) && int.TryParse (param, out int parsed)) mins = parsed;
					System.Windows.MessageBox.Show ("Timer started for " + mins + " minutes!", "Spotlight Timer", MessageBoxButton.OK, MessageBoxImage.Information);
				} catch {}
			} else if (code == "action://note") {
				try {
					string noteFile = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.MyDocuments), "SpotlightNotes.txt");
					File.AppendAllText (noteFile, DateTime.Now.ToString ("yyyy-MM-dd HH:mm:ss") + " - " + param + Environment.NewLine);
					System.Windows.MessageBox.Show ("Note saved to " + noteFile, "Spotlight Notes", MessageBoxButton.OK, MessageBoxImage.Information);
				} catch {}
			} else if (code == "action://translate") {
				try {
					Process.Start (new ProcessStartInfo {
						FileName = "chrome.exe",
						Arguments = "\"https://translate.google.com/?sl=auto&tl=en&text=" + Uri.EscapeDataString (param) + "\"",
						UseShellExecute = true
					});
				} catch {
					Process.Start (new ProcessStartInfo {
						FileName = "https://translate.google.com/?sl=auto&tl=en&text=" + Uri.EscapeDataString (param),
						UseShellExecute = true
					});
				}
			} else if (code == "action://removebg") {
				try {
					Process.Start (new ProcessStartInfo ("https://www.remove.bg/") { UseShellExecute = true });
				} catch {}
			} else if (code == "action://music") {
				try {
					Process.Start (new ProcessStartInfo ("https://www.aha-music.com/") { UseShellExecute = true });
				} catch {}
			} else if (code.StartsWith ("action://copypaste_")) {
				try {
					string val = code.Substring ("action://copypaste_".Length);
					System.Windows.Clipboard.SetText (val);
				} catch {}
			}
		}

		private bool ConfirmSystemAction (string message)
		{
			return System.Windows.MessageBox.Show (message, "WinDock Spotlight Action", MessageBoxButton.YesNo, MessageBoxImage.Warning) == MessageBoxResult.Yes;
		}

		private void OpenShellUri (string uri)
		{
			try {
				Process.Start (new ProcessStartInfo (uri) { UseShellExecute = true });
			} catch {}
		}

		private void OpenFolder (string path)
		{
			try {
				if (!string.IsNullOrEmpty (path) && Directory.Exists (path)) {
					Process.Start (new ProcessStartInfo (path) { UseShellExecute = true });
				}
			} catch {}
		}

		private void RunHiddenPowerShell (string command)
		{
			try {
				Process.Start (new ProcessStartInfo ("powershell.exe", "-NoProfile -NonInteractive -WindowStyle Hidden -Command \"" + command.Replace ("\"", "\\\"") + "\"") {
					CreateNoWindow = true,
					UseShellExecute = false
				});
			} catch {}
		}

		private void TransformClipboardText (Func<string, string> transform)
		{
			try {
				if (System.Windows.Clipboard.ContainsText ()) {
					string text = System.Windows.Clipboard.GetText ();
					System.Windows.Clipboard.SetText (transform (text));
				}
			} catch {}
		}

		private List<SearchResultItem> GetQuickActions (string query)
		{
			List<SearchResultItem> list = new List<SearchResultItem> ();
			
			var actions = new[] {
				("lk", "Lock Screen", "action://lock", "Lock this computer instantly"),
				("dm", "Toggle Dark Mode", "action://darkmode", "Switch system visual theme between dark/light"),
				("sd", "Shutdown Computer", "action://shutdown", "Perform system shutdown"),
				("rt", "Restart Computer", "action://restart", "Perform system reboot"),
				("sl", "Sleep Computer", "action://sleep", "Put this computer to sleep"),
				("hb", "Hibernate Computer", "action://hibernate", "Hibernate this computer"),
				("so", "Sign Out", "action://signout", "Sign out of Windows"),
				("as", "Abort Shutdown", "action://abortshutdown", "Cancel a pending shutdown or restart"),
				("tk", "Task Manager", "action://taskmanager", "Open Task Manager"),
				("st", "Open Settings", "action://settings", "Open Windows Settings"),
				("ds", "Display Settings", "action://displaysettings", "Open display settings"),
				("ss", "Sound Settings", "action://soundsettings", "Open sound settings"),
				("ns", "Network Settings", "action://networksettings", "Open network settings"),
				("wf", "Wi-Fi Settings", "action://wifisettings", "Open Wi-Fi settings"),
				("bt", "Bluetooth Settings", "action://bluetoothsettings", "Open Bluetooth settings"),
				("ap", "Installed Apps", "action://appsettings", "Open installed apps settings"),
				("su", "Startup Apps", "action://startupsettings", "Open startup apps settings"),
				("wu", "Windows Update", "action://updatesettings", "Open Windows Update"),
				("sg", "Storage Settings", "action://storagesettings", "Open storage settings"),
				("cs", "Clipboard Settings", "action://clipboardsettings", "Open clipboard settings"),
				("sn", "Take Screenshot", "action://snip", "Open screen snipping"),
				("ca", "Calculator", "action://calculator", "Open Calculator"),
				("np", "Notepad", "action://notepad", "Open Notepad"),
				("wt", "Terminal", "action://terminal", "Open Windows Terminal"),
				("dl", "Downloads Folder", "action://downloads", "Open Downloads"),
				("dc", "Documents Folder", "action://documents", "Open Documents"),
				("dt", "Desktop Folder", "action://desktop", "Open Desktop"),
				("rbn", "Recycle Bin", "action://recyclebin", "Open Recycle Bin"),
				("er", "Empty Recycle Bin", "action://emptyrecyclebin", "Empty Recycle Bin"),
				("cc", "Clear Clipboard", "action://clearclipboard", "Clear current clipboard content"),
				("mu", "Mute Volume", "action://mute", "Toggle mute"),
				("vu", "Volume Up", "action://volumeup", "Increase volume"),
				("vd", "Volume Down", "action://volumedown", "Decrease volume"),
				("pp", "Play Pause", "action://playpause", "Toggle media playback"),
				("nx", "Next Track", "action://nexttrack", "Skip to next media track"),
				("pv", "Previous Track", "action://prevtrack", "Go to previous media track"),
				("em", "Send Email", "action://email", "Compose a new email"),
				("msg", "Send Message", "action://message", "Open Messages or Teams chat"),
				("nn", "Create Note", "action://newnote", "Create or open a note"),
				("rmn", "Create Reminder", "action://reminder", "Add a reminder (e.g. rmn call mom)"),
				("ev", "Create Calendar Event", "action://event", "Create a calendar event file"),
				("uc", "Uppercase Clipboard", "action://uppercase", "Change copied text to uppercase"),
				("lc", "Lowercase Clipboard", "action://lowercase", "Change copied text to lowercase"),
				("tc", "Title Case Clipboard", "action://titlecase", "Change copied text to title case"),
				("sc", "Sentence Case Clipboard", "action://sentencecase", "Change copied text to sentence case"),
				("trim", "Trim Clipboard Text", "action://trimclipboard", "Trim copied text whitespace"),
				("wc", "Word Count Clipboard", "action://wordcount", "Count words in copied text"),
				("gg", "Search Google", "action://google", "Search Google (e.g. gg windock)"),
				("yt", "Search YouTube", "action://youtube", "Search YouTube"),
				("az", "Search Amazon", "action://amazon", "Search Amazon"),
				("map", "Search Maps", "action://maps", "Search maps or directions"),
				("wb", "Search Web", "action://google", "Search the web on Google"),
				("ms", "Microsoft Search", "action://bing", "Search Microsoft Bing"),
				("cam", "Open Camera", "action://camera", "Open Camera"),
				("rec", "Record Audio", "action://soundrecorder", "Open Sound Recorder"),
				("mag", "Magnifier", "action://magnifier", "Open Magnifier"),
				("pr", "Print File", "action://print", "Print a file by path"),
				("tm", "Start Timer", "action://timer", "Start a countdown timer (e.g. tm 5)"),
				("nt", "Add to Notes", "action://note", "Append text to notes file (e.g. nt buy milk)"),
				("tr", "Translate Text", "action://translate", "Translate phrase (e.g. tr hello)"),
				("rb", "Remove Background", "action://removebg", "Open background removal utility"),
				("rm", "Recognize Music", "action://music", "Recognize currently playing background music")
			};

			string queryLower = query.ToLower ();
			foreach (var item in actions) {
				string actionName = item.Item2.ToLower ();
				string actionDescription = item.Item4.ToLower ();
				string normalizedQuery = queryLower.Replace ("-", "").Replace (" ", "");
				string normalizedName = actionName.Replace ("-", "").Replace (" ", "");
				string normalizedDescription = actionDescription.Replace ("-", "").Replace (" ", "");
				bool matchesQuickKey = queryLower == item.Item1;
				bool matchesName = queryLower.Length >= 2 && (actionName.Contains (queryLower) || actionDescription.Contains (queryLower) || normalizedName.Contains (normalizedQuery) || normalizedDescription.Contains (normalizedQuery));
				bool matchesCommandPrefix = queryLower.StartsWith (item.Item1 + " ") || queryLower.StartsWith (actionName + " ");
				
				if (matchesQuickKey || matchesName || matchesCommandPrefix) {
					string param = "";
					if (queryLower.StartsWith (item.Item1 + " ")) {
						param = query.Substring (item.Item1.Length + 1).Trim ();
					} else if (queryLower.StartsWith (actionName + " ")) {
						param = query.Substring (item.Item2.Length + 1).Trim ();
					}

					string name = item.Item2;
					if (!string.IsNullOrEmpty (param)) {
						name = item.Item2 + ": \"" + param + "\"";
					}

					list.Add (new SearchResultItem {
						Name = name,
						Path = item.Item3 + (string.IsNullOrEmpty (param) ? "" : "?" + param),
						IsAction = true
					});
				}
			}
			return list;
		}

		private void UpdateSelectionVisuals ()
		{
			string effectiveTheme = ownerWindow.GetEffectiveTheme ();
			bool isDark = (effectiveTheme == "dark" || effectiveTheme == "tahoe");

			for (int i = 0; i < _rowElements.Count; i++) {
				Border row = _rowElements [i];
				SearchResultItem item = _displayedItems [i];
				
				Grid g = row.Child as Grid;
				if (g == null) continue;
				StackPanel sp = null;
				foreach (var child in g.Children) {
					if (child is StackPanel s) sp = s;
				}
				if (sp == null || sp.Children.Count < 2) continue;
				
				TextBlock titleText = sp.Children [0] as TextBlock;
				TextBlock subText = sp.Children [1] as TextBlock;
				
				if (i == _selectedIndex) {
					row.Background = new SolidColorBrush (isDark ? System.Windows.Media.Color.FromArgb (54, 255, 255, 255) : System.Windows.Media.Color.FromArgb (130, 255, 255, 255));
					row.BorderBrush = new SolidColorBrush (isDark ? System.Windows.Media.Color.FromArgb (58, 255, 255, 255) : System.Windows.Media.Color.FromArgb (145, 255, 255, 255));
					if (titleText != null) titleText.Foreground = isDark ? System.Windows.Media.Brushes.White : new SolidColorBrush (System.Windows.Media.Color.FromRgb (24, 27, 32));
					
					bool isCtrlDown = Keyboard.IsKeyDown (Key.LeftCtrl) || Keyboard.IsKeyDown (Key.RightCtrl);
					if (subText != null) {
						subText.Foreground = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (190, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromRgb (78, 83, 92));
						if (isCtrlDown && !item.IsWebSuggestion && !item.IsAction && !item.IsClipboard) {
							subText.Text = item.Path;
						} else {
							subText.Text = item.IsWebSuggestion ? "Search Google" : item.Path;
						}
					}
					row.BringIntoView ();
				} else {
					row.Background = System.Windows.Media.Brushes.Transparent;
					row.BorderBrush = System.Windows.Media.Brushes.Transparent;
					if (titleText != null) titleText.Foreground = isDark ? System.Windows.Media.Brushes.White : new SolidColorBrush (System.Windows.Media.Color.FromRgb (40, 40, 40));
					if (subText != null) {
						subText.Foreground = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (170, 175, 185)) : new SolidColorBrush (System.Windows.Media.Color.FromRgb (120, 125, 135));
						subText.Text = item.IsWebSuggestion ? "Search Google" : item.Path;
					}
				}
			}

			UpdatePreviewPane ();
		}

		private static string GetDriverHeadshotPath (string driverName)
		{
			if (string.IsNullOrEmpty (driverName)) return "";
			string titleCase = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase (driverName.ToLower ().Trim ());

			string path = F1OverlayWindow.ResolveAssetPath ("Drivers", titleCase + ".png");
			if (File.Exists (path)) return path;

			path = F1OverlayWindow.ResolveAssetPath ("Headshots", titleCase + ".png");
			if (File.Exists (path)) return path;

			path = F1OverlayWindow.ResolveAssetPath ("Drivers", driverName.Trim () + ".png");
			if (File.Exists (path)) return path;

			path = F1OverlayWindow.ResolveAssetPath ("Headshots", driverName.Trim () + ".png");
			if (File.Exists (path)) return path;

			try {
				string dir = F1OverlayWindow.ResolveAssetPath ("Drivers", "Max Verstappen.png");
				if (!string.IsNullOrEmpty (dir)) {
					string folder = System.IO.Path.GetDirectoryName (dir);
					if (Directory.Exists (folder)) {
						string query = driverName.ToLower ().Trim ();
						string[] parts = query.Split (' ');
						string lastName = parts.Length > 0 ? parts [parts.Length - 1] : query;
						string[] files = Directory.GetFiles (folder, "*.png");
						foreach (string f in files) {
							string fname = System.IO.Path.GetFileNameWithoutExtension (f).ToLower ();
							if (fname.Contains (lastName) || lastName.Contains (fname)) {
								return f;
							}
						}
					}
				}
			} catch {}

			return "";
		}

