		private static string GetDriverNumberPath (string driverName)
		{
			if (string.IsNullOrEmpty (driverName)) return "";
			string titleCase = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase (driverName.ToLower ().Trim ());

			string path = F1OverlayWindow.ResolveAssetPath ("Driver Number", titleCase + " Number.png");
			if (File.Exists (path)) return path;

			path = F1OverlayWindow.ResolveAssetPath ("Driver Number", driverName.Trim () + " Number.png");
			if (File.Exists (path)) return path;

			try {
				string sample = F1OverlayWindow.ResolveAssetPath ("Driver Number", "Max Verstappen Number.png");
				if (!string.IsNullOrEmpty (sample)) {
					string folder = System.IO.Path.GetDirectoryName (sample);
					if (Directory.Exists (folder)) {
						string query = driverName.ToLower ().Trim ();
						string[] parts = query.Split (' ');
						string lastName = parts.Length > 0 ? parts [parts.Length - 1] : query;
						string[] files = Directory.GetFiles (folder, "*.png");
						foreach (string f in files) {
							string fname = System.IO.Path.GetFileNameWithoutExtension (f).ToLower ();
							if (fname.Contains (lastName) || lastName.Contains (fname)) {
								return f;
							}
						}
					}
				}
			} catch {}

			return "";
		}

		private void FetchOnlineImageForWebCard (string query, System.Windows.Controls.Image imageControl, Border imageContainer)
		{
			if (string.IsNullOrEmpty (query) || imageControl == null || imageContainer == null) return;
			System.Threading.ThreadPool.QueueUserWorkItem (delegate {
				try {
					string cleanQuery = query.Replace ("Search for", "").Replace ("Google", "").Replace ("Search", "").Trim ();
					if (cleanQuery.Length == 0) return;

					string apiUrl = "https://en.wikipedia.org/api/rest_v1/page/summary/" + Uri.EscapeDataString (cleanQuery);
					using (System.Net.WebClient client = new System.Net.WebClient ()) {
						client.Headers.Add ("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)");
						string json = client.DownloadString (apiUrl);
						if (!string.IsNullOrEmpty (json) && json.Contains ("\"source\":\"")) {
							int idx = json.IndexOf ("\"source\":\"");
							if (idx > 0) {
								int start = idx + "\"source\":\"".Length;
								int end = json.IndexOf ("\"", start);
								if (end > start) {
									string imgUrl = json.Substring (start, end - start).Replace ("\\/", "/");
									if (!string.IsNullOrEmpty (imgUrl) && (imgUrl.EndsWith (".jpg") || imgUrl.EndsWith (".png") || imgUrl.EndsWith (".jpeg") || imgUrl.Contains ("upload.wikimedia.org"))) {
										Dispatcher.Invoke (() => {
											try {
												BitmapImage bmp = new BitmapImage ();
												bmp.BeginInit ();
												bmp.UriSource = new Uri (imgUrl, UriKind.Absolute);
												bmp.CacheOption = BitmapCacheOption.OnLoad;
												bmp.EndInit ();

												imageControl.Source = bmp;
												imageContainer.Visibility = Visibility.Visible;
											} catch {}
										});
									}
								}
							}
						}
					}
				} catch {}
			});
		}

