				CornerRadius = new CornerRadius (8.0),
				Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255)),
				Cursor = System.Windows.Input.Cursors.Hand,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				Margin = new Thickness (0, 5, 0, 5)
			};
			btn.Child = new TextBlock {
				Text = "Search Web on Google",
				Foreground = System.Windows.Media.Brushes.White,
				FontSize = 12.0,
				FontWeight = FontWeights.Bold,
				FontFamily = new System.Windows.Media.FontFamily ("SF Pro Display, Segoe UI, sans-serif"),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				VerticalAlignment = VerticalAlignment.Center
			};
			btn.MouseEnter += (s, e) => {
				btn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (20, 140, 255));
			};
			btn.MouseLeave += (s, e) => {
				btn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255));
			};
			btn.PreviewMouseLeftButtonDown += delegate {
				ExecuteItem (item);
			};
			previewPanel.Children.Add (btn);
		}

		private void UpdatePreviewPane ()
		{
			if (previewPanel == null) return;
			previewPanel.Children.Clear ();

			if (_selectedIndex < 0 || _selectedIndex >= _displayedItems.Count) {
				return;
			}

			SearchResultItem item = _displayedItems [_selectedIndex];
			string effectiveTheme = ownerWindow.GetEffectiveTheme ();
			bool isDark = (effectiveTheme == "dark" || effectiveTheme == "tahoe");
			System.Windows.Media.Brush textBrush = isDark ? System.Windows.Media.Brushes.White : new SolidColorBrush (System.Windows.Media.Color.FromRgb (40, 40, 40));
			System.Windows.Media.Brush subTextBrush = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (170, 175, 185)) : new SolidColorBrush (System.Windows.Media.Color.FromRgb (120, 125, 135));

			string queryText = searchBox != null ? searchBox.Text.Trim ().ToLower () : "";
			string itemPathLower = item.Path != null ? item.Path.ToLower () : "";
			string itemNameLower = item.Name != null ? item.Name.ToLower () : "";

			bool isF1Action = item.IsAction && item.Path.StartsWith ("action://f1_query?");
			string targetSearch = isF1Action ? item.Path.Substring ("action://f1_query?".Length).Trim ().ToLower () : (queryText.Length > 0 ? queryText : itemNameLower);

			string matchedDriver = null;
			string matchedTeam = null;
			string matchedTeamLogo = null;

			if (isF1Action || targetSearch.Contains ("f1") || targetSearch.Contains ("formula 1") || targetSearch.Contains ("formula1") || targetSearch.Contains ("grand prix")) {
				if (targetSearch.Contains ("verstappen")) { matchedDriver = "Max Verstappen"; matchedTeam = "Red Bull Racing"; matchedTeamLogo = "Redbull F1 Team Logo.png"; }
				else if (targetSearch.Contains ("hamilton")) { matchedDriver = "Lewis Hamilton"; matchedTeam = "Scuderia Ferrari"; matchedTeamLogo = "Ferrari F1 Team Logo.png"; }
				else if (targetSearch.Contains ("leclerc")) { matchedDriver = "Charles Leclerc"; matchedTeam = "Scuderia Ferrari"; matchedTeamLogo = "Ferrari F1 Team Logo.png"; }
				else if (targetSearch.Contains ("norris")) { matchedDriver = "Lando Norris"; matchedTeam = "McLaren F1 Team"; matchedTeamLogo = "McLaren F1 Team Logo.png"; }
				else if (targetSearch.Contains ("sainz")) { matchedDriver = "Carlos Sainz"; matchedTeam = "Williams Racing"; matchedTeamLogo = "Williams F1 Team Logo.png"; }
				else if (targetSearch.Contains ("piastri")) { matchedDriver = "Oscar Piastri"; matchedTeam = "McLaren F1 Team"; matchedTeamLogo = "McLaren F1 Team Logo.png"; }
				else if (targetSearch.Contains ("russell")) { matchedDriver = "George Russell"; matchedTeam = "Mercedes-AMG PETRONAS"; matchedTeamLogo = "Mercedes AMG Petronas F1 Team logo.png"; }
				else if (targetSearch.Contains ("antonelli")) { matchedDriver = "Kimi Antonelli"; matchedTeam = "Mercedes-AMG PETRONAS"; matchedTeamLogo = "Mercedes AMG Petronas F1 Team logo.png"; }
				else if (targetSearch.Contains ("alonso")) { matchedDriver = "Fernando Alonso"; matchedTeam = "Aston Martin Aramco"; matchedTeamLogo = "Aston Martin F1 Team logo-Photoroom.png"; }
				else if (targetSearch.Contains ("albon")) { matchedDriver = "Alexander Albon"; matchedTeam = "Williams Racing"; matchedTeamLogo = "Williams F1 Team Logo.png"; }
				else if (targetSearch.Contains ("gasly")) { matchedDriver = "Pierre Gasly"; matchedTeam = "Alpine F1 Team"; matchedTeamLogo = "Alpine F1 Team Logo.png"; }
				else if (targetSearch.Contains ("ocon")) { matchedDriver = "Esteban Ocon"; matchedTeam = "Haas F1 Team"; matchedTeamLogo = "TGR Haas F1 Team Logo.png"; }
				else if (targetSearch.Contains ("tsunoda")) { matchedDriver = "Yuki Tsunoda"; matchedTeam = "Visa Cash App RB"; matchedTeamLogo = "Visa RB F1 Team Logo.png"; }
				else if (targetSearch.Contains ("stroll")) { matchedDriver = "Lance Stroll"; matchedTeam = "Aston Martin Aramco"; matchedTeamLogo = "Aston Martin F1 Team logo-Photoroom.png"; }
				else if (targetSearch.Contains ("hulkenberg")) { matchedDriver = "Nico Hulkenberg"; matchedTeam = "Kick Sauber / Audi"; matchedTeamLogo = "Audi F1 Team Logopng.png"; }
			} else {
				if (targetSearch.Contains ("verstappen")) { matchedDriver = "Max Verstappen"; matchedTeam = "Red Bull Racing"; matchedTeamLogo = "Redbull F1 Team Logo.png"; }
				else if (targetSearch.Contains ("hamilton")) { matchedDriver = "Lewis Hamilton"; matchedTeam = "Scuderia Ferrari"; matchedTeamLogo = "Ferrari F1 Team Logo.png"; }
				else if (targetSearch.Contains ("leclerc")) { matchedDriver = "Charles Leclerc"; matchedTeam = "Scuderia Ferrari"; matchedTeamLogo = "Ferrari F1 Team Logo.png"; }
				else if (targetSearch.Contains ("norris")) { matchedDriver = "Lando Norris"; matchedTeam = "McLaren F1 Team"; matchedTeamLogo = "McLaren F1 Team Logo.png"; }
				else if (targetSearch.Contains ("sainz")) { matchedDriver = "Carlos Sainz"; matchedTeam = "Williams Racing"; matchedTeamLogo = "Williams F1 Team Logo.png"; }
				else if (targetSearch.Contains ("piastri")) { matchedDriver = "Oscar Piastri"; matchedTeam = "McLaren F1 Team"; matchedTeamLogo = "McLaren F1 Team Logo.png"; }
				else if (targetSearch.Contains ("russell")) { matchedDriver = "George Russell"; matchedTeam = "Mercedes-AMG PETRONAS"; matchedTeamLogo = "Mercedes AMG Petronas F1 Team logo.png"; }
				else if (targetSearch.Contains ("antonelli")) { matchedDriver = "Kimi Antonelli"; matchedTeam = "Mercedes-AMG PETRONAS"; matchedTeamLogo = "Mercedes AMG Petronas F1 Team logo.png"; }
				else if (targetSearch.Contains ("alonso")) { matchedDriver = "Fernando Alonso"; matchedTeam = "Aston Martin Aramco"; matchedTeamLogo = "Aston Martin F1 Team logo-Photoroom.png"; }
				else if (targetSearch.Contains ("albon")) { matchedDriver = "Alexander Albon"; matchedTeam = "Williams Racing"; matchedTeamLogo = "Williams F1 Team Logo.png"; }
				else if (targetSearch.Contains ("gasly")) { matchedDriver = "Pierre Gasly"; matchedTeam = "Alpine F1 Team"; matchedTeamLogo = "Alpine F1 Team Logo.png"; }
				else if (targetSearch.Contains ("ocon")) { matchedDriver = "Esteban Ocon"; matchedTeam = "Haas F1 Team"; matchedTeamLogo = "TGR Haas F1 Team Logo.png"; }
				else if (targetSearch.Contains ("tsunoda")) { matchedDriver = "Yuki Tsunoda"; matchedTeam = "Visa Cash App RB"; matchedTeamLogo = "Visa RB F1 Team Logo.png"; }
				else if (targetSearch.Contains ("stroll")) { matchedDriver = "Lance Stroll"; matchedTeam = "Aston Martin Aramco"; matchedTeamLogo = "Aston Martin F1 Team logo-Photoroom.png"; }
				else if (targetSearch.Contains ("hulkenberg")) { matchedDriver = "Nico Hulkenberg"; matchedTeam = "Kick Sauber / Audi"; matchedTeamLogo = "Audi F1 Team Logopng.png"; }
			}

			if (isF1Action || matchedDriver != null) {
				RenderF1DriverCard (matchedDriver ?? "Lewis Hamilton", matchedTeam ?? "Scuderia Ferrari", matchedTeamLogo ?? "Ferrari F1 Team Logo.png", textBrush, subTextBrush);
				return;
			}

			if (item.IsWebSuggestion || (item.IsAction && (item.Path.StartsWith ("action://google") || item.Path.StartsWith ("action://bing")))) {
				RenderWebCard (item, textBrush, subTextBrush);
				return;
			}

			Border iconBorder = new Border {
				Width = 80.0,
				Height = 80.0,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				Margin = new Thickness (0, 10, 0, 15)
			};

			System.Windows.Media.ImageSource iconSource = null;
			if (!item.IsWebSuggestion && !item.IsAction && !item.IsClipboard) {
				try {
					if (IconExtractor.GetCachedSearchIcon (item.Path, out var cached)) {
						iconSource = cached;
					} else {
						if (item.IsDirectory) {
							iconSource = IconExtractor.GetJumboIcon (item.Path);
						} else {
							iconSource = IconExtractor.ExtractHighQualityIconForSearch (item);
						}
					}
				} catch {}
			}

			if (iconSource != null) {
				double previewIconSize = 76.0;
				BitmapSource bitmapIcon = iconSource as BitmapSource;
				if (bitmapIcon != null && bitmapIcon.PixelWidth > 0 && bitmapIcon.PixelWidth < 76) {
					previewIconSize = Math.Max (32.0, Math.Min (64.0, bitmapIcon.PixelWidth));
				}
				System.Windows.Controls.Image imgCtrl = new System.Windows.Controls.Image {
					Source = iconSource,
					Width = previewIconSize,
					Height = previewIconSize,
					Stretch = System.Windows.Media.Stretch.Uniform,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					VerticalAlignment = VerticalAlignment.Center,
					SnapsToDevicePixels = true,
					UseLayoutRounding = true
				};
				RenderOptions.SetBitmapScalingMode (imgCtrl, bitmapIcon != null && bitmapIcon.PixelWidth < 76 ? BitmapScalingMode.NearestNeighbor : BitmapScalingMode.HighQuality);
				RenderOptions.SetEdgeMode (imgCtrl, EdgeMode.Unspecified);
				iconBorder.Child = imgCtrl;
			} else {
				string glyphText = "\uE71D";
				if (item.IsDirectory) {
					glyphText = "\uE8B7";
				} else if (item.IsApp) {
					glyphText = "\uE71A";
				} else if (item.IsAction) {
					glyphText = "\uF158";
				} else if (item.IsClipboard) {
					glyphText = "\uE8C8";
				} else if (item.IsWebSuggestion) {
					glyphText = "\uE12A";
				}

				iconBorder.Child = new TextBlock {
					Text = glyphText,
					FontFamily = new System.Windows.Media.FontFamily ("Segoe MDL2 Assets"),
					FontSize = 48.0,
					Foreground = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (160, 165, 175)) : new SolidColorBrush (System.Windows.Media.Color.FromRgb (110, 115, 125)),
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					VerticalAlignment = VerticalAlignment.Center
				};
			}

			previewPanel.Children.Add (iconBorder);

			string displayName = item.Name;
			if (item.IsAction && displayName.StartsWith ("Conversion: ")) {
				displayName = displayName.Substring ("Conversion: ".Length);
			}

			TextBlock titleBlock = new TextBlock {
				Text = displayName,
				Foreground = textBrush,
				FontSize = 18.0,
				FontWeight = FontWeights.Bold,
				FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
				TextWrapping = TextWrapping.Wrap,
				TextTrimming = TextTrimming.CharacterEllipsis,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				TextAlignment = TextAlignment.Center,
				Margin = new Thickness (0, 0, 0, 4)
			};
			previewPanel.Children.Add (titleBlock);

			string itemType = "Document";
			if (item.IsApp) {
				itemType = "Application";
			} else if (item.IsDirectory) {
				itemType = "Folder";
			} else if (item.IsAction) {
				itemType = "Smart Calculation / Conversion";
			} else if (item.IsClipboard) {
				itemType = "Clipboard History Item";
			} else if (item.IsWebSuggestion) {
				itemType = "Safari Web Search Suggestions";
			}

			TextBlock typeBlock = new TextBlock {
				Text = itemType,
				Foreground = subTextBrush,
				FontSize = 11.5,
				FontWeight = FontWeights.SemiBold,
				FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				Margin = new Thickness (0, 0, 0, 10)
			};
			previewPanel.Children.Add (typeBlock);

			if (item.IsClipboard) {
				Border clipPreviewBorder = new Border {
					Height = 120.0,
					Background = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (15, 0, 0, 0)),
					CornerRadius = new CornerRadius (8.0),
					BorderThickness = new Thickness (1.0),
					BorderBrush = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)),
					Padding = new Thickness (10.0),
					Margin = new Thickness (0, 5, 0, 15),
					HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
				};
				clipPreviewBorder.Child = new TextBlock {
					Text = item.Path,
					Foreground = textBrush,
					FontSize = 12.0,
					FontFamily = new System.Windows.Media.FontFamily ("Consolas, Courier New, monospace"),
					TextWrapping = TextWrapping.Wrap,
					TextTrimming = TextTrimming.CharacterEllipsis,
					VerticalAlignment = VerticalAlignment.Top,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Left
				};
				previewPanel.Children.Add (clipPreviewBorder);
			} else if (!item.IsWebSuggestion && !item.IsAction && File.Exists (item.Path) && !item.IsDirectory) {
				try {
					System.IO.FileInfo fi = new System.IO.FileInfo (item.Path);
					double sizeKB = fi.Length / 1024.0;
					string sizeStr = sizeKB > 1024.0 ? string.Format ("{0:0.##} MB", sizeKB / 1024.0) : string.Format ("{0:0.##} KB", sizeKB);

					TextBlock sizeBlock = new TextBlock {
						Text = "Size: " + sizeStr,
						Foreground = subTextBrush,
						FontSize = 12.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 0, 0, 2)
					};
					previewPanel.Children.Add (sizeBlock);

					TextBlock dateBlock = new TextBlock {
						Text = "Modified: " + fi.LastWriteTime.ToString ("g"),
						Foreground = subTextBrush,
						FontSize = 12.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 0, 0, 15)
					};
					previewPanel.Children.Add (dateBlock);

					string ext = System.IO.Path.GetExtension (item.Path).ToLower ();
					if (ext == ".txt" || ext == ".log" || ext == ".json" || ext == ".ini" || ext == ".xml" || ext == ".bat" || ext == ".ps1" || ext == ".html" || ext == ".css" || ext == ".cs") {
						if (fi.Length < 100 * 1024) {
							string[] lines = File.ReadAllLines (item.Path).Take (5).ToArray ();
							if (lines.Length > 0) {
								Border textPreviewBorder = new Border {
									Height = 80.0,
									Background = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (15, 0, 0, 0)),
									CornerRadius = new CornerRadius (8.0),
									BorderThickness = new Thickness (1.0),
									BorderBrush = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)),
									Padding = new Thickness (8.0),
									Margin = new Thickness (0, 0, 0, 10),
									HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
								};
								textPreviewBorder.Child = new TextBlock {
									Text = string.Join ("\n", lines),
									Foreground = textBrush,
									FontSize = 10.5,
									FontFamily = new System.Windows.Media.FontFamily ("Consolas, Courier New, monospace"),
									TextWrapping = TextWrapping.Wrap,
									TextTrimming = TextTrimming.CharacterEllipsis
								};
								previewPanel.Children.Add (textPreviewBorder);
							}
						}
					}
				} catch {}
			} else if (item.IsDirectory && Directory.Exists (item.Path)) {
				try {
					System.IO.DirectoryInfo di = new System.IO.DirectoryInfo (item.Path);
					int subDirs = di.GetDirectories ().Length;
					int subFiles = di.GetFiles ().Length;

					TextBlock countBlock = new TextBlock {
						Text = string.Format ("Contains: {0} folders, {1} files", subDirs, subFiles),
						Foreground = subTextBrush,
						FontSize = 12.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 0, 0, 2)
					};
					previewPanel.Children.Add (countBlock);

					TextBlock dateBlock = new TextBlock {
						Text = "Modified: " + di.LastWriteTime.ToString ("g"),
						Foreground = subTextBrush,
						FontSize = 12.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 0, 0, 15)
					};
					previewPanel.Children.Add (dateBlock);
				} catch {}
			} else if (item.IsAction) {
				if (item.Path.StartsWith ("action://copypaste_")) {
					string resultVal = item.Name;
					if (resultVal.StartsWith ("Conversion: ")) {
						resultVal = resultVal.Substring ("Conversion: ".Length);
					} else if (resultVal.StartsWith ("Result: ")) {
						resultVal = resultVal.Substring ("Result: ".Length);
					}

					TextBlock formulaBlock = new TextBlock {
						Text = searchBox.Text,
						Foreground = subTextBrush,
						FontSize = 13.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 10, 0, 4)
					};
					previewPanel.Children.Add (formulaBlock);

					TextBlock resultBlock = new TextBlock {
						Text = resultVal,
						Foreground = textBrush,
						FontSize = 26.0,
						FontWeight = FontWeights.Bold,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						TextAlignment = TextAlignment.Center,
						TextWrapping = TextWrapping.Wrap,
						Margin = new Thickness (0, 0, 0, 20)
					};
					previewPanel.Children.Add (resultBlock);

					Border copyBtn = new Border {
						Width = 140.0,
						Height = 30.0,
						CornerRadius = new CornerRadius (6.0),
						Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255)),
						Cursor = System.Windows.Input.Cursors.Hand,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 5, 0, 5)
					};
					TextBlock copyText = new TextBlock {
						Text = "Copy to Clipboard",
						Foreground = System.Windows.Media.Brushes.White,
						FontSize = 11.5,
						FontWeight = FontWeights.Bold,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						VerticalAlignment = VerticalAlignment.Center
					};
					copyBtn.Child = copyText;
					copyBtn.MouseEnter += (s, e) => {
						copyBtn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (20, 140, 255));
					};
					copyBtn.MouseLeave += (s, e) => {
						copyBtn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255));
					};
					copyBtn.PreviewMouseLeftButtonDown += delegate {
						try {
							System.Windows.Clipboard.SetText (resultVal);
							copyText.Text = "Copied!";
							System.Windows.Threading.DispatcherTimer timer = new System.Windows.Threading.DispatcherTimer {
								Interval = TimeSpan.FromSeconds (1.5)
							};
							timer.Tick += (s2, e2) => {
								copyText.Text = "Copy to Clipboard";
								timer.Stop ();
							};
							timer.Start ();
						} catch {}
					};
					previewPanel.Children.Add (copyBtn);
				} else {
					TextBlock descBlock = new TextBlock {
						Text = "System Command",
						Foreground = subTextBrush,
						FontSize = 12.0,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 10, 0, 4)
					};
					previewPanel.Children.Add (descBlock);

					TextBlock cmdBlock = new TextBlock {
						Text = item.Name,
						Foreground = textBrush,
						FontSize = 20.0,
						FontWeight = FontWeights.Bold,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						TextAlignment = TextAlignment.Center,
						TextWrapping = TextWrapping.Wrap,
						Margin = new Thickness (0, 0, 0, 20)
					};
					previewPanel.Children.Add (cmdBlock);

					Border execBtn = new Border {
						Width = 140.0,
						Height = 30.0,
						CornerRadius = new CornerRadius (6.0),
						Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255)),
						Cursor = System.Windows.Input.Cursors.Hand,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 5, 0, 5)
					};
					execBtn.Child = new TextBlock {
						Text = "Run Action",
						Foreground = System.Windows.Media.Brushes.White,
						FontSize = 12.0,
						FontWeight = FontWeights.Bold,
						FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						VerticalAlignment = VerticalAlignment.Center
					};
					execBtn.MouseEnter += (s, e) => {
						execBtn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (20, 140, 255));
					};
					execBtn.MouseLeave += (s, e) => {
						execBtn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255));
					};
					execBtn.PreviewMouseLeftButtonDown += delegate {
						ExecuteItem (item);
					};
					previewPanel.Children.Add (execBtn);
				}
			}

			if (item.IsApp || item.IsDirectory || (File.Exists (item.Path) && !item.IsDirectory) || item.IsWebSuggestion) {
				Border btn = new Border {
					Width = 140.0,
					Height = 30.0,
					CornerRadius = new CornerRadius (6.0),
					Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255)),
					Cursor = System.Windows.Input.Cursors.Hand,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					Margin = new Thickness (0, 5, 0, 5)
				};
				
				string buttonLabel = "Open File";
				if (item.IsApp) {
					buttonLabel = "Open App";
				} else if (item.IsDirectory) {
					buttonLabel = "Open Folder";
				} else if (item.IsWebSuggestion) {
					buttonLabel = "Search Google";
				}
				
				btn.Child = new TextBlock {
					Text = buttonLabel,
					Foreground = System.Windows.Media.Brushes.White,
					FontSize = 12.0,
					FontWeight = FontWeights.Bold,
					FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					VerticalAlignment = VerticalAlignment.Center
				};
				btn.MouseEnter += (s, e) => {
					btn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (20, 140, 255));
				};
				btn.MouseLeave += (s, e) => {
					btn.Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255));
				};
				btn.PreviewMouseLeftButtonDown += delegate {
					ExecuteItem (item);
				};
				previewPanel.Children.Add (btn);
			} else if (item.IsAction && item.Path.StartsWith ("action://f1_query?")) {
				string f1Param = item.Path.Substring ("action://f1_query?".Length).Trim ();
				string f1Lower = f1Param.ToLower ();

				string driverName = "";
				string teamName = "";
				if (f1Lower.Contains ("verstappen")) { driverName = "Max Verstappen"; teamName = "Redbull Racing"; }
				else if (f1Lower.Contains ("hamilton")) { driverName = "Lewis Hamilton"; teamName = "Ferrari"; }
				else if (f1Lower.Contains ("leclerc")) { driverName = "Charles Leclerc"; teamName = "Ferrari"; }
				else if (f1Lower.Contains ("norris")) { driverName = "Lando Norris"; teamName = "McLaren"; }
				else if (f1Lower.Contains ("piastri")) { driverName = "Oscar Piastri"; teamName = "McLaren"; }
				else if (f1Lower.Contains ("sainz")) { driverName = "Carlos Sainz"; teamName = "Williams"; }
				else if (f1Lower.Contains ("albon")) { driverName = "Alex Albon"; teamName = "Williams"; }
				else if (f1Lower.Contains ("antonelli") || f1Lower.Contains ("kimi")) { driverName = "Kimi Antonelli"; teamName = "Mercedes"; }
				else if (f1Lower.Contains ("russell")) { driverName = "George Russell"; teamName = "Mercedes"; }
				else if (f1Lower.Contains ("perez")) { driverName = "Sergio Perez"; teamName = "Redbull Racing"; }
				else if (f1Lower.Contains ("hulkenberg")) { driverName = "Nico Hulkenberg"; teamName = "Sauber"; }
				else if (f1Lower.Contains ("alonso")) { driverName = "Fernando Alonso"; teamName = "Aston Martin"; }
				else if (f1Lower.Contains ("stroll")) { driverName = "Lance Stroll"; teamName = "Aston Martin"; }
				else if (f1Lower.Contains ("gasly")) { driverName = "Pierre Gasly"; teamName = "Alpine"; }
				else if (f1Lower.Contains ("ocon")) { driverName = "Esteban Ocon"; teamName = "Haas"; }

				if (!string.IsNullOrEmpty (driverName)) {
					string headshotPath = F1OverlayWindow.ResolveAssetPath ("Headshots", driverName + ".png");

					Grid f1Card = new Grid { Height = 180.0, Margin = new Thickness (0, 10, 0, 10) };
					LinearGradientBrush grad = new LinearGradientBrush { StartPoint = new System.Windows.Point (0, 0), EndPoint = new System.Windows.Point (1, 1) };
					grad.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (220, 24, 25, 30), 0.0));
					grad.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (220, 200, 20, 30), 1.0));
					Border cardBg = new Border { Background = grad, CornerRadius = new CornerRadius (12.0) };
					f1Card.Children.Add (cardBg);

					StackPanel f1Stack = new StackPanel { VerticalAlignment = VerticalAlignment.Center, HorizontalAlignment = System.Windows.HorizontalAlignment.Center };

					if (!string.IsNullOrEmpty (headshotPath) && File.Exists (headshotPath)) {
						System.Windows.Controls.Image headshot = new System.Windows.Controls.Image {
							Source = new BitmapImage (new Uri (headshotPath, UriKind.Absolute)),
							Height = 80.0,
							Stretch = Stretch.Uniform,
							Margin = new Thickness (0, 0, 0, 6)
						};
						RenderOptions.SetBitmapScalingMode (headshot, BitmapScalingMode.HighQuality);
						f1Stack.Children.Add (headshot);
					}

					f1Stack.Children.Add (new TextBlock {
						Text = driverName.ToUpper (),
						Foreground = System.Windows.Media.Brushes.White,
						FontSize = 16.0,
						FontWeight = FontWeights.Black,
						FontFamily = SpotlightFont,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center
					});

					f1Stack.Children.Add (new TextBlock {
						Text = teamName,
						Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (255, 60, 60)),
						FontSize = 12.0,
						FontWeight = FontWeights.Bold,
						FontFamily = SpotlightFont,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center
					});

					f1Card.Children.Add (f1Stack);
					previewPanel.Children.Add (f1Card);

					Border openF1Btn = new Border {
						Width = 160.0, Height = 30.0, CornerRadius = new CornerRadius (7.0),
						Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (225, 6, 0)),
						Cursor = System.Windows.Input.Cursors.Hand,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 6, 0, 0)
					};
					openF1Btn.Child = new TextBlock {
						Text = "Open F1 Widget Overlay",
						Foreground = System.Windows.Media.Brushes.White,
						FontSize = 11.5, FontWeight = FontWeights.Bold,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						VerticalAlignment = VerticalAlignment.Center
					};
					openF1Btn.PreviewMouseLeftButtonDown += (s, e) => {
						ownerWindow.ShowF1Overlay ();
						Hide ();
					};
					previewPanel.Children.Add (openF1Btn);
				} else {
					TextBlock title = new TextBlock {
						Text = "🏎️ Formula 1 Live Standings",
						Foreground = textBrush, FontSize = 16.0, FontWeight = FontWeights.Bold,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 15, 0, 10)
					};
					previewPanel.Children.Add (title);

					Border openF1Btn = new Border {
						Width = 160.0, Height = 32.0, CornerRadius = new CornerRadius (8.0),
						Background = new SolidColorBrush (System.Windows.Media.Color.FromRgb (225, 6, 0)),
						Cursor = System.Windows.Input.Cursors.Hand,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new Thickness (0, 15, 0, 0)
					};
