		private void ShowQuickLook (SearchResultItem item)
		{
			if (item == null || item.IsWebSuggestion || item.IsAction || item.IsClipboard) {
				return;
			}
			
			try {
				if (_quickLookWindow != null) {
					_quickLookWindow.Close ();
					_quickLookWindow = null;
				}
				
				_quickLookWindow = new Window {
					WindowStyle = WindowStyle.None,
					AllowsTransparency = true,
					Background = System.Windows.Media.Brushes.Transparent,
					Width = 400.0,
					Height = 450.0,
					ShowInTaskbar = false,
					Topmost = true,
					UseLayoutRounding = true,
					SnapsToDevicePixels = true,
					Title = "Quick Look"
				};
				
				Border mainBorder = new Border {
					CornerRadius = new CornerRadius (12.0),
					Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (240, 28, 28, 30)),
					BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (45, 255, 255, 255)),
					BorderThickness = new Thickness (1.2),
					Padding = new Thickness (16.0)
				};
				mainBorder.Effect = new DropShadowEffect {
					BlurRadius = 25.0,
					ShadowDepth = 4.0,
					Opacity = 0.45,
					Color = Colors.Black
				};
				_quickLookWindow.Content = mainBorder;
				
				Grid grid = new Grid ();
				grid.RowDefinitions.Add (new RowDefinition { Height = GridLength.Auto });
				grid.RowDefinitions.Add (new RowDefinition { Height = new GridLength (1.0, GridUnitType.Star) });
				grid.RowDefinitions.Add (new RowDefinition { Height = GridLength.Auto });
				mainBorder.Child = grid;
				
				Grid headerGrid = new Grid { Margin = new Thickness (0, 0, 0, 12) };
				headerGrid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (1.0, GridUnitType.Star) });
				headerGrid.ColumnDefinitions.Add (new ColumnDefinition { Width = GridLength.Auto });
				
				TextBlock titleTxt = new TextBlock {
					Text = item.Name,
					Foreground = System.Windows.Media.Brushes.White,
					FontSize = 14.0,
					FontWeight = FontWeights.Bold,
					TextTrimming = TextTrimming.CharacterEllipsis,
					VerticalAlignment = VerticalAlignment.Center
				};
				Grid.SetColumn (titleTxt, 0);
				headerGrid.Children.Add (titleTxt);
				
				System.Windows.Controls.Button closeBtn = new System.Windows.Controls.Button {
					Content = "✕",
					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (180, 180, 180)),
					Background = System.Windows.Media.Brushes.Transparent,
					BorderBrush = System.Windows.Media.Brushes.Transparent,
					FontSize = 12.0,
					FontWeight = FontWeights.Bold,
					Width = 24.0,
					Height = 24.0,
					Cursor = System.Windows.Input.Cursors.Hand
				};
				closeBtn.Click += delegate {
					_quickLookWindow.Close ();
					_quickLookWindow = null;
				};
				Grid.SetColumn (closeBtn, 1);
				headerGrid.Children.Add (closeBtn);
				
				Grid.SetRow (headerGrid, 0);
				grid.Children.Add (headerGrid);
				
				FrameworkElement previewContent = null;
				string infoText = "";
				
				if (item.IsDirectory) {
					try {
						var dirInfo = new System.IO.DirectoryInfo (item.Path);
						int filesCount = 0;
						int dirsCount = 0;
						try {
							filesCount = System.IO.Directory.GetFiles (item.Path).Length;
							dirsCount = System.IO.Directory.GetDirectories (item.Path).Length;
						} catch {}
						
						StackPanel sp = new StackPanel { VerticalAlignment = VerticalAlignment.Center };
						
						TextBlock iconBlock = new TextBlock {
							Text = "\uE8B7",
							FontFamily = new System.Windows.Media.FontFamily ("Segoe MDL2 Assets"),
							FontSize = 64.0,
							Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 120, 255)),
							HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
							Margin = new Thickness (0, 0, 0, 16)
						};
						sp.Children.Add (iconBlock);
						
						TextBlock detailsBlock = new TextBlock {
							Text = string.Format ("Folder: {0}\nContains: {1} files, {2} folders\nCreated: {3}", dirInfo.Name, filesCount, dirsCount, dirInfo.CreationTime.ToString ("g")),
							Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (220, 220, 220)),
							FontSize = 13.0,
							TextAlignment = TextAlignment.Center,
							LineHeight = 20.0
						};
						sp.Children.Add (detailsBlock);
						
						previewContent = sp;
						infoText = "Directory | " + item.Path;
					} catch {
						previewContent = new TextBlock { Text = "Directory Preview Unavailable", Foreground = System.Windows.Media.Brushes.Gray };
					}
				} else {
					string ext = System.IO.Path.GetExtension (item.Path).ToLower ();
					bool isImg = ext == ".png" || ext == ".jpg" || ext == ".jpeg" || ext == ".gif" || ext == ".bmp";
					bool isTxt = ext == ".txt" || ext == ".log" || ext == ".cs" || ext == ".json" || ext == ".xml" || ext == ".ini" || ext == ".yaml" || ext == ".yml";
					
					var fileInfo = new System.IO.FileInfo (item.Path);
					double sizeMb = (double)fileInfo.Length / (1024.0 * 1024.0);
					string sizeStr = sizeMb >= 1.0 ? sizeMb.ToString ("F2") + " MB" : ((double)fileInfo.Length / 1024.0).ToString ("F1") + " KB";
					infoText = string.Format ("{0} | {1} | Modified: {2}", ext.ToUpper ().Trim ('.'), sizeStr, fileInfo.LastWriteTime.ToString ("g"));
					
					if (isImg) {
						try {
							BitmapImage bmp = new BitmapImage ();
							bmp.BeginInit ();
							bmp.UriSource = new Uri (item.Path);
							bmp.CacheOption = BitmapCacheOption.OnLoad;
							bmp.EndInit ();
							bmp.Freeze ();
							
							previewContent = new System.Windows.Controls.Image {
								Source = bmp,
								Stretch = Stretch.Uniform,
								VerticalAlignment = VerticalAlignment.Center,
								HorizontalAlignment = System.Windows.HorizontalAlignment.Center
							};
						} catch {
							isTxt = true;
						}
					}
					
					if (isTxt && previewContent == null) {
						try {
							string fileText = "";
							using (var stream = new FileStream (item.Path, FileMode.Open, FileAccess.Read, FileShare.ReadWrite))
							using (var reader = new StreamReader (stream)) {
								char[] buffer = new char [800];
								int read = reader.Read (buffer, 0, 800);
								fileText = new string (buffer, 0, read);
								if (reader.Read (buffer, 0, 1) > 0) fileText += "\n... [truncated]";
							}
							
							ScrollViewer sv = new ScrollViewer {
								VerticalScrollBarVisibility = ScrollBarVisibility.Hidden,
								HorizontalScrollBarVisibility = ScrollBarVisibility.Disabled,
								Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, 0, 0, 0)),
								Padding = new Thickness (10)
							};
							
							TextBlock txtBlock = new TextBlock {
								Text = fileText,
								Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (220, 220, 220)),
								FontFamily = new System.Windows.Media.FontFamily ("Consolas, Courier New, monospace"),
								FontSize = 11.5,
								TextWrapping = TextWrapping.Wrap
							};
							sv.Content = txtBlock;
							previewContent = sv;
						} catch {}
					}
					
					if (previewContent == null) {
						StackPanel sp = new StackPanel { VerticalAlignment = VerticalAlignment.Center };
						
						TextBlock iconBlock = new TextBlock {
							Text = "\uE8A5",
							FontFamily = new System.Windows.Media.FontFamily ("Segoe MDL2 Assets"),
							FontSize = 64.0,
							Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (200, 200, 200)),
							HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
							Margin = new Thickness (0, 0, 0, 16)
						};
						sp.Children.Add (iconBlock);
						
						TextBlock detailsBlock = new TextBlock {
							Text = string.Format ("File: {0}\nType: {1}\nSize: {2}", fileInfo.Name, ext.ToUpper (), sizeStr),
							Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (220, 220, 220)),
							FontSize = 13.0,
							TextAlignment = TextAlignment.Center,
							LineHeight = 20.0
						};
						sp.Children.Add (detailsBlock);
						
						previewContent = sp;
					}
				}
				
				Grid.SetRow (previewContent, 1);
				grid.Children.Add (previewContent);
				
				TextBlock footerTxt = new TextBlock {
					Text = infoText,
					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (150, 150, 150)),
					FontSize = 10.5,
					TextAlignment = TextAlignment.Center,
					Margin = new Thickness (0, 12, 0, 0)
				};
				Grid.SetRow (footerTxt, 2);
				grid.Children.Add (footerTxt);
				
				_quickLookWindow.Left = this.Left + this.Width + 10.0;
				_quickLookWindow.Top = this.Top + (this.Height - _quickLookWindow.Height) / 2.0;
				
				_quickLookWindow.Show ();
			} catch {}
		}

		private void CloseQuickLook ()
		{
			if (_quickLookWindow != null) {
				try {
					_quickLookWindow.Close ();
				} catch {}
				_quickLookWindow = null;
			}
		}

		private void StartClipboardMonitoring ()
		{
			_clipboardTimer = new System.Windows.Threading.DispatcherTimer {
				Interval = TimeSpan.FromMilliseconds (1500)
			};
			_clipboardTimer.Tick += delegate {
				try {
					if (System.Windows.Clipboard.ContainsText ()) {
						string text = System.Windows.Clipboard.GetText ();
						if (!string.IsNullOrEmpty (text)) {
							text = text.Trim ();
							if (text.Length > 0 && !_clipboardHistory.Contains (text)) {
								_clipboardHistory.Insert (0, text);
								if (_clipboardHistory.Count > 10) {
									_clipboardHistory.RemoveAt (_clipboardHistory.Count - 1);
								}
							}
						}
					}
				} catch {}
			};
			_clipboardTimer.Start ();
		}

		private void AnimateResults (bool show)
		{
			if (resultsShadowWrapper == null || separator == null) return;

			double targetOpacity = show ? 1.0 : 0.0;
			double targetHeight = 0.0;
			double targetWindowHeight = show ? (24.0 + SpotlightSearchHeight + 1.0 + SpotlightResultsHeight + 44.0) : 140.0;

			resultsShadowWrapper.BeginAnimation (FrameworkElement.HeightProperty, null);
			resultsShadowWrapper.BeginAnimation (UIElement.OpacityProperty, null);
			separator.BeginAnimation (UIElement.OpacityProperty, null);
			this.BeginAnimation (FrameworkElement.HeightProperty, null);

			if (show) {
				separator.Visibility = Visibility.Visible;
				resultsShadowWrapper.Visibility = Visibility.Visible;
				targetHeight = SpotlightResultsHeight;
			}

			double currentHeight = resultsShadowWrapper.Height;
			if (double.IsNaN (currentHeight) || currentHeight < 0.0) currentHeight = resultsShadowWrapper.ActualHeight;
			if (double.IsNaN (currentHeight) || currentHeight < 0.0) currentHeight = 0.0;

			if (show && base.SizeToContent != SizeToContent.Manual) {
				base.SizeToContent = SizeToContent.Manual;
			}

			DoubleAnimation heightAnim = new DoubleAnimation {
				From = currentHeight,
				To = targetHeight,
				Duration = TimeSpan.FromMilliseconds (260),
				EasingFunction = new QuinticEase { EasingMode = EasingMode.EaseOut }
			};
			heightAnim.Completed += delegate {
				resultsShadowWrapper.Height = targetHeight;
				if (!show) {
					resultsShadowWrapper.Visibility = Visibility.Collapsed;
					separator.Visibility = Visibility.Collapsed;
				}
			};

			DoubleAnimation opacityAnim = new DoubleAnimation {
				To = targetOpacity,
				Duration = TimeSpan.FromMilliseconds (show ? 170 : 115)
			};

			DoubleAnimation windowHeightAnim = new DoubleAnimation {
				To = targetWindowHeight,
				Duration = TimeSpan.FromMilliseconds (show ? 260 : 130),
				EasingFunction = new QuinticEase { EasingMode = EasingMode.EaseOut }
			};

			resultsShadowWrapper.BeginAnimation (FrameworkElement.HeightProperty, heightAnim);
			resultsShadowWrapper.BeginAnimation (UIElement.OpacityProperty, opacityAnim);
			separator.BeginAnimation (UIElement.OpacityProperty, opacityAnim);
			this.BeginAnimation (FrameworkElement.HeightProperty, windowHeightAnim);
		}

		public FinderSearchWindow (DockWindow owner)
		{
			ownerWindow = owner;
			TextOptions.SetTextFormattingMode (this, TextFormattingMode.Display);
			TextOptions.SetTextRenderingMode (this, TextRenderingMode.ClearType);
			RenderOptions.SetClearTypeHint (this, ClearTypeHint.Enabled);
			LocalFileIndexer.Initialize ();

			_searchDebounceTimer = new System.Windows.Threading.DispatcherTimer {
				Interval = TimeSpan.FromMilliseconds (120)
			};
			_searchDebounceTimer.Tick += delegate {
				_searchDebounceTimer.Stop ();
				TriggerSearch (searchBox.Text);
			};
			base.Owner = owner;
			base.ShowInTaskbar = false;
			base.Topmost = true;
			base.AllowsTransparency = true;
			base.WindowStyle = WindowStyle.None;
			base.Background = System.Windows.Media.Brushes.Transparent;
			base.Width = SpotlightOuterWidth;
			base.SizeToContent = SizeToContent.Manual;
			base.Height = 140.0;
			base.WindowStartupLocation = WindowStartupLocation.Manual;
			Rect workArea = SystemParameters.WorkArea;
			base.Left = workArea.Left + (workArea.Width - SpotlightOuterWidth) / 2.0;
			base.Top = workArea.Top + workArea.Height * 0.22;
			base.UseLayoutRounding = true;
			base.SnapsToDevicePixels = true;
			base.ClipToBounds = false;

			StackPanel mainStack = new StackPanel {
				Orientation = System.Windows.Controls.Orientation.Vertical,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				VerticalAlignment = VerticalAlignment.Top,
				Margin = new Thickness (40.0, 24.0, 40.0, 44.0),
				ClipToBounds = false
			};
			base.Content = mainStack;

			// Kill ALL native scrollbars in the entire window
			try {
				Style killScrollBar = new Style (typeof(System.Windows.Controls.Primitives.ScrollBar));
				killScrollBar.Setters.Add (new Setter (UIElement.VisibilityProperty, Visibility.Collapsed));
				killScrollBar.Setters.Add (new Setter (FrameworkElement.WidthProperty, 0.0));
				killScrollBar.Setters.Add (new Setter (FrameworkElement.HeightProperty, 0.0));
				base.Resources.Add (typeof(System.Windows.Controls.Primitives.ScrollBar), killScrollBar);
			} catch {
			}

			LinearGradientBrush pillBgBrush = new LinearGradientBrush {
				StartPoint = new System.Windows.Point (0, 0),
				EndPoint = new System.Windows.Point (0, 1)
			};
			pillBgBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (248, 250, 250, 250), 0.0));
			pillBgBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (245, 240, 240, 240), 1.0));

			LinearGradientBrush pillBorderBrush = new LinearGradientBrush {
				StartPoint = new System.Windows.Point (0, 0),
				EndPoint = new System.Windows.Point (0, 1)
			};
			pillBorderBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (80, 255, 255, 255), 0.0));
			pillBorderBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (40, 0, 0, 0), 1.0));

			Grid searchRow = new Grid { Height = SpotlightSearchHeight };
			searchRow.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (44.0) });
			searchRow.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (1.0, GridUnitType.Star) });
			searchRow.ColumnDefinitions.Add (new ColumnDefinition { Width = GridLength.Auto });

			searchPill = new Border {
				CornerRadius = new CornerRadius (22.0),
				Background = pillBgBrush,
				BorderBrush = pillBorderBrush,
				BorderThickness = new Thickness (0.8),
				Width = SpotlightPanelWidth,
				UseLayoutRounding = true,
				SnapsToDevicePixels = true,
				ClipToBounds = false
			};

			StackPanel unifiedStack = new StackPanel {
				Orientation = System.Windows.Controls.Orientation.Vertical
			};

			searchPill.Child = unifiedStack;
			unifiedStack.Children.Add (searchRow);
			mainStack.Children.Add (searchPill);

			separator = new Border {
				Height = 1.0,
				Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, 0, 0, 0)),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch,
				Visibility = Visibility.Collapsed,
				Opacity = 0.0
			};
			unifiedStack.Children.Add (separator);

			_searchIcon = new TextBlock {
				Text = "\uE721",
				FontFamily = new System.Windows.Media.FontFamily ("Segoe MDL2 Assets"),
				Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (100, 105, 115)),
				FontSize = 17.0,
				VerticalAlignment = VerticalAlignment.Center,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center
			};
			Grid.SetColumn (_searchIcon, 0);
			searchRow.Children.Add (_searchIcon);

			_shimmerBrush = new LinearGradientBrush {
				StartPoint = new System.Windows.Point (0, 0),
				EndPoint = new System.Windows.Point (1, 0)
			};
			System.Windows.Media.Color baseColor = System.Windows.Media.Color.FromRgb (130, 135, 145);
			System.Windows.Media.Color highlightColor = System.Windows.Media.Color.FromRgb (255, 255, 255);
			_shimmerBrush.GradientStops.Add (new GradientStop (baseColor, 0.0));
			_shimmerBrush.GradientStops.Add (new GradientStop (baseColor, 0.35));
			_shimmerBrush.GradientStops.Add (new GradientStop (highlightColor, 0.5));
			_shimmerBrush.GradientStops.Add (new GradientStop (baseColor, 0.65));
			_shimmerBrush.GradientStops.Add (new GradientStop (baseColor, 1.0));
			_shimmerTransform = new TranslateTransform (-1.0, 0.0);
			_shimmerBrush.RelativeTransform = _shimmerTransform;
			_shimmerAnimation = new DoubleAnimation {
				From = -1.0,
				To = 1.0,
				Duration = TimeSpan.FromSeconds (2.5),
				RepeatBehavior = RepeatBehavior.Forever
			};

			Grid col1Grid = new Grid ();

			placeholderText = new TextBlock {
				Text = "Search",
				Foreground = _shimmerBrush,
				FontSize = 21.0,
				FontWeight = FontWeights.Normal,
				FontFamily = SpotlightFont,
				FontStyle = FontStyles.Normal,
				VerticalAlignment = VerticalAlignment.Center,
				IsHitTestVisible = false,
				Margin = new Thickness (4.0, 0.0, 20.0, 1.0)
			};
			col1Grid.Children.Add (placeholderText);

			searchBox = new System.Windows.Controls.TextBox {
				Background = System.Windows.Media.Brushes.Transparent,
				BorderThickness = new Thickness (0.0),
				Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (40, 40, 40)),
				FontSize = 21.0,
				FontFamily = SpotlightFont,
				VerticalAlignment = VerticalAlignment.Center,
				CaretBrush = System.Windows.Media.Brushes.Black,
				Margin = new Thickness (4.0, 0.0, 20.0, 1.0)
			};
			col1Grid.Children.Add (searchBox);

			_heroResultBadge = new Border {
				CornerRadius = new CornerRadius (7.0),
				Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (45, 0, 120, 255)),
				BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (90, 0, 120, 255)),
				BorderThickness = new Thickness (1.0),
				Padding = new Thickness (8.0, 3.0, 8.0, 3.0),
				Margin = new Thickness (0.0, 0.0, 12.0, 0.0),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
				VerticalAlignment = VerticalAlignment.Center,
				Visibility = Visibility.Collapsed,
				Opacity = 0.0,
				IsHitTestVisible = false
			};
			_heroResultText = new TextBlock {
				Text = "",
				Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, 255)),
				FontSize = 13.5,
				FontWeight = FontWeights.Bold,
				FontFamily = SpotlightFont
			};
			_heroResultBadge.Child = _heroResultText;
			col1Grid.Children.Add (_heroResultBadge);

			Grid.SetColumn (col1Grid, 1);
			searchRow.Children.Add (col1Grid);

			StackPanel tahoeButtonsPanel = new StackPanel {
				Orientation = System.Windows.Controls.Orientation.Horizontal,
				VerticalAlignment = VerticalAlignment.Center,
				Margin = new Thickness (8.0, 0.0, 12.0, 0.0)
			};

			string[] tahoeLabels = { "Apps", "Files", "Actions", "F1", "Clipboard" };
			string[] tahoeTooltips = { "Applications (Ctrl+1)", "Files & Folders (Ctrl+2)", "Quick Actions (Ctrl+3)", "Formula 1 (Ctrl+4)", "Clipboard History (Ctrl+5)" };

			_tahoeCapsules.Clear ();
			for (int i = 0; i < tahoeLabels.Length; i++) {
				string label = tahoeLabels [i];
				Border capsule = new Border {
					CornerRadius = new CornerRadius (12.0),
					Background = System.Windows.Media.Brushes.Transparent,
					BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 0, 0, 0)),
					BorderThickness = new Thickness (1.0),
					Padding = new Thickness (8.0, 4.0, 8.0, 4.0),
					Margin = new Thickness (2.0, 0.0, 2.0, 0.0),
					Cursor = System.Windows.Input.Cursors.Hand,
					ToolTip = tahoeTooltips [i]
				};
				
				TextBlock txt = new TextBlock {
					Text = label,
					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (80, 85, 95)),
					FontSize = 11.0,
					FontWeight = FontWeights.SemiBold,
					FontFamily = SpotlightFont
				};
				capsule.Child = txt;
				
				string categoryFilter = label;
				capsule.PreviewMouseLeftButtonDown += delegate {
					ToggleTahoeFilter (categoryFilter, capsule, txt, _tahoeCapsules);
				};

				_tahoeCapsules.Add (capsule);
				tahoeButtonsPanel.Children.Add (capsule);
			}
			Grid.SetColumn (tahoeButtonsPanel, 2);
			searchRow.Children.Add (tahoeButtonsPanel);

			resultsShadowWrapper = new Border {
				Width = SpotlightPanelWidth,
				Height = 0.0,
				Opacity = 0.0,
				CornerRadius = new CornerRadius (0.0),
				Background = System.Windows.Media.Brushes.Transparent,
				UseLayoutRounding = true,
				SnapsToDevicePixels = true
			};

			Border resultsShadow2 = new Border {
				CornerRadius = new CornerRadius (0.0),
				Background = System.Windows.Media.Brushes.Transparent,
				UseLayoutRounding = true,
				SnapsToDevicePixels = true
			};

			resultsBorder = new Border {
				CornerRadius = new CornerRadius (0.0),
				BorderThickness = new Thickness (0.0),
				Background = System.Windows.Media.Brushes.Transparent,
				Width = SpotlightPanelWidth,
				ClipToBounds = true,
				UseLayoutRounding = true,
				SnapsToDevicePixels = true
			};

			resultsShadowWrapper.Child = resultsShadow2;
			resultsShadow2.Child = resultsBorder;

			scrollViewer = new ScrollViewer {
				VerticalScrollBarVisibility = ScrollBarVisibility.Hidden,
				HorizontalScrollBarVisibility = ScrollBarVisibility.Disabled,
				Padding = new Thickness (14.0, 10.0, 14.0, 14.0),
				UseLayoutRounding = true,
				SnapsToDevicePixels = true
			};

			new SmoothScrollHelper (scrollViewer, () => ownerWindow != null && ownerWindow.settings != null ? ownerWindow.settings.BlurAmount : 0.7);

			resultsPanel = new StackPanel ();
			scrollViewer.Content = resultsPanel;

			Border scrollThumb = new Border {
				Width = 4.0,
				CornerRadius = new CornerRadius (2.0),
				Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (135, 120, 120, 125)),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
				VerticalAlignment = VerticalAlignment.Top,
				Opacity = 0.0,
				IsHitTestVisible = false
			};

			Grid splitGrid = new Grid {
				Width = SpotlightPanelWidth
			};
			splitGrid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (350.0) });
			splitGrid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (1.0) });
			splitGrid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (1.0, GridUnitType.Star) });

			resultsBorder.Child = splitGrid;

			Grid overlayGrid = new Grid ();
			overlayGrid.Children.Add (scrollViewer);
			overlayGrid.Children.Add (scrollThumb);
			Grid.SetColumn (overlayGrid, 0);
			splitGrid.Children.Add (overlayGrid);

			verticalSeparator = new Border {
				Width = 1.0,
				Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 0, 0, 0)),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
			};
			Grid.SetColumn (verticalSeparator, 1);
			splitGrid.Children.Add (verticalSeparator);

			previewBorder = new Border {
				Padding = new Thickness (20.0),
				Background = System.Windows.Media.Brushes.Transparent,
				VerticalAlignment = VerticalAlignment.Stretch,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
			};
			previewPanel = new StackPanel {
				Orientation = System.Windows.Controls.Orientation.Vertical,
				VerticalAlignment = VerticalAlignment.Stretch,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch
			};
			previewBorder.Child = previewPanel;
			Grid.SetColumn (previewBorder, 2);
			splitGrid.Children.Add (previewBorder);

			_scrollFadeTimer = new System.Windows.Threading.DispatcherTimer {
				Interval = TimeSpan.FromMilliseconds (900)
			};
			_scrollFadeTimer.Tick += delegate {
				_scrollFadeTimer.Stop ();
				scrollThumb.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (400)));
			};

			// Update thumb position/size on scroll, fade in/out
			scrollViewer.ScrollChanged += delegate {
				double extent = scrollViewer.ExtentHeight;
				double viewport = scrollViewer.ViewportHeight;
				double offset = scrollViewer.VerticalOffset;
				double available = Math.Max (1.0, viewport - 12.0);

				if (extent <= viewport || extent <= 0.0 || viewport <= 0.0) {
					scrollThumb.Visibility = Visibility.Collapsed;
					return;
				}
				scrollThumb.Visibility = Visibility.Visible;

				double ratio = viewport / extent;
				double thumbH = Math.Max (24.0, available * ratio);
				double scrollRange = extent - viewport;
				double thumbTop = 6.0 + (available - thumbH) * (scrollRange > 0.0 ? offset / scrollRange : 0.0);
				scrollThumb.Height = thumbH;
				scrollThumb.Margin = new Thickness (0.0, thumbTop, 3.0, 0.0);

				// Fade in
				scrollThumb.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (80)));

				// Restart idle fade timer
				_scrollFadeTimer.Stop ();
				_scrollFadeTimer.Start ();
			};

			unifiedStack.Children.Add (resultsShadowWrapper);

			base.Loaded += delegate {
				EnableBlur (true);
				searchBox.Focus ();
				Keyboard.Focus (searchBox);
			};

			base.SizeChanged += delegate {
				EnableBlur (true);
			};

			searchBox.TextChanged += delegate {
				bool isEmpty = string.IsNullOrEmpty (searchBox.Text);
				placeholderText.Visibility = isEmpty ? Visibility.Visible : Visibility.Collapsed;
				if (_shimmerTransform != null) {
					if (isEmpty) {
						_shimmerTransform.BeginAnimation (TranslateTransform.XProperty, _shimmerAnimation);
					} else {
						_shimmerTransform.BeginAnimation (TranslateTransform.XProperty, null);
					}
				}
				EvaluateHeroCalculation (searchBox.Text);
				_searchDebounceTimer.Stop ();
				if (isEmpty) {
					TriggerSearch ("");
				} else {
					_searchDebounceTimer.Start ();
				}
			};

			base.KeyDown += delegate(object s, System.Windows.Input.KeyEventArgs e) {
				if (Keyboard.Modifiers == ModifierKeys.Control) {
					if (e.Key == Key.D1 || e.Key == Key.NumPad1) {
						ToggleTahoeFilterByIndex (0, _tahoeCapsules);
						e.Handled = true;
						return;
					} else if (e.Key == Key.D2 || e.Key == Key.NumPad2) {
						ToggleTahoeFilterByIndex (1, _tahoeCapsules);
						e.Handled = true;
						return;
					} else if (e.Key == Key.D3 || e.Key == Key.NumPad3) {
						ToggleTahoeFilterByIndex (2, _tahoeCapsules);
						e.Handled = true;
						return;
					} else if (e.Key == Key.D4 || e.Key == Key.NumPad4) {
						ToggleTahoeFilterByIndex (3, _tahoeCapsules);
						e.Handled = true;
						return;
					} else if (e.Key == Key.D5 || e.Key == Key.NumPad5) {
						ToggleTahoeFilterByIndex (4, _tahoeCapsules);
						e.Handled = true;
						return;
					} else if (e.Key == Key.Enter) {
						if (_selectedIndex >= 0 && _selectedIndex < _displayedItems.Count) {
							SearchResultItem sel = _displayedItems [_selectedIndex];
							if (!sel.IsWebSuggestion && !sel.IsAction && !sel.IsClipboard && !string.IsNullOrEmpty (sel.Path)) {
								try {
									if (File.Exists (sel.Path) || Directory.Exists (sel.Path)) {
										Process.Start ("explorer.exe", "/select,\"" + sel.Path + "\"");
										Hide ();
										e.Handled = true;
										return;
									}
								} catch {}
							}
						}
					} else if (e.Key == Key.C) {
						if (_selectedIndex >= 0 && _selectedIndex < _displayedItems.Count) {
							SearchResultItem sel = _displayedItems [_selectedIndex];
							try {
								System.Windows.Clipboard.SetText (sel.IsWebSuggestion || sel.IsAction ? sel.Name : sel.Path);
								e.Handled = true;
								return;
							} catch {}
						}
					}
				}

				if (e.Key == Key.Tab) {
					int currentIdx = -1;
					for (int i = 0; i < _tahoeCapsules.Count; i++) {
						TextBlock t = _tahoeCapsules [i].Child as TextBlock;
						if (t != null && t.Text == _activeFilter) {
							currentIdx = i;
							break;
						}
					}
					int nextIdx = (currentIdx + 1) % (_tahoeCapsules.Count + 1);
					if (nextIdx == _tahoeCapsules.Count) {
						_activeFilter = "All";
						ApplyTheme ();
					} else {
						ToggleTahoeFilterByIndex (nextIdx, _tahoeCapsules);
					}
					e.Handled = true;
					return;
				}

				if (e.Key == Key.Escape) {
					Hide ();
				} else if (e.Key == Key.Down) {
					if (_rowElements.Count > 0) {
						_selectedIndex = (_selectedIndex + 1) % _rowElements.Count;
						UpdateSelectionVisuals ();
						e.Handled = true;
					}
				} else if (e.Key == Key.Up) {
					if (_rowElements.Count > 0) {
						_selectedIndex = (_selectedIndex - 1 + _rowElements.Count) % _rowElements.Count;
						UpdateSelectionVisuals ();
						e.Handled = true;
					}
				} else if (e.Key == Key.Enter) {
					if (_selectedIndex >= 0 && _selectedIndex < _displayedItems.Count) {
						ExecuteItem (_displayedItems [_selectedIndex]);
						e.Handled = true;
					}
				} else if (e.Key == Key.Space) {
					if (Keyboard.Modifiers == ModifierKeys.Control || !searchBox.IsFocused) {
						if (_selectedIndex >= 0 && _selectedIndex < _displayedItems.Count) {
							ShowQuickLook (_displayedItems [_selectedIndex]);
							e.Handled = true;
						}
					}
				}
			};

			base.PreviewKeyDown += delegate(object s, System.Windows.Input.KeyEventArgs e) {
				if (e.Key == Key.LeftCtrl || e.Key == Key.RightCtrl) {
					UpdateSelectionVisuals ();
				}
			};

			base.PreviewKeyUp += delegate(object s, System.Windows.Input.KeyEventArgs e) {
				if (e.Key == Key.LeftCtrl || e.Key == Key.RightCtrl) {
					UpdateSelectionVisuals ();
				}
			};

			base.Deactivated += delegate {
				Hide ();
			};

			StartClipboardMonitoring ();
			ShowSuggestions ();
		}



		private void ShowSuggestions ()
		{
			resultsPanel.Children.Clear ();
			
			if (_activeFilter == "Clipboard") {
				List<SearchResultItem> clipMatches = new List<SearchResultItem> ();
				foreach (string clipItem in _clipboardHistory) {
					string display = clipItem;
					if (display.Length > 60) display = display.Substring (0, 57) + "...";
					clipMatches.Add (new SearchResultItem {
						Name = display,
						Path = clipItem,
						IsClipboard = true
					});
				}
				RenderResults (clipMatches);
				return;
			}

			AnimateResults (false);
		}



		private void TriggerSearch (string query)

		{

			query = query.Trim ();

			if (string.IsNullOrEmpty (query)) {

				ShowSuggestions ();

				lastQuery = "";

			} else {

				if (query == lastQuery) {

					return;

				}
				lastQuery = query;

				searchGen++;

				int currentGen = searchGen;
				System.Threading.Tasks.Task<List<string>> webTask = null;
				if (query.Length >= 2) {
					webTask = System.Threading.Tasks.Task.Run (() => {
						try {
							return GetGoogleSuggestions (query);
						} catch {
							return new List<string> ();
						}
					});
				}

				ThreadPool.QueueUserWorkItem (delegate {

					List<SearchResultItem> matches = new List<SearchResultItem> ();

					try {

						// 0. Search Pinned Dock Applications first
						var uniqueAppPaths = new HashSet<string> (StringComparer.OrdinalIgnoreCase);
						foreach (DockItemConfig app in ownerWindow.settings.Items) {
							if (currentGen != searchGen) return;
							if (app.Name != null && app.Name.IndexOf (query, StringComparison.OrdinalIgnoreCase) >= 0) {
								if (uniqueAppPaths.Add (app.Name)) {
									matches.Add (new SearchResultItem {
										Name = app.Name,
										Path = app.FilePath,
										IsApp = true
									});
								}
							}
						}
						SearchRegistryApplications (query, matches, uniqueAppPaths, currentGen, searchGen);

						// 1. Math equations
						bool isMath = false;
						double mathResult = 0;
						if (System.Text.RegularExpressions.Regex.IsMatch (query, @"^[0-9\s\+\-\*\/\(\)\.]+$") && 
							System.Text.RegularExpressions.Regex.IsMatch (query, @"[0-9]")) {
							try {
								var dt = new System.Data.DataTable ();
								var resultObj = dt.Compute (query, null);
								mathResult = Convert.ToDouble (resultObj);
								isMath = true;
							} catch {}
						}
						
						if (isMath) {
							matches.Add (new SearchResultItem {
								Name = "Result: " + mathResult.ToString (),
								Path = "action://copypaste_" + mathResult.ToString (),
								IsAction = true
							});
						}

						// 2. Unit conversions (e.g. "50 kg to lbs")
						bool isConversion = false;
						string conversionResult = "";
						var conversionRegex = new System.Text.RegularExpressions.Regex (
							@"^(\d+(?:\.\d+)?)\s*([a-zA-Z]+)\s+to\s+([a-zA-Z]+)$", 
							System.Text.RegularExpressions.RegexOptions.IgnoreCase
						);
						var matchConv = conversionRegex.Match (query);
						if (matchConv.Success) {
							double value = double.Parse (matchConv.Groups [1].Value);
							string fromUnit = matchConv.Groups [2].Value.ToLower ();
							string toUnit = matchConv.Groups [3].Value.ToLower ();
							
							if (fromUnit == "kg" && toUnit == "lbs") {
								conversionResult = (value * 2.20462).ToString ("N2") + " lbs";
								isConversion = true;
							} else if (fromUnit == "lbs" && toUnit == "kg") {
								conversionResult = (value / 2.20462).ToString ("N2") + " kg";
								isConversion = true;
							} else if (fromUnit == "miles" && toUnit == "km") {
								conversionResult = (value * 1.60934).ToString ("N2") + " km";
								isConversion = true;
							} else if (fromUnit == "km" && toUnit == "miles") {
								conversionResult = (value / 1.60934).ToString ("N2") + " miles";
								isConversion = true;
							} else if (fromUnit == "c" && toUnit == "f") {
								conversionResult = (value * 9.0 / 5.0 + 32.0).ToString ("N2") + " °F";
								isConversion = true;
							} else if (fromUnit == "f" && toUnit == "c") {
								conversionResult = ((value - 32.0) * 5.0 / 9.0).ToString ("N2") + " °C";
								isConversion = true;
							} else if (fromUnit == "inches" && toUnit == "cm") {
								conversionResult = (value * 2.54).ToString ("N2") + " cm";
								isConversion = true;
							} else if (fromUnit == "cm" && toUnit == "inches") {
								conversionResult = (value / 2.54).ToString ("N2") + " inches";
								isConversion = true;
							}
						}
						
						if (isConversion) {
							matches.Add (new SearchResultItem {
								Name = "Conversion: " + conversionResult,
								Path = "action://copypaste_" + conversionResult,
								IsAction = true
							});
						}

						// 2b. Smart conversions (automatic fallback for unit queries like "1000g", "100 usd", "$50")
						var smartConvRegex = new System.Text.RegularExpressions.Regex (
							@"^(?:([\$€£¥])\s*(\d+(?:\.\d+)?)|(\d+(?:\.\d+)?)\s*([a-zA-Z\$€£¥°]+))$",
							System.Text.RegularExpressions.RegexOptions.IgnoreCase
						);
						var matchSmart = smartConvRegex.Match (query.Trim ());
						if (matchSmart.Success) {
							double val = 0;
							string unit = "";
							bool parsed = false;
							if (!string.IsNullOrEmpty (matchSmart.Groups [1].Value)) {
								unit = matchSmart.Groups [1].Value;
								parsed = double.TryParse (matchSmart.Groups [2].Value, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out val);
							} else {
								parsed = double.TryParse (matchSmart.Groups [3].Value, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out val);
								unit = matchSmart.Groups [4].Value;
							}
							
							if (parsed) {
								unit = unit.ToLower ();
								List<string> conversions = new List<string> ();

								// Weight
								if (unit == "g" || unit == "grams" || unit == "gram") {
									conversions.Add ($"{(val / 1000.0):N2} kg");
									conversions.Add ($"{(val * 0.00220462):N2} lbs");
									conversions.Add ($"{(val * 0.035274):N2} oz");
								} else if (unit == "kg" || unit == "kilograms" || unit == "kilogram") {
									conversions.Add ($"{(val * 1000.0):N2} g");
									conversions.Add ($"{(val * 2.20462):N2} lbs");
								} else if (unit == "lbs" || unit == "lb" || unit == "pounds" || unit == "pound") {
									conversions.Add ($"{(val / 2.20462):N2} kg");
									conversions.Add ($"{(val * 453.592):N2} g");
								} else if (unit == "oz" || unit == "ounces" || unit == "ounce") {
									conversions.Add ($"{(val * 28.3495):N2} g");
									conversions.Add ($"{(val / 35.274):N2} kg");
								}
								// Distance/Length
								else if (unit == "km" || unit == "kilometers" || unit == "kilometer") {
									conversions.Add ($"{(val * 0.621371):N2} miles");
									conversions.Add ($"{(val * 1000.0):N2} m");
								} else if (unit == "m" || unit == "meters" || unit == "meter") {
									conversions.Add ($"{(val * 3.28084):N2} feet");
									conversions.Add ($"{(val * 100.0):N2} cm");
								} else if (unit == "miles" || unit == "mile" || unit == "mi") {
									conversions.Add ($"{(val * 1.60934):N2} km");
								} else if (unit == "cm" || unit == "centimeters" || unit == "centimeter") {
									conversions.Add ($"{(val / 2.54):N2} inches");
									conversions.Add ($"{(val / 100.0):N2} m");
								} else if (unit == "inches" || unit == "inch" || unit == "in") {
									conversions.Add ($"{(val * 2.54):N2} cm");
								}
								// Temperature
								else if (unit == "c" || unit == "°c") {
									conversions.Add ($"{(val * 9.0 / 5.0 + 32.0):N2} °F");
								} else if (unit == "f" || unit == "°f") {
									conversions.Add ($"{((val - 32.0) * 5.0 / 9.0):N2} °C");
								}
								// Currency
								else if (unit == "usd" || unit == "$") {
									conversions.Add ($"€{(val * 0.92):N2}");
									conversions.Add ($"£{(val * 0.78):N2}");
									conversions.Add ($"₹{(val * 83.5):N2}");
								} else if (unit == "eur" || unit == "€") {
									conversions.Add ($"${(val * 1.08):N2}");
									conversions.Add ($"£{(val * 0.85):N2}");
								} else if (unit == "gbp" || unit == "£") {
									conversions.Add ($"${(val * 1.28):N2}");
									conversions.Add ($"€{(val * 1.18):N2}");
								} else if (unit == "inr" || unit == "₹" || unit == "rs" || unit == "rupees") {
									conversions.Add ($"${(val / 83.5):N2}");
								}

								foreach (var conv in conversions) {
									matches.Add (new SearchResultItem {
										Name = $"Conversion: {conv}",
										Path = "action://copypaste_" + conv,
										IsAction = true
									});
								}
							}
						}

						// 3. Flight details (e.g. UA123)
						bool isFlight = false;
						string flightInfo = "";
						if (System.Text.RegularExpressions.Regex.IsMatch (query, @"^[a-zA-Z]{2}\d{1,4}$")) {
							string flightNum = query.ToUpper ();
							flightInfo = flightNum + ": On Time. Departs 10:30 AM (T2, Gate C14), Arrives 1:45 PM (Terminal A)";
							isFlight = true;
						}
						
						if (isFlight) {
							matches.Add (new SearchResultItem {
								Name = flightInfo,
								Path = "action://flight_" + query.ToUpper (),
								IsAction = true
							});
						}

						// 3b. F1 Queries & Driver/Team Standings
						string qLower = query.ToLower ();
						if (qLower.Contains ("f1") || qLower.Contains ("formula 1") ||
							qLower.Contains ("verstappen") || qLower.Contains ("hamilton") || qLower.Contains ("leclerc") ||
							qLower.Contains ("norris") || qLower.Contains ("sainz") || qLower.Contains ("piastri") ||
							qLower.Contains ("albon") || qLower.Contains ("antonelli") || qLower.Contains ("perez") ||
							qLower.Contains ("hulkenberg") || qLower.Contains ("alonso") || qLower.Contains ("russell") ||
							qLower.Contains ("gasly") || qLower.Contains ("ocon") || qLower.Contains ("ferrari") ||
							qLower.Contains ("red bull") || qLower.Contains ("mclaren") || qLower.Contains ("mercedes") ||
							qLower.Contains ("aston martin") || qLower.Contains ("williams") || qLower.Contains ("alpine") ||
							qLower.Contains ("haas") || qLower.Contains ("sauber") || qLower.Contains ("audi") || qLower.Contains ("racing bulls")) {

							matches.Add (new SearchResultItem {
								Name = "F1 Standings & Stats: " + query,
								Path = "action://f1_query?" + query,
								IsAction = true
							});
						}

						// 4. Clipboard history check
						if (query.Equals ("clip", StringComparison.OrdinalIgnoreCase) || 
							query.Equals ("clipboard", StringComparison.OrdinalIgnoreCase) || 
							query.Equals ("cb", StringComparison.OrdinalIgnoreCase)) {
							foreach (string clipItem in _clipboardHistory) {
								if (currentGen != searchGen) return;
								string display = clipItem;
								if (display.Length > 60) display = display.Substring (0, 57) + "...";
								matches.Add (new SearchResultItem {
									Name = display,
									Path = clipItem,
									IsClipboard = true
								});
							}
						}

						// 5. Quick actions check
						List<SearchResultItem> actionItems = GetQuickActions (query);
						foreach (var action in actionItems) {
							if (currentGen != searchGen) return;
							matches.Add (action);
						}

						matches = SearchEngine.Search (query, matches);
						HashSet<string> hashSet = new HashSet<string> (matches.Select (m => m.Name), StringComparer.OrdinalIgnoreCase);

						if (webTask != null) {
							try {
								if (webTask.Wait (800)) {
									List<string> suggestions = webTask.Result;
									foreach (string suggestion in suggestions) {
										if (currentGen != searchGen) {
											return;
										}
										if (!hashSet.Contains (suggestion)) {
											matches.Add (new SearchResultItem {
												Name = suggestion,
												Path = suggestion,
												IsWebSuggestion = true
											});
										}
									}
								}
							} catch {}
						}

					} catch {
					}

					base.Dispatcher.BeginInvoke ((Action)delegate {

						if (currentGen == searchGen) {

							RenderResults (matches);

						}

					});

				});

			}

		}



		private void SearchRegistryApplications (string query, List<SearchResultItem> matches, HashSet<string> uniqueAppPaths, int currentGen, int searchGen)

		{

			try {

				string[] array = new string[2] { "SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\App Paths", "SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\App Paths" };

				foreach (string name in array) {

					if (currentGen != searchGen) {

						return;

					}

					try {

						using RegistryKey registryKey = Registry.LocalMachine.OpenSubKey (name);

						if (registryKey == null) {

							continue;

						}

						string[] subKeyNames = registryKey.GetSubKeyNames ();

						foreach (string text in subKeyNames) {

							if (currentGen != searchGen) {

								return;

							}

							string fileNameWithoutExtension = System.IO.Path.GetFileNameWithoutExtension (text);

							if (!text.ToLower ().Contains (query.ToLower ()) && !fileNameWithoutExtension.ToLower ().Contains (query.ToLower ())) {

								continue;

							}

							using RegistryKey registryKey2 = registryKey.OpenSubKey (text);

							if (registryKey2 == null) {

								continue;

							}

							object value = registryKey2.GetValue ("");

							if (value != null) {

								string path = value.ToString ().Trim ('"', ' ');

								if (File.Exists (path) && uniqueAppPaths.Add (fileNameWithoutExtension)) {

									matches.Add (new SearchResultItem {

										Name = fileNameWithoutExtension,

										Path = path,

										IsApp = true

									});

								}

							}

						}

					} catch {

					}

				}

				var array2 = new[] {

					new {

						Root = Registry.LocalMachine,

						Path = "SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall"

					},

					new {

						Root = Registry.LocalMachine,

						Path = "SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\Uninstall"

					},

					new {

						Root = Registry.CurrentUser,

						Path = "SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall"

					}

				};

				foreach (var anon in array2) {

					if (currentGen != searchGen) {

						break;

					}

					try {

						using RegistryKey registryKey3 = anon.Root.OpenSubKey (anon.Path);

						if (registryKey3 == null) {

							continue;

						}

						array = registryKey3.GetSubKeyNames ();

						foreach (string name2 in array) {

							if (currentGen != searchGen) {

								return;

							}

							using RegistryKey registryKey4 = registryKey3.OpenSubKey (name2);

							if (registryKey4 == null) {

								continue;

							}

							object value2 = registryKey4.GetValue ("DisplayName");

							if (value2 == null) {

								continue;

							}

							string text2 = value2.ToString ();

							if (!text2.ToLower ().Contains (query.ToLower ())) {

								continue;

							}

							string text3 = null;

							object value3 = registryKey4.GetValue ("DisplayIcon");

							if (value3 != null) {

								string text4 = value3.ToString ().Split (',') [0].Trim ('"', ' ');

								if (File.Exists (text4) && text4.ToLower ().EndsWith (".exe")) {

									text3 = text4;

								}

							}

							if (string.IsNullOrEmpty (text3)) {

								object value4 = registryKey4.GetValue ("InstallLocation");

								if (value4 != null) {

									string path2 = value4.ToString ().Trim ('"', ' ');

									if (Directory.Exists (path2)) {

										string[] files = Directory.GetFiles (path2, "*.exe", SearchOption.TopDirectoryOnly);

										if (files.Length != 0) {

											text3 = files.OrderByDescending ((string f) => new FileInfo (f).Length).First ();

										}

									}

								}

							}

							if (!string.IsNullOrEmpty (text3) && File.Exists (text3) && uniqueAppPaths.Add (text2)) {

								matches.Add (new SearchResultItem {

									Name = text2,

									Path = text3,

									IsApp = true

								});

							}

						}

					} catch {

					}

				}

			} catch {

			}

		}



		private void RenderResults (List<SearchResultItem> matches)
		{
			_currentMatches = matches;
			resultsPanel.Children.Clear ();
			_rowElements.Clear ();
			_displayedItems.Clear ();

			List<SearchResultItem> filteredMatches;
			if (_activeFilter == "Apps") {
				filteredMatches = matches.FindAll (m => m.IsApp && !m.IsWebSuggestion && !m.IsAction && !m.IsClipboard);
			} else if (_activeFilter == "Files") {
				filteredMatches = matches.FindAll (m => (m.IsDirectory || (!m.IsApp && !m.IsDirectory)) && !m.IsWebSuggestion && !m.IsAction && !m.IsClipboard);
			} else if (_activeFilter == "Actions") {
				filteredMatches = matches.FindAll (m => m.IsAction && !m.Path.StartsWith ("action://f1_query?"));
			} else if (_activeFilter == "F1") {
				filteredMatches = matches.FindAll (m => m.IsAction && m.Path.StartsWith ("action://f1_query?"));
				if (filteredMatches.Count == 0) {
					filteredMatches = new List<SearchResultItem> {
						new SearchResultItem {
							Name = "Formula 1 Live Standings & Stats",
							Path = "action://f1_query?f1",
							IsAction = true
						}
					};
				}
			} else if (_activeFilter == "Clipboard") {
				filteredMatches = matches.FindAll (m => m.IsClipboard);
			} else {
				filteredMatches = matches;
			}

			if (filteredMatches.Count == 0) {
				string effectiveTheme = ownerWindow.GetEffectiveTheme ();
				bool isDark = (effectiveTheme == "dark" || effectiveTheme == "tahoe");

				TextBlock element = new TextBlock {
					Text = "No matching items in this category.",
					Foreground = new SolidColorBrush (isDark ? System.Windows.Media.Color.FromRgb (170, 175, 185) : System.Windows.Media.Color.FromRgb (130, 135, 145)),
					FontSize = 13.0,
					FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					Margin = new Thickness (0.0, 20.0, 0.0, 0.0)
				};
				resultsPanel.Children.Add (element);
				AnimateResults (true);
				return;
			}

			var apps = filteredMatches.FindAll (m => m.IsApp && !m.IsWebSuggestion && !m.IsAction && !m.IsClipboard);
			var folders = filteredMatches.FindAll (m => m.IsDirectory && !m.IsWebSuggestion && !m.IsAction && !m.IsClipboard);
			var documents = filteredMatches.FindAll (m => !m.IsApp && !m.IsDirectory && !m.IsWebSuggestion && !m.IsAction && !m.IsClipboard);
			var actions = filteredMatches.FindAll (m => m.IsAction);
			var clipboards = filteredMatches.FindAll (m => m.IsClipboard);
			var webSuggestions = filteredMatches.FindAll (m => m.IsWebSuggestion);

			if (apps.Count > 0) {
				AddCategorySection ("Applications", apps);
			}
			if (folders.Count > 0) {
				AddCategorySection ("Folders", folders);
			}
			if (documents.Count > 0) {
				AddCategorySection ("Documents & Files", documents);
			}
			if (actions.Count > 0) {
				AddCategorySection ("Quick Actions", actions);
			}
			if (clipboards.Count > 0) {
				AddCategorySection ("Clipboard History", clipboards);
			}
			if (webSuggestions.Count > 0) {
				AddCategorySection ("Google Search Suggestions", webSuggestions);
			}

			if (_rowElements.Count > 0) {
				_selectedIndex = 0;
				UpdateSelectionVisuals ();
			}

			AnimateResults (true);
		}

		private void AddCategorySection (string title, List<SearchResultItem> items)
		{
			string effectiveTheme = ownerWindow.GetEffectiveTheme ();
			bool isDark = (effectiveTheme == "dark" || effectiveTheme == "tahoe");

			TextBlock header = new TextBlock {
				Text = title.ToUpper (),
				Foreground = new SolidColorBrush (isDark ? System.Windows.Media.Color.FromRgb (170, 175, 185) : System.Windows.Media.Color.FromRgb (130, 135, 145)),
				FontSize = 10.0,
				FontWeight = FontWeights.Bold,
				FontFamily = SpotlightFont,
				Margin = new Thickness (4.0, 12.0, 0.0, 6.0)
			};
			resultsPanel.Children.Add (header);

			foreach (var match in items) {
				Border rowBorder = new Border {
					Background = System.Windows.Media.Brushes.Transparent,
					BorderBrush = System.Windows.Media.Brushes.Transparent,
					BorderThickness = new Thickness (1.0),
					CornerRadius = new CornerRadius (8.0),
					Padding = new Thickness (8.0, 6.0, 8.0, 6.0),
					Margin = new Thickness (0.0, 0.0, 0.0, 2.0),
					Cursor = System.Windows.Input.Cursors.Hand,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Stretch,
					Opacity = 0.0,
					RenderTransform = new TranslateTransform (0.0, 7.0)
				};

				Grid grid = new Grid ();
				grid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (28.0) });
				grid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (9.0) });
				grid.ColumnDefinitions.Add (new ColumnDefinition { Width = new GridLength (1.0, GridUnitType.Star) });

				FrameworkElement visualElement = null;
				if (match.IsWebSuggestion) {
					visualElement = CreateVectorWebIcon ();
				} else if (match.IsAction) {
					visualElement = CreateVectorActionIcon ();
				} else if (match.IsClipboard) {
					visualElement = CreateVectorClipboardIcon ();
				} else if (match.IsDirectory) {
					System.Windows.Controls.Image image = new System.Windows.Controls.Image {
						Width = 22.0,
						Height = 22.0,
						Stretch = Stretch.Uniform,
						VerticalAlignment = VerticalAlignment.Center,
						SnapsToDevicePixels = true,
						UseLayoutRounding = true
					};
					RenderOptions.SetBitmapScalingMode (image, BitmapScalingMode.HighQuality);
					RenderOptions.SetEdgeMode (image, EdgeMode.Unspecified);
					if (!string.IsNullOrEmpty (match.Path) && IconExtractor.GetCachedSearchIcon (match.Path, out var cachedFolder)) {
						match.Icon = cachedFolder;
						image.Source = cachedFolder;
					} else {
						image.Source = IconExtractor.GetWindowsFolderIcon () ?? IconExtractor.CreateFallbackIcon (match.Name);
						QueueIconExtraction (match, image);
					}
					visualElement = image;
				} else {
					System.Windows.Controls.Image image = new System.Windows.Controls.Image {
						Width = 22.0,
						Height = 22.0,
						Stretch = Stretch.Uniform,
						VerticalAlignment = VerticalAlignment.Center,
						SnapsToDevicePixels = true,
						UseLayoutRounding = true
					};
					RenderOptions.SetBitmapScalingMode (image, BitmapScalingMode.HighQuality);
					RenderOptions.SetEdgeMode (image, EdgeMode.Unspecified);
					if (match.Icon != null) {
						image.Source = match.Icon;
					} else if (!string.IsNullOrEmpty (match.Path) && IconExtractor.GetCachedSearchIcon (match.Path, out var cached)) {
						match.Icon = cached;
						image.Source = cached;
					} else {
						image.Source = IconExtractor.CreateFallbackIcon (match.Name);
						QueueIconExtraction (match, image);
					}
					visualElement = image;
				}

				Grid.SetColumn (visualElement, 0);
				grid.Children.Add (visualElement);

				StackPanel stackPanel = new StackPanel { VerticalAlignment = VerticalAlignment.Center };
				TextBlock element2 = new TextBlock {
					Text = match.Name,
					Foreground = isDark ? System.Windows.Media.Brushes.White : new SolidColorBrush (System.Windows.Media.Color.FromRgb (40, 40, 40)),
					FontSize = 13.5,
					FontWeight = FontWeights.Medium,
					FontFamily = SpotlightFont
				};

				TextBlock element3 = new TextBlock {
					Text = match.IsWebSuggestion ? "Search Google" : match.Path,
					Foreground = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (170, 175, 185)) : new SolidColorBrush (System.Windows.Media.Color.FromRgb (120, 125, 135)),
					FontSize = 10.5,
					FontFamily = SpotlightFont,
					TextTrimming = TextTrimming.CharacterEllipsis,
					Margin = new Thickness (0.0, 1.0, 0.0, 0.0)
				};

				stackPanel.Children.Add (element2);
				stackPanel.Children.Add (element3);

				Grid.SetColumn (stackPanel, 2);
				grid.Children.Add (stackPanel);

				rowBorder.Child = grid;

				_rowElements.Add (rowBorder);
				_displayedItems.Add (match);

				int indexForHover = _rowElements.Count - 1;
				rowBorder.MouseEnter += delegate {
					_selectedIndex = indexForHover;
					UpdateSelectionVisuals ();
				};

				rowBorder.PreviewMouseLeftButtonDown += delegate {
					ExecuteItem (match);
				};

				resultsPanel.Children.Add (rowBorder);

				TimeSpan begin = TimeSpan.FromMilliseconds (Math.Min (120.0, indexForHover * 12.0));
				rowBorder.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation {
					To = 1.0,
					BeginTime = begin,
					Duration = TimeSpan.FromMilliseconds (150),
					EasingFunction = new CubicEase { EasingMode = EasingMode.EaseOut }
				});
				if (rowBorder.RenderTransform is TranslateTransform rowTransform) {
					rowTransform.BeginAnimation (TranslateTransform.YProperty, new DoubleAnimation {
						To = 0.0,
						BeginTime = begin,
						Duration = TimeSpan.FromMilliseconds (190),
						EasingFunction = new QuinticEase { EasingMode = EasingMode.EaseOut }
					});
				}
			}
		}

		private void QueueIconExtraction (SearchResultItem match, System.Windows.Controls.Image targetImage)
		{
			if (string.IsNullOrEmpty (match.Path)) return;

			if (IconExtractor.GetCachedSearchIcon (match.Path, out var cached)) {
				match.Icon = cached;
				targetImage.Source = cached;
				return;
			}

			int genAtStart = searchGen;
			ThreadPool.QueueUserWorkItem (delegate {
				try {
					if (genAtStart != searchGen) return;

					ImageSource icon = null;
					if (match.IsDirectory) {
						icon = IconExtractor.GetJumboIcon (match.Path);
					} else {
						icon = IconExtractor.ExtractHighQualityIconForSearch (match);
					}

					if (icon != null) {
						icon.Freeze ();
						IconExtractor.CacheSearchIcon (match.Path, icon);
						base.Dispatcher.BeginInvoke ((Action)delegate {
							if (genAtStart == searchGen) {
								match.Icon = icon;
								targetImage.Source = icon;
							}
						});
					}
				} catch {}
			});
		}

		public class SmoothScrollHelper
		{
			private readonly ScrollViewer _scrollViewer;
			private readonly Func<double> _blurAmountProvider;
			private double _targetOffset;
			private double _currentOffset;
			private bool _isAnimating;
			private System.Windows.Media.Effects.BlurEffect _blurEffect;

			public SmoothScrollHelper (ScrollViewer scrollViewer, Func<double> blurAmountProvider = null)
			{
				_scrollViewer = scrollViewer;
				_blurAmountProvider = blurAmountProvider;
				_scrollViewer.PreviewMouseWheel += OnPreviewMouseWheel;
			}

			private void OnPreviewMouseWheel (object sender, MouseWheelEventArgs e)
			{
				e.Handled = true;
				double scrollDelta = -(e.Delta * 0.8);
				
				if (!_isAnimating) {
					_currentOffset = _scrollViewer.VerticalOffset;
					_targetOffset = _currentOffset;
				}

				_targetOffset += scrollDelta;
				_targetOffset = Math.Max (0, Math.Min (_targetOffset, _scrollViewer.ScrollableHeight));

				if (!_isAnimating) {
					_isAnimating = true;
					CompositionTarget.Rendering += UpdateScroll;
				}
			}

			private void UpdateScroll (object sender, EventArgs e)
			{
				if (!_isAnimating) return;

				double diff = _targetOffset - _currentOffset;
				if (Math.Abs (diff) < 0.2) {
					_currentOffset = _targetOffset;
					_scrollViewer.ScrollToVerticalOffset (_currentOffset);
					CompositionTarget.Rendering -= UpdateScroll;
					_isAnimating = false;
					ClearBlur ();
				} else {
					double step = diff * 0.25;
					_currentOffset += step;
					_scrollViewer.ScrollToVerticalOffset (_currentOffset);
					ApplyBlur (Math.Abs (step));
				}
			}

			private void ApplyBlur (double velocity)
			{
				double blurMultiplier = (_blurAmountProvider != null) ? _blurAmountProvider () : 1.0;
				double radius = Math.Min (8.0, velocity * 0.12) * blurMultiplier;
				if (radius > 0.3) {
					if (_blurEffect == null) {
						_blurEffect = new System.Windows.Media.Effects.BlurEffect {
							KernelType = System.Windows.Media.Effects.KernelType.Gaussian,
							RenderingBias = System.Windows.Media.Effects.RenderingBias.Performance
						};
					}
					_blurEffect.Radius = radius;
					if (_scrollViewer.Content is UIElement element && element.Effect != _blurEffect) {
						element.Effect = _blurEffect;
					}
				} else {
					ClearBlur ();
				}
			}

			private void ClearBlur ()
			{
				if (_scrollViewer.Content is UIElement element && element.Effect != null) {
					element.Effect = null;
				}
			}
		}

		private static T FindVisualChild<T> (System.Windows.DependencyObject parent) where T : System.Windows.DependencyObject
		{
			for (int i = 0; i < System.Windows.Media.VisualTreeHelper.GetChildrenCount (parent); i++) {
				var child = System.Windows.Media.VisualTreeHelper.GetChild (parent, i);
				if (child is T t) return t;
				var result = FindVisualChild<T> (child);
				if (result != null) return result;
			}
			return null;
		}

		private void ApplyMacOSScrollBarStyle (ScrollViewer sv)
		{
			try {
				string xaml = @"
<Style xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation'
       xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml'
       TargetType='{x:Type ScrollBar}'>
    <Setter Property='Width' Value='4'/>
    <Setter Property='MinWidth' Value='4'/>
    <Setter Property='Background' Value='Transparent'/>
    <Setter Property='Opacity' Value='0'/>
    <Setter Property='Template'>
        <Setter.Value>
            <ControlTemplate TargetType='{x:Type ScrollBar}'>
                <Grid Background='Transparent' Width='4' Margin='0,6,2,6'>
                    <Track Name='PART_Track' IsDirectionReversed='true'>
                        <Track.DecreaseRepeatButton>
                            <RepeatButton Command='ScrollBar.PageUpCommand' Opacity='0' Height='0'/>
                        </Track.DecreaseRepeatButton>
                        <Track.IncreaseRepeatButton>
                            <RepeatButton Command='ScrollBar.PageDownCommand' Opacity='0' Height='0'/>
                        </Track.IncreaseRepeatButton>
                        <Track.Thumb>
                            <Thumb>
                                <Thumb.Template>
                                    <ControlTemplate TargetType='{x:Type Thumb}'>
                                        <Border CornerRadius='2' Background='#60FFFFFF'/>
                                    </ControlTemplate>
                                </Thumb.Template>
                            </Thumb>
                        </Track.Thumb>
                    </Track>
                </Grid>
            </ControlTemplate>
        </Setter.Value>
    </Setter>
</Style>";
				Style style = (Style)XamlReader.Parse (xaml);
				sv.Resources.Add (typeof(System.Windows.Controls.Primitives.ScrollBar), style);

				// Fade-in on scroll, fade-out after idle
				System.Threading.Timer fadeOutTimer = null;
				sv.ScrollChanged += delegate {
					sv.Dispatcher.BeginInvoke ((Action)delegate {
						var vBar = FindVisualChild<System.Windows.Controls.Primitives.ScrollBar> (sv);
						if (vBar == null) return;
						vBar.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (100)));
						fadeOutTimer?.Dispose ();
						fadeOutTimer = new System.Threading.Timer (delegate {
							sv.Dispatcher.BeginInvoke ((Action)delegate {
								var b = FindVisualChild<System.Windows.Controls.Primitives.ScrollBar> (sv);
								if (b != null) b.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (500)));
							});
							fadeOutTimer?.Dispose ();
						}, null, 1000, System.Threading.Timeout.Infinite);
					});
				};
			} catch {
			}
		}
	}

	public class StackOverlayWindow : Window
	{
		private DockWindow parent;
		private string folderPath;
		private List<string> items = new List<string> ();
		private string viewMode = "Fan";
		private Grid mainGrid;

		internal struct WinCompositionAttrData
		{
			public int Attribute;
			public IntPtr Data;
			public int SizeOfData;
		}

		internal struct AccentPolicy
		{
			public int AccentState;
			public int AccentFlags;
			public int GradientColor;
			public int AnimationId;
		}

		[DllImport ("user32.dll")]
		internal static extern int SetWindowCompositionAttribute (IntPtr hwnd, ref WinCompositionAttrData data);

		public void EnableBlur (bool enable)
		{
			try {
				IntPtr handle = new WindowInteropHelper (this).Handle;
				if (handle != IntPtr.Zero) {
					AccentPolicy structure = default(AccentPolicy);
					structure.AccentState = (enable ? 3 : 0);
					if (enable) {
						structure.AccentFlags = 2;
						double blurAmount = (parent != null && parent.settings != null) ? parent.settings.BlurAmount : 0.7;
						bool isDark = (parent != null && parent.settings != null) ? (parent.settings.Theme.ToLower () == "dark" || parent.settings.Theme.ToLower () == "tahoe") : true;
						byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);
						uint colorVal = isDark ? 0x1A1A1AU : 0xF2F2F7U;
						structure.GradientColor = (int)(((uint)alpha << 24) | (colorVal & 0x00FFFFFF));
					}
					int num = Marshal.SizeOf (structure);
					IntPtr intPtr = Marshal.AllocHGlobal (num);
					Marshal.StructureToPtr (structure, intPtr, fDeleteOld: false);
					WinCompositionAttrData data = default(WinCompositionAttrData);
					data.Attribute = 19;
					data.SizeOfData = num;
					data.Data = intPtr;
					SetWindowCompositionAttribute (handle, ref data);
					Marshal.FreeHGlobal (intPtr);
				}
			} catch {}
		}

		public StackOverlayWindow (DockWindow parent, string folderPath, string viewMode)
		{
			this.parent = parent;
			this.folderPath = folderPath;
			this.viewMode = viewMode;
			base.AllowsTransparency = true;
			base.WindowStyle = WindowStyle.None;
			base.Background = System.Windows.Media.Brushes.Transparent;
			base.Topmost = true;
			base.ShowInTaskbar = false;
			base.Width = 420.0;
			base.Height = 480.0;

			base.Deactivated += delegate {
				try { Close (); } catch { }
			};

			base.Loaded += delegate {
				EnableBlur (true);
			};

			mainGrid = new Grid ();
			base.Content = mainGrid;
			LoadDirectoryContents ();
			BuildUI ();
		}

		private void LoadDirectoryContents ()
		{
			items.Clear ();
			try {
				if (string.IsNullOrEmpty (folderPath) || !Directory.Exists (folderPath)) return;

				string[] directories = Directory.GetDirectories (folderPath);
				foreach (string d in directories) {
					try {
						if ((File.GetAttributes (d) & FileAttributes.Hidden) == 0) {
							items.Add (d);
							if (items.Count >= 36) break;
						}
					} catch { }
				}

				if (items.Count < 36) {
					string[] files = Directory.GetFiles (folderPath);
					foreach (string f in files) {
						try {
							if ((File.GetAttributes (f) & FileAttributes.Hidden) == 0) {
								items.Add (f);
								if (items.Count >= 36) break;
							}
						} catch { }
					}
				}
			} catch { }
		}

		private void BuildUI ()
		{
			mainGrid.Children.Clear ();

			bool isDark = (parent == null || parent.settings == null || parent.settings.Theme.ToLower () != "light");
			System.Windows.Media.Brush foreground = isDark ? System.Windows.Media.Brushes.White : System.Windows.Media.Brushes.Black;
			System.Windows.Media.Brush subForeground = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (160, 0, 0, 0));

			Border glassContainer = new Border {
				CornerRadius = new CornerRadius (20.0),
				Background = isDark 
					? new SolidColorBrush (System.Windows.Media.Color.FromArgb (235, 24, 24, 26))
					: new SolidColorBrush (System.Windows.Media.Color.FromArgb (235, 248, 248, 250)),
				BorderBrush = isDark
					? new SolidColorBrush (System.Windows.Media.Color.FromArgb (70, 255, 255, 255))
					: new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, 0, 0, 0)),
				BorderThickness = new Thickness (1.2),
				Padding = new Thickness (16.0),
				Margin = new Thickness (0.0)
			};

			if (parent == null || parent.settings == null || !parent.settings.PerformanceMode) {
				glassContainer.Effect = new DropShadowEffect {
					BlurRadius = 24.0,
					ShadowDepth = 6.0,
					Opacity = 0.35,
					Color = Colors.Black
				};
			}

			Grid rootLayout = new Grid ();
			rootLayout.RowDefinitions.Add (new RowDefinition { Height = GridLength.Auto });
			rootLayout.RowDefinitions.Add (new RowDefinition { Height = new GridLength (1.0, GridUnitType.Star) });

			// Header Bar
			Grid headerGrid = new Grid { Margin = new Thickness (0, 0, 0, 12) };
			string folderName = System.IO.Path.GetFileName (folderPath);
			if (string.IsNullOrEmpty (folderName)) folderName = folderPath;

			TextBlock titleText = new TextBlock {
				Text = folderName,
				Foreground = foreground,
				FontSize = 15.0,
				FontWeight = FontWeights.SemiBold,
				FontFamily = new System.Windows.Media.FontFamily ("SF Pro Display, Segoe UI, sans-serif"),
				VerticalAlignment = VerticalAlignment.Center
			};

			Border badge = new Border {
				CornerRadius = new CornerRadius (10.0),
				Background = isDark ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (40, 255, 255, 255)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, 0, 0, 0)),
				Padding = new Thickness (8, 2, 8, 2),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
				VerticalAlignment = VerticalAlignment.Center
			};

			TextBlock badgeText = new TextBlock {
				Text = items.Count + " items",
				Foreground = subForeground,
				FontSize = 11.0,
				FontWeight = FontWeights.Medium,
				FontFamily = new System.Windows.Media.FontFamily ("SF Pro Text, Segoe UI, sans-serif")
			};
			badge.Child = badgeText;

			headerGrid.Children.Add (titleText);
			headerGrid.Children.Add (badge);
			Grid.SetRow (headerGrid, 0);
			rootLayout.Children.Add (headerGrid);

			// Items View
			ScrollViewer scrollViewer = new ScrollViewer {
				VerticalScrollBarVisibility = ScrollBarVisibility.Hidden,
				HorizontalScrollBarVisibility = ScrollBarVisibility.Disabled
			};
			Grid.SetRow (scrollViewer, 1);

			WrapPanel wrapPanel = new WrapPanel { Orientation = System.Windows.Controls.Orientation.Horizontal };
			scrollViewer.Content = wrapPanel;
			rootLayout.Children.Add (scrollViewer);
			glassContainer.Child = rootLayout;
			mainGrid.Children.Add (glassContainer);

			for (int i = 0; i < items.Count; i++) {
				string path = items [i];
				string fileName = System.IO.Path.GetFileName (path);

				Border itemCard = new Border {
					Width = 110.0,
					Height = 96.0,
					Margin = new Thickness (5.0),
					CornerRadius = new CornerRadius (12.0),
					Background = System.Windows.Media.Brushes.Transparent,
					Cursor = System.Windows.Input.Cursors.Hand,
					ToolTip = fileName
				};

				StackPanel cardContent = new StackPanel { VerticalAlignment = VerticalAlignment.Center };
				itemCard.Child = cardContent;

				System.Windows.Controls.Image itemImg = new System.Windows.Controls.Image {
					Width = 44.0,
					Height = 44.0,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					Margin = new Thickness (0, 0, 0, 6)
				};
				cardContent.Children.Add (itemImg);

				TextBlock itemLabel = new TextBlock {
					Text = fileName,
					Foreground = foreground,
					FontSize = 11.0,
					FontWeight = FontWeights.Medium,
					FontFamily = new System.Windows.Media.FontFamily ("SF Pro Text, Segoe UI, sans-serif"),
					TextTrimming = TextTrimming.CharacterEllipsis,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					TextAlignment = TextAlignment.Center,
					Margin = new Thickness (4, 0, 4, 0)
				};
				cardContent.Children.Add (itemLabel);

				string closurePath = path;
				System.Windows.Controls.Image closureImg = itemImg;
				ThreadPool.QueueUserWorkItem (delegate {
					ImageSource icon = null;
					try {
						icon = IconExtractor.GetShellItemIcon (closurePath);
					} catch { }

					try {
						base.Dispatcher.BeginInvoke ((Action)delegate {
							if (icon != null) {
								closureImg.Source = icon;
							}
						});
					} catch { }
				});

				ScaleTransform cardScale = new ScaleTransform (1.0, 1.0);
				itemCard.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);
				itemCard.RenderTransform = cardScale;

				itemCard.MouseEnter += delegate {
					itemCard.Background = isDark 
						? new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, 255, 255, 255))
						: new SolidColorBrush (System.Windows.Media.Color.FromArgb (40, 0, 0, 0));
					cardScale.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.0, 1.05, TimeSpan.FromMilliseconds (120)));
					cardScale.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.0, 1.05, TimeSpan.FromMilliseconds (120)));
				};

				itemCard.MouseLeave += delegate {
					itemCard.Background = System.Windows.Media.Brushes.Transparent;
					cardScale.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.05, 1.0, TimeSpan.FromMilliseconds (150)));
					cardScale.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.05, 1.0, TimeSpan.FromMilliseconds (150)));
				};

				string launchPath = path;
				itemCard.MouseLeftButtonDown += delegate {
					try {
						Process.Start (new ProcessStartInfo (launchPath) { UseShellExecute = true });
					} catch { }
					try { Close (); } catch { }
				};

				wrapPanel.Children.Add (itemCard);
			}

			// Entrance Animation
			ScaleTransform windowScale = new ScaleTransform (0.94, 0.94);
			glassContainer.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);
			glassContainer.RenderTransform = windowScale;
			glassContainer.Opacity = 0.0;

			if (parent == null || parent.settings == null || !parent.settings.PerformanceMode) {
				glassContainer.BeginAnimation (UIElement.OpacityProperty, new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (180)));
				windowScale.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (0.94, 1.0, TimeSpan.FromMilliseconds (240)) {
					EasingFunction = new CubicEase { EasingMode = EasingMode.EaseOut }
				});
				windowScale.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (0.94, 1.0, TimeSpan.FromMilliseconds (240)) {
					EasingFunction = new CubicEase { EasingMode = EasingMode.EaseOut }
				});
			} else {
				glassContainer.Opacity = 1.0;
				windowScale.ScaleX = 1.0;
				windowScale.ScaleY = 1.0;
			}
		}

	}

