	public static class SystemControls

	{

		[StructLayout (LayoutKind.Sequential, CharSet = CharSet.Auto)]

		private class MEMORYSTATUSEX

		{

			public uint dwLength;



			public uint dwMemoryLoad;



			public ulong ullTotalPhys;



			public ulong ullAvailPhys;



			public ulong ullTotalPageFile;



			public ulong ullAvailPageFile;



			public ulong ullTotalVirtual;



			public ulong ullAvailVirtual;



			public ulong ullAvailExtendedVirtual;



			public MEMORYSTATUSEX ()

			{

				dwLength = (uint)Marshal.SizeOf (typeof(MEMORYSTATUSEX));

			}

		}



		private struct SYSTEM_POWER_STATUS

		{

			public byte ACLineStatus;



			public byte BatteryFlag;



			public byte BatteryLifePercent;



			public byte Reserved1;



			public uint BatteryLifeTime;



			public uint BatteryFullLifeTime;

		}



		private static System.Runtime.InteropServices.ComTypes.FILETIME _prevIdle;



		private static System.Runtime.InteropServices.ComTypes.FILETIME _prevKernel;



		private static System.Runtime.InteropServices.ComTypes.FILETIME _prevUser;



		private static bool _hasPrevCpu;



		[DllImport ("kernel32.dll", SetLastError = true)]

		[return: MarshalAs (UnmanagedType.Bool)]

		private static extern bool GetSystemTimes (out System.Runtime.InteropServices.ComTypes.FILETIME lpIdleTime, out System.Runtime.InteropServices.ComTypes.FILETIME lpKernelTime, out System.Runtime.InteropServices.ComTypes.FILETIME lpUserTime);



		[DllImport ("kernel32.dll", CharSet = CharSet.Auto, SetLastError = true)]

		[return: MarshalAs (UnmanagedType.Bool)]

		private static extern bool GlobalMemoryStatusEx ([In][Out] MEMORYSTATUSEX lpBuffer);



		[DllImport ("kernel32.dll", SetLastError = true)]

		private static extern bool GetSystemPowerStatus (out SYSTEM_POWER_STATUS lpSystemPowerStatus);



		private static IAudioEndpointVolume GetMasterVolumeController ()

		{

			try {

				if ((new MMDeviceEnumerator () as IMMDeviceEnumerator).GetDefaultAudioEndpoint (0, 0, out var ppEndpoint) == 0 && ppEndpoint != null) {

					Guid iid = new Guid ("5CDF2C82-841E-4546-9722-0CF74078229A");

					if (ppEndpoint.Activate (ref iid, 23, IntPtr.Zero, out var ppInterface) == 0) {

						return ppInterface as IAudioEndpointVolume;

					}

				}

			} catch {

			}

			return null;

		}



		public static float GetSystemVolume ()

		{

			try {

				IAudioEndpointVolume masterVolumeController = GetMasterVolumeController ();

				if (masterVolumeController != null && masterVolumeController.GetMasterVolumeLevelScalar (out var level) == 0) {

					return level;

				}

			} catch {

			}

			return 0.5f;

		}



		public static void SetSystemVolume (float level)

		{

			try {

				IAudioEndpointVolume masterVolumeController = GetMasterVolumeController ();

				if (masterVolumeController != null) {

					Guid eventContext = Guid.Empty;

					masterVolumeController.SetMasterVolumeLevelScalar (level, ref eventContext);

				}

			} catch {

			}

		}



		public static int GetScreenBrightness ()

		{

			try {

				using ManagementObjectSearcher managementObjectSearcher = new ManagementObjectSearcher (new ManagementScope ("\\\\.\\Root\\WMI"), new SelectQuery ("SELECT * FROM WmiMonitorBrightness"));

				using ManagementObjectCollection managementObjectCollection = managementObjectSearcher.Get ();

				using ManagementObjectCollection.ManagementObjectEnumerator managementObjectEnumerator = managementObjectCollection.GetEnumerator ();

				if (managementObjectEnumerator.MoveNext ()) {

					return int.Parse (((ManagementObject)managementObjectEnumerator.Current) ["CurrentBrightness"].ToString ());

				}

			} catch {

			}

			return 80;

		}



		public static void SetScreenBrightness (int percent)

		{

			try {

				using ManagementObjectSearcher managementObjectSearcher = new ManagementObjectSearcher (new ManagementScope ("\\\\.\\Root\\WMI"), new SelectQuery ("SELECT * FROM WmiMonitorBrightnessMethods"));

				using ManagementObjectCollection managementObjectCollection = managementObjectSearcher.Get ();

				foreach (ManagementObject item in managementObjectCollection) {

					item.InvokeMethod ("WmiSetBrightness", new object[2] {

						uint.MaxValue,

						(byte)percent

					});

				}

			} catch {

			}

		}



		public static double GetCpuUsage ()

		{

			if (GetSystemTimes (out var lpIdleTime, out var lpKernelTime, out var lpUserTime)) {

				ulong num = (ulong)(((long)lpIdleTime.dwHighDateTime << 32) | (uint)lpIdleTime.dwLowDateTime);

				ulong num2 = (ulong)(((long)lpKernelTime.dwHighDateTime << 32) | (uint)lpKernelTime.dwLowDateTime);

				ulong num3 = (ulong)(((long)lpUserTime.dwHighDateTime << 32) | (uint)lpUserTime.dwLowDateTime);

				if (_hasPrevCpu) {

					ulong num4 = (ulong)(((long)_prevIdle.dwHighDateTime << 32) | (uint)_prevIdle.dwLowDateTime);

					ulong num5 = (ulong)(((long)_prevKernel.dwHighDateTime << 32) | (uint)_prevKernel.dwLowDateTime);

					ulong num6 = (ulong)(((long)_prevUser.dwHighDateTime << 32) | (uint)_prevUser.dwLowDateTime);

					ulong num7 = num - num4;

					ulong num8 = num2 - num5;

					ulong num9 = num3 - num6;

					ulong num10 = num8 + num9;

					if (num10 != 0) {

						double val = (double)(num10 - num7) / (double)num10;

						_prevIdle = lpIdleTime;

						_prevKernel = lpKernelTime;

						_prevUser = lpUserTime;

						return Math.Max (0.0, Math.Min (1.0, val)) * 100.0;

					}

				}

				_prevIdle = lpIdleTime;

				_prevKernel = lpKernelTime;

				_prevUser = lpUserTime;

				_hasPrevCpu = true;

			}

			return 15.0;

		}



		public static double GetRamUsage ()

		{

			MEMORYSTATUSEX mEMORYSTATUSEX = new MEMORYSTATUSEX ();

			if (GlobalMemoryStatusEx (mEMORYSTATUSEX)) {

				return mEMORYSTATUSEX.dwMemoryLoad;

			}

			return 45.0;

		}



		public static double GetBatteryPercent (out bool isCharging)

		{

			isCharging = false;

			if (GetSystemPowerStatus (out var lpSystemPowerStatus)) {

				isCharging = lpSystemPowerStatus.ACLineStatus == 1;

				if (lpSystemPowerStatus.BatteryLifePercent != byte.MaxValue) {

					return (int)lpSystemPowerStatus.BatteryLifePercent;

				}

			}

			return 100.0;

		}

	}

