		private StackPanel CreateGaugeStack (string label, out System.Windows.Shapes.Path ringPath, out TextBlock pctTxt)

		{

			StackPanel obj = new StackPanel {

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				VerticalAlignment = VerticalAlignment.Center

			};

			TextBlock element = new TextBlock {

				Text = label,

				Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (170, 170, 170)),

				FontSize = 9.0,

				FontWeight = FontWeights.Bold,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				Margin = new Thickness (0.0, 0.0, 0.0, 4.0)

			};

			obj.Children.Add (element);

			Grid grid = new Grid {

				Width = 52.0,

				Height = 52.0

			};

			obj.Children.Add (grid);

			Ellipse element2 = new Ellipse {

				Stroke = new SolidColorBrush (System.Windows.Media.Color.FromArgb (40, byte.MaxValue, byte.MaxValue, byte.MaxValue)),

				StrokeThickness = 3.5,

				Width = 46.0,

				Height = 46.0

			};

			grid.Children.Add (element2);

			ringPath = new System.Windows.Shapes.Path {

				Stroke = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue)),

				StrokeThickness = 3.5,

				StrokeStartLineCap = PenLineCap.Round,

				StrokeEndLineCap = PenLineCap.Round,

				Width = 52.0,

				Height = 52.0

			};

			grid.Children.Add (ringPath);

			pctTxt = new TextBlock {

				Text = "--%",

				Foreground = System.Windows.Media.Brushes.White,

				FontSize = 9.5,

				FontWeight = FontWeights.Bold,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				VerticalAlignment = VerticalAlignment.Center

			};

			grid.Children.Add (pctTxt);

			return obj;

		}



		private void UpdateMetrics ()

		{

			try {

				double cpuUsage = SystemControls.GetCpuUsage ();

				double ramUsage = SystemControls.GetRamUsage ();

				bool isCharging;

				double batteryPercent = SystemControls.GetBatteryPercent (out isCharging);

				cpuTxt.Text = $"{cpuUsage:0}%";

				ramTxt.Text = $"{ramUsage:0}%";

				batTxt.Text = $"{batteryPercent:0}%";

				UpdateGaugeArc (cpuRing, cpuUsage / 100.0, System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue));

				UpdateGaugeArc (ramRing, ramUsage / 100.0, System.Windows.Media.Color.FromRgb (155, 89, 182));

				System.Windows.Media.Color col = ((batteryPercent < 20.0) ? System.Windows.Media.Color.FromRgb (231, 76, 60) : (isCharging ? System.Windows.Media.Color.FromRgb (46, 204, 113) : System.Windows.Media.Color.FromRgb (241, 196, 15)));

				UpdateGaugeArc (batRing, batteryPercent / 100.0, col);

			} catch {

			}

		}



		private void UpdateGaugeArc (System.Windows.Shapes.Path ring, double percent, System.Windows.Media.Color col)

		{

			ring.Stroke = new SolidColorBrush (col);

			double num = percent * 359.9;

			double num2 = (num - 90.0) * Math.PI / 180.0;

			double num3 = 26.0;

			double num4 = 26.0;

			double num5 = 23.0;

			double num6 = num3 + Math.Cos (num2) * num5;

			double num7 = num4 + Math.Sin (num2) * num5;

			string source = string.Format (CultureInfo.InvariantCulture, "M {0} {1} A {2} {2} 0 {3} 1 {4} {5}", num3, num4 - num5, num5, (num > 180.0) ? 1 : 0, num6, num7);

			if (percent >= 0.999) {

				source = string.Format (CultureInfo.InvariantCulture, "M {0} {1} A {2} {2} 0 1 1 {3} {4}", num3, num4 - num5, num5, num3 - 0.01, num4 - num5);

			}

			ring.Data = Geometry.Parse (source);

		}

	}

