			mainGrid.Children.Add (border3);

			border.Child = mainGrid;

			base.Content = border;

			_timer = new DispatcherTimer {

				Interval = TimeSpan.FromMilliseconds (50.0)

			};

			_timer.Tick += delegate {

				UpdateTime ();

			};

			base.Loaded += delegate {

				ApplyTheme ();

				_timer.Start ();

			};

			base.Unloaded += delegate {

				_timer.Stop ();

			};

			UpdateTime ();

		}



		private void UpdateTime ()

		{

			DateTime now = DateTime.Now;

			_timeText.Text = now.ToString ("h:mm:ss tt");

			_dateText.Text = now.ToString ("dddd, MMMM d");

			_hourTransform.Angle = ((double)(now.Hour % 12) + (double)now.Minute / 60.0) * 30.0;

			_minTransform.Angle = ((double)now.Minute + (double)now.Second / 60.0) * 6.0;

			_secTransform.Angle = ((double)now.Second + (double)now.Millisecond / 1000.0) * 6.0;

		}



		public void ApplyTheme ()

		{

			if (base.Opacity > 0.1) {

				DoubleAnimation doubleAnimation = new DoubleAnimation (base.Opacity, 0.0, TimeSpan.FromMilliseconds (150.0));

				doubleAnimation.Completed += delegate {

					ApplyThemeInternal ();

					DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (150.0));

					BeginAnimation (UIElement.OpacityProperty, animation);

				};

				BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

			} else {

				ApplyThemeInternal ();

			}

		}



		private void ApplyThemeInternal ()

		{

			bool flag = true;

			if (_dw != null) {

				flag = _dw.GetEffectiveTheme ().ToLower () == "dark";

			}

			base.Resources ["DynamicForeground"] = (flag ? System.Windows.Media.Brushes.White : System.Windows.Media.Brushes.Black);

			base.Resources ["ClockFaceBg"] = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (byte.MaxValue, 40, 40, 40)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (byte.MaxValue, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

			base.Resources ["ClockFaceBorder"] = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (byte.MaxValue, 60, 60, 60)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (byte.MaxValue, 220, 220, 220)));

			base.Resources ["SidebarBg"] = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (230, 30, 30, 30)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (240, 245, 245, 245)));

			base.Resources ["RightBg"] = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (230, 20, 20, 20)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (245, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

		}

	}

