		[DllImport ("dwmapi.dll")]

		internal static extern int DwmSetWindowAttribute (IntPtr hwnd, int attr, ref int attrValue, int attrSize);



		[DllImport ("gdi32.dll")]

		private static extern IntPtr CreateRoundRectRgn (int nLeftRect, int nTopRect, int nRightRect, int nBottomRect, int nWidthEllipse, int nHeightEllipse);



		[DllImport ("user32.dll")]

		private static extern int SetWindowRgn (IntPtr hWnd, IntPtr hRgn, bool bRedraw);



		private void ApplyRoundedRegion ()

		{

			try {

				IntPtr handle = new WindowInteropHelper (this).Handle;

				int attr = 33;

				int attrValue = 2;

				DwmSetWindowAttribute (handle, attr, ref attrValue, Marshal.SizeOf (typeof(int)));

				if (Environment.OSVersion.Version.Build < 22000) {

					PresentationSource presentationSource = PresentationSource.FromVisual (this);

					double num = ((presentationSource != null && presentationSource.CompositionTarget != null) ? presentationSource.CompositionTarget.TransformToDevice.M11 : 1.0);

					double num2 = ((presentationSource != null && presentationSource.CompositionTarget != null) ? presentationSource.CompositionTarget.TransformToDevice.M22 : 1.0);

					int nRightRect = (int)(base.ActualWidth * num);

					int nBottomRect = (int)(base.ActualHeight * num2);

					int num3 = (int)(32.0 * num);

					IntPtr hRgn = CreateRoundRectRgn (0, 0, nRightRect, nBottomRect, num3, num3);

					SetWindowRgn (handle, hRgn, bRedraw: true);

				}

			} catch {

			}

		}



		[DllImport ("user32.dll")]

		internal static extern int SetWindowCompositionAttribute (IntPtr hwnd, ref WinCompositionAttrData data);



		public void EnableBlur (bool enable)

		{

			try {

				IntPtr handle = new WindowInteropHelper (this).Handle;

				if (handle != IntPtr.Zero) {

					AccentPolicy structure = default(AccentPolicy);

					structure.AccentState = (enable ? 3 : 0);

					if (enable) {

						structure.AccentFlags = 2;

						double blurAmount = (_dw != null && _dw.settings != null) ? _dw.settings.BlurAmount : 0.7;

						bool isDark = (_dw != null && _dw.settings != null) ? (_dw.settings.Theme.ToLower () == "dark" || _dw.settings.Theme.ToLower () == "tahoe") : true;

						byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);

						uint colorVal = isDark ? 0x1A1A1AU : 0xF2F2F7U;

						structure.GradientColor = (int)(((uint)alpha << 24) | (colorVal & 0x00FFFFFF));

					}

					int num = Marshal.SizeOf (structure);

					IntPtr intPtr = Marshal.AllocHGlobal (num);

					Marshal.StructureToPtr (structure, intPtr, fDeleteOld: false);

					WinCompositionAttrData data = default(WinCompositionAttrData);

					data.Attribute = 19;

					data.SizeOfData = num;

					data.Data = intPtr;

					SetWindowCompositionAttribute (handle, ref data);

					Marshal.FreeHGlobal (intPtr);

				}

			} catch {

			}

		}



		public CalendarOverlayWindow (DockWindow owner)

		{

			_dw = owner;

			_currentYear = DateTime.Now.Year;

			_currentMonth = DateTime.Now.Month;

			LoadEvents ();

			base.WindowStyle = WindowStyle.None;

			base.AllowsTransparency = true;

			base.Background = System.Windows.Media.Brushes.Transparent;

			base.Topmost = true;

			base.ShowInTaskbar = false;

			base.Width = 840.0;

			base.Height = 520.0;

			Border border = new Border {

				CornerRadius = new CornerRadius (14.0)

			};

			mainGrid = new Grid ();

			mainGrid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (180.0)

			});

			mainGrid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			RectangleGeometry clip = new RectangleGeometry {

				RadiusX = 14.0,

				RadiusY = 14.0,

				Rect = new Rect (0.0, 0.0, 840.0, 520.0)

			};

			mainGrid.Clip = clip;

			sidebarGrid = new Grid ();

			BuildSidebar ();

			Grid.SetColumn (sidebarGrid, 0);

			mainGrid.Children.Add (sidebarGrid);

			rightGrid = new Grid ();

			BuildRightView ();

			BuildDayView ();

			Grid.SetColumn (rightGrid, 1);

