		}



		private void LoadEvents ()

		{

			if (!File.Exists (_eventsPath)) {

				return;

			}

			try {

				using FileStream stream = File.OpenRead (_eventsPath);

				CalendarEventCollection calendarEventCollection = (CalendarEventCollection)new DataContractJsonSerializer (typeof(CalendarEventCollection)).ReadObject ((Stream)stream);

				_events = calendarEventCollection.Events ?? new List<CalendarEvent> ();

			} catch {

				_events = new List<CalendarEvent> ();

			}

		}



		private void SaveEvents ()

		{

			try {

				using FileStream stream = File.Create (_eventsPath);

				CalendarEventCollection graph = new CalendarEventCollection {

					Events = _events

				};

				new DataContractJsonSerializer (typeof(CalendarEventCollection)).WriteObject ((Stream)stream, (object)graph);

			} catch {

			}

		}



		private void AddEvent (DateTime date, string title)

		{

			if (!string.IsNullOrWhiteSpace (title)) {

				_events.Add (new CalendarEvent {

					Date = date.ToString ("yyyy-MM-dd"),

					Title = title

				});

				SaveEvents ();

				newEventTextBox.Text = "";

				ShowDayView (date);

			}

		}



		private void RemoveEvent (CalendarEvent ev)

		{

			_events.Remove (ev);

			SaveEvents ();

			ShowDayView (_selectedDate);

		}



