		private void ShowDayView (DateTime date)

		{

			_selectedDate = date;

			matrixGrid.Visibility = Visibility.Collapsed;

			dayViewGrid.Visibility = Visibility.Visible;

			dayViewTitle.Text = date.ToString ("dddd, MMMM d, yyyy");

			dayViewListPanel.Children.Clear ();

			string dateStr = date.ToString ("yyyy-MM-dd");

			List<CalendarEvent> list = _events.Where ((CalendarEvent e) => e.Date == dateStr).ToList ();

			if (list.Count == 0) {

				TextBlock element = new TextBlock {

					Text = "No events scheduled.",

					Foreground = System.Windows.Media.Brushes.Gray,

					FontStyle = FontStyles.Italic,

					Margin = new Thickness (0.0, 20.0, 0.0, 0.0)

				};

				dayViewListPanel.Children.Add (element);

				return;

			}

			foreach (CalendarEvent item in list) {

				Grid grid = new Grid {

					Margin = new Thickness (0.0, 0.0, 0.0, 8.0)

				};

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.0, GridUnitType.Star)

				});

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (30.0)

				});

				Border border = new Border {

					Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 128, 128, 128)),

					CornerRadius = new CornerRadius (6.0),

					Padding = new Thickness (12.0, 8.0, 12.0, 8.0)

				};

				TextBlock textBlock = new TextBlock {

					Text = item.Title,

					FontSize = 14.0

				};

				textBlock.SetResourceReference (TextBlock.ForegroundProperty, "DynamicForeground");

				border.Child = textBlock;

				Grid.SetColumn (border, 0);

				grid.Children.Add (border);

				Border border2 = new Border {

					Background = System.Windows.Media.Brushes.Transparent,

					CornerRadius = new CornerRadius (6.0),

					Cursor = System.Windows.Input.Cursors.Hand

				};

				TextBlock textBlock2 = new TextBlock {

					Text = "X",

					FontWeight = FontWeights.Bold,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

					VerticalAlignment = VerticalAlignment.Center

				};

				textBlock2.SetResourceReference (TextBlock.ForegroundProperty, "CalendarAccentBrush");

				border2.Child = textBlock2;

				CalendarEvent closureEv = item;

				border2.MouseLeftButtonDown += delegate {

					RemoveEvent (closureEv);

				};

				Grid.SetColumn (border2, 1);

				grid.Children.Add (border2);

				dayViewListPanel.Children.Add (grid);

			}

		}



