			matrixGrid.Visibility = Visibility.Visible;

			UpdateYearMatrix ();

			UpdateSidebarMonth ();

		}



		private void UpdateSidebarMonth ()

		{

			sidebarMonthGrid.Children.Clear ();

			sidebarMonthGrid.RowDefinitions.Clear ();

			sidebarMonthGrid.ColumnDefinitions.Clear ();

			sidebarMonthGrid.RowDefinitions.Add (new RowDefinition {

				Height = new GridLength (20.0)

			});

			sidebarMonthGrid.RowDefinitions.Add (new RowDefinition {

				Height = new GridLength (20.0)

			});

			for (int i = 0; i < 6; i++) {

				sidebarMonthGrid.RowDefinitions.Add (new RowDefinition {

					Height = new GridLength (24.0)

				});

			}

			for (int j = 0; j < 7; j++) {

				sidebarMonthGrid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.0, GridUnitType.Star)

				});

			}

			DateTime dateTime = new DateTime (_currentYear, _currentMonth, 1);

			int dayOfWeek = (int)dateTime.DayOfWeek;

			int num = DateTime.DaysInMonth (_currentYear, _currentMonth);

			TextBlock textBlock = new TextBlock {

				Text = dateTime.ToString ("MMMM yyyy"),

				FontSize = 12.0,

				FontWeight = FontWeights.SemiBold,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center

			};

			textBlock.SetResourceReference (TextBlock.ForegroundProperty, "DynamicForeground");

			Grid.SetRow (textBlock, 0);

			Grid.SetColumnSpan (textBlock, 7);

			sidebarMonthGrid.Children.Add (textBlock);

			string[] array = new string[7] { "S", "M", "T", "W", "T", "F", "S" };

			for (int k = 0; k < 7; k++) {

				TextBlock element = new TextBlock {

					Text = array [k],

					FontSize = 10.0,

					Foreground = System.Windows.Media.Brushes.Gray,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

					VerticalAlignment = VerticalAlignment.Center

				};

				Grid.SetRow (element, 1);

				Grid.SetColumn (element, k);

				sidebarMonthGrid.Children.Add (element);

			}

			int num2 = 1;

			for (int l = 2; l < 8; l++) {

				for (int m = 0; m < 7; m++) {

					if (l == 2 && m < dayOfWeek) {

						continue;

					}

					if (num2 > num) {

						break;

					}

					Border border = new Border {

						CornerRadius = new CornerRadius (12.0),

						Width = 24.0,

						Height = 24.0,

						Cursor = System.Windows.Input.Cursors.Hand,

						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

						VerticalAlignment = VerticalAlignment.Center

					};

					TextBlock textBlock2 = new TextBlock {

						Text = num2.ToString (),

						FontSize = 11.0,

						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

						VerticalAlignment = VerticalAlignment.Center

					};

					textBlock2.SetResourceReference (TextBlock.ForegroundProperty, "DynamicForeground");

					if (_currentYear == DateTime.Now.Year && _currentMonth == DateTime.Now.Month && num2 == DateTime.Now.Day) {

						border.SetResourceReference (Border.BackgroundProperty, "CalendarAccentBrush");

						textBlock2.Foreground = System.Windows.Media.Brushes.White;

					}

					Grid grid = new Grid ();

					grid.Children.Add (textBlock2);

					DateTime thisDate = new DateTime (_currentYear, _currentMonth, num2);

					string ds = thisDate.ToString ("yyyy-MM-dd");

					if (_events.Any ((CalendarEvent ev) => ev.Date == ds)) {

						Ellipse ellipse = new Ellipse {

							Width = 3.0,

							Height = 3.0,

							Fill = System.Windows.Media.Brushes.Gray,

							HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

							VerticalAlignment = VerticalAlignment.Bottom,

							Margin = new Thickness (0.0, 0.0, 0.0, 2.0)

						};

						if (_currentYear == DateTime.Now.Year && _currentMonth == DateTime.Now.Month && num2 == DateTime.Now.Day) {

							ellipse.Fill = System.Windows.Media.Brushes.White;

						}

						grid.Children.Add (ellipse);

					}

					border.Child = grid;

					border.MouseLeftButtonDown += delegate {

						ShowDayView (thisDate);

					};

					Grid.SetRow (border, l);

					Grid.SetColumn (border, m);

					sidebarMonthGrid.Children.Add (border);

					num2++;

				}

			}

		}



