		public void ApplyTheme ()

		{

			if (base.Opacity > 0.1) {

				DoubleAnimation doubleAnimation = new DoubleAnimation (base.Opacity, 0.0, TimeSpan.FromMilliseconds (150.0));

				doubleAnimation.Completed += delegate {

					ApplyThemeInternal ();

					DoubleAnimation animation = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (150.0));

					BeginAnimation (UIElement.OpacityProperty, animation);

				};

				BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

			} else {

				ApplyThemeInternal ();

			}

		}



		private void ApplyThemeInternal ()

		{

			bool flag = true;

			string text = "dark";

			if (_dw != null) {

				text = _dw.GetEffectiveTheme ().ToLower ();

				flag = text == "dark" || text == "tahoe";

			}

			base.Resources ["DynamicForeground"] = (flag ? System.Windows.Media.Brushes.White : System.Windows.Media.Brushes.Black);

			System.Windows.Media.Color color = System.Windows.Media.Color.FromRgb (byte.MaxValue, 59, 48);

			if (base.Content is Border border) {

				if (text == "tahoe") {

					color = System.Windows.Media.Color.FromRgb (218, 0, byte.MaxValue);

					LinearGradientBrush linearGradientBrush = new LinearGradientBrush {

						StartPoint = new System.Windows.Point (0.2, 0.0),

						EndPoint = new System.Windows.Point (0.8, 1.0)

					};

					linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (240, 10, 16, 26), 0.0));

					linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (240, 24, 8, 36), 0.5));

					linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (240, 10, 16, 26), 1.0));

					border.Background = linearGradientBrush;

					LinearGradientBrush linearGradientBrush2 = new LinearGradientBrush {

						StartPoint = new System.Windows.Point (0.0, 0.0),

						EndPoint = new System.Windows.Point (1.0, 1.0)

					};

					linearGradientBrush2.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (210, 0, 212, byte.MaxValue), 0.0));

					linearGradientBrush2.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (140, 218, 0, byte.MaxValue), 1.0));

					border.BorderBrush = linearGradientBrush2;

					border.BorderThickness = new Thickness (1.2);

					border.Effect = new DropShadowEffect {

						BlurRadius = 35.0,

						ShadowDepth = 2.0,

						Opacity = 0.35,

						Color = System.Windows.Media.Color.FromRgb (140, 0, byte.MaxValue)

					};

					sidebarGrid.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, 0, 0, 0));

					rightGrid.Background = System.Windows.Media.Brushes.Transparent;

				} else {

					border.Background = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (230, 20, 20, 20)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (245, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

					border.BorderBrush = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, byte.MaxValue, byte.MaxValue, byte.MaxValue)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, 0, 0, 0)));

					border.BorderThickness = new Thickness (1.0);

					border.Effect = new DropShadowEffect {

						BlurRadius = 18.0,

						ShadowDepth = 3.0,

						Opacity = 0.45,

						Color = Colors.Black

					};

					sidebarGrid.Background = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (230, 30, 30, 30)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (240, 245, 245, 245)));

					rightGrid.Background = (flag ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (230, 20, 20, 20)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (245, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

				}

			}

			base.Resources ["CalendarAccentBrush"] = new SolidColorBrush (color);

		}

	}

	public class LaunchpadWindow : Window
	{
		private DockWindow parent;
		private WrapPanel appPanel;
		private System.Windows.Controls.TextBox searchBox;
		private TextBlock placeholderText;
		private ScrollViewer scrollViewer;
		private List<SearchResultItem> allApps = new List<SearchResultItem> ();
		private List<SearchResultItem> filteredApps = new List<SearchResultItem> ();

		internal struct WinCompositionAttrData
		{
			public int Attribute;
			public IntPtr Data;
			public int SizeOfData;
		}

		internal struct AccentPolicy
		{
			public int AccentState;
			public int AccentFlags;
			public int GradientColor;
			public int AnimationId;
		}

		[DllImport ("user32.dll")]
		internal static extern int SetWindowCompositionAttribute (IntPtr hwnd, ref WinCompositionAttrData data);

		[DllImport ("gdi32.dll")]
		[return: MarshalAs (UnmanagedType.Bool)]
		public static extern bool DeleteObject (IntPtr hObject);

		public void EnableBlur (bool enable)
		{
			try {
				IntPtr handle = new WindowInteropHelper (this).Handle;
				if (handle != IntPtr.Zero) {
					AccentPolicy structure = default(AccentPolicy);
					structure.AccentState = (enable ? 3 : 0);
					if (enable) {
						structure.AccentFlags = 2;
						double blurAmount = (parent != null && parent.settings != null) ? parent.settings.BlurAmount : 0.7;
						bool isDark = (parent != null && parent.settings != null) ? (parent.settings.Theme.ToLower () == "dark" || parent.settings.Theme.ToLower () == "tahoe") : true;
						byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);
						uint colorVal = isDark ? 0x1A1A1AU : 0xF2F2F7U;
						structure.GradientColor = (int)(((uint)alpha << 24) | (colorVal & 0x00FFFFFF));
					}
					int num = Marshal.SizeOf (structure);
					IntPtr intPtr = Marshal.AllocHGlobal (num);
					Marshal.StructureToPtr (structure, intPtr, fDeleteOld: false);
					WinCompositionAttrData data = default(WinCompositionAttrData);
					data.Attribute = 19;
					data.SizeOfData = num;
					data.Data = intPtr;
					SetWindowCompositionAttribute (handle, ref data);
					Marshal.FreeHGlobal (intPtr);
				}
			} catch {}
		}

