		private void LoadAndRenderApps ()
		{
			System.Threading.Tasks.Task.Run (delegate {
				HashSet<string> hashSet = new HashSet<string> (StringComparer.OrdinalIgnoreCase);
				List<SearchResultItem> apps = new List<SearchResultItem> ();

				foreach (DockItemConfig item in parent.settings.Items) {
					if (!string.IsNullOrEmpty (item.Name) && hashSet.Add (item.Name)) {
						apps.Add (new SearchResultItem {
							Name = item.Name,
							Path = item.FilePath,
							IsApp = true
						});
					}
				}

				List<string> list = new List<string> ();
				try {
					string folderPath = Environment.GetFolderPath (Environment.SpecialFolder.CommonPrograms);
					if (!string.IsNullOrEmpty (folderPath) && Directory.Exists (folderPath)) {
						list.Add (folderPath);
					}
				} catch {}
				try {
					string folderPath2 = Environment.GetFolderPath (Environment.SpecialFolder.Programs);
					if (!string.IsNullOrEmpty (folderPath2) && Directory.Exists (folderPath2)) {
						list.Add (folderPath2);
					}
				} catch {}

				Action<string> safeEnumerateLnk = null;
				safeEnumerateLnk = delegate (string dir) {
					try {
						foreach (string file in Directory.GetFiles (dir, "*.lnk")) {
							string name = System.IO.Path.GetFileNameWithoutExtension (file);
							if (name.ToLower ().Contains ("uninstall") || name.ToLower ().Contains ("unins")) {
								continue;
							}
							if (hashSet.Add (name)) {
								apps.Add (new SearchResultItem {
									Name = name,
									Path = file,
									IsApp = true
								});
							}
						}
					} catch {}
					try {
						foreach (string subDir in Directory.GetDirectories (dir)) {
							safeEnumerateLnk (subDir);
						}
					} catch {}
				};

				foreach (string item2 in list) {
					safeEnumerateLnk (item2);
				}

				try {
					string winAppsPath = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.LocalApplicationData), "Microsoft", "WindowsApps");
					if (Directory.Exists (winAppsPath)) {
						foreach (string file in Directory.GetFiles (winAppsPath, "*.exe", SearchOption.TopDirectoryOnly)) {
							string name = System.IO.Path.GetFileNameWithoutExtension (file);
							if (name.Equals ("python", StringComparison.OrdinalIgnoreCase) || 
								name.Equals ("python3", StringComparison.OrdinalIgnoreCase) ||
								name.Equals ("olk", StringComparison.OrdinalIgnoreCase)) {
								continue;
							}
							if (hashSet.Add (name)) {
								apps.Add (new SearchResultItem {
									Name = name,
									Path = file,
									IsApp = true
								});
							}
						}
					}
				} catch {}

				var array2 = new[] {
					new { Root = Registry.LocalMachine, Path = "SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall" },
					new { Root = Registry.LocalMachine, Path = "SOFTWARE\\Wow6432Node\\Microsoft\\Windows\\CurrentVersion\\Uninstall" },
					new { Root = Registry.CurrentUser, Path = "SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall" }
				};

				foreach (var anon in array2) {
					try {
						using RegistryKey registryKey3 = anon.Root.OpenSubKey (anon.Path);
						if (registryKey3 == null) continue;
						foreach (string name2 in registryKey3.GetSubKeyNames ()) {
							try {
								using RegistryKey registryKey4 = registryKey3.OpenSubKey (name2);
								if (registryKey4 == null) continue;
								object value2 = registryKey4.GetValue ("DisplayName");
								if (value2 == null) continue;
								string text2 = value2.ToString ();
								
								string text3 = null;
								object value3 = registryKey4.GetValue ("DisplayIcon");
								if (value3 != null) {
									string text4 = value3.ToString ().Split (',') [0].Trim ('"', ' ');
									if (File.Exists (text4) && text4.ToLower ().EndsWith (".exe")) {
										text3 = text4;
									}
								}
								if (string.IsNullOrEmpty (text3)) {
									object value4 = registryKey4.GetValue ("InstallLocation");
									if (value4 != null) {
										string path2 = value4.ToString ().Trim ('"', ' ');
										if (Directory.Exists (path2)) {
											string[] files = Directory.GetFiles (path2, "*.exe", SearchOption.TopDirectoryOnly);
											if (files.Length != 0) {
												text3 = files.OrderByDescending (f => new FileInfo (f).Length).First ();
											}
										}
									}
								}
								if (!string.IsNullOrEmpty (text3) && File.Exists (text3) && hashSet.Add (text2)) {
									apps.Add (new SearchResultItem {
										Name = text2,
										Path = text3,
										IsApp = true
									});
								}
							} catch {}
						}
					} catch {}
				}

				try {
					string spotifyPath = System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.ApplicationData), "Spotify", "Spotify.exe");
					if (File.Exists (spotifyPath) && hashSet.Add ("Spotify")) {
						apps.Add (new SearchResultItem {
							Name = "Spotify",
							Path = spotifyPath,
							IsApp = true
						});
					}
				} catch {}

				foreach (var app in apps) {
					try {
						string resolvedPath = app.Path;
						if (app.Path.EndsWith (".lnk", StringComparison.OrdinalIgnoreCase)) {
							resolvedPath = IconExtractor.ResolveShortcut (app.Path);
						}
						app.Icon = IconExtractor.GetHighQualityIcon (resolvedPath, 256);
						if (app.Icon == null) {
							app.Icon = IconExtractor.GetJumboIcon (resolvedPath);
						}
						if (app.Icon == null) {
							app.Icon = IconExtractor.GetIcon (resolvedPath);
						}
					} catch {}
					if (app.Icon == null) {
						app.Icon = IconExtractor.CreateFallbackIcon (app.Name);
					}
				}

				Dispatcher.BeginInvoke (new Action (delegate {
					allApps = apps.OrderBy (a => a.Name).ToList ();
					FilterApps ();
				}));
			});
		}

		private void FilterApps ()
		{
			appPanel.Children.Clear ();
			string query = searchBox.Text.ToLower ();
			filteredApps = string.IsNullOrEmpty (query) 
				? allApps 
				: allApps.FindAll (a => a.Name.ToLower ().Contains (query));

			foreach (var app in filteredApps) {
				Border itemBorder = new Border {
					Width = 120.0,
					Height = 130.0,
					Margin = new Thickness (10.0),
					CornerRadius = new CornerRadius (12.0),
					Cursor = System.Windows.Input.Cursors.Hand,
					Background = System.Windows.Media.Brushes.Transparent
				};

				StackPanel itemStack = new StackPanel {
					VerticalAlignment = VerticalAlignment.Center,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center
				};

				System.Windows.Controls.Image appIcon = new System.Windows.Controls.Image {
					Source = app.Icon,
					Width = 64.0,
					Height = 64.0,
					Stretch = Stretch.Uniform,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center
				};
				RenderOptions.SetBitmapScalingMode (appIcon, BitmapScalingMode.HighQuality);

				TextBlock appName = new TextBlock {
					Text = app.Name,
					Foreground = System.Windows.Media.Brushes.White,
					FontSize = 12.0,
					FontFamily = new System.Windows.Media.FontFamily ("SF Pro, SF Pro Text, SF Pro Display, -apple-system, BlinkMacSystemFont, Segoe UI, Arial, sans-serif"),
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
					TextAlignment = TextAlignment.Center,
					TextWrapping = TextWrapping.Wrap,
					MaxWidth = 100.0,
					Margin = new Thickness (0.0, 8.0, 0.0, 0.0)
				};

				itemStack.Children.Add (appIcon);
				itemStack.Children.Add (appName);
				itemBorder.Child = itemStack;

				itemBorder.MouseEnter += delegate {
					itemBorder.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (35, 255, 255, 255));
				};
				itemBorder.MouseLeave += delegate {
					itemBorder.Background = System.Windows.Media.Brushes.Transparent;
				};

				string targetPath = app.Path;
				itemBorder.PreviewMouseLeftButtonDown += delegate {
					HideAnimated ();
					try {
						Process.Start (new ProcessStartInfo {
							FileName = targetPath,
							UseShellExecute = true
						});
					} catch {}
				};

				appPanel.Children.Add (itemBorder);
			}
		}

		public void ShowAnimated ()
		{
			base.Opacity = 0.0;
			this.Show ();
			this.Activate ();
			LoadAndRenderApps ();

			if (!(scrollViewer.RenderTransform is ScaleTransform)) {
				scrollViewer.RenderTransform = new ScaleTransform (1.05, 1.05);
				scrollViewer.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);
			}

			DoubleAnimation fadeAnim = new DoubleAnimation (0.0, 1.0, TimeSpan.FromMilliseconds (200.0));
			DoubleAnimation scaleAnim = new DoubleAnimation (1.05, 1.0, TimeSpan.FromMilliseconds (200.0)) {
				EasingFunction = new CubicEase { EasingMode = EasingMode.EaseOut }
			};

			BeginAnimation (UIElement.OpacityProperty, fadeAnim);
			((ScaleTransform)scrollViewer.RenderTransform).BeginAnimation (ScaleTransform.ScaleXProperty, scaleAnim);
			((ScaleTransform)scrollViewer.RenderTransform).BeginAnimation (ScaleTransform.ScaleYProperty, scaleAnim);

			searchBox.Text = "";
			searchBox.Focus ();
		}

		public void HideAnimated ()
		{
			if (!(scrollViewer.RenderTransform is ScaleTransform)) {
				scrollViewer.RenderTransform = new ScaleTransform (1.0, 1.0);
				scrollViewer.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);
			}

			DoubleAnimation fadeAnim = new DoubleAnimation (base.Opacity, 0.0, TimeSpan.FromMilliseconds (150.0));
			fadeAnim.Completed += delegate {
				Hide ();
			};

			DoubleAnimation scaleAnim = new DoubleAnimation (1.0, 1.05, TimeSpan.FromMilliseconds (150.0)) {
				EasingFunction = new CubicEase { EasingMode = EasingMode.EaseIn }
			};

			((ScaleTransform)scrollViewer.RenderTransform).BeginAnimation (ScaleTransform.ScaleXProperty, scaleAnim);
			((ScaleTransform)scrollViewer.RenderTransform).BeginAnimation (ScaleTransform.ScaleYProperty, scaleAnim);
			BeginAnimation (UIElement.OpacityProperty, fadeAnim);
		}
	}

