					AccentPolicy structure = default(AccentPolicy);

					structure.AccentState = 3;

					structure.AccentFlags = 2;

					double blurAmount = (_parent != null && _parent.settings != null) ? _parent.settings.BlurAmount : 0.7;

					bool isDark = (_parent != null && _parent.settings != null) ? (_parent.settings.Theme.ToLower () == "dark" || _parent.settings.Theme.ToLower () == "tahoe") : true;

					byte alpha = (byte)((1.0 - blurAmount) * 200.0 + 20.0);

