		private List<IntentModel> LoadIntents ()

		{

			string path = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "intents.json");

			EnsureIntentsFileExists (path);

			try {

				string input = File.ReadAllText (path);

				return new JavaScriptSerializer ().Deserialize<List<IntentModel>> (input) ?? new List<IntentModel> ();

			} catch {

				return new List<IntentModel> ();

			}

		}



		private void SaveIntents (List<IntentModel> intents)

		{

			string path = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "intents.json");

			try {

				string contents = new JavaScriptSerializer ().Serialize (intents);

				File.WriteAllText (path, contents);

			} catch {

			}

		}



		public AIAssistantWindow (DockWindow parent)

		{

			_parent = parent;

			base.WindowStyle = WindowStyle.None;

			base.AllowsTransparency = true;

			base.Background = System.Windows.Media.Brushes.Transparent;

			base.Topmost = true;

