			textBlock.TextWrapping = TextWrapping.Wrap;

			textBlock.FontSize = 14.0;

			textBlock.FontFamily = new System.Windows.Media.FontFamily ("Segoe UI Variable Display, Segoe UI, sans-serif");

			UIElement uIElement2 = (border.Child = textBlock);

			TextBlock textBlock2 = (TextBlock)uIElement2;

			switch (sender) {

			case "User":

				border.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (110, 60, 60, 65));

				border.BorderBrush = System.Windows.Media.Brushes.Transparent;

				border.BorderThickness = new Thickness (0.0);

				border.HorizontalAlignment = System.Windows.HorizontalAlignment.Right;

				textBlock2.Foreground = System.Windows.Media.Brushes.White;

				break;

			case "Assistant":
			case "System":

				border.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (130, 25, 25, 30));

				border.BorderBrush = System.Windows.Media.Brushes.Transparent;

				border.BorderThickness = new Thickness (0.0);

				border.HorizontalAlignment = System.Windows.HorizontalAlignment.Left;

				textBlock2.Foreground = System.Windows.Media.Brushes.White;

				break;

			default:

				border.Background = new SolidColorBrush (System.Windows.Media.Color.FromArgb (180, 60, 20, 20));

				border.BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (40, byte.MaxValue, 100, 100));

				border.BorderThickness = new Thickness (1.0);

				border.HorizontalAlignment = System.Windows.HorizontalAlignment.Left;

				textBlock2.Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (byte.MaxValue, 160, 160));

				break;

