		public void ProcessCommand (string prompt)

		{

			SetSiriState ("thinking");

			AppendChat ("User", prompt);

			string intentName;

			string example;

			string actionScript;

			double maxScore;

			IntentModel bestIntent;

			Exception ex2;

			Task.Run (delegate {

				try {

					string text = prompt.Trim ();

					if (text.StartsWith ("train ", StringComparison.OrdinalIgnoreCase)) {

						string[] array = text.Substring (6).Trim ().Split ('|');

						if (array.Length == 3) {

							intentName = array [0].Trim ();

							example = array [1].Trim ();

							actionScript = array [2].Trim ();

							if (!string.IsNullOrEmpty (intentName) && !string.IsNullOrEmpty (example) && !string.IsNullOrEmpty (actionScript)) {

								List<IntentModel> list = LoadIntents ();

								IntentModel intentModel = list.FirstOrDefault ((IntentModel i) => i.Intent.Equals (intentName, StringComparison.OrdinalIgnoreCase));

								if (intentModel != null) {

									if (!intentModel.Examples.Any ((string ex) => ex.Equals (example, StringComparison.OrdinalIgnoreCase))) {

										intentModel.Examples.Add (example);

									}

									intentModel.Action = actionScript;

								} else {

									list.Add (new IntentModel {

										Intent = intentName,

										Examples = new List<string> { example },

										Action = actionScript

									});

								}

								SaveIntents (list);

								base.Dispatcher.BeginInvoke ((Action)delegate {

									SetSiriState ("calm");

									AppendChat ("Assistant", $"Successfully trained locally!\nIntent: {intentName}\nExample: \"{example}\"\nAction: {actionScript}");

								});

								return;

							}

						}

						base.Dispatcher.BeginInvoke ((Action)delegate {

							SetSiriState ("calm");

							AppendChat ("Assistant", "To train me locally, type:\ntrain <intent> | <example> | <powershell_script>\n\nExample:\ntrain open_calc | open calculator | Start-Process calc");

						});

					} else {

						List<IntentModel> list2 = LoadIntents ();

						maxScore = 0.0;

						bestIntent = null;

						string example2 = "";

						List<string> vec = Tokenize (text);

						foreach (IntentModel item in list2) {

							foreach (string example3 in item.Examples) {

								List<string> vec2 = Tokenize (example3);

								double num = CosineSimilarity (vec, vec2);

								if (num > maxScore) {

									maxScore = num;

									bestIntent = item;

									example2 = example3;

								}

							}

						}

						if (bestIntent != null && maxScore >= 0.25) {

							string text2 = bestIntent.Action;

							if (text2.Contains ("{query}")) {

								string newValue = ExtractQueryParameter (text, example2);

								text2 = text2.Replace ("{query}", newValue);

							}

							base.Dispatcher.BeginInvoke ((Action)delegate {

								AppendChat ("Assistant", $"Matched Intent: {bestIntent.Intent} (Confidence: {maxScore:P0})\nExecuting local action...");

							});

							ExecutePowerShell (text2);

						} else {

							base.Dispatcher.BeginInvoke ((Action)delegate {

								AppendChat ("Assistant", "Searching the web for an answer...");

							});

							string text3 = text.Replace ("'", "''");

							string script = "\r\ntry {\r\n    $url = 'https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=' + [uri]::EscapeDataString('" + text3 + "') + '&utf8=&format=json'\r\n    $res = Invoke-RestMethod -Uri $url -ErrorAction Stop\r\n    if ($res.query.search.Count -gt 0) {\r\n        $snippet = $res.query.search[0].snippet -replace '<[^>]+>', ''\r\n        Write-Output ($res.query.search[0].title + ': ' + $snippet + ' (Source: Wikipedia)')\r\n    } else {\r\n        $ddgUrl = 'https://api.duckduckgo.com/?q=' + [uri]::EscapeDataString('" + text3 + "') + '&format=json'\r\n        $ddgRes = Invoke-RestMethod -Uri $ddgUrl -ErrorAction SilentlyContinue\r\n        if ($ddgRes.AbstractText) {\r\n            Write-Output ($ddgRes.AbstractText + ' (Source: DuckDuckGo)')\r\n        } else {\r\n            Write-Output 'I searched the web but couldn''t find a direct answer.'\r\n        }\r\n    }\r\n} catch {\r\n    Write-Output 'Failed to connect to the internet to find an answer.'\r\n}\r\n";

							ExecutePowerShell (script);

						}

					}

				} catch (Exception ex3) {

					ex2 = ex3;

					base.Dispatcher.BeginInvoke ((Action)delegate {

						SetSiriState ("calm");

						AppendChat ("Error", "Error: " + ex2.Message);

					});

				}

			});

		}



		private List<string> Tokenize (string text)

		{

			List<string> list = new List<string> ();

			if (string.IsNullOrEmpty (text)) {

				return list;

			}

			string[] array = new string (text.Where ((char c) => !char.IsPunctuation (c)).ToArray ()).ToLower ().Split (new char[1] { ' ' }, StringSplitOptions.RemoveEmptyEntries);

			list.AddRange (array);

			for (int i = 0; i < array.Length - 1; i++) {

				list.Add (array [i] + "_" + array [i + 1]);

			}

			return list;

		}



		private double CosineSimilarity (List<string> vec1, List<string> vec2)

		{

			if (vec1.Count == 0 || vec2.Count == 0) {

				return 0.0;

			}

			Dictionary<string, int> dictionary = (from w in vec1

				group w by w).ToDictionary ((IGrouping<string, string> g) => g.Key, (IGrouping<string, string> g) => g.Count ());

			Dictionary<string, int> dictionary2 = (from w in vec2

				group w by w).ToDictionary ((IGrouping<string, string> g) => g.Key, (IGrouping<string, string> g) => g.Count ());

			IEnumerable<string> enumerable = dictionary.Keys.Union (dictionary2.Keys);

			double num = 0.0;

			double num2 = 0.0;

			double num3 = 0.0;

			foreach (string item in enumerable) {

				int num4 = (dictionary.ContainsKey (item) ? dictionary [item] : 0);

				int num5 = (dictionary2.ContainsKey (item) ? dictionary2 [item] : 0);

				num += (double)(num4 * num5);

				num2 += (double)(num4 * num4);

				num3 += (double)(num5 * num5);

			}

			if (num2 == 0.0 || num3 == 0.0) {

				return 0.0;

			}

			return num / (Math.Sqrt (num2) * Math.Sqrt (num3));

		}



		private string ExtractQueryParameter (string input, string example)

		{

			List<string> exampleTokens = (from t in Tokenize (example)

				where !t.Contains ("_")

				select t).ToList ();

			List<string> list = (from w in new string (input.Where ((char c) => !char.IsPunctuation (c)).ToArray ()).Split (new char[1] { ' ' }, StringSplitOptions.RemoveEmptyEntries)

				where !exampleTokens.Contains (w.ToLower ())

				select w).ToList ();

			if (list.Count > 0) {

				return string.Join (" ", list);

			}

			return "";

		}



		private void ExecutePowerShell (string script)

		{

			try {

				string text = string.Format ("$DockAppDir = '{0}';\r\nfunction Start-AppByName ($name) {{\r\n    if ((Get-Command $name -ErrorAction SilentlyContinue)) {{\r\n        Start-Process $name; return\r\n    }}\r\n    if ((Get-Command \"$name.exe\" -ErrorAction SilentlyContinue)) {{\r\n        Start-Process \"$name.exe\"; return\r\n    }}\r\n    $app = Get-StartApps | Where-Object {{ $_.Name -match $name }} | Select-Object -First 1\r\n    if ($app) {{\r\n        Start-Process \"shell:AppsFolder\\$($app.AppID)\"\r\n        return\r\n    }}\r\n    Write-Error \"Could not find app matching $name.\"\r\n}}\r\n", AppDomain.CurrentDomain.BaseDirectory.Replace ("\\", "\\\\"));

				string text2 = System.IO.Path.Combine (System.IO.Path.GetTempPath (), "windock_cmd_" + Guid.NewGuid ().ToString ("N").Substring (0, 8) + ".ps1");

				File.WriteAllText (text2, text + script);

				Process process = Process.Start (new ProcessStartInfo ("powershell.exe", "-NoProfile -NonInteractive -ExecutionPolicy Bypass -File \"" + text2 + "\"") {

					CreateNoWindow = true,

					UseShellExecute = false,

					RedirectStandardOutput = true,

					RedirectStandardError = true

				});

				StringBuilder outputBuilder = new StringBuilder ();

				StringBuilder errorBuilder = new StringBuilder ();

				process.OutputDataReceived += delegate(object sSender, DataReceivedEventArgs sArgs) {

					if (sArgs.Data != null) {

						lock (outputBuilder) {

							outputBuilder.AppendLine (sArgs.Data);

						}

					}

				};

				process.ErrorDataReceived += delegate(object sSender, DataReceivedEventArgs sArgs) {

					if (sArgs.Data != null) {

						lock (errorBuilder) {

							errorBuilder.AppendLine (sArgs.Data);

						}

					}

				};

				process.BeginOutputReadLine ();

				process.BeginErrorReadLine ();

				if (!process.WaitForExit (15000)) {

					try {

						process.Kill ();

					} catch {

					}

				}

				Thread.Sleep (100);

				string text3 = "";

				string text4 = "";

				lock (outputBuilder) {

					text3 = outputBuilder.ToString ();

				}

				lock (errorBuilder) {

					text4 = errorBuilder.ToString ();

				}

				string finalOutput = (text3 + "\n" + text4).Trim ();

				try {

					File.Delete (text2);

				} catch {

				}

				base.Dispatcher.BeginInvoke ((Action)delegate {

					SetSiriState ("calm");

					if (!string.IsNullOrWhiteSpace (finalOutput)) {

						AppendChat ("System", finalOutput);

					} else {

						AppendChat ("System", "Done!");

					}

				});

			} catch (Exception ex2) {

				Exception ex = ex2;

				base.Dispatcher.BeginInvoke ((Action)delegate {

					SetSiriState ("calm");

					AppendChat ("Error", "Execution Error: " + ex.Message);

				});

			}

		}



		public void ShowAnimated ()

		{

			base.Opacity = 0.0;

			Show ();

			Activate ();

			DoubleAnimation animation = new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (250.0)) {

				EasingFunction = new CircleEase {

					EasingMode = EasingMode.EaseOut

				}

			};

			BeginAnimation (UIElement.OpacityProperty, animation);

		}



		public void HideAnimated ()

		{

			DoubleAnimation doubleAnimation = new DoubleAnimation (0.0, TimeSpan.FromMilliseconds (200.0)) {

				EasingFunction = new CircleEase {

					EasingMode = EasingMode.EaseIn

				}

			};

			doubleAnimation.Completed += delegate {

				Hide ();

			};

			BeginAnimation (UIElement.OpacityProperty, doubleAnimation);

		}

		private void CreateWaveformVisualizer ()
		{
			waveformPanel = new StackPanel {
				Orientation = System.Windows.Controls.Orientation.Horizontal,
				VerticalAlignment = VerticalAlignment.Center,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
				Margin = new Thickness (5.0, 0.0, 5.0, 0.0),
				Visibility = Visibility.Collapsed
			};

			int[] heights = new int[] { 8, 14, 20, 14, 8 };
			for (int i = 0; i < 5; i++) {
				var bar = new System.Windows.Shapes.Rectangle {
					Width = 3.0,
					Height = heights[i],
					Fill = new LinearGradientBrush {
						StartPoint = new System.Windows.Point (0, 0),
						EndPoint = new System.Windows.Point (0, 1),
						GradientStops = {
							new GradientStop (System.Windows.Media.Color.FromRgb (0, 120, 255), 0.0),
							new GradientStop (System.Windows.Media.Color.FromRgb (0, 220, 255), 1.0)
						}
					},
					Margin = new Thickness (1.5, 0.0, 1.5, 0.0),
					RadiusX = 1.5,
					RadiusY = 1.5
				};
				waveBars.Add (bar);
				waveformPanel.Children.Add (bar);
			}
		}

		private void StartWaveformAnimation ()
		{
			double[] targetHeights = new double[] { 16.0, 24.0, 32.0, 24.0, 16.0 };
			double[] minHeights = new double[] { 6.0, 10.0, 14.0, 10.0, 6.0 };
			for (int i = 0; i < waveBars.Count; i++) {
				var bar = waveBars [i];
				DoubleAnimation anim = new DoubleAnimation {
					From = minHeights [i],
					To = targetHeights [i],
					Duration = TimeSpan.FromMilliseconds (300 + i * 50),
					AutoReverse = true,
					RepeatBehavior = RepeatBehavior.Forever
				};
				bar.BeginAnimation (FrameworkElement.HeightProperty, anim);
			}
		}

		private void StopWaveformAnimation ()
		{
			for (int i = 0; i < waveBars.Count; i++) {
				waveBars [i].BeginAnimation (FrameworkElement.HeightProperty, null);
			}
		}

		private void ToggleVoiceInput ()
		{
			if (_parent.speechManager == null) {
				_parent.StartSpeechManager ();
			}

			if (_isListeningSpeech) {
				StopVoiceInput ();
			} else {
				StartVoiceInput ();
			}
		}

		private void StartVoiceInput ()
		{
			if (_parent.speechManager == null) return;
			_isListeningSpeech = true;
			micButton.Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (255, 60, 60));
			
			waveformPanel.Visibility = Visibility.Visible;
			StartWaveformAnimation ();

			if (txtInput.Text == "Type to Apple Intelligence...") {
				txtInput.Text = "";
				txtInput.Foreground = System.Windows.Media.Brushes.White;
			}

			_parent.speechManager.StartManualDictation (
				delegate (string result) {
					Dispatcher.BeginInvoke (new Action (delegate {
						if (!string.IsNullOrEmpty (result)) {
							txtInput.Text = result;
							txtInput.Foreground = System.Windows.Media.Brushes.White;
							StopVoiceInput ();
							ProcessCommand (result);
						}
					}));
				},
				delegate (string hypothesis) {
					Dispatcher.BeginInvoke (new Action (delegate {
						if (!string.IsNullOrEmpty (hypothesis)) {
							txtInput.Text = hypothesis;
							txtInput.Foreground = System.Windows.Media.Brushes.LightBlue;
						}
					}));
				},
				delegate {
					Dispatcher.BeginInvoke (new Action (delegate {
						StopVoiceInput ();
					}));
				}
			);
		}

		private void StopVoiceInput ()
		{
			if (!_isListeningSpeech) return;
			_isListeningSpeech = false;
			micButton.Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (180, 185, 195));
			
			waveformPanel.Visibility = Visibility.Collapsed;
			StopWaveformAnimation ();

			if (_parent.speechManager != null) {
				_parent.speechManager.StopManualDictation ();
			}

			if (string.IsNullOrEmpty (txtInput.Text)) {
				txtInput.Text = "Type to Apple Intelligence...";
				txtInput.Foreground = System.Windows.Media.Brushes.LightGray;
			}
		}
	}

	public class IntentModel

	{

		[DataMember (Order = 0)]

		public string Intent { get; set; }



		[DataMember (Order = 1)]

		public List<string> Examples { get; set; }



		[DataMember (Order = 2)]

		public string Action { get; set; }

	}

	public class SpeechManager

	{

		private const double WakeWordMinConfidence = 0.55;



		private const double DictationCommandMinConfidence = 0.42;



		private const double LocalIntentAlternateMinConfidence = 0.55;



		private const double ManualDictationMinConfidence = 0.3;



		private const double RiskySingleWordMinConfidence = 0.8;



		private SpeechRecognitionEngine recognizer;



		private DockWindow _dockWindow;



		private bool _isListeningCommand;



		private System.Threading.Timer _timeoutTimer;



		private bool _isManualDictation;



		private Action<string> _manualDictationCallback;



		private Action<string> _manualDictationHypothesisCallback;



		private Action _manualDictationCompleted;



		public string SpeechInitializationError;



		public bool IsRunning => recognizer != null;



		public SpeechManager (DockWindow dockWindow)

		{

			_dockWindow = dockWindow;

		}



		private SpeechRecognitionEngine CreatePreferredSpeechRecognitionEngine ()

		{

			string[] array = (_dockWindow.settings.VoiceRecognitionCulture ?? "").Split (new char[1] { ',' }, StringSplitOptions.RemoveEmptyEntries);

			foreach (string text in array) {

				try {

					CultureInfo cultureInfo = new CultureInfo (text.Trim ());

					RecognizerInfo recognizerInfo = null;

					foreach (RecognizerInfo item in SpeechRecognitionEngine.InstalledRecognizers ()) {

						if (item.Culture != null && item.Culture.Name.Equals (cultureInfo.Name, StringComparison.OrdinalIgnoreCase)) {

							recognizerInfo = item;

							break;

						}

					}

					if (recognizerInfo != null) {

						return new SpeechRecognitionEngine (recognizerInfo);

					}

				} catch {

				}

			}

			return new SpeechRecognitionEngine ();

		}



		public void Start ()

		{

			Task.Run (delegate {

				try {

					SpeechInitializationError = null;

					if (recognizer != null) {

						try {

							recognizer.Dispose ();

						} catch {

						}

						recognizer = null;

					}

					try {

						recognizer = CreatePreferredSpeechRecognitionEngine ();

					} catch (Exception ex) {

						SpeechInitializationError = "Engine initialization failed: " + ex.Message;

						return;

					}

					try {

						recognizer.SetInputToDefaultAudioDevice ();

					} catch (Exception ex2) {

						SpeechInitializationError = "Microphone connection error: " + ex2.Message;

						try {

							recognizer.Dispose ();

						} catch {

						}

						recognizer = null;

						return;

					}

					try {

						LoadWakeWordGrammars ();

						recognizer.SpeechRecognized += Recognizer_SpeechRecognized;

						recognizer.SpeechHypothesized += Recognizer_SpeechHypothesized;

						recognizer.RecognizeAsync (RecognizeMode.Multiple);

					} catch (Exception ex3) {

						SpeechInitializationError = "Recognition start failed: " + ex3.Message;

						try {

							recognizer.Dispose ();

						} catch {

						}

						recognizer = null;

					}

				} catch (Exception ex4) {

					SpeechInitializationError = "Startup failed: " + ex4.Message;

				}

			});

		}



		public void Stop ()

		{

			try {

				if (recognizer != null) {

					recognizer.RecognizeAsyncStop ();

					recognizer.SpeechRecognized -= Recognizer_SpeechRecognized;

					recognizer.SpeechHypothesized -= Recognizer_SpeechHypothesized;

					recognizer.Dispose ();

					recognizer = null;

				}

				if (_timeoutTimer != null) {

					_timeoutTimer.Dispose ();

					_timeoutTimer = null;

				}

				_isListeningCommand = false;

				_isManualDictation = false;

			} catch (Exception) {

			}

		}



		private void SafeSwitchGrammar (Action action)

		{

			if (recognizer == null) {

				return;

			}

			try {

				recognizer.RecognizeAsyncCancel ();

				int num = 0;

				while (recognizer != null && recognizer.AudioState != 0 && num < 10) {

					Thread.Sleep (50);

					num++;

				}

			} catch (Exception) {

			}

			try {

				recognizer.UnloadAllGrammars ();

				action ();

			} catch (Exception) {

				Thread.Sleep (200);

				try {

					recognizer.UnloadAllGrammars ();

					action ();

				} catch (Exception ex2) {

					throw ex2;

				}

			}

		}



		private void LoadWakeWordGrammars ()

		{

			if (recognizer != null) {

				Choices choices = new Choices ();

				choices.Add ("hey chonk");

				choices.Add ("chonk");

				choices.Add ("hey chunk");

				choices.Add ("chunk");

				choices.Add ("hay chonk");

				choices.Add ("shonk");

				choices.Add ("chank");

				choices.Add ("hey chang");

				choices.Add ("hey shonk");

				choices.Add ("hey chank");

				Grammar grammar = new Grammar (NewGrammarBuilder (choices));

				grammar.Name = "WakeWord";

				recognizer.LoadGrammar (grammar);

				try {

					Choices localIntentsChoices = GetLocalIntentsChoices ();

					GrammarBuilder grammarBuilder = NewGrammarBuilder ();

					grammarBuilder.Append (choices);

					grammarBuilder.Append (localIntentsChoices);

					Grammar grammar2 = new Grammar (grammarBuilder);

					grammar2.Name = "WakeWordLocalIntent";

					recognizer.LoadGrammar (grammar2);

				} catch (Exception) {

				}

				GrammarBuilder grammarBuilder2 = NewGrammarBuilder ();

				grammarBuilder2.Append (choices);

				grammarBuilder2.AppendDictation ();

				Grammar grammar3 = new Grammar (grammarBuilder2);

				grammar3.Name = "WakeWordDictation";

				recognizer.LoadGrammar (grammar3);

			}

		}



		private GrammarBuilder NewGrammarBuilder ()

		{

			GrammarBuilder grammarBuilder = new GrammarBuilder ();

			try {

				if (recognizer != null) {

					if (recognizer.RecognizerInfo != null) {

						if (recognizer.RecognizerInfo.Culture != null) {

							grammarBuilder.Culture = recognizer.RecognizerInfo.Culture;

							return grammarBuilder;

						}

						return grammarBuilder;

					}

					return grammarBuilder;

				}

				return grammarBuilder;

			} catch {

				return grammarBuilder;

			}

		}



		private GrammarBuilder NewGrammarBuilder (Choices choices)

		{

			GrammarBuilder grammarBuilder = NewGrammarBuilder ();

			grammarBuilder.Append (choices);

			return grammarBuilder;

		}



		private Choices GetLocalIntentsChoices ()

		{

			Choices choices = new Choices ();

			bool flag = false;

			try {

				string path = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "intents.json");

				if (File.Exists (path)) {

					string input = File.ReadAllText (path);

					List<IntentModel> list = new JavaScriptSerializer ().Deserialize<List<IntentModel>> (input);

					if (list != null) {

						HashSet<string> seen = new HashSet<string> (StringComparer.OrdinalIgnoreCase);

						foreach (IntentModel item in list) {

							if (item.Examples == null) {

								continue;

							}

							foreach (string example in item.Examples) {

								AddIndianEnglishChoiceVariants (choices, seen, example);

								flag = true;

							}

						}

					}

				}

			} catch (Exception) {

			}

			if (!flag) {

				choices.Add ("open spotify");

				choices.Add ("open chrome");

				choices.Add ("play music");

				choices.Add ("mute volume");

			}

			return choices;

		}



		private static void AddChoice (Choices choices, HashSet<string> seen, string phrase)

		{

			string text = (phrase ?? "").Trim ();

			if (text.Length != 0 && !seen.Contains (text)) {

				seen.Add (text);

				choices.Add (text);

			}

		}



		private void AddIndianEnglishChoiceVariants (Choices choices, HashSet<string> seen, string phrase)

		{

			string text = CollapseSpaces ((phrase ?? "").Replace ("{query}", "").ToLowerInvariant ());

			if (text.Length == 0) {

				return;

			}

			AddChoice (choices, seen, text);

			AddChoice (choices, seen, "please " + text);

			AddChoice (choices, seen, "kindly " + text);

			if (text.Contains ("open ")) {

				string text2 = CollapseSpaces (text.Replace ("open ", ""));

				if (text2.Length > 0) {

					AddChoice (choices, seen, "open the " + text2);

					AddChoice (choices, seen, "start " + text2);

					AddChoice (choices, seen, "launch " + text2);

				}

			}

			if (text.Contains ("play ")) {

				AddChoice (choices, seen, text.Replace ("play ", "start playing "));

				AddChoice (choices, seen, text.Replace ("play ", "please play "));

			}

			if (text.Contains ("volume up")) {

				AddChoice (choices, seen, "increase the volume");

				AddChoice (choices, seen, "raise the volume");

				AddChoice (choices, seen, "make it louder");

			}

			if (text.Contains ("volume down")) {

				AddChoice (choices, seen, "decrease the volume");

				AddChoice (choices, seen, "lower the volume");

				AddChoice (choices, seen, "make it quieter");

			}

			if (text.Contains ("mute")) {

				AddChoice (choices, seen, "mute the volume");

				AddChoice (choices, seen, "mute sound");

			}

		}



		public void StartManualDictation (Action<string> onResult, Action onCompleted)

		{

			StartManualDictation (onResult, null, onCompleted);

		}



		public void StartManualDictation (Action<string> onResult, Action<string> onHypothesis, Action onCompleted)

		{

			_manualDictationCallback = onResult;

			_manualDictationHypothesisCallback = onHypothesis;

			_manualDictationCompleted = onCompleted;

			string error;

			Task.Run (delegate {

				try {

					int num = 0;

					while (recognizer == null && num < 25) {

						Thread.Sleep (100);

						num++;

					}

					if (recognizer == null) {

						error = SpeechInitializationError;

						_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

							if (!string.IsNullOrEmpty (error) && _dockWindow.aiAssistantOverlay != null) {

								_dockWindow.aiAssistantOverlay.AppendChat ("Assistant", "Could not start microphone: " + error + ". Please ensure a default recording device is connected and enabled.");

							}

							if (onCompleted != null) {

								onCompleted ();

							}

						});

					} else {

						_isManualDictation = true;

						SafeSwitchGrammar (delegate {

							Choices localIntentsChoices = GetLocalIntentsChoices ();

							Grammar grammar = new Grammar (NewGrammarBuilder (localIntentsChoices)) {

								Name = "LocalIntents"

							};

							recognizer.LoadGrammar (grammar);

							DictationGrammar grammar2 = new DictationGrammar {

								Name = "ManualDictation"

							};

							recognizer.LoadGrammar (grammar2);

						});

						recognizer.RecognizeAsync (RecognizeMode.Multiple);

						if (_timeoutTimer != null) {

							_timeoutTimer.Dispose ();

						}

						_timeoutTimer = new System.Threading.Timer (OnManualTimeout, null, 10000, -1);

					}

				} catch (Exception) {

					if (onCompleted != null) {

						_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

							onCompleted ();

						});

					}

				}

			});

		}



		private void OnManualTimeout (object state)

		{

			StopManualDictation ();

		}



		public void StopManualDictation ()

		{

			if (!_isManualDictation) {

				return;

			}

			_isManualDictation = false;

			if (_timeoutTimer != null) {

				_timeoutTimer.Dispose ();

				_timeoutTimer = null;

			}

			Task.Run (delegate {

				try {

					if (recognizer != null) {

						if (_dockWindow.settings.EnableVoiceCommands) {

							SafeSwitchGrammar (delegate {

								LoadWakeWordGrammars ();

							});

							recognizer.RecognizeAsync (RecognizeMode.Multiple);

						} else {

							Stop ();

						}

					}

				} catch (Exception) {

				} finally {

					if (_manualDictationCompleted != null) {

						_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

							_manualDictationCompleted ();

						});

					}

				}

			});

		}



		private void Recognizer_SpeechHypothesized (object sender, SpeechHypothesizedEventArgs e)

		{

			if (e.Result == null) {

				return;

			}

			string hypText = e.Result.Text;

			if (string.IsNullOrWhiteSpace (hypText)) {

				return;

			}

			_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

				if (_isManualDictation && _manualDictationHypothesisCallback != null) {

					_manualDictationHypothesisCallback (hypText);

				} else if (_dockWindow.aiAssistantOverlay != null && _dockWindow.aiAssistantOverlay.IsVisible) {

					_dockWindow.aiAssistantOverlay.UpdateHypothesis (hypText);

				}

			});

		}



		private void Recognizer_SpeechRecognized (object sender, SpeechRecognizedEventArgs e)

		{

			if (e.Result == null) {

				return;

			}

			if (_isManualDictation) {

				string text = e.Result.Text;

				double confidence = e.Result.Confidence;

				string grammarName = ((e.Result.Grammar != null) ? e.Result.Grammar.Name : "");

				if (TryGetLocalIntentAlternate (e.Result, 0.55, out var alternateText, out var alternateConfidence)) {

					text = alternateText;

					confidence = alternateConfidence;

					grammarName = "LocalIntents";

				}

				text = NormalizeRecognizedText (text);

				if (ShouldAcceptRecognizedCommand (text, confidence, grammarName, isManualDictation: true) && !string.IsNullOrWhiteSpace (text)) {

					if (_manualDictationCallback != null) {

						_manualDictationCallback (text);

					}

					StopManualDictation ();

				}

				return;

			}

			string text2 = NormalizeRecognizedText (e.Result.Text);

			if (!_isListeningCommand) {

				if ((double)e.Result.Confidence < 0.55 || GetMatchedWakeWord (text2) == null) {

					return;

				}

				_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

					if (_dockWindow.aiAssistantOverlay == null) {

						_dockWindow.aiAssistantOverlay = new AIAssistantWindow (_dockWindow);

					}

					if (!_dockWindow.aiAssistantOverlay.IsVisible) {

						_dockWindow.aiAssistantOverlay.ShowAnimated ();

					}

					_dockWindow.aiAssistantOverlay.AppendChat ("Assistant", "Yes? I am listening...");

					_dockWindow.aiAssistantOverlay.SetSiriState ("thinking");

					_isListeningCommand = true;

					Task.Run (delegate {

						try {

							SafeSwitchGrammar (delegate {

								DictationGrammar grammar = new DictationGrammar {

									Name = "Dictation"

								};

								recognizer.LoadGrammar (grammar);

								Choices localIntentsChoices = GetLocalIntentsChoices ();

								Grammar grammar2 = new Grammar (NewGrammarBuilder (localIntentsChoices)) {

									Name = "LocalIntents"

								};

								recognizer.LoadGrammar (grammar2);

							});

							recognizer.RecognizeAsync (RecognizeMode.Multiple);

							if (_timeoutTimer != null) {

								_timeoutTimer.Dispose ();

							}

							_timeoutTimer = new System.Threading.Timer (OnTimeout, null, 7000, -1);

						} catch (Exception) {

						}

					});

				});

				return;

			}

			string command = e.Result.Text;

			double confidence2 = e.Result.Confidence;

			string grammarName2 = ((e.Result.Grammar != null) ? e.Result.Grammar.Name : "");

			if (TryGetLocalIntentAlternate (e.Result, 0.55, out var alternateText2, out var alternateConfidence2)) {

				command = alternateText2;

				confidence2 = alternateConfidence2;

				grammarName2 = "LocalIntents";

			}

			command = NormalizeRecognizedText (command);

			if (!ShouldAcceptRecognizedCommand (command, confidence2, grammarName2, isManualDictation: false)) {

				return;

			}

			_isListeningCommand = false;

			if (_timeoutTimer != null) {

				_timeoutTimer.Dispose ();

			}

			_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

				if (_dockWindow.aiAssistantOverlay != null) {

					_dockWindow.aiAssistantOverlay.ProcessCommand (command);

				}

			});

			Task.Run (delegate {

				try {

					if (_dockWindow.settings.EnableVoiceCommands) {

						SafeSwitchGrammar (delegate {

							LoadWakeWordGrammars ();

						});

						recognizer.RecognizeAsync (RecognizeMode.Multiple);

					} else {

						Stop ();

					}

				} catch (Exception) {

				}

			});

		}



		private void OnTimeout (object state)

		{

			if (!_isListeningCommand) {

				return;

			}

			_isListeningCommand = false;

			_dockWindow.Dispatcher.BeginInvoke ((Action)delegate {

				if (_dockWindow.aiAssistantOverlay != null) {

					_dockWindow.aiAssistantOverlay.AppendChat ("Assistant", "Timed out listening for command.");

					_dockWindow.aiAssistantOverlay.SetSiriState ("calm");

				}

			});

			try {

				if (_dockWindow.settings.EnableVoiceCommands) {

					SafeSwitchGrammar (delegate {

						LoadWakeWordGrammars ();

					});

					recognizer.RecognizeAsync (RecognizeMode.Multiple);

				} else {

					Stop ();

				}

			} catch (Exception) {

			}

		}



		private string GetMatchedWakeWord (string text)

		{

			if (string.IsNullOrEmpty (text)) {

				return null;

			}

			string[] array = new string[10] { "hey chonk", "hey chunk", "chonk", "chunk", "hay chonk", "shonk", "chank", "hey chang", "hey shonk", "hey chank" };

			foreach (string text2 in array) {

				if (text.Contains (text2)) {

					return text2;

				}

			}

			return null;

		}



		private bool TryGetLocalIntentAlternate (RecognitionResult result, double minConfidence, out string alternateText, out double alternateConfidence)

		{

			alternateText = null;

			alternateConfidence = 0.0;

			if (result == null || result.Alternates == null) {

				return false;

			}

			HashSet<string> hashSet = new HashSet<string> (StringComparer.OrdinalIgnoreCase);

			try {

				string path = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "intents.json");

				if (File.Exists (path)) {

					string input = File.ReadAllText (path);

					List<IntentModel> list = new JavaScriptSerializer ().Deserialize<List<IntentModel>> (input);

					if (list != null) {

						foreach (IntentModel item2 in list) {

							if (item2.Examples == null) {

								continue;

							}

							foreach (string example in item2.Examples) {

								string text = NormalizeRecognizedText (example.Replace ("{query}", ""));

								if (!string.IsNullOrEmpty (text)) {

									hashSet.Add (text);

									hashSet.Add ("please " + text);

									hashSet.Add ("kindly " + text);

								}

							}

						}

					}

				}

			} catch {

			}

			if (hashSet.Count == 0) {

				hashSet.Add ("open spotify");

				hashSet.Add ("open chrome");

				hashSet.Add ("play music");

				hashSet.Add ("mute volume");

			}

			foreach (RecognizedPhrase alternate in result.Alternates) {

				if ((double)alternate.Confidence >= minConfidence) {

					string item = NormalizeRecognizedText (alternate.Text);

					if (hashSet.Contains (item)) {

						alternateText = alternate.Text;

						alternateConfidence = alternate.Confidence;

						return true;

					}

				}

			}

			return false;

		}



		private string NormalizeRecognizedText (string text)

		{

			if (string.IsNullOrEmpty (text)) {

				return "";

			}

			string text2 = text.ToLowerInvariant ();

			StringBuilder stringBuilder = new StringBuilder ();

			string text3 = text2;

			foreach (char c in text3) {

				if (!char.IsPunctuation (c)) {

					stringBuilder.Append (c);

				}

			}

			return CollapseSpaces (stringBuilder.ToString ()).Trim ();

		}



		private string CollapseSpaces (string text)

		{

			if (string.IsNullOrEmpty (text)) {

				return "";

			}

			return Regex.Replace (text, "\\s+", " ");

		}



		private bool ShouldAcceptRecognizedCommand (string text, double confidence, string grammarName, bool isManualDictation)

		{

			if (string.IsNullOrEmpty (text)) {

				return false;

			}

			double num = 0.42;

			if (isManualDictation) {

				num = 0.3;

			} else {

				switch (grammarName) {

				case "WakeWord":

				case "WakeWordLocalIntent":

				case "WakeWordDictation":

					num = 0.55;

					break;

				case "LocalIntents":

					num = 0.55;

					break;

				}

			}

			if (text.Split (new char[1] { ' ' }, StringSplitOptions.RemoveEmptyEntries).Length <= 1) {

				num = Math.Max (num, 0.8);

			}

			return confidence >= num;

		}

	}

