		private static void UpdateSimulationTick ()

		{

			InitializeSimulation ();

			simLapPercent += 5.0;

			if (simLapPercent >= 100.0) {

				simLapPercent = 0.0;

				simLapNumber++;

				string arg = TimeSpan.FromSeconds (78.0 + rand.NextDouble () * 1.5).ToString ("m\\:ss\\.fff");

				simLaps.Insert (0, $"VER - Lap {simLapNumber - 1} - {arg}s");

			}

			if (rand.Next (0, 8) == 0) {

				int num = rand.Next (1, simPositions.Count - 2);

				SimDriverPosition simDriverPosition = simPositions [num];

				SimDriverPosition simDriverPosition2 = simPositions [num + 1];

				simPositions [num] = simDriverPosition2;

				simPositions [num + 1] = simDriverPosition;

				simRaceControl.Insert (0, $"LAP {simLapNumber}: CAR {simDriverPosition2.Number} ({simDriverPosition2.Code}) OVERTOOK CAR {simDriverPosition.Number} ({simDriverPosition.Code}) FOR P{num + 1}");

			}

			if (rand.Next (0, 15) == 0) {

				int index = rand.Next (4, simPositions.Count);

				SimDriverPosition simDriverPosition3 = simPositions [index];

				double num2 = 2.1 + rand.NextDouble () * 1.5;

				simPitStops.Insert (0, $"Lap {simLapNumber} | {simDriverPosition3.Code} | {num2:F1}s");

				simRaceControl.Insert (0, $"LAP {simLapNumber}: CAR {simDriverPosition3.Number} ({simDriverPosition3.Code}) PIT STOP - {num2:F1}s");

			}

			simTrackTemp += (rand.NextDouble () - 0.5) * 0.2;

			if (simTrackTemp < 35.0) {

				simTrackTemp = 35.0;

			}

			if (simTrackTemp > 42.0) {

				simTrackTemp = 42.0;

			}

		}



		private static Border CreateToggleButton (string text, bool isActive, bool isLight)

		{

			System.Windows.Media.Color color = System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue);

			System.Windows.Media.Color color2 = (isLight ? System.Windows.Media.Color.FromArgb (15, 0, 0, 0) : System.Windows.Media.Color.FromArgb (25, byte.MaxValue, byte.MaxValue, byte.MaxValue));

			System.Windows.Media.Color color3 = (isActive ? Colors.White : (isLight ? Colors.Black : Colors.White));

			return new Border {

				Background = new SolidColorBrush (isActive ? color : color2),

				CornerRadius = new CornerRadius (6.0),

				Padding = new Thickness (0.0, 6.0, 0.0, 6.0),

				Margin = new Thickness (4.0),

				Cursor = System.Windows.Input.Cursors.Hand,

				Child = new TextBlock {

					Text = text,

					Foreground = new SolidColorBrush (color3),

					FontWeight = (isActive ? FontWeights.Bold : FontWeights.SemiBold),

					FontSize = 11.0,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Center

				}

			};

		}



		public static async void Render (string tabName, StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			activePollingTab = tabName;

			Grid grid = new Grid {

				Margin = new Thickness (10.0, 0.0, 10.0, 10.0)

			};

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			Border border = CreateToggleButton ("API FEED", !isSimulationMode, isLight);

			Border border2 = CreateToggleButton ("\ud83d\udd34 SIMULATOR", isSimulationMode, isLight);

			Grid.SetColumn (border, 0);

			Grid.SetColumn (border2, 1);

			grid.Children.Add (border);

			grid.Children.Add (border2);

			border.MouseLeftButtonUp += delegate {

				isSimulationMode = false;

				Render (tabName, listPanel, isLight);

			};

			border2.MouseLeftButtonUp += delegate {

				isSimulationMode = true;

				Render (tabName, listPanel, isLight);

			};

			listPanel.Children.Add (grid);

			StackPanel contentContainer = new StackPanel ();

			listPanel.Children.Add (contentContainer);

			try {

				while (activePollingTab == tabName) {

					if (isSimulationMode) {

						UpdateSimulationTick ();

						if (tabName == "Weather") {

							RenderSimWeather (contentContainer, isLight);

						} else if (tabName == "Race Control") {

							RenderSimRaceControl (contentContainer, isLight);

						} else if (tabName == "Pit Stops") {

							RenderSimPitStops (contentContainer, isLight);

						} else if (tabName == "Positions") {

							RenderSimPositions (contentContainer, isLight);

						} else if (tabName == "Laps") {

							RenderSimLaps (contentContainer, isLight);

						} else if (tabName == "Telemetry") {

							RenderSimTelemetry (contentContainer, isLight);

						}

					} else if (tabName == "Weather") {

						await RenderWeather (contentContainer, isLight);

					} else if (tabName == "Race Control") {

						await RenderRaceControl (contentContainer, isLight);

					} else if (tabName == "Pit Stops") {

						await RenderPitStops (contentContainer, isLight);

					} else if (tabName == "Positions") {

						await RenderPositions (contentContainer, isLight);

					} else if (tabName == "Laps") {

						await RenderLaps (contentContainer, isLight);

					} else if (tabName == "Telemetry") {

						await RenderTelemetry (contentContainer, isLight);

					}

					if (activePollingTab != tabName) {

						break;

					}

					await Task.Delay (2000);

				}

			} catch (Exception ex) {

				contentContainer.Children.Clear ();

				contentContainer.Children.Add (new TextBlock {

					Text = "Error loading data: " + ex.Message,

					Foreground = System.Windows.Media.Brushes.Red,

					Margin = new Thickness (20.0)

				});

			}

		}



		private static async Task RenderWeather (StackPanel listPanel, bool isLight)

		{

			List<OpenF1Weather> list = await OpenF1Client.GetWeatherAsync ();

			if (activePollingTab != "Weather" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			if (list == null || list.Count == 0) {

				listPanel.Children.Add (new TextBlock {

					Text = "No weather data available.",

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					Margin = new Thickness (20.0)

				});

				return;

			}

			OpenF1Weather openF1Weather = list.OrderByDescending ((OpenF1Weather w) => w.date).FirstOrDefault ();

			Grid grid = new Grid {

				Margin = new Thickness (20.0)

			};

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.Children.Add (CreateWeatherCard ("Air Temp", $"{openF1Weather.air_temperature}°C", isLight, 0, 0));

			grid.Children.Add (CreateWeatherCard ("Track Temp", $"{openF1Weather.track_temperature}°C", isLight, 0, 1));

			grid.Children.Add (CreateWeatherCard ("Humidity", $"{openF1Weather.humidity}%", isLight, 1, 0));

			grid.Children.Add (CreateWeatherCard ("Rainfall", (openF1Weather.rainfall > 0.0) ? "Yes" : "No", isLight, 1, 1));

			grid.Children.Add (CreateWeatherCard ("Wind Speed", $"{openF1Weather.wind_speed} m/s", isLight, 2, 0));

			grid.Children.Add (CreateWeatherCard ("Wind Dir", $"{openF1Weather.wind_direction}°", isLight, 2, 1));

			listPanel.Children.Add (grid);

		}



