		private static void AttachHoverAnimation (Border b, bool isLight)

		{

			System.Windows.Media.Brush defaultBg = b.Background;

			SolidColorBrush hoverBg = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, byte.MaxValue, byte.MaxValue, byte.MaxValue)));

			ScaleTransform transform = new ScaleTransform (1.0, 1.0);

			b.RenderTransformOrigin = new System.Windows.Point (0.5, 0.5);

			b.RenderTransform = transform;

			b.MouseEnter += delegate {

				transform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.02, TimeSpan.FromMilliseconds (150.0)));

				transform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.02, TimeSpan.FromMilliseconds (150.0)));

				b.Background = hoverBg;

			};

			b.MouseLeave += delegate {

				transform.BeginAnimation (ScaleTransform.ScaleXProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (200.0)));

				transform.BeginAnimation (ScaleTransform.ScaleYProperty, new DoubleAnimation (1.0, TimeSpan.FromMilliseconds (200.0)));

				b.Background = defaultBg;

			};

		}



		private static UIElement CreateWeatherCard (string title, string value, bool isLight, int row, int col)

		{

			Border obj = new Border {

				Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (20, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

				CornerRadius = new CornerRadius (10.0),

				Padding = new Thickness (15.0),

				Margin = new Thickness (5.0)

			};

			AttachHoverAnimation (obj, isLight);

			StackPanel stackPanel = new StackPanel {

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center

			};

			stackPanel.Children.Add (new TextBlock {

				Text = title,

				FontSize = 12.0,

				Foreground = (isLight ? System.Windows.Media.Brushes.DarkGray : System.Windows.Media.Brushes.LightGray),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center

			});

			stackPanel.Children.Add (new TextBlock {

				Text = value,

				FontSize = 24.0,

				FontWeight = FontWeights.Bold,

				Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center

			});

			obj.Child = stackPanel;

			Grid.SetRow (obj, row);

			Grid.SetColumn (obj, col);

			return obj;

		}



		private static async Task RenderRaceControl (StackPanel listPanel, bool isLight)

		{

			List<OpenF1RaceControl> list = await OpenF1Client.GetRaceControlAsync ();

			if (activePollingTab != "Race Control" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			if (list == null || list.Count == 0) {

				return;

			}

			foreach (OpenF1RaceControl item in list.OrderByDescending ((OpenF1RaceControl m) => m.date).Take (30)) {

				Border border = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (5.0),

					Padding = new Thickness (10.0),

					Margin = new Thickness (5.0)

				};

				AttachHoverAnimation (border, isLight);

				StackPanel stackPanel = new StackPanel ();

				stackPanel.Children.Add (new TextBlock {

					Text = item.date,

					FontSize = 10.0,

					Foreground = System.Windows.Media.Brushes.Gray

				});

				stackPanel.Children.Add (new TextBlock {

					Text = item.message,

					FontSize = 14.0,

					FontWeight = FontWeights.SemiBold,

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					TextWrapping = TextWrapping.Wrap

				});

				if (!string.IsNullOrEmpty (item.flag)) {

					stackPanel.Children.Add (new TextBlock {

						Text = "FLAG: " + item.flag,

						FontSize = 12.0,

						Foreground = new SolidColorBrush (isLight ? System.Windows.Media.Color.FromRgb (byte.MaxValue, 59, 48) : System.Windows.Media.Color.FromRgb (byte.MaxValue, 69, 58)),

						FontWeight = FontWeights.Bold

					});

				}

				border.Child = stackPanel;

				listPanel.Children.Add (border);

			}

		}



		private static void RenderSimRaceControl (StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			foreach (string item in simRaceControl.Take (30)) {

				Border border = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (5.0),

					Padding = new Thickness (10.0),

					Margin = new Thickness (5.0)

				};

				AttachHoverAnimation (border, isLight);

				StackPanel stackPanel = new StackPanel ();

				stackPanel.Children.Add (new TextBlock {

					Text = "LIVE SESSION LOG",

					FontSize = 9.0,

					Foreground = System.Windows.Media.Brushes.Gray

				});

				stackPanel.Children.Add (new TextBlock {

					Text = item,

					FontSize = 13.0,

					FontWeight = FontWeights.SemiBold,

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					TextWrapping = TextWrapping.Wrap

				});

				if (item.Contains ("YELLOW FLAG") || item.Contains ("PENALTY")) {

					stackPanel.Children.Add (new TextBlock {

