						Foreground = new SolidColorBrush (isLight ? System.Windows.Media.Color.FromRgb (byte.MaxValue, 59, 48) : System.Windows.Media.Color.FromRgb (byte.MaxValue, 69, 58)),

						FontWeight = FontWeights.Bold

					});

				}

				border.Child = stackPanel;

				listPanel.Children.Add (border);

			}

		}



		private static async Task RenderPitStops (StackPanel listPanel, bool isLight)

		{

			Task<List<OpenF1PitStop>> pitStopsTask = OpenF1Client.GetPitStopsAsync ();

			Task<List<OpenF1Driver>> driversTask = OpenF1Client.GetDriversAsync ();

			await Task.WhenAll (pitStopsTask, driversTask);

			if (activePollingTab != "Pit Stops" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			List<OpenF1PitStop> result = pitStopsTask.Result;

			List<OpenF1Driver> result2 = driversTask.Result;

			if (result == null || result.Count == 0) {

				return;

			}

			foreach (OpenF1PitStop stop in result.OrderByDescending ((OpenF1PitStop p) => p.date).Take (30)) {

				OpenF1Driver openF1Driver = result2?.FirstOrDefault ((OpenF1Driver d) => d.driver_number == stop.driver_number);

				string text = ((openF1Driver != null) ? openF1Driver.name_acronym : stop.driver_number.ToString ());

				Border border = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (5.0),

					Padding = new Thickness (10.0),

					Margin = new Thickness (5.0)

				};

				AttachHoverAnimation (border, isLight);

				Grid grid = new Grid ();

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (50.0)

				});

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.0, GridUnitType.Star)

				});

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = GridLength.Auto

				});

				grid.Children.Add (new TextBlock {

					Text = $"Lap {stop.lap_number}",

					Foreground = System.Windows.Media.Brushes.Gray,

					VerticalAlignment = VerticalAlignment.Center

				});

				TextBlock element = new TextBlock {

					Text = text,

					FontWeight = FontWeights.Bold,

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					VerticalAlignment = VerticalAlignment.Center

				};

				Grid.SetColumn (element, 1);

				grid.Children.Add (element);

				TextBlock element2 = new TextBlock {

					Text = $"{stop.pit_duration}s",

					FontWeight = FontWeights.Bold,

					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue)),

					VerticalAlignment = VerticalAlignment.Center

				};

				Grid.SetColumn (element2, 2);

				grid.Children.Add (element2);

				border.Child = grid;

				listPanel.Children.Add (border);

			}

		}



		private static void RenderSimPitStops (StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			foreach (string item in simPitStops.Take (30)) {

				string[] array = item.Split ('|');

				if (array.Length >= 3) {

					Border border = new Border {

						Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

						CornerRadius = new CornerRadius (5.0),

						Padding = new Thickness (10.0),

						Margin = new Thickness (5.0)

					};

					AttachHoverAnimation (border, isLight);

					Grid grid = new Grid ();

					grid.ColumnDefinitions.Add (new ColumnDefinition {

						Width = new GridLength (60.0)

					});

					grid.ColumnDefinitions.Add (new ColumnDefinition {

						Width = new GridLength (1.0, GridUnitType.Star)

					});

					grid.ColumnDefinitions.Add (new ColumnDefinition {

						Width = GridLength.Auto

					});

					grid.Children.Add (new TextBlock {

						Text = array [0].Trim (),

						Foreground = System.Windows.Media.Brushes.Gray,

						VerticalAlignment = VerticalAlignment.Center

					});

					TextBlock element = new TextBlock {

						Text = array [1].Trim (),

						FontWeight = FontWeights.Bold,

						Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

						VerticalAlignment = VerticalAlignment.Center

					};

					Grid.SetColumn (element, 1);

					grid.Children.Add (element);

					TextBlock element2 = new TextBlock {

						Text = array [2].Trim (),

						FontWeight = FontWeights.Bold,

						Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue)),

						VerticalAlignment = VerticalAlignment.Center

					};

					Grid.SetColumn (element2, 2);

					grid.Children.Add (element2);

					border.Child = grid;

					listPanel.Children.Add (border);

				}

			}

		}



		private static FrameworkElement CreateTickerRibbon (List<Tuple<int, string, System.Windows.Media.Color>> drivers, bool isLight)

		{

			Border ribbonBorder = new Border {

				Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (15, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

				CornerRadius = new CornerRadius (8.0),

				Padding = new Thickness (6.0),

				Margin = new Thickness (10.0, 5.0, 10.0, 10.0),

				Height = 36.0

			};

			ScrollViewer scrollViewer = new ScrollViewer {

				HorizontalScrollBarVisibility = ScrollBarVisibility.Hidden,

				VerticalScrollBarVisibility = ScrollBarVisibility.Disabled,

				Focusable = false

			};

			StackPanel stackPanel = new StackPanel {

				Orientation = System.Windows.Controls.Orientation.Horizontal

			};

			foreach (Tuple<int, string, System.Windows.Media.Color> driver in drivers) {

				int pos = driver.Item1;

				string code = driver.Item2;

				System.Windows.Media.Color color = driver.Item3;

				Border itemBorder = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (30, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (4.0),

					BorderThickness = new Thickness (3.0, 0.0, 0.0, 0.0),

					BorderBrush = new SolidColorBrush (color),

					Padding = new Thickness (8.0, 2.0, 8.0, 2.0),

					Margin = new Thickness (4.0, 0.0, 4.0, 0.0),

					VerticalAlignment = VerticalAlignment.Center

				};

				TextBlock textBlock = new TextBlock {

					Text = $"{code} P{pos}",

					FontSize = 11.0,

					FontWeight = FontWeights.Bold,

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					VerticalAlignment = VerticalAlignment.Center

				};

				itemBorder.Child = textBlock;

				stackPanel.Children.Add (itemBorder);

			}

			scrollViewer.Content = stackPanel;

			ribbonBorder.Child = scrollViewer;

			return ribbonBorder;

		}



		private static async Task RenderPositions (StackPanel listPanel, bool isLight)

		{

			Task<List<OpenF1Position>> positionsTask = OpenF1Client.GetPositionsAsync ();

			Task<List<OpenF1Driver>> driversTask = OpenF1Client.GetDriversAsync ();

			await Task.WhenAll (positionsTask, driversTask);

			if (activePollingTab != "Positions" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			List<OpenF1Position> result = positionsTask.Result;

			List<OpenF1Driver> result2 = driversTask.Result;

			if (result == null || result.Count == 0) {

				return;

			}

			List<OpenF1Position> orderedPositions = (from p in result

				group p by p.driver_number into g

				select g.OrderByDescending ((OpenF1Position p) => p.date).First () into p

				orderby p.position

				select p).ToList ();

			List<Tuple<int, string, System.Windows.Media.Color>> tickerDrivers = new List<Tuple<int, string, System.Windows.Media.Color>> ();

			foreach (OpenF1Position pos in orderedPositions) {

				OpenF1Driver openF1Driver = result2?.FirstOrDefault ((OpenF1Driver d) => d.driver_number == pos.driver_number);

				string acronym = openF1Driver?.name_acronym ?? pos.driver_number.ToString ();

				System.Windows.Media.Color color = System.Windows.Media.Color.FromRgb (100, 100, 100);

				if (openF1Driver != null && !string.IsNullOrEmpty (openF1Driver.team_colour)) {

					try {

						color = (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#" + openF1Driver.team_colour);

					} catch {

					}

				}

				tickerDrivers.Add (Tuple.Create (pos.position ?? 0, acronym, color));

			}

			if (tickerDrivers.Count > 0) {

				listPanel.Children.Add (CreateTickerRibbon (tickerDrivers, isLight));

			}

			foreach (OpenF1Position pos in orderedPositions) {

				OpenF1Driver openF1Driver = result2?.FirstOrDefault ((OpenF1Driver d) => d.driver_number == pos.driver_number);

				string text = ((openF1Driver != null) ? openF1Driver.full_name : pos.driver_number.ToString ());

				System.Windows.Media.Color color = System.Windows.Media.Color.FromRgb (100, 100, 100);

				if (openF1Driver != null && !string.IsNullOrEmpty (openF1Driver.team_colour)) {

					try {

						color = (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#" + openF1Driver.team_colour);

					} catch {

					}

				}

				string acronym2 = openF1Driver?.name_acronym ?? "";

				string teamName2 = openF1Driver?.team_name ?? "";

				listPanel.Children.Add (BuildDriverRow (pos.position ?? 0, text, acronym2, teamName2, color, "", "", isLight));

			}

		}



		// ── Static asset helpers (mirrors instance helpers on F1OverlayWindow) ──────────────────

		private static string GetStaticHeadshotPath (string fullName)

		{

			if (string.IsNullOrEmpty (fullName)) return "";

			// Normalise known aliases
			string n = fullName
				.Replace ("Andrea Kimi Antonelli", "Kimi Antonelli")
				.Replace ("Andrea Antonelli", "Kimi Antonelli")
				.Replace ("H\u00fclkenberg", "Hulkenberg")
				.Replace ("P\u00e9rez", "Perez")
				.Replace ("Alexander Albon", "Alex Albon");

			string path = n + ".png";
			return F1OverlayWindow.ResolveAssetPath ("Headshots", path);
		}

		private static string GetStaticDriverNumberPath (string fullName)
		{
			if (string.IsNullOrEmpty (fullName)) return "";

			string n = fullName
				.Replace ("Andrea Kimi Antonelli", "Andrea Kimi Antonelli")
				.Replace ("H\u00fclkenberg", "Nico Hulkenberg")
				.Replace ("P\u00e9rez", "Sergio Perez")
				.Replace ("Alexander Albon", "Alex Albon");

			string path = n + " Number.png";
			return F1OverlayWindow.ResolveAssetPath ("Driver Number", path);
		}

		private static string GetStaticTeamLogoPath (string teamName)
		{
			if (string.IsNullOrEmpty (teamName)) return "";

			string lower = teamName.ToLowerInvariant ();
			string logoFile = "";

			if (lower.Contains ("red bull")) logoFile = "Redbull F1 Team Logo.png";
			else if (lower.Contains ("ferrari")) logoFile = "Ferrari F1 Team Logo.png";
			else if (lower.Contains ("mclaren")) logoFile = "McLaren F1 Team Logo.png";
			else if (lower.Contains ("mercedes")) logoFile = "Mercedes AMG Petronas F1 Team logo.png";
			else if (lower.Contains ("aston martin")) logoFile = "Aston Martin F1 Team logo-Photoroom.png";
			else if (lower.Contains ("williams")) logoFile = "Williams F1 Team Logo.png";
			else if (lower.Contains ("alpine")) logoFile = "Alpine F1 Team Logo.png";
			else if (lower.Contains ("haas")) logoFile = "TGR Haas F1 Team Logo.png";
			else if (lower.Contains ("sauber") || lower.Contains ("audi")) logoFile = "Audi F1 Team Logopng.png";
			else if (lower.Contains ("visa") || lower.Contains (" rb") || lower.Contains ("racing bulls")) logoFile = "Visa RB F1 Team Logo.png";
			else if (lower.Contains ("cadillac")) logoFile = "Cadillac F1 Team Logo.png";

			if (string.IsNullOrEmpty (logoFile)) return "";
			return F1OverlayWindow.ResolveAssetPath ("Team Logos", logoFile);
		}



		// ── Build a rich driver row card (gradient bg, number art, headshot, team logo) ────────

		private static UIElement BuildDriverRow (int position, string fullName, string acronym, string teamName, System.Windows.Media.Color teamColor, string rightLabel, string rightSub, bool isLight)

		{

			// Outer wrapper grid (position number sits left of the card)
			Grid outerGrid = new Grid {

				Margin = new Thickness (5.0, 3.0, 10.0, 3.0),

				Height = 52.0

			};

			// Gradient background
			LinearGradientBrush grad = new LinearGradientBrush { StartPoint = new System.Windows.Point (0, 0), EndPoint = new System.Windows.Point (1, 0) };

			grad.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (255, (byte)(teamColor.R * 0.12), (byte)(teamColor.G * 0.12), (byte)(teamColor.B * 0.12)), 0.0));

			grad.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (120, teamColor.R, teamColor.G, teamColor.B), 1.0));

			Border card = new Border {

				Background = grad,

				CornerRadius = new CornerRadius (7.0),

				Padding = new Thickness (8.0, 0.0, 8.0, 0.0)

			};

			Grid inner = new Grid ();

			// Position number
			inner.Children.Add (new TextBlock {

				Text = position.ToString (),

				Foreground = System.Windows.Media.Brushes.White,

				FontSize = 18.0,

				FontWeight = FontWeights.Black,

				VerticalAlignment = VerticalAlignment.Center,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Left,

				Width = 28.0

			});

			// Team logo watermark (behind everything)
			string logoPath = GetStaticTeamLogoPath (teamName);

			if (!string.IsNullOrEmpty (logoPath)) {

				inner.Children.Add (new System.Windows.Controls.Image {

					Source = new BitmapImage (new Uri (logoPath, UriKind.Absolute)),

					Stretch = Stretch.Uniform,

					Height = 36.0,

					Width = 36.0,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					VerticalAlignment = VerticalAlignment.Center,

					Margin = new Thickness (0, 0, 54, 0),

					Opacity = 0.18

				});

			}

			// Driver number image
			string numPath = GetStaticDriverNumberPath (fullName);

			if (!string.IsNullOrEmpty (numPath)) {

				inner.Children.Add (new System.Windows.Controls.Image {

					Source = new BitmapImage (new Uri (numPath, UriKind.Absolute)),

					Stretch = Stretch.Uniform,

					Height = 34.0,

					Width = 50.0,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Left,

					VerticalAlignment = VerticalAlignment.Center,

					Margin = new Thickness (24, 0, 0, 0)

				});

			}

			// Driver name + team label (centre-left)
			StackPanel namePanel = new StackPanel {

				Orientation = System.Windows.Controls.Orientation.Vertical,

				VerticalAlignment = VerticalAlignment.Center,

				Margin = new Thickness (80, 0, 0, 0)

			};

			namePanel.Children.Add (new TextBlock {

				Text = (string.IsNullOrEmpty (acronym) ? "" : acronym + "  ") + fullName,

				Foreground = System.Windows.Media.Brushes.White,

				FontSize = 12.0,

				FontWeight = FontWeights.Bold

			});

			namePanel.Children.Add (new TextBlock {

				Text = teamName,

				Foreground = new SolidColorBrush (System.Windows.Media.Color.FromArgb (170, 255, 255, 255)),

				FontSize = 9.0,

				FontWeight = FontWeights.Medium

			});

			inner.Children.Add (namePanel);

			// Time / gap label (right)
			if (!string.IsNullOrEmpty (rightLabel)) {

				StackPanel timePanel = new StackPanel {

					Orientation = System.Windows.Controls.Orientation.Vertical,

					VerticalAlignment = VerticalAlignment.Center,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					Margin = new Thickness (0, 0, 56, 0)

				};

				timePanel.Children.Add (new TextBlock {

					Text = rightLabel,

					Foreground = System.Windows.Media.Brushes.White,

					FontSize = 12.0,

					FontWeight = FontWeights.Bold,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right

				});

				if (!string.IsNullOrEmpty (rightSub)) {

					timePanel.Children.Add (new TextBlock {

						Text = rightSub,

						Foreground = new SolidColorBrush (position == 1 ? System.Windows.Media.Color.FromRgb (0, 210, 190) : System.Windows.Media.Color.FromArgb (170, 255, 255, 255)),

						FontSize = 9.0,

						FontWeight = FontWeights.Medium,

						HorizontalAlignment = System.Windows.HorizontalAlignment.Right

					});

				}

				inner.Children.Add (timePanel);

			}

			// Headshot (front-most)
			string hsPath = GetStaticHeadshotPath (fullName);

			if (!string.IsNullOrEmpty (hsPath)) {

				inner.Children.Add (new System.Windows.Controls.Image {

					Source = new BitmapImage (new Uri (hsPath, UriKind.Absolute)),

					Stretch = Stretch.Uniform,

					Height = 52.0,

					HorizontalAlignment = System.Windows.HorizontalAlignment.Right,

					VerticalAlignment = VerticalAlignment.Center,

					Margin = new Thickness (0, 0, 4, 0),

					Opacity = 0.93

				});

			}

			card.Child = inner;

			outerGrid.Children.Add (card);

			return outerGrid;

		}



		private static void RenderSimPositions (StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			List<Tuple<int, string, System.Windows.Media.Color>> tickerDrivers = new List<Tuple<int, string, System.Windows.Media.Color>> ();

			int num = 1;

			foreach (SimDriverPosition simPosition in simPositions) {

				tickerDrivers.Add (Tuple.Create (num, simPosition.Code, simPosition.TeamColor));

				num++;

			}

			if (tickerDrivers.Count > 0) {

				listPanel.Children.Add (CreateTickerRibbon (tickerDrivers, isLight));

			}

			num = 1;

			foreach (SimDriverPosition simPosition in simPositions) {

				listPanel.Children.Add (BuildDriverRow (num, simPosition.Name, simPosition.Code, simPosition.Team, simPosition.TeamColor, "", "", isLight));

				num++;

			}

		}



		private static async Task RenderLaps (StackPanel listPanel, bool isLight)

		{

			List<OpenF1Lap> list = await OpenF1Client.GetLapsAsync ();

			if (activePollingTab != "Laps" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			if (list == null || list.Count == 0) {

				return;

			}

			foreach (OpenF1Lap item in list.OrderByDescending ((OpenF1Lap l) => l.lap_number).Take (20)) {

				Border border = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (5.0),

					Padding = new Thickness (10.0),

					Margin = new Thickness (5.0, 2.0, 5.0, 2.0)

				};

				AttachHoverAnimation (border, isLight);

				StackPanel stackPanel = new StackPanel {

					Orientation = System.Windows.Controls.Orientation.Horizontal

				};

				stackPanel.Children.Add (new TextBlock {

					Text = $"Driver {item.driver_number} - Lap {item.lap_number} - ",

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White)

				});

				stackPanel.Children.Add (new TextBlock {

					Text = $"{item.lap_duration}s",

					FontWeight = FontWeights.Bold,

					Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue))

				});

				border.Child = stackPanel;

				listPanel.Children.Add (border);

			}

		}



		private static void RenderSimLaps (StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			foreach (string item in simLaps.Take (20)) {

				Border border = new Border {

					Background = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (10, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

					CornerRadius = new CornerRadius (5.0),

					Padding = new Thickness (10.0),

					Margin = new Thickness (5.0, 2.0, 5.0, 2.0)

				};

				AttachHoverAnimation (border, isLight);

				int num = item.IndexOf ("- Lap");

				int num2 = item.LastIndexOf ("-");

				if (num >= 0 && num2 >= 0) {

					string text = item.Substring (0, num2 + 1);

					string text2 = item.Substring (num2 + 1);

					StackPanel stackPanel = new StackPanel {

						Orientation = System.Windows.Controls.Orientation.Horizontal

					};

					stackPanel.Children.Add (new TextBlock {

						Text = text + " ",

						Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White)

					});

					stackPanel.Children.Add (new TextBlock {

						Text = text2,

						FontWeight = FontWeights.Bold,

						Foreground = new SolidColorBrush (System.Windows.Media.Color.FromRgb (0, 122, byte.MaxValue))

					});

					border.Child = stackPanel;

				} else {

					border.Child = new TextBlock {

						Text = item,

						Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White)

					};

				}

				listPanel.Children.Add (border);

			}

		}



		private static async Task RenderTelemetry (StackPanel listPanel, bool isLight)

		{

			List<OpenF1CarData> list = await OpenF1Client.GetCarDataAsync ();

			if (activePollingTab != "Telemetry" || isSimulationMode) {

				return;

			}

			listPanel.Children.Clear ();

			if (list == null || list.Count == 0) {

				listPanel.Children.Add (new TextBlock {

					Text = "No telemetry data available.",

					Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

					Margin = new Thickness (20.0)

				});

				return;

			}

			OpenF1CarData openF1CarData = list.OrderByDescending ((OpenF1CarData c) => c.date).FirstOrDefault ();

			Grid grid = new Grid {

				Margin = new Thickness (20.0)

			};

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.Children.Add (CreateWeatherCard ("Speed", $"{openF1CarData.speed} km/h", isLight, 0, 0));

			grid.Children.Add (CreateWeatherCard ("RPM", $"{openF1CarData.rpm}", isLight, 0, 1));

			grid.Children.Add (CreateWeatherCard ("Gear", $"{openF1CarData.n_gear}", isLight, 1, 0));

			grid.Children.Add (CreateWeatherCard ("Throttle", $"{openF1CarData.throttle}%", isLight, 1, 1));

			grid.Children.Add (CreateWeatherCard ("Brake", $"{openF1CarData.brake}%", isLight, 2, 0));

			grid.Children.Add (CreateWeatherCard ("DRS", (openF1CarData.drs > 8) ? "Active" : "Closed", isLight, 2, 1));

			listPanel.Children.Add (new TextBlock {

				Text = "MAX VERSTAPPEN TELEMETRY",

				FontWeight = FontWeights.Bold,

				Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				Margin = new Thickness (0.0, 0.0, 0.0, 10.0)

			});

			listPanel.Children.Add (grid);

		}



		private static void RenderSimTelemetry (StackPanel listPanel, bool isLight)

		{

			listPanel.Children.Clear ();

			double num = 120.0;

			double num2 = 8000.0;

			string text = "3";

			double num3 = 100.0;

			double num4 = 0.0;

			bool flag = false;

			if (simLapPercent < 40.0) {

				double num5 = simLapPercent / 40.0;

				num = 180.0 + num5 * 152.0;

				num2 = 9500.0 + num5 * 2900.0;

				text = (4 + (int)(num5 * 4.0)).ToString ();

				num3 = 100.0;

				num4 = 0.0;

				flag = simLapPercent > 15.0;

			} else if (simLapPercent < 55.0) {

				double num6 = (simLapPercent - 40.0) / 15.0;

				num = 332.0 - num6 * 222.0;

				num2 = 12400.0 - num6 * 6400.0;

				text = (8 - (int)(num6 * 5.0)).ToString ();

				num3 = 0.0;

				num4 = 100.0;

				flag = false;

			} else if (simLapPercent < 75.0) {

				double num7 = (simLapPercent - 55.0) / 20.0;

				num = 110.0 + num7 * 60.0;

				num2 = 6000.0 + num7 * 2500.0;

				text = "4";

				num3 = 50.0 + num7 * 30.0;

				num4 = 0.0;

				flag = false;

			} else {

				double num8 = (simLapPercent - 75.0) / 25.0;

				num = 170.0 + num8 * 125.0;

				num2 = 8500.0 + num8 * 3200.0;

				text = (4 + (int)(num8 * 3.0)).ToString ();

				num3 = 100.0;

				num4 = 0.0;

				flag = simLapPercent > 90.0;

			}

			Grid grid = new Grid {

				Margin = new Thickness (20.0)

			};

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.ColumnDefinitions.Add (new ColumnDefinition {

				Width = new GridLength (1.0, GridUnitType.Star)

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.RowDefinitions.Add (new RowDefinition {

				Height = GridLength.Auto

			});

			grid.Children.Add (CreateWeatherCard ("Speed", $"{(int)num} km/h", isLight, 0, 0));

			grid.Children.Add (CreateWeatherCard ("RPM", $"{(int)num2}", isLight, 0, 1));

			grid.Children.Add (CreateWeatherCard ("Gear", text, isLight, 1, 0));

			grid.Children.Add (CreateWeatherCard ("Throttle", $"{(int)num3}%", isLight, 1, 1));

			grid.Children.Add (CreateWeatherCard ("Brake", $"{(int)num4}%", isLight, 2, 0));

			grid.Children.Add (CreateWeatherCard ("DRS", flag ? "Active" : "Closed", isLight, 2, 1));

			listPanel.Children.Add (new TextBlock {

				Text = "MAX VERSTAPPEN TELEMETRY (SIMULATED)",

				FontWeight = FontWeights.Bold,

				Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				Margin = new Thickness (0.0, 0.0, 0.0, 10.0)

			});

			listPanel.Children.Add (grid);

		}

	}

	public class OpenF1Session

	{

		public int? session_key { get; set; }



		public string session_name { get; set; }



		public string date_start { get; set; }



		public string date_end { get; set; }



