	public static class OpenF1Client

	{

		private static JavaScriptSerializer serializer = new JavaScriptSerializer {

			MaxJsonLength = int.MaxValue

		};



		private static T Fetch<T> (string endpoint)

		{

			try {

				using TimeoutWebClient webClient = new TimeoutWebClient { TimeoutMs = 8000 };

				string input = webClient.DownloadString ("https://api.openf1.org/v1/" + endpoint);

				return serializer.Deserialize<T> (input);

			} catch (Exception ex) {

				Console.WriteLine ("OpenF1 Fetch Error: " + ex.Message);

				return default(T);

			}

		}



		public static async Task<T> FetchAsync<T> (string endpoint)

		{

			return await Task.Run (() => Fetch<T> (endpoint));

		}



		public static async Task<List<OpenF1Session>> GetSessionsAsync (int year = 2024)

		{

			return await FetchAsync<List<OpenF1Session>> ($"sessions?year={year}");

		}



		public static async Task<List<OpenF1Driver>> GetDriversAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1Driver>> ("drivers?session_key=" + sessionKey);

		}



		public static async Task<List<OpenF1Position>> GetPositionsAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1Position>> ("position?session_key=" + sessionKey);

		}



		public static async Task<List<OpenF1PitStop>> GetPitStopsAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1PitStop>> ("pit_stops?session_key=" + sessionKey);

		}



		public static async Task<List<OpenF1Weather>> GetWeatherAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1Weather>> ("weather?session_key=" + sessionKey);

		}



		public static async Task<List<OpenF1RaceControl>> GetRaceControlAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1RaceControl>> ("race_control?session_key=" + sessionKey);

		}



		public static async Task<List<OpenF1CarData>> GetCarDataAsync (string sessionKey = "latest", int driverNumber = 1)

		{

			return await FetchAsync<List<OpenF1CarData>> ($"car_data?session_key={sessionKey}&driver_number={driverNumber}");

		}



		public static async Task<List<OpenF1Lap>> GetLapsAsync (string sessionKey = "latest")

		{

			return await FetchAsync<List<OpenF1Lap>> ("laps?session_key=" + sessionKey);

		}

	}

