		}



		private static Popup _currentPopup;



		private static JavaScriptSerializer serializer = new JavaScriptSerializer ();



		private static Dictionary<string, List<ErgastResult>> cachedResults = new Dictionary<string, List<ErgastResult>> ();



		private static List<OpenF1Session> cachedSessions2024 = null;



		private static Dictionary<string, List<OpenF1Driver>> cachedSessionDrivers = new Dictionary<string, List<OpenF1Driver>> ();



		public static async Task ShowPopup (UIElement placementTarget, string round, string raceName, string countryCode, bool isLight)

		{

			if (_currentPopup != null) {

				_currentPopup.IsOpen = false;

			}

			Popup popup = new Popup ();

			popup.PlacementTarget = placementTarget;

			popup.Placement = PlacementMode.Right;

			popup.StaysOpen = true;

			popup.AllowsTransparency = true;

			popup.PopupAnimation = PopupAnimation.Fade;

			popup.HorizontalOffset = 15.0;

			System.Windows.Media.Brush background;

			System.Windows.Media.Brush borderBrush;

			if (isLight) {

				background = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.2, 0.0),

					EndPoint = new System.Windows.Point (0.8, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (240, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (235, 245, 245, 247), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 230, 230, 235), 1.0)

					}

				};

				borderBrush = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (180, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (50, 0, 0, 0), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (100, 0, 0, 0), 1.0)

					}

				};

			} else {

				background = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.2, 0.0),

					EndPoint = new System.Windows.Point (0.8, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 40, 40, 45), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (235, 28, 28, 33), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (240, 18, 18, 22), 1.0)

					}

				};

				borderBrush = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (180, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (50, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.5),

						new GradientStop (System.Windows.Media.Color.FromArgb (100, 0, 0, 0), 1.0)

					}

				};

			}

			Border mainBorder = new Border {

				Background = background,

				CornerRadius = new CornerRadius (12.0),

				Width = 400.0,

				MinHeight = 500.0,

				BorderBrush = borderBrush,

				BorderThickness = new Thickness (1.0),

				Effect = new DropShadowEffect {

					BlurRadius = 25.0,

					ShadowDepth = 5.0,

					Opacity = (isLight ? 0.25 : 0.5)

				}

			};

			TextElement.SetFontFamily (mainBorder, new System.Windows.Media.FontFamily ("Bahnschrift, Segoe UI, sans-serif"));

			TranslateTransform slideTransform = new TranslateTransform (0.0, 20.0);

			mainBorder.RenderTransform = slideTransform;

			popup.Opened += delegate {

				DoubleAnimation animation = new DoubleAnimation (20.0, 0.0, TimeSpan.FromMilliseconds (250.0)) {

					EasingFunction = new CubicEase {

						EasingMode = EasingMode.EaseOut

					}

				};

				slideTransform.BeginAnimation (TranslateTransform.YProperty, animation);

			};

			Grid layoutGrid = new Grid {

				RowDefinitions = {

					new RowDefinition {

						Height = GridLength.Auto

					},

					new RowDefinition {

						Height = GridLength.Auto

					},

					new RowDefinition {

						Height = new GridLength (1.0, GridUnitType.Star)

					}

				}

			};

			Border element = new Border {

				CornerRadius = new CornerRadius (12.0),

				IsHitTestVisible = false,

				Background = new LinearGradientBrush {

					StartPoint = new System.Windows.Point (0.0, 0.0),

					EndPoint = new System.Windows.Point (1.0, 1.0),

					GradientStops = {

						new GradientStop (System.Windows.Media.Color.FromArgb (30, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.0),

						new GradientStop (System.Windows.Media.Color.FromArgb (0, byte.MaxValue, byte.MaxValue, byte.MaxValue), 0.45),

						new GradientStop (System.Windows.Media.Color.FromArgb (0, 0, 0, 0), 1.0)

					}

				}

			};

			Grid.SetRowSpan (element, 3);

			layoutGrid.Children.Add (element);

			TextBlock loadingText = new TextBlock {

				Text = "Loading Race Results...",

				Foreground = (isLight ? System.Windows.Media.Brushes.Black : System.Windows.Media.Brushes.White),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,

				VerticalAlignment = VerticalAlignment.Center,

				Margin = new Thickness (0.0, 100.0, 0.0, 0.0)

			};

			layoutGrid.Children.Add (loadingText);

			Grid.SetRow (loadingText, 1);

			mainBorder.Child = layoutGrid;

			popup.Child = mainBorder;

			Border border = new Border {

				Background = System.Windows.Media.Brushes.Transparent,

				BorderBrush = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, 0, 0, 0)) : new SolidColorBrush (System.Windows.Media.Color.FromArgb (25, byte.MaxValue, byte.MaxValue, byte.MaxValue))),

				BorderThickness = new Thickness (0.0, 0.0, 0.0, 1.0),

				CornerRadius = new CornerRadius (11.0, 11.0, 0.0, 0.0),

				Padding = new Thickness (12.0)

			};

			TextBlock textBlock = (TextBlock)(border.Child = new TextBlock {

				Text = "ROUND " + round.PadLeft (2, '0') + " / " + raceName.ToUpper (),

				Foreground = (isLight ? new SolidColorBrush (System.Windows.Media.Color.FromRgb (30, 30, 30)) : System.Windows.Media.Brushes.White),

				FontWeight = FontWeights.Bold,

				FontSize = 14.0,

				HorizontalAlignment = System.Windows.HorizontalAlignment.Center

			});

			Grid.SetRow (border, 0);

			layoutGrid.Children.Add (border);

			popup.IsOpen = true;

			_currentPopup = popup;

			Window parentWindow = Window.GetWindow (placementTarget);

			if (parentWindow != null) {

				MouseButtonEventHandler clickOutsideHandler = null;

				EventHandler deactivateHandler = null;

				System.Windows.Input.KeyEventHandler escHandler = null;

				clickOutsideHandler = delegate(object s, MouseButtonEventArgs e) {

					if (popup.IsOpen && popup.Child != null) {

						System.Windows.Point position = e.GetPosition (popup.Child);

						if (position.X < 0.0 || position.Y < 0.0 || position.X > mainBorder.ActualWidth || position.Y > mainBorder.ActualHeight) {

							popup.IsOpen = false;

						}

					}

				};

				deactivateHandler = delegate {

					popup.IsOpen = false;

				};

				escHandler = delegate(object s, System.Windows.Input.KeyEventArgs e) {

					if (e.Key == Key.Escape) {

						popup.IsOpen = false;

						e.Handled = true;

					}

				};

				parentWindow.PreviewMouseLeftButtonDown += clickOutsideHandler;

				parentWindow.Deactivated += deactivateHandler;

				parentWindow.PreviewKeyDown += escHandler;

				popup.Closed += delegate {

					parentWindow.PreviewMouseLeftButtonDown -= clickOutsideHandler;

					parentWindow.Deactivated -= deactivateHandler;

					parentWindow.PreviewKeyDown -= escHandler;

				};

			}

			List<ErgastResult> results = null;

			if (cachedResults.ContainsKey (round)) {

				results = cachedResults [round];

			} else {

				try {

					string url = "https://api.jolpi.ca/ergast/f1/current/" + round + "/results.json";

					TimeoutWebClient client = new TimeoutWebClient { TimeoutMs = 8000 };

					try {

						string input = await Task.Run (() => client.DownloadString (url));

						ErgastResultsResponse ergastResultsResponse = serializer.Deserialize<ErgastResultsResponse> (input);

						if (ergastResultsResponse != null && ergastResultsResponse.MRData?.RaceTable?.Races?.Count > 0) {

							results = ergastResultsResponse.MRData.RaceTable.Races [0].Results;

							cachedResults [round] = results;

						}

					} finally {

						if (client != null) {

							((IDisposable)client).Dispose ();

						}

					}

				} catch {

				}

			}

			if (results == null || results.Count == 0 || _currentPopup != popup || !popup.IsOpen) {

				return;

			}

			layoutGrid.Children.Remove (loadingText);

			List<OpenF1Driver> openF1Drivers = null;

			try {

				if (cachedSessions2024 == null) {

					cachedSessions2024 = await OpenF1Client.GetSessionsAsync ();

				}

				if (cachedSessions2024 != null) {

					List<OpenF1Session> list = (from s in cachedSessions2024

						where s.session_name == "Race"

						orderby s.date_start

						select s).ToList ();

					int num = int.Parse (round) - 1;

					string targetSessionKey = "latest";

					if (num >= 0 && num < list.Count) {

						targetSessionKey = list [num].session_key.GetValueOrDefault ().ToString ();

					}

					if (cachedSessionDrivers.ContainsKey (targetSessionKey)) {

						openF1Drivers = cachedSessionDrivers [targetSessionKey];

					} else {

						openF1Drivers = await OpenF1Client.GetDriversAsync (targetSessionKey);

						if (openF1Drivers != null) {

							cachedSessionDrivers [targetSessionKey] = openF1Drivers;

						}

					}

				}

			} catch {

			}

			if (_currentPopup == popup && popup.IsOpen) {

				Grid grid = new Grid {

					Margin = new Thickness (15.0)

				};

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.0, GridUnitType.Star)

				});

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.1, GridUnitType.Star)

				});

				grid.ColumnDefinitions.Add (new ColumnDefinition {

					Width = new GridLength (1.0, GridUnitType.Star)

				});

				ErgastResult ergastResult = results.FirstOrDefault ((ErgastResult r) => r.position == "1");

				ErgastResult ergastResult2 = results.FirstOrDefault ((ErgastResult r) => r.position == "2");

				ErgastResult ergastResult3 = results.FirstOrDefault ((ErgastResult r) => r.position == "3");

				if (ergastResult2 != null) {

					grid.Children.Add (CreatePodiumCard (ergastResult2, 2, openF1Drivers));

				}

				if (ergastResult != null) {

					grid.Children.Add (CreatePodiumCard (ergastResult, 1, openF1Drivers));

				}

				if (ergastResult3 != null) {

					grid.Children.Add (CreatePodiumCard (ergastResult3, 3, openF1Drivers));

				}

				Grid.SetRow (grid, 1);

				layoutGrid.Children.Add (grid);

				StackPanel stackPanel = new StackPanel {

					Margin = new Thickness (15.0, 0.0, 15.0, 15.0)

				};

				for (int i = 3; i < 10 && i < results.Count; i++) {

					ErgastResult result = results [i];

					stackPanel.Children.Add (CreateListItem (result, openF1Drivers, isLight));

				}

				Grid.SetRow (stackPanel, 2);

				layoutGrid.Children.Add (stackPanel);

			}

		}



		public static void HidePopup ()

		{

			if (_currentPopup != null) {

				_currentPopup.IsOpen = false;

				_currentPopup = null;

			}

		}



		private static string GetLocalImagePath (string givenName, string familyName)

		{

			if (givenName.Contains ("Andrea Kimi") || (givenName == "Andrea" && familyName.Contains ("Kimi"))) {

				givenName = "Kimi";

				familyName = "Antonelli";

			}

			if (familyName == "Hülkenberg") {

				familyName = "Hulkenberg";

			}

			if (familyName == "Pérez") {

				familyName = "Perez";

			}

			if (givenName == "Alexander" && familyName == "Albon") {

				givenName = "Alex";

			}

			if (givenName == "Guanyu" && familyName == "Zhou") {

				givenName = "Zhou";

				familyName = "Guanyu";

			}

			string text = System.IO.Path.Combine (AppDomain.CurrentDomain.BaseDirectory, "Drivers");

			if (!Directory.Exists (text)) {

				return null;

			}

			string text2 = System.IO.Path.Combine (text, givenName + " " + familyName + ".png");

			if (File.Exists (text2)) {

				return text2;

			}

			string[] files = Directory.GetFiles (text, "*.png");

			foreach (string text3 in files) {

				if (text3.IndexOf (familyName, StringComparison.OrdinalIgnoreCase) >= 0) {

					return text3;

				}

			}

			return null;

		}



		private static System.Windows.Media.Color GetTeamColor (ErgastResult result, OpenF1Driver openDriver)

		{

			string text = result.Constructor?.name?.ToLower () ?? "";

			if (text.Contains ("mercedes")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#27F4D2");

			}

			if (text.Contains ("ferrari")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#E8002D");

			}

			if (text.Contains ("red bull")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#3671C6");

			}

			if (text.Contains ("mclaren")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#FF8000");

			}

			if (text.Contains ("aston martin")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#229971");

			}

			if (text.Contains ("alpine")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#FF87BC");

			}

			if (text.Contains ("williams")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#64C4FF");

			}

			if (text.Contains ("haas")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#B6BABD");

			}

			if (text.Contains ("sauber") || text.Contains ("audi")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#52E252");

			}

			if (text.Contains ("rb") || text.Contains ("racing bulls") || text.Contains ("alphatauri")) {

				return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#6692FF");

			}

			if (openDriver != null && !string.IsNullOrEmpty (openDriver.team_colour)) {

				try {

					return (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString ("#" + openDriver.team_colour);

				} catch {

				}

			}

			return System.Windows.Media.Color.FromRgb (80, 80, 80);

		}



		private static UIElement CreatePodiumCard (ErgastResult result, int pos, List<OpenF1Driver> openDrivers)

		{

			OpenF1Driver openF1Driver = openDrivers?.FirstOrDefault ((OpenF1Driver d) => d.name_acronym?.ToLower () == result.Driver.code?.ToLower () || d.last_name?.ToLower () == result.Driver.familyName?.ToLower ());

			System.Windows.Media.Color teamColor = GetTeamColor (result, openF1Driver);

			LinearGradientBrush linearGradientBrush = new LinearGradientBrush {

				StartPoint = new System.Windows.Point (0.0, 0.0),

				EndPoint = new System.Windows.Point (1.0, 1.0)

			};

			linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (byte.MaxValue, (byte)((double)(int)teamColor.R * 0.2), (byte)((double)(int)teamColor.G * 0.2), (byte)((double)(int)teamColor.B * 0.2)), 0.0));

			linearGradientBrush.GradientStops.Add (new GradientStop (System.Windows.Media.Color.FromArgb (byte.MaxValue, (byte)((double)(int)teamColor.R * 0.6), (byte)((double)(int)teamColor.G * 0.6), (byte)((double)(int)teamColor.B * 0.6)), 1.0));

			Grid grid = new Grid {

				Margin = new Thickness (5.0, (pos == 1) ? 25 : 35, 5.0, 5.0),

				Height = ((pos == 1) ? 140 : 120),

				VerticalAlignment = VerticalAlignment.Bottom

			};

			Border border = new Border {

				Background = linearGradientBrush,

				CornerRadius = new CornerRadius (12.0),

				ClipToBounds = true,

				BorderBrush = new SolidColorBrush (System.Windows.Media.Color.FromArgb (50, byte.MaxValue, byte.MaxValue, byte.MaxValue)),

				BorderThickness = new Thickness (1.0)

			};

			grid.Children.Add (border);

			Grid grid2 = new Grid ();

			TextBlock element = new TextBlock {

				Text = pos.ToString (),

				FontSize = 140.0,

				FontWeight = FontWeights.Black,

				Foreground = System.Windows.Media.Brushes.White,

				Opacity = 0.08,

				Margin = new Thickness (-10.0, -35.0, 0.0, 0.0),

				HorizontalAlignment = System.Windows.HorizontalAlignment.Left,

				VerticalAlignment = VerticalAlignment.Top

			};

			grid2.Children.Add (element);

			border.Child = grid2;

			Grid grid3 = new Grid {

				Margin = new Thickness (0.0, -35.0, 0.0, 30.0),

				ClipToBounds = true

			};

			object obj = GetLocalImagePath (result.Driver.givenName, result.Driver.familyName);

			bool flag = obj != null;

			if (obj == null) {

				obj = openF1Driver?.headshot_url;

			}

			string text = (string)obj;

			if (!string.IsNullOrEmpty (text)) {

				BitmapImage bitmapImage = new BitmapImage ();

				try {

					bitmapImage.BeginInit ();

					bitmapImage.UriSource = new Uri (text, UriKind.RelativeOrAbsolute);

					if (flag) {

						bitmapImage.DecodePixelHeight = 280;

						bitmapImage.CacheOption = BitmapCacheOption.OnLoad;

					}

					bitmapImage.EndInit ();

				} catch {

				}

