	public class IndexedFile
	{
		public string Name { get; set; }
		public string Path { get; set; }
		public bool IsDirectory { get; set; }
		public bool IsApp { get; set; }
		public HashSet<string> Keywords { get; set; }
		public string Content { get; set; }
		public DateTime LastModified { get; set; }

		public IndexedFile()
		{
			Keywords = new HashSet<string> (StringComparer.OrdinalIgnoreCase);
		}
	}

	public static class LocalFileIndexer
	{
		private static List<IndexedFile> _index = new List<IndexedFile> ();
		private static bool _isIndexing = false;
		private static readonly object _lock = new object ();
		private static Thread _indexerThread;

		public static void Initialize ()
		{
			if (_indexerThread != null && _indexerThread.IsAlive) return;

			_indexerThread = new Thread (RunIndexer) {
				IsBackground = true,
				Priority = ThreadPriority.BelowNormal
			};
			_indexerThread.SetApartmentState (ApartmentState.STA);
			_indexerThread.Start ();
		}

		private static void RunIndexer ()
		{
			while (true) {
				try {
					RebuildIndex ();
				} catch {}
				Thread.Sleep (60000); // Re-index every 60 seconds
			}
		}

		public static List<IndexedFile> GetIndex ()
		{
			lock (_lock) {
				return new List<IndexedFile> (_index);
			}
		}

		private static void RebuildIndex ()
		{
			lock (_lock) {
				if (_isIndexing) return;
				_isIndexing = true;
			}

			var tempIndex = new List<IndexedFile> ();
			var uniquePaths = new HashSet<string> (StringComparer.OrdinalIgnoreCase);

			// 1. Scan default user search roots
			List<string> searchRootsList = new List<string> {
				Environment.GetFolderPath (Environment.SpecialFolder.Desktop),
				Environment.GetFolderPath (Environment.SpecialFolder.Personal),
				System.IO.Path.Combine (Environment.GetFolderPath (Environment.SpecialFolder.UserProfile), "Downloads"),
				Environment.GetFolderPath (Environment.SpecialFolder.MyPictures),
				Environment.GetFolderPath (Environment.SpecialFolder.MyMusic),
				Environment.GetFolderPath (Environment.SpecialFolder.MyVideos),
			};

			foreach (var root in searchRootsList) {
				if (string.IsNullOrEmpty (root) || !Directory.Exists (root)) continue;

				try {
					// Add root directory itself
					AddDirectoryToIndex (root, tempIndex, uniquePaths);

					// Scan subdirectories
					foreach (var dir in Directory.EnumerateDirectories (root, "*", SearchOption.TopDirectoryOnly)) {
						AddDirectoryToIndex (dir, tempIndex, uniquePaths);
					}

					// Scan files
					foreach (var file in Directory.EnumerateFiles (root, "*", SearchOption.TopDirectoryOnly)) {
						AddFileToIndex (file, tempIndex, uniquePaths);
					}
				} catch {}
			}

			// 2. Scan installed apps (Start Menu, Registry)
			ScanApps (tempIndex, uniquePaths);

			lock (_lock) {
				_index = tempIndex;
				_isIndexing = false;
			}
		}

		private static void AddDirectoryToIndex (string dirPath, List<IndexedFile> indexList, HashSet<string> uniquePaths)
		{
			if (!uniquePaths.Add (dirPath)) return;
			string name = System.IO.Path.GetFileName (dirPath);
			if (string.IsNullOrEmpty (name)) name = dirPath;

			var item = new IndexedFile {
				Name = name,
				Path = dirPath,
				IsDirectory = true,
				IsApp = false,
				LastModified = Directory.GetLastWriteTime (dirPath)
			};
			TokenizeName (name, item.Keywords);
			indexList.Add (item);
		}

		private static void AddFileToIndex (string filePath, List<IndexedFile> indexList, HashSet<string> uniquePaths)
		{
			if (!uniquePaths.Add (filePath)) return;
			string name = System.IO.Path.GetFileName (filePath);
			string ext = System.IO.Path.GetExtension (filePath).ToLower ();

			var item = new IndexedFile {
				Name = name,
				Path = filePath,
				IsDirectory = false,
				IsApp = (ext == ".exe" || ext == ".lnk" || ext == ".url"),
				LastModified = File.GetLastWriteTime (filePath)
			};
			TokenizeName (name, item.Keywords);

			// Index content for text-based files up to 2KB
			if (IsTextFile (ext)) {
				try {
					using (var reader = new StreamReader (filePath)) {
						char[] buffer = new char[2048];
						int read = reader.ReadBlock (buffer, 0, buffer.Length);
						if (read > 0) {
							item.Content = new string (buffer, 0, read);
							TokenizeContent (item.Content, item.Keywords);
						}
					}
				} catch {}
			}

			indexList.Add (item);
		}

		private static void TokenizeName (string text, HashSet<string> keywords)
		{
			if (string.IsNullOrEmpty (text)) return;
			var parts = text.Split (new[] { ' ', '_', '-', '.', '(', ')', '[', ']' }, StringSplitOptions.RemoveEmptyEntries);
			foreach (var part in parts) {
				if (part.Length >= 2) {
					keywords.Add (part.ToLower ());
				}
			}
		}

		private static void TokenizeContent (string text, HashSet<string> keywords)
		{
			if (string.IsNullOrEmpty (text)) return;
			var parts = text.Split (new[] { ' ', '\r', '\n', '\t', ',', '.', ';', ':', '!', '?', '(', ')', '[', ']', '{', '}', '<', '>', '/', '\\', '"', '\'' }, StringSplitOptions.RemoveEmptyEntries);
			foreach (var part in parts) {
				if (part.Length >= 3 && part.Length <= 15) {
					keywords.Add (part.ToLower ());
				}
			}
		}

		private static bool IsTextFile (string ext)
		{
			string[] textExts = { ".txt", ".md", ".json", ".csv", ".xml", ".log", ".cs", ".ini", ".cfg", ".html", ".css", ".js" };
			return textExts.Contains (ext);
		}

		private static void SafeEnumerateShortcuts (string path, List<IndexedFile> indexList, HashSet<string> uniquePaths)
		{
			try {
				foreach (var file in Directory.GetFiles (path, "*.lnk")) {
					try {
						if (!uniquePaths.Add (file)) continue;
						string name = System.IO.Path.GetFileNameWithoutExtension (file);
						var item = new IndexedFile {
							Name = name,
							Path = file,
							IsApp = true,
							IsDirectory = false,
							LastModified = File.GetLastWriteTime (file)
						};
						TokenizeName (name, item.Keywords);
						indexList.Add (item);
					} catch {}
				}
			} catch {}

			try {
				foreach (var file in Directory.GetFiles (path, "*.url")) {
					try {
						if (!uniquePaths.Add (file)) continue;
						string name = System.IO.Path.GetFileNameWithoutExtension (file);
						var item = new IndexedFile {
							Name = name,
							Path = file,
							IsApp = true,
							IsDirectory = false,
							LastModified = File.GetLastWriteTime (file)
						};
						TokenizeName (name, item.Keywords);
						indexList.Add (item);
					} catch {}
				}
			} catch {}

			try {
				foreach (var subDir in Directory.GetDirectories (path)) {
					SafeEnumerateShortcuts (subDir, indexList, uniquePaths);
				}
			} catch {}
		}

		private static void ScanUwpApps (List<IndexedFile> indexList, HashSet<string> uniquePaths)
		{
			try {
				Type shellType = Type.GetTypeFromProgID ("Shell.Application");
				if (shellType == null) return;
				object shell = Activator.CreateInstance (shellType);
				object folder = shellType.InvokeMember ("NameSpace", BindingFlags.InvokeMethod, null, shell, new object[] { "shell:AppsFolder" });
				if (folder == null) return;
				object items = folder.GetType ().InvokeMember ("Items", BindingFlags.InvokeMethod, null, folder, null);
				if (items == null) return;
				int count = (int)items.GetType ().InvokeMember ("Count", BindingFlags.GetProperty, null, items, null);
				for (int i = 0; i < count; i++) {
					try {
						object item = items.GetType ().InvokeMember ("Item", BindingFlags.InvokeMethod, null, items, new object[] { i });
						if (item == null) continue;
						string name = (string)item.GetType ().InvokeMember ("Name", BindingFlags.GetProperty, null, item, null);
						string path = (string)item.GetType ().InvokeMember ("Path", BindingFlags.GetProperty, null, item, null);
						
						if (string.IsNullOrEmpty (name) || string.IsNullOrEmpty (path)) continue;

						if (path.StartsWith ("::") || name.Contains ("Uninstall") || path.Contains ("ms-settings:")) continue;

						string executePath = path;
						if (!path.Contains ("\\") && !path.Contains (":")) {
							executePath = "shell:AppsFolder\\" + path;
						}

						if (!uniquePaths.Add (executePath)) continue;

						var fileItem = new IndexedFile {
							Name = name,
							Path = executePath,
							IsApp = true,
							IsDirectory = false,
							LastModified = DateTime.Now
						};
						TokenizeName (name, fileItem.Keywords);
						indexList.Add (fileItem);
					} catch {}
				}
			} catch {}
		}

		private static void ScanApps (List<IndexedFile> indexList, HashSet<string> uniquePaths)
		{
			List<string> appFolders = new List<string> ();
			try {
				string commonProg = Environment.GetFolderPath (Environment.SpecialFolder.CommonPrograms);
				if (Directory.Exists (commonProg)) appFolders.Add (commonProg);
			} catch {}
			try {
				string userProg = Environment.GetFolderPath (Environment.SpecialFolder.Programs);
				if (Directory.Exists (userProg)) appFolders.Add (userProg);
			} catch {}

			foreach (var folder in appFolders) {
				SafeEnumerateShortcuts (folder, indexList, uniquePaths);
			}

			ScanUwpApps (indexList, uniquePaths);

			string[] registryPaths = {
				@"SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths",
				@"SOFTWARE\Wow6432Node\Microsoft\Windows\CurrentVersion\App Paths"
			};

			foreach (var path in registryPaths) {
				try {
					using (var key = Registry.LocalMachine.OpenSubKey (path)) {
						if (key == null) continue;
						foreach (var subKeyName in key.GetSubKeyNames ()) {
							using (var subKey = key.OpenSubKey (subKeyName)) {
								if (subKey == null) continue;
								string exePath = subKey.GetValue ("") as string;
								if (!string.IsNullOrEmpty (exePath) && File.Exists (exePath)) {
									if (!uniquePaths.Add (exePath)) continue;
									string name = System.IO.Path.GetFileNameWithoutExtension (exePath);
									var item = new IndexedFile {
										Name = name,
										Path = exePath,
										IsApp = true,
										IsDirectory = false,
										LastModified = File.GetLastWriteTime (exePath)
									};
									TokenizeName (name, item.Keywords);
									indexList.Add (item);
								}
							}
						}
					}
				} catch {}
			}
		}
	}

	public static class SearchEngine
	{
		private static readonly Dictionary<string, List<string>> SemanticSynonyms = new Dictionary<string, List<string>> (StringComparer.OrdinalIgnoreCase) {
			{ "budget", new List<string> { "finance", "money", "salary", "cash", "payment", "cost", "expense", "invoice", "accounting", "ledger", "excel", "spreadsheet", "sheet", "report", "tax", "contract", "q3", "q4", "earning", "earnings" } },
			{ "finance", new List<string> { "budget", "money", "salary", "cash", "payment", "cost", "expense", "invoice", "accounting", "ledger", "excel", "spreadsheet", "sheet", "report", "tax" } },
			{ "work", new List<string> { "document", "docx", "pdf", "office", "schedule", "calendar", "task", "project", "meeting", "report", "presentation", "slides", "notes", "word" } },
			{ "code", new List<string> { "visual studio", "vs", "code", "github", "git", "repository", "programming", "c#", "cpp", "python", "java", "javascript", "html", "css", "script", "develop", "cplusplus", "development" } },
			{ "develop", new List<string> { "visual studio", "vs", "code", "github", "git", "repository", "programming", "c#", "cpp", "python", "java", "javascript", "html", "css", "script", "code" } },
			{ "media", new List<string> { "image", "photo", "picture", "png", "jpg", "jpeg", "video", "movie", "film", "mp4", "avi", "mkv", "clip", "graphic", "illustration", "camera" } },
			{ "music", new List<string> { "spotify", "song", "audio", "mp3", "wav", "playlist", "sound", "music", "album", "track", "tune", "melody" } },
			{ "game", new List<string> { "steam", "play", "xbox", "epic", "gta", "minecraft", "riot", "valorant", "league", "cyberpunk", "control", "gaming", "playstation" } },
			{ "document", new List<string> { "docx", "pdf", "txt", "pages", "paper", "write", "office", "notes", "memo" } }
		};

		public static List<SearchResultItem> Search (string query, List<SearchResultItem> baseItems)
		{
			var results = new List<Tuple<SearchResultItem, double>> ();
			var queryTokens = query.ToLower ().Split (new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);

			if (queryTokens.Length == 0) return baseItems;

			var expandedTokens = new List<string> (queryTokens);
			foreach (var token in queryTokens) {
				if (SemanticSynonyms.TryGetValue (token, out var synonyms)) {
					expandedTokens.AddRange (synonyms);
				}
			}
			expandedTokens = expandedTokens.Distinct (StringComparer.OrdinalIgnoreCase).ToList ();

			var indexedFiles = LocalFileIndexer.GetIndex ();
			var allItemsToSearch = new List<SearchResultItem> ();

			foreach (var item in baseItems) {
				allItemsToSearch.Add (item);
			}

			foreach (var file in indexedFiles) {
				allItemsToSearch.Add (new SearchResultItem {
					Name = file.Name,
					Path = file.Path,
					IsApp = file.IsApp,
					IsDirectory = file.IsDirectory,
					IsClipboard = false,
					IsAction = false,
					IsWebSuggestion = false
				});
			}

			foreach (var item in allItemsToSearch) {
				double score = CalculateScore (item, query, queryTokens, expandedTokens);
				if (score > 0) {
					results.Add (new Tuple<SearchResultItem, double> (item, score));
				}
			}

			var uniqueResults = results
				.OrderByDescending (r => r.Item2)
				.GroupBy (r => r.Item1.Path.ToLower ())
				.Select (g => g.First ().Item1)
				.Take (40)
				.ToList ();

			return uniqueResults;
		}

		private static double CalculateScore (SearchResultItem item, string query, string[] queryTokens, List<string> expandedTokens)
		{
			// Direct action matches (math, conversion, flight, clipboard) get top priority
			if (item.IsAction && (item.Path.StartsWith ("action://copypaste_") || item.Path.StartsWith ("action://flight_"))) {
				return 1000.0;
			}
			if (item.IsClipboard) {
				return 900.0;
			}

			string name = item.Name.ToLower ();
			string path = item.Path.ToLower ();
			double score = 0;

			if (name.StartsWith (query.ToLower ())) {
				score += 100.0;
			} else if (name.Contains (query.ToLower ())) {
				score += 70.0;
			}

			int matchingTokens = 0;
			foreach (var token in queryTokens) {
				if (name.Contains (token)) {
					matchingTokens++;
				}
			}
			if (matchingTokens > 0) {
				score += (double)matchingTokens / queryTokens.Length * 50.0;
			}

			var nameWords = name.Split (new[] { ' ', '_', '-', '.' }, StringSplitOptions.RemoveEmptyEntries);
			double maxFuzzyScore = 0;
			foreach (var qToken in queryTokens) {
				foreach (var word in nameWords) {
					if (word.Length < 3 || qToken.Length < 3) continue;
					int dist = LevenshteinDistance (qToken, word);
					double similarity = 1.0 - ((double)dist / Math.Max (qToken.Length, word.Length));
					if (similarity > 0.7 && similarity > maxFuzzyScore) {
						maxFuzzyScore = similarity;
					}
				}
			}
			score += maxFuzzyScore * 40.0;

			double maxSemanticScore = 0;
			foreach (var extToken in expandedTokens) {
				if (queryTokens.Contains (extToken, StringComparer.OrdinalIgnoreCase)) continue;

				if (name.Contains (extToken)) {
					maxSemanticScore = Math.Max (maxSemanticScore, 0.6);
				} else {
					foreach (var word in nameWords) {
						int dist = LevenshteinDistance (extToken, word);
						double similarity = 1.0 - ((double)dist / Math.Max (extToken.Length, word.Length));
						if (similarity > 0.7) {
							maxSemanticScore = Math.Max (maxSemanticScore, 0.4);
						}
					}
				}
			}
			score += maxSemanticScore * 30.0;

			// Only add app/action bonus if there was an actual match
			if (score > 0) {
				if (item.IsApp) score += 10.0;
				if (item.IsAction) score += 20.0;
			}

			return score;
		}

		public static int LevenshteinDistance (string s, string t)
		{
			if (string.IsNullOrEmpty (s)) return string.IsNullOrEmpty (t) ? 0 : t.Length;
			if (string.IsNullOrEmpty (t)) return s.Length;
			int n = s.Length;
			int m = t.Length;
			int[,] d = new int[n + 1, m + 1];
			for (int i = 0; i <= n; d[i, 0] = i++) ;
			for (int j = 0; j <= m; d[0, j] = j++) ;
			for (int i = 1; i <= n; i++) {
				for (int j = 1; j <= m; j++) {
					int cost = (t[j - 1] == s[i - 1]) ? 0 : 1;
					d[i, j] = Math.Min (Math.Min (d[i - 1, j] + 1, d[i, j - 1] + 1), d[i - 1, j - 1] + cost);
				}
			}
			return d[n, m];
		}
	}
}

